// ===== ADMIN FUNCTIONS =====

// ===== GLOBAL HELPER FUNCTIONS =====
function $val(id) {
    var el = document.getElementById(id);
    return el ? el.value.trim() : '';
}

function $setVal(id, val) {
    var el = document.getElementById(id);
    if (el) el.value = val || '';
}

function $setText(id, text) {
    var el = document.getElementById(id);
    if (el) el.textContent = text;
}

function $setHide(id, hide) {
    var el = document.getElementById(id);
    if (el) el.style.display = hide ? 'none' : 'block';
}

var currentProfileId = null;

function initAdminDashboard() {
    appData = loadData();

    // Safety: ensure arrays exist
    if (!appData.students) appData.students = [];
    if (!appData.records) appData.records = [];
    if (!appData.attendance) appData.attendance = [];
    if (!appData.cashbook) appData.cashbook = [];

    // ✅ Helper — jalankan fungsi dengan try-catch berasingan
    // Kalau 1 fungsi gagal, fungsi lain tetap jalan
    function safeInit(fnName, fn) {
        try {
            fn();
        } catch (e) {
            console.error('❌ initAdminDashboard — gagal: ' + fnName, e);
            // Teruskan ke fungsi seterusnya walaupun ada error
        }
    }

    safeInit('updateStats',              function() { updateStats(); });
    safeInit('renderStudentList',        function() { renderStudentList(); });
    safeInit('renderProfileList',        function() {
        if (document.getElementById('profileListContainer')) {
            renderProfileList();
        }
    });
    safeInit('populateStudentDropdown',  function() { populateStudentDropdown(); });
    safeInit('populateJuzDropdown',      function() { populateJuzDropdown(); });
    safeInit('setDefaultDate',           function() { setDefaultDate(); });
    safeInit('generateReport',           function() { generateReport(); });
    safeInit('initAttendance',           function() { initAttendance(); });
    safeInit('initCashbook',             function() { initCashbook(); });
    safeInit('initGallery',              function() { initGallery(); });
    safeInit('initFinancePro',           function() { initFinancePro(); });
    safeInit('initPrayerTimes',          function() { initPrayerTimes(); });
    safeInit('initBackupSystem',         function() { initBackupSystem(); });
    safeInit('initPunchAdmin',           function() { initPunchAdmin(); });
    safeInit('initSchedule',             function() {
        if (typeof initSchedule === 'function') initSchedule();
    // initDapurAdmin dipanggil dari switchAdminCategory bila user klik tab
    // (sama pattern dengan initHutang & initInfaqAdmin)
    });
}

function updateStats() {
    var students = appData.students || [];
    var records = appData.records || [];

    var totalStudentsEl = document.getElementById('totalStudents');
    var totalRecordsEl = document.getElementById('totalRecords');

    if (totalStudentsEl) totalStudentsEl.textContent = students.length;
    if (totalRecordsEl) totalRecordsEl.textContent = records.length;

    var avgScoreEl = document.getElementById('avgScore');
    if (records.length > 0) {
        var total = 0;
        for (var i = 0; i < records.length; i++) {
            total += (records[i].score || 0);
        }
        var avg = Math.round(total / records.length);
        if (avgScoreEl) avgScoreEl.textContent = avg;
    } else {
        if (avgScoreEl) avgScoreEl.textContent = '0';
    }

    var completedJuz = [];
    for (var i = 0; i < records.length; i++) {
        if (records[i].score >= 80) {
            var j = records[i].juz;
            if (Array.isArray(j)) {
                for (var k = 0; k < j.length; k++) {
                    if (completedJuz.indexOf(j[k]) === -1) completedJuz.push(j[k]);
                }
            } else {
                if (completedJuz.indexOf(j) === -1) completedJuz.push(j);
            }
        }
    }
    var completedJuzEl = document.getElementById('completedJuz');
    if (completedJuzEl) completedJuzEl.textContent = completedJuz.length;

        // Today attendance
    var todayStr = new Date().toISOString().split('T')[0];
    var todayAtt = null;
    if (appData.attendance) {
        for (var i = 0; i < appData.attendance.length; i++) {
            if (appData.attendance[i].date === todayStr) {
                todayAtt = appData.attendance[i];
                break;
            }
        }
    }
        var todayEl = document.getElementById('todayAttendance');
    if (todayEl) {
        var todayStr = new Date().toISOString().split('T')[0];
        var todayAtt = null;
        var attendance = appData.attendance || [];

        for (var i = 0; i < attendance.length; i++) {
            if (attendance[i].date === todayStr) {
                todayAtt = attendance[i];
                break;
            }
        }

        if (todayAtt && todayAtt.records) {
            var h = 0;
            for (var i = 0; i < todayAtt.records.length; i++) {
                if (todayAtt.records[i].status === 'hadir' || todayAtt.records[i].status === 'lewat') h++;
            }
            todayEl.textContent = h + '/' + todayAtt.records.length;
        } else {
            todayEl.textContent = '-';
        }
    }
}

function getStudentRecords(studentId) {
    var result = [];
    var records = appData.records || [];
    for (var i = 0; i < records.length; i++) {
        if (records[i].studentId === studentId) {
            result.push(records[i]);
        }
    }
    result.sort(function (a, b) {
        return new Date(a.date) - new Date(b.date);
    });
    return result;
}

// ===== FORMAT SURAH & JUZ =====
function formatSurahDisplay(surah) {
    if (Array.isArray(surah)) {
        if (surah.length <= 3) return surah.join(', ');
        return surah.slice(0, 3).join(', ') + ' (+' + (surah.length - 3) + ' lagi)';
    }
    return surah || '-';
}

function formatJuzDisplay(juz) {
    if (Array.isArray(juz)) {
        var parts = [];
        for (var i = 0; i < juz.length; i++) {
            parts.push('Juz ' + juz[i]);
        }
        return parts.join(', ');
    }
    return juz ? 'Juz ' + juz : '-';
}

// ===== RENDER STUDENT LIST =====
function renderStudentList() {
    var searchEl = document.getElementById('searchStudent');
    var search = searchEl ? searchEl.value.toLowerCase() : '';
    var tbody = document.getElementById('studentTableBody');

    var filtered = [];
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (search) {
            var nameMatch = s.name.toLowerCase().indexOf(search) > -1;
            var classMatch = s.class.toLowerCase().indexOf(search) > -1;
            var fatherMatch = s.fatherName && s.fatherName.toLowerCase().indexOf(search) > -1;
            var parentMatch = s.parentName && s.parentName.toLowerCase().indexOf(search) > -1;
            if (nameMatch || classMatch || fatherMatch || parentMatch) {
                filtered.push(s);
            }
        } else {
            filtered.push(s);
        }
    }

    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="9" class="text-center" style="padding:40px;"><div class="empty-state"><div class="empty-icon">📭</div><p>Tiada pelajar ditemui</p></div></td></tr>';
        return;
    }

    var html = '';
    for (var i = 0; i < filtered.length; i++) {
        var student = filtered[i];
        var records = getStudentRecords(student.id);
        var lastRecord = records.length > 0 ? records[records.length - 1] : null;
        var lastSurah = lastRecord ? formatSurahDisplay(lastRecord.surah) : '-';
        var lastScore = lastRecord ? lastRecord.score : '-';

        var surahSet = [];
        for (var j = 0; j < records.length; j++) {
            var rs = records[j].surah;
            if (Array.isArray(rs)) {
                for (var k = 0; k < rs.length; k++) {
                    if (surahSet.indexOf(rs[k]) === -1) surahSet.push(rs[k]);
                }
            } else {
                if (surahSet.indexOf(rs) === -1) surahSet.push(rs);
            }
        }
        var progress = Math.round((surahSet.length / 114) * 100);

        var progressClass = progress >= 60 ? 'progress-green' : progress >= 30 ? 'progress-yellow' : 'progress-red';
        var scoreClass = '';
        if (lastScore !== '-') {
            scoreClass = lastScore >= 80 ? 'badge-lancar' : lastScore >= 60 ? 'badge-sederhana' : 'badge-gagal';
        }

        // ✅ FIXED: escape parentDisplay & phoneDisplay
        var parentDisplay = escapeHtml(student.fatherName || student.parentName || '-');
        var phoneDisplay = escapeHtml(student.fatherPhone || student.parentPhone || '-');

        html += '<tr>';
        html += '<td>' + (i + 1) + '</td>';

        // ✅ FIXED: escape student.name dalam status badge & td
        var studentStatus = '';
        if (student.status === 'berhenti' || student.employStatus === 'resigned') {
            studentStatus = ' <span style="background:#fee2e2;color:#991b1b;padding:2px 8px;border-radius:10px;font-size:0.68rem;font-weight:700;">🔴 BERHENTI</span>';
        }
        html += '<td><strong>' + escapeHtml(student.name) + '</strong>' + studentStatus + '</td>';

        // ✅ FIXED: escape class
        html += '<td>' + escapeHtml(student.class) + '</td>';
        html += '<td style="font-size:0.85rem;">' + parentDisplay + '</td>';
        html += '<td style="font-size:0.85rem;">' + phoneDisplay + '</td>';

        // lastSurah datang dari formatSurahDisplay() — nama surah dari array tetap (selamat)
        // lastScore adalah nombor (selamat)
        html += '<td>' + lastSurah + '</td>';
        html += '<td><span class="badge ' + scoreClass + '">' + lastScore + (lastScore !== '-' ? '%' : '') + '</span></td>';
        html += '<td><div style="display:flex;align-items:center;gap:8px;"><div class="progress-bar" style="flex:1;"><div class="progress-fill ' + progressClass + '" style="width:' + progress + '%"></div></div><span style="font-size:0.75rem;color:var(--text-light);">' + progress + '%</span></div></td>';

        // ✅ FIXED: escape student.id dalam onclick attribute
        html += '<td><div style="display:flex;gap:5px;"><button class="btn btn-sm btn-view" onclick="viewStudent(\'' + escapeHtml(student.id) + '\')">👁</button><button class="btn btn-sm btn-delete" onclick="deleteStudent(\'' + escapeHtml(student.id) + '\')">🗑</button></div></td>';
        html += '</tr>';
    }

    tbody.innerHTML = html;
}

// ===== ADD STUDENT =====
function addStudent(event) {
    event.preventDefault();

    var getVal = function (id) {
        var el = document.getElementById(id);
        return el ? el.value.trim() : '';
    };

    // ✅ FIXED #4: Validate required fields di JS
    // (jangan harap HTML required sahaja — boleh bypass via devtools)
    var name       = getVal('studentName');
    var cls        = getVal('studentClass');
    var fatherName = getVal('fatherName');
    var loginId    = getVal('parentLoginId');
    var loginPass  = getVal('parentLoginPass');

    if (!name) {
        showToast('❌ Nama pelajar wajib diisi');
        return;
    }
    if (!cls) {
        showToast('❌ Kelas wajib dipilih');
        return;
    }
    if (!fatherName) {
        showToast('❌ Nama bapa wajib diisi');
        return;
    }
    if (!loginId) {
        showToast('❌ ID Login ibu bapa wajib diisi');
        return;
    }
    if (!loginPass) {
        showToast('❌ Kata laluan ibu bapa wajib diisi');
        return;
    }

    // Check duplicate loginId
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].parentLoginId === loginId) {
            showToast('❌ ID Login sudah digunakan oleh pelajar lain!');
            return;
        }
    }

    var juzSelect = document.getElementById('prevJuzCompleted');
    var selectedJuzArr = [];
    if (juzSelect) {
        for (var i = 0; i < juzSelect.selectedOptions.length; i++) {
            selectedJuzArr.push(juzSelect.selectedOptions[i].value);
        }
    }

    var newStudent = {
        id: 'STU' + Date.now(),
        name: name,
        ic: getVal('studentIC'),
        dob: getVal('studentDOB'),
        gender: getVal('studentGender'),
        class: cls,
        startDate: getVal('studentStartDate'),
        photo: getVal('studentPhoto'),
        address: {
            line1: getVal('address1'),
            line2: getVal('address2'),
            postcode: getVal('postcode'),
            city: getVal('city'),
            state: getVal('state')
        },
        fatherName: fatherName,
        fatherIC: getVal('fatherIC'),
        fatherPhone: getVal('fatherPhone'),
        fatherJob: getVal('fatherJob'),
        fatherEmail: getVal('fatherEmail'),
        motherName: getVal('motherName'),
        motherIC: getVal('motherIC'),
        motherPhone: getVal('motherPhone'),
        motherJob: getVal('motherJob'),
        emergencyName: getVal('emergencyName'),
        emergencyRelation: getVal('emergencyRelation'),
        emergencyPhone: getVal('emergencyPhone'),
        prevSchool: getVal('prevSchool'),
        prevSchoolDuration: getVal('prevSchoolDuration'),
        prevSchoolAddress: getVal('prevSchoolAddress'),
        prevTeacher: getVal('prevTeacher'),
        prevTeacherPhone: getVal('prevTeacherPhone'),
        quranLevel: getVal('quranLevel'),
        tajwidLevel: getVal('tajwidLevel'),
        prevJuzCompleted: selectedJuzArr,
        prevSurahList: getVal('prevSurahList'),
        prevAchievements: getVal('prevAchievements'),
        allergy: getVal('allergy'),
        chronicDisease: getVal('chronicDisease'),
        healthNotes: getVal('healthNotes'),
        parentName: fatherName,
        parentPhone: getVal('fatherPhone'),
        parentLoginId: loginId,
        parentLoginPass: loginPass,
        enrollReason: getVal('enrollReason'),
        hafazanTarget: getVal('hafazanTarget'),
        additionalNotes: getVal('additionalNotes'),
        createdAt: new Date().toISOString().split('T')[0]
    };

    appData.students.push(newStudent);

    // ✅ FIXED #4: try-catch + savePathSafely (bukan saveData whole-tree)
    try {
        savePathSafely('hafazanData/students', appData.students, function(ok) {
            if (ok) {
                document.getElementById('addStudentForm').reset();
                showToast('✅ Pelajar berjaya didaftarkan!');
                initAdminDashboard();
                switchTab('students', document.querySelector('.tab-btn'));
            } else {
                // Rollback local jika Firebase gagal
                appData.students.pop();
                showToast('❌ Gagal simpan ke Firebase. Sila cuba lagi.');
            }
        });
    } catch (e) {
        // Rollback local
        appData.students.pop();
        console.error('addStudent error:', e);
        showToast('❌ Ralat tidak dijangka. Sila cuba lagi.');
    }
}
function resetStudentForm() {
    document.getElementById('addStudentForm').reset();
    showToast('🔄 Borang telah dikosongkan');
}

// ===== DELETE STUDENT =====
function deleteStudent(studentId) {
    // ✅ FIXED #6: Cari student dulu untuk tunjuk nama dalam confirm
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }

    if (!student) {
        showToast('❌ Pelajar tidak ditemui');
        return;
    }

    // ✅ FIXED #6: Confirm dengan nama pelajar (bukan generic)
    if (!confirm('⚠️ Padam pelajar "' + student.name + '"?\n\nSemua rekod hafazan pelajar ini turut dipadam.\nTindakan ini TIDAK BOLEH diundur!')) return;

    // ✅ FIXED #6: Backup ke Firebase sebelum padam
    // Simpan dalam path berasingan — boleh recover kalau tersalah padam
    var deletedAt = new Date().toISOString();
    var backupData = {
        student: student,
        records: [],
        deletedAt: deletedAt,
        deletedBy: 'admin'
    };

    // Kumpul rekod pelajar untuk backup
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].studentId === studentId) {
            backupData.records.push(appData.records[i]);
        }
    }

    // Simpan backup ke Firebase dulu, baru padam
    if (firebaseDb && firebaseReady) {
        var backupKey = 'deleted_' + studentId + '_' + Date.now();
        firebaseDb.ref('deletedStudents/' + backupKey).set(backupData)
            .then(function() {
                // Backup berjaya — proceed padam
                performDeleteStudent(studentId, student.name);
            })
            .catch(function(err) {
                // Backup gagal — tanya confirm lagi sebelum proceed
                console.error('Backup gagal:', err);
                if (confirm('⚠️ Backup gagal disimpan.\n\nAdakah anda tetap ingin memadam tanpa backup?')) {
                    performDeleteStudent(studentId, student.name);
                }
            });
    } else {
        // Offline — padam terus (tak boleh backup)
        if (confirm('⚠️ Anda sedang offline. Backup tidak dapat disimpan.\n\nTeruskan padam?')) {
            performDeleteStudent(studentId, student.name);
        }
    }
}

// ✅ Helper — lakukan padam sebenar (dipanggil selepas backup selesai)
function performDeleteStudent(studentId, studentName) {
    var newStudents = [];
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id !== studentId) newStudents.push(appData.students[i]);
    }
    appData.students = newStudents;

    var newRecords = [];
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].studentId !== studentId) newRecords.push(appData.records[i]);
    }
    appData.records = newRecords;

    // ✅ FIXED: tulis students & records sahaja (bukan whole tree)
    savePathSafely('hafazanData/students', appData.students, function(ok1) {
        savePathSafely('hafazanData/records', appData.records, function(ok2) {
            if (ok1 && ok2) {
                showToast('🗑 Pelajar "' + studentName + '" telah dipadam (backup disimpan)');
            } else {
                showToast('⚠️ Padam berjaya tapi ada ralat sync Firebase');
            }
            initAdminDashboard();
        });
    });
}

// ===== VIEW STUDENT (Modal) =====
function viewStudent(studentId) {
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }

    // ✅ FIXED #3: Guard kalau student tak jumpa
    if (!student) {
        showToast('❌ Pelajar tidak ditemui');
        return;
    }

    var records = getStudentRecords(studentId);

    // ✅ FIXED: escape name untuk textContent (selamat tanpa escapeHtml)
    document.getElementById('modalStudentName').textContent = '📖 ' + student.name;

    var addr = student.address;
    var fullAddress = '-';
    if (addr) {
        var parts = [addr.line1, addr.line2, addr.postcode, addr.city, addr.state];
        var filtered = [];
        for (var i = 0; i < parts.length; i++) {
            if (parts[i]) filtered.push(parts[i]);
        }
        fullAddress = filtered.join(', ') || '-';
    }

    var html = '';

    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">👨‍🎓 Maklumat Pelajar</h3>';
    html += '<div class="info-grid">';
    html += '<div class="info-item"><span class="info-label">No. MyKid/MyKad:</span> ' + escapeHtml(student.ic || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tarikh Lahir:</span> ' + (student.dob ? formatDate(student.dob) : '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Jantina:</span> ' + escapeHtml(student.gender || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Kelas:</span> ' + escapeHtml(student.class || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tarikh Mula:</span> ' + (student.startDate ? formatDate(student.startDate) : '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Sasaran:</span> ' + escapeHtml(student.hafazanTarget || '-') + '</div>';
    html += '</div></div>';

    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">🏠 Alamat</h3>';
    // ✅ FIXED: escape fullAddress (datang dari data user)
    html += '<p style="color:var(--text);">' + escapeHtml(fullAddress) + '</p>';
    html += '</div>';

    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">👨‍👩‍👧 Ibu Bapa / Penjaga</h3>';
    html += '<div class="info-grid">';
    html += '<div class="info-item"><span class="info-label">Bapa:</span> ' + escapeHtml(student.fatherName || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tel Bapa:</span> ' + escapeHtml(student.fatherPhone || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Kerja Bapa:</span> ' + escapeHtml(student.fatherJob || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Ibu:</span> ' + escapeHtml(student.motherName || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tel Ibu:</span> ' + escapeHtml(student.motherPhone || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Kerja Ibu:</span> ' + escapeHtml(student.motherJob || '-') + '</div>';
    if (student.emergencyName) {
        html += '<div class="info-item"><span class="info-label">Kecemasan:</span> ' + escapeHtml(student.emergencyName) + ' (' + escapeHtml(student.emergencyRelation || '-') + ')</div>';
        html += '<div class="info-item"><span class="info-label">Tel Kecemasan:</span> ' + escapeHtml(student.emergencyPhone || '-') + '</div>';
    }
    html += '</div></div>';

    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">🏆 Pencapaian Terdahulu</h3>';
    html += '<div class="info-grid">';
    html += '<div class="info-item"><span class="info-label">Sekolah Lama:</span> ' + escapeHtml(student.prevSchool || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tahap Bacaan:</span> ' + escapeHtml(student.quranLevel || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Tahap Tajwid:</span> ' + escapeHtml(student.tajwidLevel || '-') + '</div>';
    html += '<div class="info-item"><span class="info-label">Juz Dihafaz:</span> ' + escapeHtml(student.prevJuzCompleted ? student.prevJuzCompleted.join(', ') : '-') + '</div>';
    html += '</div>';
    if (student.prevAchievements) {
        html += '<div style="margin-top:10px;"><span class="info-label">Pencapaian:</span>';
        // ✅ FIXED: escape prevAchievements
        html += '<p style="white-space:pre-line;margin-top:5px;color:var(--text);">' + escapeHtml(student.prevAchievements) + '</p></div>';
    }
    html += '</div>';

    if (student.allergy || student.chronicDisease || student.healthNotes) {
        html += '<div class="modal-section">';
        html += '<h3 class="modal-section-title">🏥 Maklumat Kesihatan</h3>';
        html += '<div class="info-grid">';
        html += '<div class="info-item"><span class="info-label">Alahan:</span> ' + escapeHtml(student.allergy || 'Tiada') + '</div>';
        html += '<div class="info-item"><span class="info-label">Penyakit Kronik:</span> ' + escapeHtml(student.chronicDisease || 'Tiada') + '</div>';
        html += '</div>';
        if (student.healthNotes) {
            html += '<p style="margin-top:8px;color:var(--text);">📝 ' + escapeHtml(student.healthNotes) + '</p>';
        }
        html += '</div>';
    }

    // ✅ FIXED: guna maskPassword untuk kata laluan
    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">🔐 Maklumat Login Ibu Bapa</h3>';
    html += '<div class="info-grid">';
    html += '<div class="info-item"><span class="info-label">ID Login:</span> <code>' + escapeHtml(student.parentLoginId || '-') + '</code></div>';
    html += '<div class="info-item"><span class="info-label">Kata Laluan:</span> <code>' + maskPassword(student.parentLoginPass, student.id) + '</code></div>';
    html += '</div></div>';

    html += '<div class="modal-section">';
    html += '<h3 class="modal-section-title">📚 Sejarah Hafazan (' + records.length + ' rekod)</h3>';

    if (records.length === 0) {
        html += '<div class="empty-state"><div class="empty-icon">📭</div><p>Belum ada rekod hafazan</p></div>';
    } else {
        html += '<div class="table-responsive"><table class="report-table">';
        html += '<thead><tr>';
        html += '<th>Tarikh</th><th>Sesi</th><th>Jenis</th><th>Penyemak</th>';
        html += '<th>Bacaan</th><th>Markah</th><th>Status</th><th>Catatan</th>';
        html += '</tr></thead><tbody>';

        for (var i = records.length - 1; i >= 0; i--) {
            var r = records[i];
            var badgeClass = getBadgeClass(r.status);

            html += '<tr>';
            html += '<td>' + formatDate(r.date) + '</td>';
            html += '<td>' + (typeof getSessionBadge === 'function' ? getSessionBadge(r.session) : escapeHtml(r.session || '-')) + '</td>';
            html += '<td>' + (typeof getReadingTypeBadge === 'function' ? getReadingTypeBadge(r.readingType) : escapeHtml(r.readingType || '-')) + '</td>';

            // ✅ FIXED: escape checkerName
            var checkerIcon = r.checkerType === 'pelajar' ? '👨‍🎓' : '👨‍🏫';
            html += '<td><small>' + checkerIcon + ' ' + escapeHtml(r.checkerName || '-') + '</small></td>';

            html += '<td>';
            if (r.isIqra) {
                html += '📕 ' + escapeHtml(r.iqraBook || 'Iqra');
                html += '<br><small>ms ' + escapeHtml(String(r.iqraPage || '-')) + ', baris ' + escapeHtml(String(r.iqraLineFrom || '-')) + '-' + escapeHtml(String(r.iqraLineTo || '-')) + '</small>';
            } else {
                var surahText = typeof formatSurahWithAyatFull === 'function' ? formatSurahWithAyatFull(r) : escapeHtml(r.surah || '-');
                html += surahText;
                var juzText = typeof formatJuzDisplay === 'function' ? formatJuzDisplay(r.juz) : escapeHtml(String(r.juz || '-'));
                html += '<br><small style="color:#64748b;">' + juzText + '</small>';
            }
            html += '</td>';

            // score adalah nombor — selamat
            html += '<td><strong>' + r.score + '%</strong></td>';
            html += '<td><span class="badge ' + badgeClass + '">' + escapeHtml(r.status || '-') + '</span></td>';

            // ✅ FIXED: escape notes
            html += '<td style="font-size:0.8rem;max-width:200px;">' + escapeHtml(r.notes || '-') + '</td>';
            html += '</tr>';
        }

        html += '</tbody></table></div>';
    }

    html += '</div>';

    document.getElementById('modalBody').innerHTML = html;
    document.getElementById('studentModal').classList.remove('hidden');
}

function closeModal() {
    document.getElementById('studentModal').classList.add('hidden');
}

// ===== DROPDOWNS =====
function populateStudentDropdown() {
    var select = document.getElementById('recordStudent');
    if (!select) return;
    select.innerHTML = '<option value="">Pilih pelajar</option>';
    
    // Filter HANYA pelajar aktif
    var activeStudents = appData.students.filter(function(s) {
        var status = s.status || 'aktif';
        return status === 'aktif';
    });
    
    // Sort by name
    activeStudents.sort(function(a, b) {
        return (a.name || '').localeCompare(b.name || '');
    });
    
    for (var i = 0; i < activeStudents.length; i++) {
        var s = activeStudents[i];
        select.innerHTML += '<option value="' + s.id + '">' + s.name + ' (' + s.class + ')</option>';
    }
    
    // Populate checker dropdowns juga
    if (typeof populateCheckerDropdowns === 'function') {
        populateCheckerDropdowns();
    }
}
function populateJuzDropdown() {
    var select = document.getElementById('recordJuz');
    if (!select) return;
    select.innerHTML = '<option value="">Pilih Juz</option>';
    for (var i = 1; i <= 30; i++) {
        select.innerHTML += '<option value="' + i + '">Juz ' + i + '</option>';
    }
}

function updateSurahList() {
    var juz = parseInt(document.getElementById('recordJuz').value);
    var select = document.getElementById('recordSurah');
    if (!select) return;
    select.innerHTML = '<option value="">Pilih Surah</option>';
    if (!juz) return;
    for (var i = 0; i < SURAH_LIST.length; i++) {
        if (SURAH_LIST[i].juz === juz) {
            select.innerHTML += '<option value="' + SURAH_LIST[i].name + '">' + SURAH_LIST[i].no + '. ' + SURAH_LIST[i].name + '</option>';
        }
    }
}

function setDefaultDate() {
    var el = document.getElementById('recordDate');
    if (el) el.value = new Date().toISOString().split('T')[0];
}

// ===== TAB SWITCHING =====
function switchTab(tabName, btn) {
    var tabs = document.querySelectorAll('.tab-content');
    for (var i = 0; i < tabs.length; i++) {
        tabs[i].classList.remove('active');
    }
    var btns = document.querySelectorAll('.tab-btn');
    for (var i = 0; i < btns.length; i++) {
        btns[i].classList.remove('active');
    }

    var targetTab = document.getElementById('tab-' + tabName);
    if (targetTab) targetTab.classList.add('active');
    if (btn) btn.classList.add('active');

    // BARU: Auto-scroll active tab into view
    if (btn) {
        setTimeout(function() {
            btn.scrollIntoView({
                behavior: 'smooth',
                block: 'nearest',
                inline: 'center'
            });
        }, 100);
    }

    // Auto-init untuk tab tertentu
    if (tabName === 'manageRecords' && typeof initManageRecords === 'function') {
        initManageRecords();
    }
    if (tabName === 'progressHafazan' && typeof initProgressHafazan === 'function') {
        initProgressHafazan();
    }
}

// ===== REPORTS =====
function generateReport() {
    var reportClass = document.getElementById('reportClass');
    if (!reportClass) return;
    var classFilter = reportClass.value;
    var students = [];

    for (var i = 0; i < appData.students.length; i++) {
        if (classFilter === 'all' || appData.students[i].class === classFilter) {
            students.push(appData.students[i]);
        }
    }

    var reportContent = document.getElementById('reportContent');
    if (!reportContent) return;

    if (students.length === 0) {
        reportContent.innerHTML = '<div class="empty-state" style="padding:40px;"><div class="empty-icon">📭</div><p>Tiada data untuk dipaparkan</p></div>';
        return;
    }

    var html = '<div style="padding:20px;"><table class="report-table">';
    html += '<thead><tr><th>No</th><th>Nama Pelajar</th><th>Kelas</th><th>Jml. Rekod</th><th>Surah Dihafaz</th><th>Purata Markah</th><th>Status Terkini</th></tr></thead><tbody>';

    for (var i = 0; i < students.length; i++) {
        var student = students[i];
        var records = getStudentRecords(student.id);

        var surahSet = [];
        var totalScore = 0;
        for (var j = 0; j < records.length; j++) {
            totalScore += records[j].score;
            var rs = records[j].surah;
            if (Array.isArray(rs)) {
                for (var k = 0; k < rs.length; k++) {
                    if (surahSet.indexOf(rs[k]) === -1) surahSet.push(rs[k]);
                }
            } else {
                if (surahSet.indexOf(rs) === -1) surahSet.push(rs);
            }
        }
        var avg = records.length > 0 ? Math.round(totalScore / records.length) : 0;
        var lastRecord = records.length > 0 ? records[records.length - 1] : null;
        var lastStatus = lastRecord ? lastRecord.status : '-';
        var badgeClass = getBadgeClass(lastStatus);

        html += '<tr>';
        html += '<td>' + (i + 1) + '</td>';
        html += '<td><strong>' + student.name + '</strong></td>';
        html += '<td>' + student.class + '</td>';
        html += '<td>' + records.length + '</td>';
        html += '<td>' + surahSet.length + '</td>';
        html += '<td><strong>' + avg + '%</strong></td>';
        html += '<td><span class="badge ' + badgeClass + '">' + lastStatus + '</span></td>';
        html += '</tr>';
    }

    html += '</tbody></table></div>';
    reportContent.innerHTML = html;
}

// ===== HELPERS =====
function getBadgeClass(status) {
    if (status === 'Lancar') return 'badge-lancar';
    if (status === 'Sederhana') return 'badge-sederhana';
    if (status === 'Perlu Ulang') return 'badge-ulang';
    if (status === 'Tidak Lulus') return 'badge-gagal';
    return '';
}

function formatDate(dateStr) {
    var d = new Date(dateStr);
    var months = ['Jan', 'Feb', 'Mac', 'Apr', 'Mei', 'Jun', 'Jul', 'Ogo', 'Sep', 'Okt', 'Nov', 'Dis'];
    return d.getDate() + ' ' + months[d.getMonth()] + ' ' + d.getFullYear();
}

function getMonthName(num) {
    var months = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                  'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    return months[num] || '';
}

function showToast(message) {
    var toast = document.getElementById('toast');
    if (!toast) return;
    var msgEl = document.getElementById('toastMsg');
    if (msgEl) msgEl.textContent = message;
    toast.classList.remove('hidden');
    setTimeout(function () {
        toast.classList.add('hidden');
    }, 3000);
}

// ===== PROFILE LIST =====
function renderProfileList() {
    var container = document.getElementById('profileListContainer');
    if (!container) return;

    var searchEl = document.getElementById('profileSearch');
    var search = searchEl ? searchEl.value.toLowerCase() : '';
    var filterEl = document.getElementById('profileFilter');
    var classFilter = filterEl ? filterEl.value : 'all';

    var students = [];
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (!s) continue;
        var classOk = classFilter === 'all' || s.class === classFilter;
        var searchOk = true;
        if (search) {
            searchOk = s.name.toLowerCase().indexOf(search) > -1 ||
                (s.fatherName && s.fatherName.toLowerCase().indexOf(search) > -1) ||
                (s.motherName && s.motherName.toLowerCase().indexOf(search) > -1) ||
                (s.parentLoginId && s.parentLoginId.toLowerCase().indexOf(search) > -1);
        }
        if (classOk && searchOk) students.push(s);
    }

    if (students.length === 0) {
        container.innerHTML = '<div class="empty-state" style="grid-column:1/-1;padding:60px;"><div class="empty-icon">📭</div><p>Tiada pelajar ditemui</p></div>';
        return;
    }

    // Separate by status
var aktifList = [];
var inactiveList = [];

for (var i = 0; i < students.length; i++) {
    var s = students[i];
    var status = s.status || 'aktif';
    
    if (status === 'aktif') {
        aktifList.push(s);
    } else {
        inactiveList.push(s);
    }
}

    var html = '';

    // ===== PELAJAR AKTIF =====
    if (aktifList.length > 0) {
        html += '<div style="grid-column:1/-1;margin-bottom:10px;display:flex;align-items:center;gap:10px;">';
        html += '<h3 style="color:#7c3aed;font-size:1rem;margin:0;">🟢 Pelajar Aktif (' + aktifList.length + ')</h3>';
        html += '</div>';

        for (var i = 0; i < aktifList.length; i++) {
            html += buildProfileCard(aktifList[i], false);
        }
    }

    // ===== PELAJAR TIDAK AKTIF =====
if (inactiveList.length > 0) {
    html += '<div style="grid-column:1/-1;margin:20px 0 10px;display:flex;align-items:center;gap:10px;">';
    html += '<h3 style="color:#64748b;font-size:1rem;margin:0;">📋 Pelajar Tidak Aktif (' + inactiveList.length + ')</h3>';
    html += '<small style="color:#94a3b8;">Berhenti / Dibuang / Cuti / Pindah / Tamat</small>';
    html += '</div>';

    for (var i = 0; i < inactiveList.length; i++) {
        html += buildProfileCard(inactiveList[i]);
    }
}

    container.innerHTML = html;
}

function buildProfileCard(student) {
    var records = getStudentRecords(student.id);

    var surahSet = [];
    var totalScore = 0;
    for (var j = 0; j < records.length; j++) {
        totalScore += records[j].score;
        var rs = records[j].surah;
        if (Array.isArray(rs)) {
            for (var k = 0; k < rs.length; k++) {
                if (surahSet.indexOf(rs[k]) === -1) surahSet.push(rs[k]);
            }
        } else {
            if (surahSet.indexOf(rs) === -1) surahSet.push(rs);
        }
    }
    var avgScore = records.length > 0 ? Math.round(totalScore / records.length) : 0;
    var genderIcon = student.gender === 'Perempuan' ? '👧' : '👦';

    // ===== GET STATUS INFO =====
    var status = student.status || 'aktif';
    var statusConfig = {
        aktif:    { label: 'AKTIF',    icon: '🟢', bg: '#e9d5ff', color: '#5b21b6', borderColor: '#a78bfa' },
        berhenti: { label: 'BERHENTI', icon: '🔴', bg: '#fee2e2', color: '#991b1b', borderColor: '#ef4444' },
        dibuang:  { label: 'DIBUANG',  icon: '⚫', bg: '#f1f5f9', color: '#1f2937', borderColor: '#475569' },
        cuti:     { label: 'CUTI',     icon: '🟡', bg: '#fef3c7', color: '#78350f', borderColor: '#f59e0b' },
        pindah:   { label: 'PINDAH',   icon: '🔵', bg: '#dbeafe', color: '#1e40af', borderColor: '#3b82f6' },
        tamat:    { label: 'TAMAT',    icon: '🟣', bg: '#ede9fe', color: '#5b21b6', borderColor: '#8b5cf6' }
    };

    var sConfig = statusConfig[status] || statusConfig.aktif;
    var isActive = status === 'aktif';
    var cardOpacity = isActive ? '' : 'opacity:0.85;';
    var headerBg = isActive ? '' : 'background:linear-gradient(135deg,#475569,#334155);';

    var statusBadge = '<div style="margin-top:5px;">';
    statusBadge += '<span style="background:' + sConfig.bg + ';color:' + sConfig.color + ';padding:4px 12px;border-radius:12px;font-size:0.75rem;font-weight:800;border:2px solid ' + sConfig.borderColor + ';">';
    statusBadge += sConfig.icon + ' ' + sConfig.label;
    if (student.endDate) {
        // ✅ FIXED: escape endDate
        statusBadge += ' • Tamat: ' + escapeHtml(student.endDate);
    }
    statusBadge += '</span>';

    if (student.endReason && !isActive) {
        // ✅ FIXED: escape endReason
        statusBadge += '<div style="font-size:0.72rem;color:rgba(255,255,255,0.85);margin-top:5px;">Sebab: ' + escapeHtml(student.endReason) + '</div>';
    }
    statusBadge += '</div>';

    var html = '';
    html += '<div class="profile-card" style="' + cardOpacity + '">';

    // Header
    html += '<div class="profile-card-header" style="' + headerBg + '">';
    html += '<div class="profile-avatar">' + genderIcon + '</div>';
    html += '<div class="profile-card-name">';
    // ✅ FIXED: escape name & class
    html += '<h3>' + escapeHtml(student.name) + '</h3>';
    html += '<p>' + escapeHtml(student.class) + '</p>';
    html += statusBadge;
    html += '</div>';
    html += '</div>';

    // Body
    html += '<div class="profile-card-body">';
    // ✅ FIXED: escape ic, fatherName, parentName, fatherPhone, parentPhone, quranLevel
    html += '<div class="profile-info-row"><span class="profile-info-label">No. IC:</span><span class="profile-info-value">' + escapeHtml(student.ic || '-') + '</span></div>';
    html += '<div class="profile-info-row"><span class="profile-info-label">Bapa:</span><span class="profile-info-value">' + escapeHtml(student.fatherName || student.parentName || '-') + '</span></div>';
    html += '<div class="profile-info-row"><span class="profile-info-label">Telefon:</span><span class="profile-info-value">' + escapeHtml(student.fatherPhone || student.parentPhone || '-') + '</span></div>';
    html += '<div class="profile-info-row"><span class="profile-info-label">Surah Dihafaz:</span><span class="profile-info-value">' + surahSet.length + ' surah</span></div>';
    html += '<div class="profile-info-row"><span class="profile-info-label">Purata Markah:</span><span class="profile-info-value">' + avgScore + '%</span></div>';
    html += '<div class="profile-info-row"><span class="profile-info-label">Tahap Bacaan:</span><span class="profile-info-value">' + escapeHtml(student.quranLevel || '-') + '</span></div>';

    if (!isActive) {
        if (student.endDate) {
            // ✅ FIXED: escape endDate
            html += '<div class="profile-info-row"><span class="profile-info-label">Tarikh Tamat:</span><span class="profile-info-value" style="color:' + sConfig.color + ';font-weight:700;">' + escapeHtml(student.endDate) + '</span></div>';
        }
        if (student.endReason) {
            // ✅ FIXED: escape endReason
            html += '<div class="profile-info-row"><span class="profile-info-label">Sebab:</span><span class="profile-info-value" style="color:' + sConfig.color + ';">' + escapeHtml(student.endReason) + '</span></div>';
        }
    }

    if (student.startDate) {
        // ✅ FIXED: escape startDate
        html += '<div class="profile-info-row"><span class="profile-info-label">Tarikh Mula:</span><span class="profile-info-value">' + escapeHtml(student.startDate) + '</span></div>';
    }

    html += '</div>';

    // Footer — onclick attributes guna escapeHtml untuk id & name
    // ✅ FIXED: escape id dalam onclick
    // ✅ FIXED: guna escapeHtml untuk name dalam shareUpdateLink (bukan string replace manual)
    html += '<div class="profile-card-footer">';
    html += '<button class="btn btn-sm btn-view" onclick="viewProfileDetail(\'' + escapeHtml(student.id) + '\')">👁 Lihat Penuh</button>';
html += '<button class="btn btn-sm btn-print" onclick="viewProfileDetail(\'' + escapeHtml(student.id) + '\'); setTimeout(printProfile, 500);">🖨 Cetak</button>';

// ✅ FIXED: name dalam onclick — escapeHtml handle both ' dan "
html += '<button class="btn btn-sm" style="background:#a78bfa;color:white;" onclick="shareUpdateLink(\'' + escapeHtml(student.id) + '\', \'' + escapeHtml(student.name) + '\', \'' + escapeHtml(student.fatherPhone || student.motherPhone || '') + '\')">📤 Hantar Link</button>';
html += '<button class="btn btn-sm btn-delete" onclick="deleteStudent(\'' + escapeHtml(student.id) + '\')">🗑</button>';
    html += '</div>';

    html += '</div>';

    return html;
}

// ===== PROFILE DETAIL =====
function viewProfileDetail(studentId) {
    currentProfileId = studentId;
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    var records = getStudentRecords(studentId);

    if (!student) {
        showToast('❌ Pelajar tidak ditemui');
        return;
    }

    var surahSet = [];
    var totalScore = 0;
    for (var j = 0; j < records.length; j++) {
        totalScore += records[j].score;
        var rs = records[j].surah;
        if (Array.isArray(rs)) {
            for (var k = 0; k < rs.length; k++) {
                if (surahSet.indexOf(rs[k]) === -1) surahSet.push(rs[k]);
            }
        } else {
            if (surahSet.indexOf(rs) === -1) surahSet.push(rs);
        }
    }
    var avgScore = records.length > 0 ? Math.round(totalScore / records.length) : 0;
    var genderIcon = student.gender === 'Perempuan' ? '👧' : '👦';

    var addr = student.address;
    var fullAddress = '-';
    if (addr) {
        var parts = [addr.line1, addr.line2, addr.postcode, addr.city, addr.state];
        var filtered = [];
        for (var i = 0; i < parts.length; i++) {
            if (parts[i]) filtered.push(parts[i]);
        }
        fullAddress = filtered.join(', ') || '-';
    }

    var html = '';

    // Header
    html += '<div class="profile-detail-header">';
    html += '<div class="profile-detail-avatar">' + genderIcon + '</div>';
    html += '<div class="profile-detail-name">';
    // ✅ FIXED
html += '<h2>' + escapeHtml(student.name) + '</h2>';
html += '<p>' + escapeHtml(student.class) + '</p>';
html += '<span class="detail-badge">ID: ' + escapeHtml(student.id) + '</span>';
html += '<span class="detail-badge">' + escapeHtml(student.gender || '-') + '</span>';
// surahSet.length & avgScore adalah nombor — selamat tanpa escape
html += '<span class="detail-badge">📖 ' + surahSet.length + ' Surah</span>';
html += '<span class="detail-badge">⭐ ' + avgScore + '%</span>';
if (student.hafazanTarget) {
    // ✅ FIXED
    html += '<span class="detail-badge">🎯 ' + escapeHtml(student.hafazanTarget) + '</span>';
}
    html += '</div></div></div>';

    // Sections
    html += '<div class="detail-sections">';

    // Maklumat Pelajar
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header green">👨‍🎓 Maklumat Pelajar</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Nama Penuh', student.name);
    html += detailRow('No. MyKid/MyKad', student.ic);
    html += detailRow('Tarikh Lahir', student.dob ? formatDate(student.dob) : '-');
    html += detailRow('Jantina', student.gender);
    html += detailRow('Kelas', student.class);
    html += detailRow('Tarikh Mula', student.startDate ? formatDate(student.startDate) : '-');
    html += detailRow('Tarikh Daftar', student.createdAt ? formatDate(student.createdAt) : '-');
    html += '</div></div>';

    // Alamat
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header blue">🏠 Alamat Rumah</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Alamat', fullAddress);
    if (addr) {
        html += detailRow('Poskod', addr.postcode);
        html += detailRow('Bandar', addr.city);
        html += detailRow('Negeri', addr.state);
    }
    html += '</div></div>';

    // Bapa
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header orange">👨 Maklumat Bapa</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Nama', student.fatherName);
    html += detailRow('No. MyKad', student.fatherIC);
    html += detailRow('No. Telefon', student.fatherPhone, true);
    html += detailRow('Pekerjaan', student.fatherJob);
    html += detailRow('Email', student.fatherEmail);
    html += '</div></div>';

    // Ibu
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header orange">👩 Maklumat Ibu</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Nama', student.motherName);
    html += detailRow('No. MyKad', student.motherIC);
    html += detailRow('No. Telefon', student.motherPhone, true);
    html += detailRow('Pekerjaan', student.motherJob);
    html += '</div></div>';

    // Kecemasan
    if (student.emergencyName) {
        html += '<div class="detail-section">';
        html += '<div class="detail-section-header red">🆘 Penjaga Kecemasan</div>';
        html += '<div class="detail-section-body">';
        html += detailRow('Nama', student.emergencyName);
        html += detailRow('Hubungan', student.emergencyRelation);
        html += detailRow('No. Telefon', student.emergencyPhone, true);
        html += '</div></div>';
    }

    // Sekolah Terdahulu
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header purple">🏫 Sekolah Terdahulu</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Nama Sekolah', student.prevSchool);
    html += detailRow('Alamat', student.prevSchoolAddress);
    html += detailRow('Tempoh', student.prevSchoolDuration);
    html += detailRow('Guru Terdahulu', student.prevTeacher);
    html += detailRow('Tel Guru', student.prevTeacherPhone);
    html += '</div></div>';

    // Pencapaian
    html += '<div class="detail-section detail-section-full">';
    html += '<div class="detail-section-header gold">🏆 Pencapaian Al-Quran Terdahulu</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Tahap Bacaan', student.quranLevel);
    html += detailRow('Tahap Tajwid', student.tajwidLevel);
    html += detailRow('Juz Dihafaz', student.prevJuzCompleted ? student.prevJuzCompleted.join(', ') : '-');
    if (student.prevSurahList) {
        html += '<div class="detail-row"><div class="detail-label">Surah Dihafaz</div><div class="detail-value"><pre>' + escapeHtml(student.prevSurahList) + '</pre></div></div>';
}
    if (student.prevAchievements) {
        html += '<div class="detail-row"><div class="detail-label">Pencapaian/Anugerah</div><div class="detail-value"><pre>' + escapeHtml(student.prevAchievements) + '</pre></div></div>';
}
    html += '</div></div>';

    // Kesihatan
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header red">🏥 Maklumat Kesihatan</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('Alahan', student.allergy || 'Tiada');
    html += detailRow('Penyakit Kronik', student.chronicDisease || 'Tiada');
    html += detailRow('Catatan Kesihatan', student.healthNotes || 'Tiada');
    html += '</div></div>';

    // Login
    html += '<div class="detail-section">';
    html += '<div class="detail-section-header teal">🔐 Akaun Login Ibu Bapa</div>';
    html += '<div class="detail-section-body">';
    html += detailRow('ID Login', student.parentLoginId, false, true);
    html += detailRow('Kata Laluan', student.parentLoginPass, false, true);
    html += '</div></div>';

    // Catatan
    if (student.enrollReason || student.additionalNotes || student.hafazanTarget) {
        html += '<div class="detail-section detail-section-full">';
        html += '<div class="detail-section-header green">📝 Catatan Tambahan</div>';
        html += '<div class="detail-section-body">';
        html += detailRow('Sebab Daftar', student.enrollReason);
        html += detailRow('Sasaran Hafazan', student.hafazanTarget);
        html += detailRow('Catatan Lain', student.additionalNotes);
        html += '</div></div>';
    }

    // Rekod Hafazan
    html += '<div class="detail-section detail-section-full">';
    html += '<div class="detail-section-header green">📚 Rekod Hafazan (' + records.length + ' rekod)</div>';
    html += '<div class="detail-section-body">';

    if (records.length === 0) {
        html += '<div class="empty-state"><div class="empty-icon">📭</div><p>Belum ada rekod hafazan</p></div>';
    } else {
                html += '<div class="table-responsive"><table class="report-table">';
        html += '<thead><tr>';
        html += '<th>Tarikh</th>';
        html += '<th>Sesi</th>';
        html += '<th>Jenis</th>';
        html += '<th>Penyemak</th>';
        html += '<th>Bacaan</th>';
        html += '<th>Markah</th>';
        html += '<th>Status</th>';
        html += '<th>Catatan</th>';
        html += '</tr></thead><tbody>';

        for (var i = records.length - 1; i >= 0; i--) {
            var r = records[i];
            html += '<tr>';
            html += '<td>' + formatDate(r.date) + '</td>';
            html += '<td>' + (typeof getSessionBadge === 'function' ? getSessionBadge(r.session) : (r.session || '-')) + '</td>';
            html += '<td>' + (typeof getReadingTypeBadge === 'function' ? getReadingTypeBadge(r.readingType) : (r.readingType || '-')) + '</td>';

            var cIcon = r.checkerType === 'pelajar' ? '👨‍🎓' : '👨‍🏫';
            html += '<td><small>' + cIcon + ' ' + escapeHtml(r.checkerName || '-') + '</small></td>';

            html += '<td>';
            if (r.isIqra) {
                html += '📕 ' + (r.iqraBook || 'Iqra') + '<br><small>ms ' + (r.iqraPage || '-') + '</small>';
            } else {
                html += '<strong>' + (typeof formatSurahWithAyatFull === 'function' ? formatSurahWithAyatFull(r) : (r.surah || '-')) + '</strong>';
                html += '<br><small>' + (typeof formatJuzDisplay === 'function' ? formatJuzDisplay(r.juz) : '') + '</small>';
            }
            html += '</td>';

            html += '<td><strong>' + r.score + '%</strong></td>';
            html += '<td><span class="badge ' + getBadgeClass(r.status) + '">' + r.status + '</span></td>';
            html += '<td style="font-size:0.8rem;max-width:200px;">' + escapeHtml(r.notes || '-') + '</td>';
            html += '</tr>';
        }

        html += '</tbody></table></div>';
    }

    html += '</div></div>';
    html += '</div>';

    document.getElementById('profileDetailContent').innerHTML = html;

    var tabs = document.querySelectorAll('.tab-content');
    for (var i = 0; i < tabs.length; i++) tabs[i].classList.remove('active');
    document.getElementById('tab-profileDetail').classList.add('active');

    window.scrollTo({ top: 0, behavior: 'smooth' });
}

// ===== DETAIL ROW HELPER =====
function detailRow(label, value, isPhone, isCode) {
    var displayValue = value || '-';
    var valueHtml = '';

    if (isPhone && value) {
        valueHtml = '<a href="tel:' + escapeHtml(value) + '" style="color:var(--primary);text-decoration:none;font-weight:600;">📞 ' + escapeHtml(value) + '</a>';
    } else if (isCode && value) {
        // ✅ FIXED: Guna maskPassword untuk field password
        // Cara detect: kalau label mengandungi 'Laluan' atau 'Pass' → mask
        var lowerLabel = label ? label.toLowerCase() : '';
        if (lowerLabel.indexOf('laluan') > -1 || lowerLabel.indexOf('pass') > -1) {
            // Password field — mask dengan toggle
            valueHtml = '<code>' + maskPassword(value, value.substring(0, 8)) + '</code>';
        } else {
            // Code field lain (loginId) — escape biasa
            valueHtml = '<code>' + escapeHtml(value) + '</code>';
        }
    } else {
        valueHtml = escapeHtml(displayValue);
    }

    return '<div class="detail-row"><div class="detail-label">' + escapeHtml(label) + '</div><div class="detail-value">' + valueHtml + '</div></div>';
}
// ===== PRINT =====
function printProfile() {
    document.body.classList.add('printing', 'print-profile');
    setTimeout(function() {
        window.print();
        document.body.classList.remove('printing', 'print-profile');
    }, 300);
}

// ===== EXPORT =====
function exportData() {
    if (appData.students.length === 0) {
        showToast('❌ Tiada data untuk diexport');
        return;
    }

    var csv = 'Nama,IC,Kelas,Jantina,Nama Bapa,Tel Bapa,Nama Ibu,Tel Ibu,Tahap Bacaan,Tarikh Daftar\n';

    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        csv += '"' + s.name + '","' + (s.ic || '') + '","' + s.class + '","' + (s.gender || '') + '",';
        csv += '"' + (s.fatherName || s.parentName || '') + '","' + (s.fatherPhone || s.parentPhone || '') + '",';
        csv += '"' + (s.motherName || '') + '","' + (s.motherPhone || '') + '",';
        csv += '"' + (s.quranLevel || '') + '","' + (s.createdAt || '') + '"\n';
    }

    var blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'senarai_pelajar_madrasah_' + new Date().toISOString().split('T')[0] + '.csv';
    link.click();

    showToast('✅ Data berjaya diexport!');
}

