function updateSummary() {
    var summary = document.getElementById('selectionSummary');
    var content = document.getElementById('summaryContent');
    if (!summary || !content) return;

    if (selectedJuz.length === 0 && selectedSurah.length === 0) {
        summary.classList.add('hidden');
        return;
    }

    summary.classList.remove('hidden');
    var html = '';
    if (selectedJuz.length > 0) {
        var juzParts = [];
        for (var i = 0; i < selectedJuz.length; i++) juzParts.push('Juz ' + selectedJuz[i]);
        html += '<div class="summary-item"><strong>Juz:</strong> ' + juzParts.join(', ') + '</div>';
    }
    if (selectedSurah.length > 0) {
        html += '<div class="summary-item"><strong>Surah (' + selectedSurah.length + '):</strong> ' + selectedSurah.join(', ') + '</div>';
    }
    content.innerHTML = html;
}

function updateScoreDisplay(value) {
    document.getElementById('recordScore').value = value;
    updateScoreLabel(value);
}

