function updateScoreLabel(score) {
    var label = document.getElementById('scoreLabel');
    if (!label) return;
    score = parseInt(score);
    if (score >= 90) {
        label.textContent = '🌟 Cemerlang';
        label.className = 'score-label excellent';
    } else if (score >= 75) {
        label.textContent = '👍 Baik';
        label.className = 'score-label good';
    } else if (score >= 60) {
        label.textContent = '⚠️ Sederhana';
        label.className = 'score-label average';
    } else {
        label.textContent = '❌ Lemah';
        label.className = 'score-label poor';
    }
}

function addQuickNote(note) {
    var textarea = document.getElementById('recordNotes');
    if (!textarea) return;
    if (textarea.value && textarea.value.charAt(textarea.value.length - 1) !== ' ' && textarea.value.charAt(textarea.value.length - 1) !== '\n') {
        textarea.value += ' ';
    }
    textarea.value += note + ' ';
    textarea.focus();
}

