// 🛡️ Simpan rekod hafazan dengan selamat - HANYA tulis path 'records', bukan seluruh appData
function saveHafazanRecordSafely(newRecord, callback) {
    if (!firebaseReady || !firebaseDb) {
        // Offline - guna cara lama (local only)
        appData.records.push(newRecord);
        saveData(appData);
        if (callback) callback(true);
        return;
    }

    firebaseDb.ref('hafazanData/records').once('value').then(function(snapshot) {
        var cloudRecords = snapshot.val() || [];

        // Firebase kadang return object (kalau ada gap index) - normalize jadi array
        if (!Array.isArray(cloudRecords)) {
            var arr = [];
            for (var key in cloudRecords) { arr.push(cloudRecords[key]); }
            cloudRecords = arr;
        }

        // Tambah rekod baru pada data TERKINI dari cloud (bukan copy local lama)
        cloudRecords.push(newRecord);

        // Tulis HANYA path 'records' - tak sentuh students/attendance/cashbook/dll
        firebaseDb.ref('hafazanData/records').set(cloudRecords).then(function() {
            firebaseDb.ref('hafazanData/lastUpdated').set(Date.now());

            // Update local copy supaya UI konsisten
            appData.records = cloudRecords;
            localStorage.setItem('hafazanData', JSON.stringify(appData));

            if (callback) callback(true);
        }).catch(function(err) {
            console.error('Ralat simpan rekod:', err);
            if (callback) callback(false, err);
        });
    }).catch(function(err) {
        console.error('Ralat baca data cloud:', err);
        if (callback) callback(false, err);
    });
}

function addHafazanRecord(event) {
    event.preventDefault();

    if (selectedJuz.length === 0) {
        showToast('❌ Sila pilih sekurang-kurangnya satu Juz');
        return;
    }
    if (selectedSurah.length === 0) {
        showToast('❌ Sila pilih sekurang-kurangnya satu Surah');
        return;
    }

    var studentId = document.getElementById('recordStudent').value;
    var date = document.getElementById('recordDate').value;
    var score = parseInt(document.getElementById('recordScore').value);
    
    // ✅ FIXED #13: check NaN sebelum proceed
    if (isNaN(score) || score < 0 || score > 100) {
        showToast('❌ Markah tidak sah — sila masukkan nilai antara 0 hingga 100');
        return;
    }

    // ✅ FIXED: validate studentId & date juga (isu #14 sekali)
    if (!studentId) {
        showToast('❌ Sila pilih pelajar');
        return;
    }
    if (!date) {
        showToast('❌ Sila pilih tarikh');
        return;
    }

    var status = document.getElementById('recordStatus').value;
    var notes = document.getElementById('recordNotes').value.trim();

    // === INTEGRASI MUKHTAR KHATAM (TAMBAH REKOD) ===
    var readingTypeEl = document.getElementById('recordReadingType');
    var readingType = readingTypeEl ? readingTypeEl.value : '';

    if (readingType && readingType.toLowerCase().indexOf('mukhtar') > -1 && readingType.toLowerCase().indexOf('khatam') > -1) {
        var mukhtarResultInput = document.getElementById('addMukhtarResult');
        var mukhtarResult = mukhtarResultInput ? mukhtarResultInput.value : 'Lulus';
        
        var customNotesEl = document.getElementById('addMukhtarNotes');
        var customMukhtarNotes = customNotesEl ? customNotesEl.value.trim() : '';

        var prefix = (mukhtarResult === 'Lulus') ? '🟢 LULUS' : '🔴 TIDAK LULUS';
        var formattedNotes = '[' + prefix + ']';
        if (customMukhtarNotes) {
            formattedNotes += ' ' + customMukhtarNotes;
        }

        // Satukan catatan keputusan dengan catatan am (jika ada)
        if (notes) {
            notes = formattedNotes + ' | ' + notes;
        } else {
            notes = formattedNotes;
        }
    }

    var getVal2 = function (id) {
        var el = document.getElementById(id);
        return el ? el.value : '';
    };

    // Build surah details dengan ayat
    var surahDetails = [];
    for (var i = 0; i < selectedSurah.length; i++) {
        var surahName = selectedSurah[i];
        var ayatInfo = surahAyatData[surahName] || { from: '', to: '' };

        var surahInfo = getSurahInfo(surahName);

        var juzValue = 0;
        if (surahInfo) {
            if (surahInfo.juzList && surahInfo.juzList.length > 0) {
                juzValue = surahInfo.juzList[0];
            } else if (surahInfo.juz) {
                juzValue = surahInfo.juz;
            }
        }

        surahDetails.push({
            name: surahName,
            juz: juzValue || 0,
            ayatFrom: ayatInfo.from || 1,
            ayatTo: ayatInfo.to || (surahInfo ? surahInfo.ayat : 0)
        });
    }

    var sessionEl = document.querySelector('input[name="recordSession"]:checked');
    var session = sessionEl ? sessionEl.value : 'pagi';

    // 🔍 Semak duplicate entry - pelajar + tarikh + sesi sama
    var isDuplicate = false;
    for (var di = 0; di < appData.records.length; di++) {
        var r = appData.records[di];
        if (r.studentId === studentId && r.date === date && r.session === session) {
            isDuplicate = true;
            break;
        }
    }
    if (isDuplicate) {
        var confirmDup = confirm('⚠️ Pelajar ini SUDAH ada rekod hafazan untuk tarikh & sesi yang sama.\n\nTeruskan tambah rekod baru? (akan jadi 2 rekod berasingan untuk sesi sama)');
        if (!confirmDup) return;
    }

    var isIqra = document.querySelector('input[name="isIqra"]:checked');
    var isIqraValue = isIqra ? isIqra.value === 'yes' : false;

    // Get checker info
    var checkerType = document.querySelector('input[name="checkerType"]:checked');
    var checkerTypeValue = checkerType ? checkerType.value : 'guru';
    var checkerName = '';

    if (checkerTypeValue === 'guru') {
        checkerName = document.getElementById('checkerGuru').value || '';
    } else {
        checkerName = document.getElementById('checkerStudent').value || '';
    }

    var newRecord = {
        id: 'REC' + Date.now(),
        studentId: studentId,
        date: date,
        session: session,
        readingType: readingType,
        
        // Checker info
        checkerType: checkerTypeValue,
        checkerName: checkerName,
        // Iqra data
        isIqra: isIqraValue,
        iqraBook: isIqraValue ? (document.getElementById('iqraBook').value || '') : '',
        iqraPage: isIqraValue ? (document.getElementById('iqraPage').value || '') : '',
        iqraLineFrom: isIqraValue ? (document.getElementById('iqraLineFrom').value || '') : '',
        iqraLineTo: isIqraValue ? (document.getElementById('iqraLineTo').value || '') : '',
        iqraLevel: isIqraValue ? (document.getElementById('iqraLevel').value || '') : '',
        iqraNotes: isIqraValue ? (document.getElementById('iqraNotes').value.trim() || '') : '',
        juz: selectedJuz.length === 1 ? selectedJuz[0] : selectedJuz.slice(),
        surah: selectedSurah.length === 1 ? selectedSurah[0] : selectedSurah.slice(),
        juzList: selectedJuz.slice(),
        surahList: selectedSurah.slice(),
        surahDetails: surahDetails,
        score: score,
        status: status,
        notes: notes,
        detailScores: {
            kelancaran: getVal2('scoreKelancaran'),
            tajwid: getVal2('scoreTajwid'),
            makhraj: getVal2('scoreMakhraj'),
            adab: getVal2('scoreAdab')
        }
    };

    var surahCount = selectedSurah.length;

    showToast('⏳ Menyimpan rekod...');

    saveHafazanRecordSafely(newRecord, function(success, err) {
        if (success) {
            selectedJuz = [];
            selectedSurah = [];
            surahAyatData = {};
            resetRecordForm();
            
            var addContainer = document.getElementById('addMukhtarContainer');
            if (addContainer) addContainer.style.display = 'none';
            
            showToast('✅ Rekod hafazan berjaya disimpan! (' + surahCount + ' surah)');
            initAdminDashboard();
        } else {
            showToast('❌ Gagal simpan rekod. Sila semak internet & cuba lagi.');
        }
    });
}
