function trackEditChanges() {
    var form = document.getElementById('editProfileForm');
    if (!form) return;

    var inputs = form.querySelectorAll('input, select, textarea');

    for (var i = 0; i < inputs.length; i++) {
        var input = inputs[i];

        // ✅ FIXED #18: Skip kalau listener dah attached
        // Guna dataset flag — elak listener bertimbun bila overlay dibuka berulang kali
        if (input.dataset.changeListenerAttached === 'true') continue;

        // Guna IIFE untuk capture input reference dengan betul
        (function(el) {
            var markChanged = function() {
                var fg = el.closest('.form-group');
                if (fg) fg.classList.add('changed');
                var statusEl = document.getElementById('editStatus');
                if (statusEl) {
                    statusEl.textContent = '● Ada perubahan belum disimpan';
                    statusEl.className = 'edit-status';
                }
            };
            el.addEventListener('input',  markChanged);
            el.addEventListener('change', markChanged);
        })(input);

        // ✅ Flag: dah attach, jangan attach lagi
        input.dataset.changeListenerAttached = 'true';
    }
}

// ✅ TAMBAH: Reset flag bila overlay ditutup
// Cari fungsi closeEditOverlay() dan tambah reset di sana:
function closeEditOverlay() {
    var overlay = document.getElementById('editProfileOverlay');
    if (overlay) overlay.classList.remove('active');

    // ✅ FIXED #18: Reset flag supaya listener fresh bila overlay dibuka semula
    var form = document.getElementById('editProfileForm');
    if (form) {
        var inputs = form.querySelectorAll('input, select, textarea');
        for (var i = 0; i < inputs.length; i++) {
            delete inputs[i].dataset.changeListenerAttached;
        }
    }

    editingStudentId = null;
}

function saveEdit() {
    if (!editingStudentId) return;

    var getVal = function (id) {
        var el = document.getElementById(id);
        return el ? el.value.trim() : '';
    };

    // Validate required fields
    var name = getVal('editStudentName');
    var cls = getVal('editStudentClass');
    var fatherName = getVal('editFatherName');
    var loginId = getVal('editParentLoginId');
    var loginPass = getVal('editParentLoginPass');

    if (!name || !cls || !fatherName || !loginId || !loginPass) {
        showToast('❌ Sila isi semua ruangan wajib (*)');
        return;
    }

    // Check duplicate login ID (exclude current student)
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id !== editingStudentId &&
            appData.students[i].parentLoginId === loginId) {
            showToast('❌ ID Login sudah digunakan oleh pelajar lain!');
            return;
        }
    }

    // Find and update student
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === editingStudentId) {
            var s = appData.students[i];

            s.name = name;
            s.ic = getVal('editStudentIC');
            s.dob = getVal('editStudentDOB');
            s.gender = getVal('editStudentGender');
            s.class = cls;
            s.startDate = getVal('editStudentStartDate');

            s.address = {
                line1: getVal('editAddress1'),
                line2: getVal('editAddress2'),
                postcode: getVal('editPostcode'),
                city: getVal('editCity'),
                state: getVal('editState')
            };

            s.fatherName = fatherName;
            s.fatherIC = getVal('editFatherIC');
            s.fatherPhone = getVal('editFatherPhone');
            s.fatherJob = getVal('editFatherJob');
            s.fatherEmail = getVal('editFatherEmail');

            s.motherName = getVal('editMotherName');
            s.motherIC = getVal('editMotherIC');
            s.motherPhone = getVal('editMotherPhone');
            s.motherJob = getVal('editMotherJob');

            s.emergencyName = getVal('editEmergencyName');
            s.emergencyRelation = getVal('editEmergencyRelation');
            s.emergencyPhone = getVal('editEmergencyPhone');

            s.prevSchool = getVal('editPrevSchool');
            s.prevSchoolDuration = getVal('editPrevSchoolDuration');
            s.prevSchoolAddress = getVal('editPrevSchoolAddress');
            s.prevTeacher = getVal('editPrevTeacher');
            s.prevTeacherPhone = getVal('editPrevTeacherPhone');

            s.quranLevel = getVal('editQuranLevel');
            s.tajwidLevel = getVal('editTajwidLevel');
            s.prevSurahList = getVal('editPrevSurahList');
            s.prevAchievements = getVal('editPrevAchievements');

            s.allergy = getVal('editAllergy');
            s.chronicDisease = getVal('editChronicDisease');
            s.healthNotes = getVal('editHealthNotes');

            s.parentName = fatherName;
            s.parentPhone = getVal('editFatherPhone');
            // Status fields
            s.status = getVal('editStudentStatus') || 'aktif';
            s.endDate = getVal('editStudentEndDate');
            s.endReason = getVal('editStudentEndReason');
            s.parentLoginId = loginId;
            s.parentLoginPass = loginPass;

            s.enrollReason = getVal('editEnrollReason');
            s.hafazanTarget = getVal('editHafazanTarget');
            s.additionalNotes = getVal('editAdditionalNotes');

            break;
        }
    }

    savePathSafely('hafazanData/students', appData.students, function(ok) {
    if (!ok) showToast('⚠️ Ralat simpan data — cuba lagi');
});

    // Update status
    document.getElementById('editStatus').textContent = '✅ Berjaya disimpan!';
    document.getElementById('editStatus').className = 'edit-status saved';

    // Remove changed indicators
    var changed = document.querySelectorAll('.form-group.changed');
    for (var i = 0; i < changed.length; i++) {
        changed[i].classList.remove('changed');
    }

    showToast('✅ Profil pelajar berjaya dikemas kini!');

    // Close overlay after short delay
    setTimeout(function () {
        closeEditOverlay();
        // Refresh profile detail
        viewProfileDetail(editingStudentId);
        initAdminDashboard();
    }, 800);
}

