// ============================================
// ===== DARK MODE TOGGLE =====================
// ============================================

function initDarkMode() {
    // Check saved preference
    var saved = localStorage.getItem('darkMode');

    // Check system preference
    var systemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    // Apply: saved preference > system preference
    if (saved === 'dark' || (saved === null && systemDark)) {
        document.documentElement.setAttribute('data-theme', 'dark');
    }

    // Listen for system preference changes
    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', function (e) {
        if (localStorage.getItem('darkMode') === null) {
            document.documentElement.setAttribute('data-theme', e.matches ? 'dark' : 'light');
        }
    });
}

function toggleDarkMode() {
    var current = document.documentElement.getAttribute('data-theme');

    if (current === 'dark') {
        document.documentElement.setAttribute('data-theme', 'light');
        localStorage.setItem('darkMode', 'light');
        showToast('☀️ Light Mode');
    } else {
        document.documentElement.setAttribute('data-theme', 'dark');
        localStorage.setItem('darkMode', 'dark');
        showToast('🌙 Dark Mode');
    }

    // Update toggle button icon
    updateDarkModeIcon();
}

function updateDarkModeIcon() {
    var isDark = document.documentElement.getAttribute('data-theme') === 'dark';
    var btns = document.querySelectorAll('.theme-toggle');

    for (var i = 0; i < btns.length; i++) {
        btns[i].textContent = isDark ? '☀️' : '🌙';
        btns[i].title = isDark ? 'Switch to Light Mode' : 'Switch to Dark Mode';
    }
}

// Auto-init on page load
document.addEventListener('DOMContentLoaded', function () {
    initDarkMode();
    updateDarkModeIcon();
});

// Also init immediately (for scripts loaded after DOMContentLoaded)
if (document.readyState !== 'loading') {
    initDarkMode();
    updateDarkModeIcon();
}

console.log('✅ Dark Mode loaded');

