function removeCashItem(itemId) {
    var el = document.getElementById(itemId);
    if (el) {
        el.style.animation = 'itemSlideIn 0.3s ease reverse';
        setTimeout(function() {
            el.remove();
            renumberItems();
            updateItemsTotal();

            // Show empty state if no items
            var container = document.getElementById('cashItemsList');
            if (container.children.length === 0) {
                showEmptyItems();
            }
        }, 250);
    }
}

function renumberItems() {
    var items = document.querySelectorAll('#cashItemsList .cash-item-row');
    for (var i = 0; i < items.length; i++) {
        var num = items[i].querySelector('.cash-item-number');
        if (num) num.textContent = (i + 1);
    }
}

function updateItemsTotal() {
    var inputs = document.querySelectorAll('#cashItemsList .cash-item-amount');
    var total = 0;
    for (var i = 0; i < inputs.length; i++) {
        var val = parseFloat(inputs[i].value) || 0;
        total += val;
    }

    var totalEl = document.getElementById('cashItemsTotal');
    if (totalEl) {
        totalEl.textContent = 'RM ' + total.toFixed(2);
    }
}

function showEmptyItems() {
    var container = document.getElementById('cashItemsList');
    container.innerHTML = '<div class="empty-items"><div class="empty-items-icon">📝</div>Tiada butiran. Klik "➕ Tambah Butiran" untuk mula.</div>';
}

function onCashTypeChange() {
    var type = document.getElementById('cashType').value;
    var section = document.querySelector('.cash-items-section');
    var refInput = document.getElementById('cashRef');
    var dateInput = document.getElementById('cashDate');

    // SKIP auto-generate kalau dalam edit mode
    if (editingCashEntryId) {
        // Just update styling, jangan tukar ref number
        if (type === 'debit') {
            if (section) section.style.borderColor = 'var(--primary)';
            if (refInput) {
                refInput.style.background = '#f0faf4';
                refInput.style.fontWeight = '700';
                refInput.style.color = 'var(--primary-dark)';
            }
            updateRefHint('🧾 Resit Rasmi');
        } else if (type === 'credit') {
            if (section) section.style.borderColor = 'var(--red)';
            if (refInput) {
                refInput.style.background = '#faf0f0';
                refInput.style.fontWeight = '700';
                refInput.style.color = '#8b1a1a';
            }
            updateRefHint('📋 Payment Voucher');
        }
        return; // JANGAN generate ref baru
    }

    // Original logic untuk ADD mode
    var year = dateInput && dateInput.value ? parseInt(dateInput.value.split('-')[0]) : new Date().getFullYear();

    if (type === 'debit') {
        if (section) section.style.borderColor = 'var(--primary)';
        if (refInput) {
            refInput.value = getNextReceiptNumber(year);
            refInput.style.background = '#f0faf4';
            refInput.style.fontWeight = '700';
            refInput.style.color = 'var(--primary-dark)';
        }
        updateRefHint('🧾 Resit Rasmi');
    } else if (type === 'credit') {
        if (section) section.style.borderColor = 'var(--red)';
        if (refInput) {
            refInput.value = getNextPVNumber(year);
            refInput.style.background = '#faf0f0';
            refInput.style.fontWeight = '700';
            refInput.style.color = '#8b1a1a';
        }
        updateRefHint('📋 Payment Voucher');
    } else {
        if (section) section.style.borderColor = 'var(--primary)';
        if (refInput) {
            refInput.value = '';
            refInput.style.background = '';
            refInput.style.fontWeight = '';
            refInput.style.color = '';
        }
        updateRefHint('');
    }
}

function updateRefHint(text) {
    var hint = document.getElementById('refHint');
    if (hint) {
        hint.textContent = text;
        hint.style.display = text ? 'inline-block' : 'none';
    }
}

function resetCashForm() {
    document.getElementById('cashEntryForm').reset();
    document.getElementById('cashDate').value = new Date().toISOString().split('T')[0];

    // Reset ref styling
    var refInput = document.getElementById('cashRef');
    if (refInput) {
        refInput.value = '';
        refInput.style.background = '';
        refInput.style.fontWeight = '';
        refInput.style.color = '';
    }
    updateRefHint('');
    var studentLink = document.getElementById('cashStudentLink');
if (studentLink) studentLink.value = '';


    cashItemCount = 0;
    document.getElementById('cashItemsList').innerHTML = '';
    showEmptyItems();
    updateItemsTotal();
    toggleCashForm();
        // Reset hutang dropdown
    var hutangSelect = document.getElementById('cashHutangLink');
    if (hutangSelect) hutangSelect.value = '';
    
    var hutangSection = document.getElementById('hutangLinkSection');
    if (hutangSection) hutangSection.style.display = 'none';
}

function addCashEntry(event) {
    event.preventDefault();

    if (!appData.cashbook) appData.cashbook = [];

    var type = document.getElementById('cashType').value;
    if (!type) {
        showToast('❌ Sila pilih jenis transaksi');
        return;
    }

    var items = [];
    var itemRows = document.querySelectorAll('#cashItemsList .cash-item-row');

    if (itemRows.length === 0) {
        showToast('❌ Sila tambah sekurang-kurangnya satu butiran');
        return;
    }

    for (var i = 0; i < itemRows.length; i++) {
        var row = itemRows[i];
        var desc = row.querySelector('.cash-item-desc').value.trim();
        var cat = row.querySelector('.cash-item-category').value;
        var amt = parseFloat(row.querySelector('.cash-item-amount').value);

        if (!desc || !cat || !amt) {
            showToast('❌ Sila lengkapkan butiran #' + (i + 1));
            return;
        }

        items.push({
            description: desc,
            category: cat,
            amount: amt
        });
    }

    var commonDate = document.getElementById('cashDate').value;
    var commonRef = document.getElementById('cashRef').value.trim();
    var commonPayMethod = document.getElementById('cashPayMethod').value;
    var commonPerson = document.getElementById('cashPerson').value.trim();
    var commonNotes = document.getElementById('cashNotes').value.trim();
    var commonStudentId = document.getElementById('cashStudentLink').value;
    var commonHutangIndex = document.getElementById('cashHutangLink') ? document.getElementById('cashHutangLink').value : '';
    var batchId = 'BATCH' + Date.now();

    // Save the ref to history
    if (commonRef) {
        if (type === 'debit') {
            if (!appData.receiptHistory) appData.receiptHistory = [];
            if (appData.receiptHistory.indexOf(commonRef) === -1) {
                appData.receiptHistory.push(commonRef);
            }
        } else if (type === 'credit') {
            if (!appData.pvHistory) appData.pvHistory = [];
            if (appData.pvHistory.indexOf(commonRef) === -1) {
                appData.pvHistory.push(commonRef);
            }
        }
    }

    // ===== ADD EACH ITEM AS SEPARATE ENTRY =====
    var savedEntries = [];
    
    for (var i = 0; i < items.length; i++) {
        var entry = {
            id: 'CASH' + Date.now() + '_' + i,
            batchId: batchId,
            batchIndex: i + 1,
            batchTotal: items.length,
            date: commonDate,
            ref: commonRef,
            description: items[i].description,
            category: items[i].category,
            type: type,
            amount: items[i].amount,
            payMethod: commonPayMethod,
            notes: commonNotes,
            person: commonPerson,
            studentId: commonStudentId || null,
            createdAt: new Date().toISOString()
        };
        appData.cashbook.push(entry);
        savedEntries.push(entry);
    }

    saveData(appData);
    
    // ===== AUTO-RECORD HUTANG (SEKALI SAHAJA untuk SEMUA hutang items) =====
    // Total semua items yang berkaitan hutang
    if (type === 'credit' && commonHutangIndex !== '') {
        var totalHutangAmount = 0;
        var hutangItemCount = 0;
        var firstHutangEntry = null;
        
        for (var h = 0; h < savedEntries.length; h++) {
            var e = savedEntries[h];
            if (e.category === 'Bayaran Hutang Madrasah' || 
                e.category === 'Bayaran Hutang Peribadi' ||
                e.category === 'Ansuran Bulanan') {
                totalHutangAmount += e.amount;
                hutangItemCount++;
                if (!firstHutangEntry) firstHutangEntry = e;
            }
        }
        
        // Record hutang HANYA kalau ada item dengan kategori hutang
        if (hutangItemCount > 0 && firstHutangEntry) {
            var combinedEntry = {
                id: firstHutangEntry.id,
                date: firstHutangEntry.date,
                amount: totalHutangAmount,
                ref: firstHutangEntry.ref,
                description: hutangItemCount === 1 
                    ? firstHutangEntry.description 
                    : 'Multiple items (' + hutangItemCount + ')',
                type: 'credit'
            };
            
            autoRecordHutangPaymentManual(combinedEntry, commonHutangIndex);
            
            // Reset hutang dropdown
            var hutangSelect = document.getElementById('cashHutangLink');
            if (hutangSelect) hutangSelect.value = '';
        }
    }

    // ===== AUTO-CHECK GAJI CUKUP =====
    if (type === 'credit') {
        setTimeout(function() {
            checkGajiCukup(savedEntries);
        }, 500);
    }

    var totalAmount = 0;
    for (var i = 0; i < items.length; i++) totalAmount += items[i].amount;

    var typeText = type === 'debit' ? 'Resit' : 'PV';
    showToast('✅ ' + typeText + ' ' + commonRef + ' disimpan! Total: RM ' + totalAmount.toFixed(2));

    resetCashForm();
    renderCashbook();
    // Refresh category filter
    if (typeof populateCashCategoryFilter === 'function') {
        populateCashCategoryFilter();
    }
}
function renderCashbook() {
    if (!appData.cashbook) appData.cashbook = [];

    var monthFilter = document.getElementById('cashFilterMonth').value;
    var yearFilter = document.getElementById('cashFilterYear').value;
    var catFilter = document.getElementById('cashFilterCategory').value;
    var payMethodFilter = document.getElementById('cashFilterPayMethod') ? document.getElementById('cashFilterPayMethod').value : 'all';

    var filtered = [];
    for (var i = 0; i < appData.cashbook.length; i++) {
        var entry = appData.cashbook[i];
        var parts = entry.date.split('-');
        var entryYear = parts[0];
        var entryMonth = parseInt(parts[1]);

        var yearOk = entryYear === yearFilter;
        var monthOk = monthFilter === 'all' || entryMonth === parseInt(monthFilter);
        var catOk = catFilter === 'all' || entry.category === catFilter;
        
        // ===== FILTER KAEDAH BAYARAN =====
        var payMethodOk = true;
        if (payMethodFilter === 'tunai') {
            payMethodOk = (entry.payMethod || 'Tunai').toLowerCase() === 'tunai';
        } else if (payMethodFilter === 'bank') {
            payMethodOk = (entry.payMethod || 'Tunai').toLowerCase() !== 'tunai';
        }

                // ===== SKIP HIDDEN ZAKAT CHILD ENTRIES =====
        if (entry._hideFromCashbook || entry._isZakatChild) continue;
        
        if (yearOk && monthOk && catOk && payMethodOk) {
            filtered.push(entry);
        }
    }

        filtered.sort(function (a, b) {
        var dateCompare = new Date(a.date) - new Date(b.date);
        if (dateCompare !== 0) return dateCompare;
        // Kalau tarikh sama, sort by sortOrder
        var orderA = typeof a.sortOrder === 'number' ? a.sortOrder : 99999;
        var orderB = typeof b.sortOrder === 'number' ? b.sortOrder : 99999;
        return orderA - orderB;
    });

    var tbody = document.getElementById('cashbookBody');
    var tfoot = document.getElementById('cashbookFoot');

    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="9" class="text-center" style="padding:40px;"><div class="empty-state"><div class="empty-icon">📒</div><p>Tiada rekod untuk tempoh ini</p></div></td></tr>';
        tfoot.innerHTML = '';
        updateCashSummary(0, 0);
        return;
    }

    var totalDebit = 0;
    var totalCredit = 0;
    var runningBalance = 0;

    // Calculate opening balance
    for (var i = 0; i < appData.cashbook.length; i++) {
        var e = appData.cashbook[i];
        if (e._hideFromCashbook || e._isZakatChild) continue;
        var eParts = e.date.split('-');
        var eYear = parseInt(eParts[0]);
        var eMonth = parseInt(eParts[1]);
        var filterYear = parseInt(yearFilter);
        var filterMonth = monthFilter === 'all' ? 1 : parseInt(monthFilter);

        if (monthFilter === 'all') {
            if (eYear < filterYear) {
                if (e.type === 'debit') runningBalance += e.amount;
                else runningBalance -= e.amount;
            }
        } else {
                        if (eYear < filterYear || (eYear === filterYear && eMonth < filterMonth)) {
                // ===== FILTER KAEDAH BAYARAN UNTUK B/F =====
                var eMethod = (e.payMethod || 'Tunai').toLowerCase();
                var eIsTunai = (eMethod === 'tunai');
                
                var bfPayMethodOk = true;
                if (payMethodFilter === 'tunai') {
                    bfPayMethodOk = eIsTunai;
                } else if (payMethodFilter === 'bank') {
                    bfPayMethodOk = !eIsTunai;
                }
                
                if (bfPayMethodOk) {
                    if (e.type === 'debit') runningBalance += e.amount;
                    else runningBalance -= e.amount;
                }
            }
        }
    }

        var openingBalance = runningBalance;

    // Build body HTML
    var bodyHtml = '';

    // ===== BAKI BAWA BAWAH (B/F) - di atas table =====
    if (monthFilter !== 'all') {
        bodyHtml += '<tr style="background:linear-gradient(90deg, #fef3c7, #fde68a);border-bottom:2px solid #f59e0b;">';
        bodyHtml += '<td style="padding:14px 12px;font-weight:800;color:#78350f;">→</td>';
        bodyHtml += '<td colspan="4" style="padding:14px 12px;font-weight:800;color:#78350f;">';
        bodyHtml += '<span style="background:#f59e0b;color:white;padding:3px 10px;border-radius:6px;font-size:0.78rem;margin-right:10px;">B/F</span>';
        bodyHtml += '<strong>Baki Bawa Bawah</strong>';
        bodyHtml += ' <small style="color:#92400e;font-weight:normal;">(dari bulan sebelum)</small>';
        bodyHtml += '</td>';
        bodyHtml += '<td></td>';
        bodyHtml += '<td></td>';
        bodyHtml += '<td style="text-align:right;padding:14px 12px;font-weight:800;color:' + (openingBalance < 0 ? '#dc2626' : '#7c3aed') + ';font-size:1.05rem;">RM ' + formatMoney(openingBalance) + '</td>';
        bodyHtml += '<td class="no-print"></td>';
        bodyHtml += '</tr>';
    }

    for (var i = 0; i < filtered.length; i++) {
        var entry = filtered[i];
        var debitAmt = entry.type === 'debit' ? entry.amount : 0;
        var creditAmt = entry.type === 'credit' ? entry.amount : 0;

        totalDebit += debitAmt;
        totalCredit += creditAmt;
        runningBalance += debitAmt - creditAmt;

        var catClass = entry.type === 'debit' ? 'cat-income' : 'cat-expense';

        bodyHtml += '<tr>';
        bodyHtml += '<td>' + (i + 1) + '</td>';
        bodyHtml += '<td>' + formatDate(entry.date) + '</td>';
        bodyHtml += '<td>' + escapeHtml(entry.ref || '-') + '</td>';
        bodyHtml += '<td>';
        // ✅ FIXED: escapeHtml() untuk elak XSS dari free-text input admin
        bodyHtml += '<strong>' + escapeHtml(entry.description) + '</strong>';
        if (entry.person) {
            bodyHtml += '<br><small style="color:var(--text-light);">' + escapeHtml(entry.person);
            if (entry.studentId) {
                var linkedStudent = null;
                for (var k = 0; k < appData.students.length; k++) {
                    if (appData.students[k].id === entry.studentId) {
                        linkedStudent = appData.students[k];
                        break;
                    }
                }
                if (linkedStudent) {
                    bodyHtml += ' <span style="background:#e8f5e9;color:#1b5e20;padding:1px 6px;border-radius:8px;font-size:0.7rem;font-weight:600;">🔗 ' + escapeHtml(linkedStudent.name) + '</span>';
                }
            }
            bodyHtml += '</small>';
        }
        if (entry.notes) bodyHtml += '<br><small style="color:var(--text-light);font-style:italic;">📝 ' + escapeHtml(entry.notes) + '</small>';
        bodyHtml += '</td>';
        bodyHtml += '<td><span class="cash-category-badge ' + catClass + '">' + escapeHtml(entry.category) + '</span></td>';
        bodyHtml += '<td style="text-align:right;" class="debit-cell">' + (debitAmt > 0 ? formatMoney(debitAmt) : '') + '</td>';
        bodyHtml += '<td style="text-align:right;" class="credit-cell">' + (creditAmt > 0 ? formatMoney(creditAmt) : '') + '</td>';
        bodyHtml += '<td style="text-align:right;" class="balance-cell' + (runningBalance < 0 ? ' balance-negative' : '') + '">' + formatMoney(runningBalance) + '</td>';

        // Action buttons
                // Check if same date entries exist (for reorder buttons)
        var hasSameDateAbove = false;
        var hasSameDateBelow = false;
        for (var j = 0; j < filtered.length; j++) {
            if (j < i && filtered[j].date === entry.date) hasSameDateAbove = true;
            if (j > i && filtered[j].date === entry.date) hasSameDateBelow = true;
        }

        bodyHtml += '<td class="no-print" style="text-align:center;">';
        bodyHtml += '<div style="display:inline-flex;gap:4px;align-items:center;justify-content:center;flex-wrap:wrap;">';

        // Reorder buttons - only show if same date entries exist
        if (hasSameDateAbove || hasSameDateBelow) {
            bodyHtml += '<div style="display:flex;flex-direction:column;gap:2px;margin-right:4px;">';
            if (hasSameDateAbove) {
                bodyHtml += '<button class="btn btn-sm" style="background:#94a3b8;color:white;padding:2px 6px;font-size:0.7rem;min-height:22px;min-width:22px;" onclick="moveCashEntry(\'' + entry.id + '\', -1)" title="Naik">▲</button>';
            }
            if (hasSameDateBelow) {
                bodyHtml += '<button class="btn btn-sm" style="background:#94a3b8;color:white;padding:2px 6px;font-size:0.7rem;min-height:22px;min-width:22px;" onclick="moveCashEntry(\'' + entry.id + '\', 1)" title="Turun">▼</button>';
            }
            bodyHtml += '</div>';
        }
        if (entry.type === 'debit') {
            bodyHtml += '<button class="btn btn-sm btn-view" onclick="generateReceipt(\'' + entry.id + '\')" title="Jana Resit">🧾</button>';
            if (typeof sendReceiptWhatsApp === 'function') {
                bodyHtml += '<button class="btn btn-sm" style="background:#25d366;color:white;" onclick="sendReceiptWhatsApp(\'' + entry.id + '\')" title="WhatsApp">📱</button>';
            }
        } else {
            bodyHtml += '<button class="btn btn-sm" style="background:#1a5276;color:white;" onclick="generatePV(\'' + entry.id + '\')" title="Jana Baucar">📋</button>';
        }
        bodyHtml += '<button class="btn btn-sm btn-edit" onclick="editCashEntry(\'' + entry.id + '\')" title="Edit">✏️</button>';
        bodyHtml += '<button class="btn btn-sm btn-delete" onclick="deleteCashEntry(\'' + entry.id + '\')" title="Padam">🗑</button>';
        bodyHtml += '</div>';
        bodyHtml += '</td>';
    }

    tbody.innerHTML = bodyHtml;

        // Build footer HTML
    var footerHtml = '';

    // ===== ROW JUMLAH =====
    footerHtml += '<tr style="background:linear-gradient(135deg, #faf5ff, #f5f3ff);border-top:3px double #a78bfa;">';
    footerHtml += '<td colspan="5" style="text-align:right;padding:14px 12px;letter-spacing:1px;font-weight:800;color:#4c1d95;font-size:1rem;">JUMLAH BULAN INI</td>';
    footerHtml += '<td style="text-align:right;padding:14px 12px;color:#8b5cf6;font-weight:800;font-size:1rem;">' + formatMoney(totalDebit) + '</td>';
    footerHtml += '<td style="text-align:right;padding:14px 12px;color:#dc2626;font-weight:800;font-size:1rem;">' + formatMoney(totalCredit) + '</td>';
    footerHtml += '<td style="text-align:right;padding:14px 12px;font-weight:800;font-size:1rem;color:' + (runningBalance < 0 ? '#dc2626' : '#1f2937') + ';">' + formatMoney(runningBalance) + '</td>';
    footerHtml += '<td class="no-print"></td>';
    footerHtml += '</tr>';

    // ===== ROW BAKI BAWA HADAPAN (C/F) =====
    if (monthFilter !== 'all') {
        var netChange = totalDebit - totalCredit;
        footerHtml += '<tr style="background:linear-gradient(90deg, #dbeafe, #bfdbfe);border-bottom:2px solid #3b82f6;">';
        footerHtml += '<td style="padding:14px 12px;font-weight:800;color:#1e40af;">←</td>';
        footerHtml += '<td colspan="4" style="padding:14px 12px;font-weight:800;color:#1e40af;">';
        footerHtml += '<span style="background:#3b82f6;color:white;padding:3px 10px;border-radius:6px;font-size:0.78rem;margin-right:10px;">C/F</span>';
        footerHtml += '<strong>Baki Bawa Hadapan</strong>';
        footerHtml += ' <small style="color:#1e3a8a;font-weight:normal;">(ke bulan seterusnya)</small>';
        footerHtml += '</td>';
        footerHtml += '<td style="text-align:right;padding:14px 12px;font-size:0.85rem;color:#1e40af;">';
        footerHtml += '<small>Net: ' + (netChange >= 0 ? '+' : '') + formatMoney(netChange) + '</small>';
        footerHtml += '</td>';
        footerHtml += '<td></td>';
        footerHtml += '<td style="text-align:right;padding:14px 12px;font-weight:800;color:' + (runningBalance < 0 ? '#dc2626' : '#7c3aed') + ';font-size:1.1rem;">RM ' + formatMoney(runningBalance) + '</td>';
        footerHtml += '<td class="no-print"></td>';
        footerHtml += '</tr>';
    }

    tfoot.innerHTML = footerHtml;

    updateCashSummary(totalDebit, totalCredit);

    // Update print header
    var printRange = document.getElementById('printDateRange');
    if (printRange) {
        var months = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun', 'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
        if (monthFilter === 'all') {
            printRange.textContent = 'Tahun ' + yearFilter;
        } else {
            printRange.textContent = months[parseInt(monthFilter)] + ' ' + yearFilter;
        }
    }
    var printDate = document.getElementById('printDate');
    if (printDate) {
        printDate.textContent = 'Dicetak pada: ' + new Date().toLocaleDateString('ms-MY');
    }
}

function updateCashSummary(totalDebit, totalCredit) {
    var balance = totalDebit - totalCredit;

    var debitEl = document.getElementById('cashTotalDebit');
    var creditEl = document.getElementById('cashTotalCredit');
    var balanceEl = document.getElementById('cashBalance');

    if (debitEl) debitEl.textContent = 'RM ' + totalDebit.toFixed(2);
    if (creditEl) creditEl.textContent = 'RM ' + totalCredit.toFixed(2);
    if (balanceEl) {
        balanceEl.textContent = 'RM ' + balance.toFixed(2);
        balanceEl.style.color = balance < 0 ? 'var(--red)' : 'var(--gold)';
    }
    
    // ===== KIRA BAKI TUNAI & BANK BERASINGAN =====
    var tunaiDebit = 0;
    var tunaiCredit = 0;
    var bankDebit = 0;
    var bankCredit = 0;
    
    var monthFilter = document.getElementById('cashFilterMonth').value;
    var yearFilter = document.getElementById('cashFilterYear').value;
    
    if (!appData.cashbook) appData.cashbook = [];
    
    for (var i = 0; i < appData.cashbook.length; i++) {
        var entry = appData.cashbook[i];
        if (entry._hideFromCashbook || entry._isZakatChild) continue;
        var parts = entry.date.split('-');
        var entryYear = parts[0];
        var entryMonth = parseInt(parts[1]);
        
        var yearOk = entryYear === yearFilter;
        var monthOk = monthFilter === 'all' || entryMonth === parseInt(monthFilter);
        
        if (!yearOk || !monthOk) continue;
        
        var method = (entry.payMethod || 'Tunai').toLowerCase();
        var isTunai = (method === 'tunai');
        
        if (entry.type === 'debit') {
            if (isTunai) {
                tunaiDebit += entry.amount;
            } else {
                bankDebit += entry.amount;
            }
        } else {
            if (isTunai) {
                tunaiCredit += entry.amount;
            } else {
                bankCredit += entry.amount;
            }
        }
    }
    
    var tunaiBalance = tunaiDebit - tunaiCredit;
    var bankBalance = bankDebit - bankCredit;
    
    // Update Tunai card
    var tunaiEl = document.getElementById('cashBalanceTunai');
    if (tunaiEl) {
        tunaiEl.textContent = 'RM ' + tunaiBalance.toFixed(2);
        tunaiEl.style.color = tunaiBalance < 0 ? '#ef4444' : '#a78bfa';
    }
    
    // Update Bank card
    var bankEl = document.getElementById('cashBalanceBank');
    if (bankEl) {
        bankEl.textContent = 'RM ' + bankBalance.toFixed(2);
        bankEl.style.color = bankBalance < 0 ? '#ef4444' : '#3b82f6';
    }
}

function formatMoney(amount) {
    if (amount < 0) {
        return '(' + Math.abs(amount).toFixed(2) + ')';
    }
    return amount.toFixed(2);
}

function deleteCashEntry(entryId) {
    if (!confirm('Padam catatan ini?')) return;

    var newCashbook = [];
    for (var i = 0; i < appData.cashbook.length; i++) {
        if (appData.cashbook[i].id !== entryId) {
            newCashbook.push(appData.cashbook[i]);
        }
    }
    appData.cashbook = newCashbook;
    saveData(appData);
    showToast('🗑 Catatan dipadam');
    renderCashbook();
}

