function getPVCount() {
    if (!appData.pvCount) appData.pvCount = 0;
    appData.pvCount++;
    saveData(appData);
    return appData.pvCount;
}

function getCategoryCode(category) {
    var codes = {
        'Gaji Guru': 'A1-001',
        'Sewa': 'A2-001',
        'Utiliti': 'A2-002',
        'Buku & Alatan': 'A3-001',
        'Makanan': 'A3-002',
        'Penyelenggaraan': 'A4-001',
        'Pengangkutan': 'A4-002',
        'Percetakan': 'A4-003',
        'Perbelanjaan Lain': 'A5-001',
        'Yuran Bulanan': 'B1-001',
        'Yuran Pendaftaran': 'B1-002',
        'Derma': 'B2-001',
        'Jualan': 'B3-001',
        'Pendapatan Lain': 'B4-001'
    };
    return codes[category] || 'A0-000';
}

// ===== AUTO GENERATE REF NUMBERS =====

function getNextReceiptNumber(year) {
    if (!appData.cashbook) appData.cashbook = [];

    // Default ke tahun semasa kalau tak bagi
    if (!year) year = new Date().getFullYear();

    var yearShort = String(year).slice(-2);
    var prefix = 'RT-PSB-' + yearShort;

    // Cari nombor tertinggi untuk tahun ni
    var maxNum = 0;
    for (var i = 0; i < appData.cashbook.length; i++) {
        var ref = appData.cashbook[i].ref;
        if (ref && ref.indexOf(prefix) === 0) {
            var numPart = ref.substring(prefix.length);
            var num = parseInt(numPart) || 0;
            if (num > maxNum) maxNum = num;
        }
    }

    // Juga check dari receipt history
    if (appData.receiptHistory) {
        for (var i = 0; i < appData.receiptHistory.length; i++) {
            var ref = appData.receiptHistory[i];
            if (ref && ref.indexOf(prefix) === 0) {
                var numPart = ref.substring(prefix.length);
                var num = parseInt(numPart) || 0;
                if (num > maxNum) maxNum = num;
            }
        }
    }

    var nextNum = maxNum + 1;
    return prefix + String(nextNum).padStart(4, '0');
}

function getNextPVNumber(year) {
    if (!appData.cashbook) appData.cashbook = [];

    // Default ke tahun semasa kalau tak bagi
    if (!year) year = new Date().getFullYear();

    var prefix = 'PV/' + year + '/';

    // Cari nombor tertinggi untuk tahun ni
    var maxNum = 0;
    for (var i = 0; i < appData.cashbook.length; i++) {
        var ref = appData.cashbook[i].ref;
        if (ref && ref.indexOf(prefix) === 0) {
            var numPart = ref.substring(prefix.length);
            var num = parseInt(numPart) || 0;
            if (num > maxNum) maxNum = num;
        }
    }

    // Juga check dari PV history
    if (appData.pvHistory) {
        for (var i = 0; i < appData.pvHistory.length; i++) {
            var ref = appData.pvHistory[i];
            if (ref && ref.indexOf(prefix) === 0) {
                var numPart = ref.substring(prefix.length);
                var num = parseInt(numPart) || 0;
                if (num > maxNum) maxNum = num;
            }
        }
    }

    var nextNum = maxNum + 1;
    return prefix + String(nextNum).padStart(4, '0');
}

function previewNextRef(type) {
    if (type === 'debit') {
        return getNextReceiptNumber();
    } else if (type === 'credit') {
        return getNextPVNumber();
    }
    return '';
}

