function populateStudentLinkDropdown() {
    var select = document.getElementById('cashStudentLink');
    if (!select) return;

    select.innerHTML = '<option value="">🔗 Link ke Pelajar (Optional)</option>';

    // Sort by name
    var sortedStudents = appData.students.slice().sort(function(a, b) {
        return a.name.localeCompare(b.name);
    });

    for (var i = 0; i < sortedStudents.length; i++) {
        var s = sortedStudents[i];
        select.innerHTML += '<option value="' + s.id + '">' + s.name + ' (' + s.class + ')</option>';
    }
}

function onStudentSelect() {
    var studentId = document.getElementById('cashStudentLink').value;
    if (!studentId) return;

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    // Auto fill person field
    var personField = document.getElementById('cashPerson');
    if (personField) {
        var payerName = student.fatherName || student.parentName || student.name;
        personField.value = payerName;
    }
}

