// ===== PHOTO GALLERY ========
// ============================

// ⚠️ PENTING: Tukar dengan API Key anda dari https://api.imgbb.com
// var IMGBB_API_KEY = 'moved to serverless function';
// Now using /api/upload-image endpoint

// ===== CLOUDINARY CONFIG (untuk video) =====
// var CLOUDINARY_CLOUD_NAME = 'moved to serverless';
// var CLOUDINARY_UPLOAD_PRESET = 'moved to serverless';
// Now fetched from /api/upload-video

// Upload video to Cloudinary
function uploadVideoToCloudinary(file, onProgress) {
    return new Promise(function(resolve, reject) {
        // ===== SECURE: Get config from serverless function =====
        fetch('/api/upload-video')
            .then(function(res) { return res.json(); })
            .then(function(configData) {
                if (!configData.success) {
                    reject(new Error(configData.error || 'Config failed'));
                    return;
                }
                
                var config = configData.config;
                var formData = new FormData();
                formData.append('file', file);
                formData.append('upload_preset', config.uploadPreset);
                
                var xhr = new XMLHttpRequest();
                xhr.open('POST', config.uploadUrl, true);
                
                // Progress tracker
                xhr.upload.onprogress = function(e) {
                    if (e.lengthComputable && onProgress) {
                        var percent = Math.round((e.loaded / e.total) * 100);
                        onProgress(percent);
                    }
                };
                
                xhr.onload = function() {
                    if (xhr.status === 200) {
                        try {
                            var data = JSON.parse(xhr.responseText);
                            resolve({
                                url: data.secure_url,
                                thumb: data.secure_url.replace('/upload/', '/upload/w_400,c_fit,so_1/').replace(/\.[^.]+$/, '.jpg'),
                                publicId: data.public_id,
                                duration: data.duration,
                                format: data.format,
                                bytes: data.bytes
                            });
                        } catch (err) {
                            reject(new Error('Parse error: ' + err.message));
                        }
                    } else {
                        reject(new Error('Upload failed: ' + xhr.statusText));
                    }
                };
                
                xhr.onerror = function() {
                    reject(new Error('Network error'));
                };
                
                xhr.send(formData);
            })
            .catch(function(err) {
                reject(new Error('Config fetch failed: ' + err.message));
            });
    });
}

