// Init Gallery
function initGallery() {
    if (!appData.gallery) appData.gallery = [];

    var dateEl = document.getElementById('galleryDate');
    if (dateEl && !dateEl.value) {
        dateEl.value = new Date().toISOString().split('T')[0];
    }

    populateGalleryYears();
    renderGallery();
}

function populateGalleryYears() {
    var yearEl = document.getElementById('galleryFilterYear');
    if (!yearEl) return;

    var years = {};
    var currentYear = new Date().getFullYear();
    years[currentYear] = true;

    for (var i = 0; i < appData.gallery.length; i++) {
        if (appData.gallery[i].date) {
            var y = parseInt(appData.gallery[i].date.split('-')[0]);
            years[y] = true;
        }
    }

    var yearList = [];
    for (var y in years) yearList.push(parseInt(y));
    yearList.sort(function(a, b) { return b - a; });

    var html = '<option value="all">Semua Tahun</option>';
    for (var i = 0; i < yearList.length; i++) {
        html += '<option value="' + yearList[i] + '">' + yearList[i] + '</option>';
    }
    yearEl.innerHTML = html;
}

