// Preview files sebelum upload
function previewGalleryFiles(input) {
    var files = input.files;
    var preview = document.getElementById('galleryPreview');
    
    // Clear existing photo previews (kekal video previews)
    var videoPreviewCount = galleryVideoFiles.length;
    preview.innerHTML = '';
    galleryFiles = [];

    // Add photo previews
    for (var i = 0; i < files.length; i++) {
        var file = files[i];
        if (!file.type.startsWith('image/')) continue;
        
        if (file.size > 32 * 1024 * 1024) {
            alert('❌ ' + file.name + ' terlalu besar! Max 32MB');
            continue;
        }

        galleryFiles.push(file);

        (function(f) {
            var reader = new FileReader();
            reader.onload = function(e) {
                var item = document.createElement('div');
                item.className = 'gallery-preview-item';
                item.style.cssText = 'aspect-ratio:1;border-radius:8px;overflow:hidden;background:#f1f5f9;position:relative;';
                item.innerHTML = '<img src="' + e.target.result + '" style="width:100%;height:100%;object-fit:cover;">' +
                                '<div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,0.7);color:white;padding:3px 6px;font-size:0.65rem;">📷</div>';
                preview.appendChild(item);
            };
            reader.readAsDataURL(f);
        })(file);
    }

    // Re-add video previews
    for (var i = 0; i < galleryVideoFiles.length; i++) {
        var file = galleryVideoFiles[i];
        var item = document.createElement('div');
        item.className = 'gallery-preview-item';
        item.style.cssText = 'aspect-ratio:1;border-radius:8px;overflow:hidden;background:linear-gradient(135deg,#7c3aed,#5b21b6);display:flex;align-items:center;justify-content:center;color:white;flex-direction:column;padding:10px;';
        item.innerHTML = '<div style="font-size:2rem;">🎥</div>' +
                        '<div style="font-size:0.7rem;text-align:center;margin-top:5px;word-break:break-word;">' + file.name.substring(0, 20) + '</div>';
        preview.appendChild(item);
    }

    updateUploadButton();
}

