// Update button text based on files count
function updateUploadButton() {
    var btn = document.getElementById('uploadSubmitBtn');
    if (!btn) return;
    
    var totalFiles = galleryFiles.length + galleryVideoFiles.length;
    
    if (totalFiles === 0) {
        btn.textContent = '📤 Upload';
    } else {
        var parts = [];
        if (galleryFiles.length > 0) parts.push(galleryFiles.length + ' gambar');
        if (galleryVideoFiles.length > 0) parts.push(galleryVideoFiles.length + ' video');
        btn.textContent = '📤 Upload ' + parts.join(' & ');
    }
}

// Main upload function
function uploadGalleryPhoto(event) {
    event.preventDefault();

    var totalFiles = galleryFiles.length + galleryVideoFiles.length;
    
    if (totalFiles === 0) {
        showToast('❌ Sila pilih gambar atau video dahulu');
        return;
    }

    if (IMGBB_API_KEY === 'PASTE_API_KEY_ANDA_DI_SINI' || !IMGBB_API_KEY) {
        alert('⚠️ PENTING!\n\nSila set ImgBB API Key dalam fail js/admin.js');
        return;
    }

    var title = document.getElementById('galleryTitle').value.trim();
    var category = document.getElementById('galleryCategory').value;
    var date = document.getElementById('galleryDate').value;
    var location = document.getElementById('galleryLocation').value.trim();
    var description = document.getElementById('galleryDescription').value.trim();

    if (!title || !category) {
        showToast('❌ Sila isi tajuk dan kategori');
        return;
    }

    var albumId = 'ALBUM' + Date.now();
    var uploadedFiles = 0;
    var uploadedPhotos = [];
    var uploadedVideos = [];
    var failedFiles = 0;

    // Prepare all files
    var allFiles = [];
    for (var i = 0; i < galleryFiles.length; i++) {
        allFiles.push({ file: galleryFiles[i], type: 'photo' });
    }
    for (var i = 0; i < galleryVideoFiles.length; i++) {
        allFiles.push({ file: galleryVideoFiles[i], type: 'video' });
    }

    document.getElementById('uploadProgress').classList.remove('hidden');
    document.getElementById('uploadSubmitBtn').disabled = true;

    function updateProgress(customMsg) {
        var percent = Math.round((uploadedFiles / totalFiles) * 100);
        document.getElementById('uploadProgressFill').style.width = percent + '%';
        document.getElementById('uploadProgressText').textContent =
            customMsg || ('Uploading ' + uploadedFiles + ' / ' + totalFiles + ' (' + percent + '%)');
    }

    function finalizeUpload() {
        if (uploadedPhotos.length === 0 && uploadedVideos.length === 0) {
            showToast('❌ Tiada fail berjaya diupload');
            document.getElementById('uploadProgress').classList.add('hidden');
            document.getElementById('uploadSubmitBtn').disabled = false;
            document.getElementById('uploadProgressFill').style.width = '0%';
            return;
        }

        if (!appData.gallery) appData.gallery = [];

        var album = {
            id: albumId,
            title: title,
            category: category,
            date: date,
            location: location,
            description: description,
            photos: uploadedPhotos,
            videos: uploadedVideos,
            uploadedAt: new Date().toISOString(),
            uploadedBy: currentUser ? currentUser.name : 'Admin'
        };

        appData.gallery.push(album);
        saveData(appData);

        var parts = [];
        if (uploadedPhotos.length > 0) parts.push(uploadedPhotos.length + ' gambar');
        if (uploadedVideos.length > 0) parts.push(uploadedVideos.length + ' video');
        
        var msg = '✅ Berjaya upload ' + parts.join(' & ') + '!';
        if (failedFiles > 0) msg += ' (' + failedFiles + ' gagal)';
        showToast(msg);

        document.getElementById('uploadProgress').classList.add('hidden');
        document.getElementById('uploadSubmitBtn').disabled = false;
        document.getElementById('uploadProgressFill').style.width = '0%';
        galleryFiles = [];
        galleryVideoFiles = [];
        toggleGalleryUpload();
        renderGallery();
    }

    function uploadNext(index) {
    if (index >= totalFiles) {
        finalizeUpload();
        return;
    }

    var item = allFiles[index];
    updateProgress('Memproses ' + (index + 1) + ' / ' + totalFiles + '...');

    // ===== VIDEO: Upload to Cloudinary =====
    if (item.type === 'video') {
        updateProgress('Uploading video ' + (index + 1) + ' / ' + totalFiles + '...');
        
        uploadVideoToCloudinary(item.file, function(percent) {
            updateProgress('Video ' + (index + 1) + ' / ' + totalFiles + ' - ' + percent + '%');
        })
        .then(function(result) {
            uploadedVideos.push({
                url: result.url,
                thumb: result.thumb,
                publicId: result.publicId,
                duration: result.duration,
                format: result.format,
                bytes: result.bytes,
                name: item.file.name,
                uploadedAt: new Date().toISOString()
            });
            uploadedFiles++;
            console.log('✅ Video uploaded:', item.file.name);
            updateProgress();
            setTimeout(function() { uploadNext(index + 1); }, 300);
        })
        .catch(function(err) {
            console.log('❌ Video upload failed:', item.file.name, err);
            failedFiles++;
            uploadedFiles++;
            updateProgress();
            setTimeout(function() { uploadNext(index + 1); }, 300);
        });
        
        return;
    }

    // ===== PHOTO: Upload to ImgBB =====
    // ===== VIDEO: Cloudinary =====
if (item.type === 'video') {
    updateProgress('Uploading video ' + (index + 1) + '/' + totalFiles + '...');
    
    uploadVideoToCloudinary(item.file, function(percent) {
        updateProgress('Video ' + (index + 1) + '/' + totalFiles + ' - ' + percent + '%');
    })
    .then(function(result) {
        newVideos.push({
            url: result.url,
            thumb: result.thumb,
            publicId: result.publicId,
            duration: result.duration,
            format: result.format,
            bytes: result.bytes,
            name: item.file.name,
            uploadedAt: new Date().toISOString()
        });
        uploaded++;
        updateProgress();
        setTimeout(function() { uploadNext(index + 1); }, 300);
    })
    .catch(function(err) {
        console.log('❌ Video failed:', err);
        failed++;
        uploaded++;
        updateProgress();
        setTimeout(function() { uploadNext(index + 1); }, 300);
    });
    return;
}

// ===== PHOTO: ImgBB =====
var reader = new FileReader();
reader.onload = function(e) {
    var base64 = e.target.result.split(',')[1];
    var formData = new FormData();
    formData.append('image', base64);
    
    updateProgress('Uploading ' + (index + 1) + '/' + totalFiles + '...');
    
    fetch('/api/upload-image', {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json'
    },
    body: JSON.stringify({ image: base64 })
})
    .then(function(r) { return r.json(); })
    .then(function(data) {
        if (data.success && data.data) {
            newPhotos.push({
                url: data.data.url,
                displayUrl: data.data.display_url || data.data.url,
                thumb: (data.data.thumb && data.data.thumb.url) ? data.data.thumb.url : data.data.url,
                deleteUrl: data.data.delete_url || '',
                id: data.data.id || '',
                name: item.file.name,
                uploadedAt: new Date().toISOString()
            });
            uploaded++;
        } else {
            failed++;
            uploaded++;
        }
        updateProgress();
        setTimeout(function() { uploadNext(index + 1); }, 300);
    })
    .catch(function(err) {
        failed++;
        uploaded++;
        updateProgress();
        setTimeout(function() { uploadNext(index + 1); }, 300);
    });
};
reader.onerror = function() {
    failed++;
    uploaded++;
    uploadNext(index + 1);
};
reader.readAsDataURL(item.file);
}

    uploadNext(0);
}
// Render Gallery
function renderGallery() {
    var container = document.getElementById('galleryContainer');
    if (!container) return;

    if (!appData.gallery) appData.gallery = [];

    // Get filter values
    var searchInput = document.getElementById('gallerySearchInput');
    var searchVal = searchInput ? searchInput.value.toLowerCase().trim() : '';
    
    var categoryFilter = document.getElementById('galleryFilterCategory').value;
    var yearFilter = document.getElementById('galleryFilterYear').value;
    var locationFilter = document.getElementById('galleryFilterLocation');
    locationFilter = locationFilter ? locationFilter.value : 'all';
    
    var sortBy = document.getElementById('gallerySortBy');
    sortBy = sortBy ? sortBy.value : 'newest';
    
    // Show/hide clear button
    var clearBtn = document.getElementById('gallerySearchClear');
    if (clearBtn) clearBtn.style.display = searchVal ? 'block' : 'none';

    // Populate location filter dropdown
    populateLocationFilter();

    // Filter albums
    var filtered = [];
    var totalAlbums = appData.gallery.length;
    
    for (var i = 0; i < appData.gallery.length; i++) {
        var album = appData.gallery[i];
        
        // Category filter
        var catOk = categoryFilter === 'all' || album.category === categoryFilter;
        
        // Year filter
        var yearOk = yearFilter === 'all' || (album.date && album.date.indexOf(yearFilter) === 0);
        
        // Location filter
        var locOk = locationFilter === 'all';
        if (!locOk && album.location) {
            var albumLocations = album.location.split(',').map(function(l) { return l.trim().toLowerCase(); });
            locOk = albumLocations.indexOf(locationFilter.toLowerCase()) > -1;
        }
        
        // Search filter (title, description, location)
        var searchOk = !searchVal;
        if (!searchOk) {
            var searchable = (album.title || '') + ' ' + (album.description || '') + ' ' + (album.location || '') + ' ' + (album.category || '');
            searchOk = searchable.toLowerCase().indexOf(searchVal) > -1;
        }
        
        if (catOk && yearOk && locOk && searchOk) filtered.push(album);
    }

    // Sort
    filtered.sort(function(a, b) {
        if (sortBy === 'newest') {
            return new Date(b.date || b.uploadedAt) - new Date(a.date || a.uploadedAt);
        } else if (sortBy === 'oldest') {
            return new Date(a.date || a.uploadedAt) - new Date(b.date || b.uploadedAt);
        } else if (sortBy === 'title_asc') {
            return (a.title || '').localeCompare(b.title || '');
        } else if (sortBy === 'title_desc') {
            return (b.title || '').localeCompare(a.title || '');
        } else if (sortBy === 'most_photos') {
            var aCount = (a.photos ? a.photos.length : 0) + (a.videos ? a.videos.length : 0);
            var bCount = (b.photos ? b.photos.length : 0) + (b.videos ? b.videos.length : 0);
            return bCount - aCount;
        } else if (sortBy === 'least_photos') {
            var aCount = (a.photos ? a.photos.length : 0) + (a.videos ? a.videos.length : 0);
            var bCount = (b.photos ? b.photos.length : 0) + (b.videos ? b.videos.length : 0);
            return aCount - bCount;
        }
        return 0;
    });
    
    // Update results info
    var infoEl = document.getElementById('galleryResultsInfo');
    if (infoEl) {
        if (filtered.length === totalAlbums) {
            infoEl.innerHTML = '📊 Menunjukkan <strong>' + totalAlbums + '</strong> album';
            infoEl.style.borderLeftColor = '#7c3aed';
            infoEl.style.color = '#5b21b6';
        } else if (filtered.length === 0) {
            infoEl.innerHTML = '❌ <strong>Tiada album ditemui</strong> - Cuba ubah filter atau kata kunci';
            infoEl.style.borderLeftColor = '#ef4444';
            infoEl.style.color = '#991b1b';
        } else {
            infoEl.innerHTML = '🔍 Menunjukkan <strong>' + filtered.length + '</strong> dari <strong>' + totalAlbums + '</strong> album';
            infoEl.style.borderLeftColor = '#3b82f6';
            infoEl.style.color = '#1e40af';
        }
    }

    if (filtered.length === 0) {
        var emptyMsg = searchVal || categoryFilter !== 'all' || yearFilter !== 'all' || locationFilter !== 'all'
            ? '🔍 Tiada album match dengan filter'
            : '📷 Belum ada album';
        container.innerHTML = '<div class="empty-state" style="padding:60px;"><div class="empty-icon">' + (searchVal ? '🔍' : '📷') + '</div><p>' + emptyMsg + '</p><small style="color:var(--text-light);">' + (searchVal ? 'Cuba kata kunci lain' : 'Klik "Upload Gambar" untuk mula') + '</small></div>';
        return;
    }

    var html = '';
    for (var i = 0; i < filtered.length; i++) {
        var album = filtered[i];
        var photoCount = album.photos ? album.photos.length : 0;
        var videoCount = album.videos ? album.videos.length : 0;

        html += '<div class="gallery-album">';
        html += '<div class="gallery-album-header">';
        html += '<div style="flex:1;min-width:0;">';
        html += '<h3 class="gallery-album-title">';
        html += '<span class="gallery-category-badge">' + escapeHtml(album.category) + '</span>';
        html += escapeHtml(album.title);
        html += '</h3>';
        html += '<div class="gallery-album-meta">';
        if (album.date) html += '📅 ' + formatDate(album.date);
        html += ' • 📷 ' + photoCount + ' gambar';
        if (videoCount > 0) html += ' • 🎥 ' + videoCount + ' video';
        if (album.description) html += '<br>💬 ' + escapeHtml(album.description);
        
        // Multiple locations sebagai chips
        if (album.location) {
            var locations = album.location.split(',').map(function(l) { return l.trim(); }).filter(function(l) { return l; });
            if (locations.length > 0) {
                html += '<div style="display:flex;flex-wrap:wrap;gap:5px;margin-top:8px;">';
                for (var l = 0; l < locations.length; l++) {
                    html += '<span style="background:#faf5ff;color:#7c3aed;padding:3px 10px;border-radius:12px;font-size:0.75rem;font-weight:600;">📍 ' + escapeHtml(locations[l]) + '</span>';
                }
                html += '</div>';
            }
        }
        
        html += '</div>';
        html += '</div>';
        html += '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
        html += '<button class="btn btn-sm" style="background:#3b82f6;color:white;" onclick="openAddMediaModal(\'' + album.id + '\')" title="Tambah gambar/video">➕ Tambah</button>';
html += '<button class="btn btn-sm" style="background:#f59e0b;color:white;" onclick="openEditAlbumModal(\'' + album.id + '\')" title="Edit album">✏️ Edit</button>';
html += '<button class="btn btn-sm" style="background:#10b981;color:white;" onclick="downloadAllPhotos(\'' + album.id + '\')" title="Download semua gambar">📥 Download</button>';
html += '<button class="btn btn-sm" style="background:#25d366;color:white;" onclick="shareAlbumWhatsApp(\'' + album.id + '\')" title="Share ke WhatsApp">📱 Share</button>';
html += '<button class="btn btn-sm btn-delete" onclick="deleteAlbum(\'' + album.id + '\')">🗑 Padam</button>';
        html += '</div>';
        html += '</div>';

        // Videos
if (album.videos && album.videos.length > 0) {
    html += '<div style="padding:15px;background:#faf5ff;">';
    html += '<h4 style="color:#7c3aed;margin-bottom:10px;font-size:0.9rem;">🎥 Video (' + album.videos.length + ')</h4>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:12px;">';
    for (var v = 0; v < album.videos.length; v++) {
        var vid = album.videos[v];
        var poster = vid.thumb || '';
        var durationText = '';
        if (vid.duration) {
            var mins = Math.floor(vid.duration / 60);
            var secs = Math.floor(vid.duration % 60);
            durationText = mins + ':' + (secs < 10 ? '0' : '') + secs;
        }
        
        html += '<div style="background:white;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.1);position:relative;">';
        html += '<video controls preload="metadata" ';
        if (poster) html += 'poster="' + poster + '" ';
        html += 'style="width:100%;height:150px;object-fit:cover;background:#000;">';
        html += '<source src="' + vid.url + '" type="video/mp4">';
        html += 'Video tidak dapat dimuat</video>';
        
        // Duration badge
        if (durationText) {
            html += '<div style="position:absolute;bottom:8px;left:8px;background:rgba(0,0,0,0.75);color:white;padding:3px 8px;border-radius:6px;font-size:0.7rem;font-weight:700;">⏱ ' + durationText + '</div>';
        }
        
        // Delete button
        html += '<button onclick="deleteVideo(\'' + album.id + '\', ' + v + ')" style="position:absolute;top:8px;right:8px;background:rgba(239,68,68,0.9);color:white;border:none;width:30px;height:30px;border-radius:50%;cursor:pointer;font-size:0.9rem;">🗑</button>';
        
        html += '</div>';
    }
    html += '</div>';
    html += '</div>';
}

        // Photos
        if (album.photos && album.photos.length > 0) {
            html += '<div class="gallery-grid">';
            for (var j = 0; j < album.photos.length; j++) {
                var photo = album.photos[j];
                var imgUrl = photo.thumb || photo.url;
                html += '<div class="gallery-item" onclick="openLightbox(\'' + album.id + '\', ' + j + ')">';
                html += '<img src="' + imgUrl + '" alt="" loading="lazy">';
                html += '<button class="gallery-item-delete" onclick="event.stopPropagation(); deletePhoto(\'' + album.id + '\', ' + j + ')">🗑</button>';
                html += '<div class="gallery-item-overlay">' + escapeHtml(album.title) + '</div>';
                html += '</div>';
            }
            html += '</div>';
        }

        html += '</div>';
    }

    container.innerHTML = html;
}

function deleteAlbum(albumId) {
    if (!confirm('Padam album ini dari website?\n\n⚠️ Nota: Gambar masih ada di ImgBB.\nUntuk padam terus, login imgbb.com')) return;

    var newGallery = [];
    for (var i = 0; i < appData.gallery.length; i++) {
        if (appData.gallery[i].id !== albumId) newGallery.push(appData.gallery[i]);
    }
    appData.gallery = newGallery;
    saveData(appData);

    showToast('🗑 Album dipadam');
    renderGallery();
}

function deletePhoto(albumId, photoIndex) {
    if (!confirm('Padam gambar ini?')) return;

    for (var i = 0; i < appData.gallery.length; i++) {
        if (appData.gallery[i].id === albumId) {
            var album = appData.gallery[i];
            if (album.photos && album.photos[photoIndex]) {
                album.photos.splice(photoIndex, 1);
                saveData(appData);
                showToast('🗑 Gambar dipadam');
                renderGallery();
            }
            break;
        }
    }
}

// ===== LIGHTBOX =====

function openLightbox(albumId, photoIndex) {
    var album = null;
    for (var i = 0; i < appData.gallery.length; i++) {
        if (appData.gallery[i].id === albumId) {
            album = appData.gallery[i];
            break;
        }
    }
    if (!album || !album.photos) return;

    lightboxImages = album.photos.map(function(p) {
        return {
            url: p.url || p.displayUrl,
            title: album.title,
            meta: album.category + (album.date ? ' • ' + formatDate(album.date) : '')
        };
    });
    lightboxIndex = photoIndex;

    showLightboxImage();
    document.getElementById('lightbox').classList.remove('hidden');
    document.body.style.overflow = 'hidden';
}

function showLightboxImage() {
    if (lightboxImages.length === 0) return;
    var img = lightboxImages[lightboxIndex];
    document.getElementById('lightboxImage').src = img.url;
    document.getElementById('lightboxTitle').textContent = img.title;
    document.getElementById('lightboxMeta').textContent = img.meta;
    document.getElementById('lightboxCounter').textContent = (lightboxIndex + 1) + ' / ' + lightboxImages.length;
}

function lightboxPrev() {
    lightboxIndex = (lightboxIndex - 1 + lightboxImages.length) % lightboxImages.length;
    showLightboxImage();
}

function lightboxNext() {
    lightboxIndex = (lightboxIndex + 1) % lightboxImages.length;
    showLightboxImage();
}

function closeLightbox() {
    document.getElementById('lightbox').classList.add('hidden');
    document.body.style.overflow = '';
}

// Keyboard navigation
document.addEventListener('keydown', function(e) {
    var lb = document.getElementById('lightbox');
    if (lb && !lb.classList.contains('hidden')) {
        if (e.key === 'ArrowLeft') lightboxPrev();
        else if (e.key === 'ArrowRight') lightboxNext();
        else if (e.key === 'Escape') closeLightbox();
    }
});

// ============================
// ===== LOCATION SEARCH ======
// ============================

var locationSearchTimeout = null;

function searchLocation(query) {
    var suggestionsBox = document.getElementById('locationSuggestions');
    if (!suggestionsBox) return;

    // Clear previous timeout
    if (locationSearchTimeout) {
        clearTimeout(locationSearchTimeout);
    }

    // Minimum 3 huruf
    if (!query || query.length < 3) {
        suggestionsBox.classList.add('hidden');
        return;
    }

    // Show loading
    suggestionsBox.innerHTML = '<div class="location-loading">🔍 Mencari...</div>';
    suggestionsBox.classList.remove('hidden');

    // Debounce - tunggu 500ms selepas user stop typing
    locationSearchTimeout = setTimeout(function() {
        fetchLocations(query);
    }, 500);
}

function fetchLocations(query) {
    // OpenStreetMap Nominatim API (FREE)
    // Limit kepada Malaysia
    var url = 'https://nominatim.openstreetmap.org/search?' +
              'q=' + encodeURIComponent(query) +
              '&format=json' +
              '&countrycodes=my' +  // Malaysia sahaja
              '&limit=8' +
              '&addressdetails=1';

    fetch(url, {
        headers: {
            'Accept-Language': 'ms,en' // Bahasa Malaysia
        }
    })
    .then(function(response) { return response.json(); })
    .then(function(data) {
        displayLocationSuggestions(data);
    })
    .catch(function(error) {
        console.log('Location search error:', error);
        var suggestionsBox = document.getElementById('locationSuggestions');
        suggestionsBox.innerHTML = '<div class="location-empty">❌ Gagal mencari lokasi</div>';
    });
}

function displayLocationSuggestions(results) {
    var suggestionsBox = document.getElementById('locationSuggestions');
    if (!suggestionsBox) return;

    if (!results || results.length === 0) {
        suggestionsBox.innerHTML = '<div class="location-empty">📭 Tiada lokasi ditemui</div>';
        return;
    }

    var html = '';
    for (var i = 0; i < results.length; i++) {
        var place = results[i];
        var displayName = place.display_name;
        var parts = displayName.split(',');

        // Nama utama (yang paling depan)
        var mainName = parts[0].trim();

        // Address (selepas nama utama)
        var address = parts.slice(1, 4).join(', ').trim();

        // Icon ikut type
        var icon = '📍';
        var type = (place.type || '').toLowerCase();
        var category = (place.category || '').toLowerCase();

        if (type === 'mosque' || displayName.toLowerCase().indexOf('masjid') > -1 || displayName.toLowerCase().indexOf('surau') > -1) {
            icon = '🕌';
        } else if (type === 'school' || displayName.toLowerCase().indexOf('sekolah') > -1 || displayName.toLowerCase().indexOf('madrasah') > -1) {
            icon = '🏫';
        } else if (type === 'hospital' || displayName.toLowerCase().indexOf('hospital') > -1) {
            icon = '🏥';
        } else if (category === 'shop' || type === 'mall') {
            icon = '🏬';
        } else if (type === 'restaurant' || type === 'cafe') {
            icon = '🍽️';
        } else if (type === 'park') {
            icon = '🌳';
        } else if (category === 'building') {
            icon = '🏢';
        } else if (type === 'city' || type === 'town' || type === 'village') {
            icon = '🏘️';
        }

        // Escape untuk JSON
        var safeName = mainName.replace(/'/g, "\\'");
        var fullLocation = (mainName + (address ? ', ' + address : '')).replace(/'/g, "\\'");

        html += '<div class="location-suggestion-item" onclick="selectLocation(\'' + fullLocation + '\')">';
        html += '<div class="location-suggestion-icon">' + icon + '</div>';
        html += '<div class="location-suggestion-info">';
        html += '<div class="location-suggestion-name">' + mainName + '</div>';
        if (address) {
            html += '<div class="location-suggestion-address">' + address + '</div>';
        }
        html += '</div>';
        html += '</div>';
    }

    suggestionsBox.innerHTML = html;
}

function selectLocation(location) {
    var input = document.getElementById('galleryLocation');
    if (input) {
        input.value = location;
    }
    hideLocationSuggestions();
}

function hideLocationSuggestions() {
    var box = document.getElementById('locationSuggestions');
    if (box) {
        box.classList.add('hidden');
    }
}

// ============================
// === WHATSAPP INTEGRATION ===
// ============================

// Helper: Format nombor telefon
function formatWhatsAppNumber(phone) {
    if (!phone) return '';

    // Remove semua bukan nombor
    var clean = phone.replace(/[^0-9]/g, '');

    // Kalau start dengan 0, tukar ke 60
    if (clean.startsWith('0')) {
        clean = '60' + clean.substring(1);
    }
    // Kalau dah ada 60, biarkan
    else if (clean.startsWith('60')) {
        // OK
    }
    // Kalau tak ada code, assume Malaysia
    else if (clean.length === 9 || clean.length === 10) {
        clean = '60' + clean;
    }

    return clean;
}

// Helper: Buka WhatsApp dengan mesej
function openWhatsApp(phone, message) {
    var formattedPhone = formatWhatsAppNumber(phone);
    if (!formattedPhone) {
        showToast('❌ No telefon tidak sah');
        return;
    }

    var url = 'https://wa.me/' + formattedPhone + '?text=' + encodeURIComponent(message);
    window.open(url, '_blank');
}

// ===== 1. HANTAR RESIT PEMBAYARAN =====
function sendReceiptWhatsApp(entryId) {
    var entry = null;
    for (var i = 0; i < appData.cashbook.length; i++) {
        if (appData.cashbook[i].id === entryId) {
            entry = appData.cashbook[i];
            break;
        }
    }
    if (!entry) return;

    // Cari student & phone
    var student = null;
    var phone = '';

    if (entry.studentId) {
        for (var i = 0; i < appData.students.length; i++) {
            if (appData.students[i].id === entry.studentId) {
                student = appData.students[i];
                phone = student.fatherPhone || student.motherPhone || student.parentPhone || '';
                break;
            }
        }
    }

    if (!phone) {
        var manualPhone = prompt('Masukkan no telefon ibu/bapa:\n(cth: 0123456789)');
        if (!manualPhone) return;
        phone = manualPhone;
    }

    // Get batch items
    var batchEntries = [];
    if (entry.batchId) {
        for (var i = 0; i < appData.cashbook.length; i++) {
            if (appData.cashbook[i].batchId === entry.batchId) {
                batchEntries.push(appData.cashbook[i]);
            }
        }
    } else {
        batchEntries = [entry];
    }

    var totalAmount = 0;
    var itemsList = '';
    for (var i = 0; i < batchEntries.length; i++) {
        totalAmount += batchEntries[i].amount;
        itemsList += '• ' + batchEntries[i].description + ' - RM ' + batchEntries[i].amount.toFixed(2) + '\n';
    }

    var msg = '*🧾 RESIT RASMI - MADRASAH TAHFIZ PEKAN SUNGAI BULOH*\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n\n';
    msg += 'Assalamualaikum,\n\n';
    msg += 'Terima kasih atas pembayaran anda.\n\n';
    msg += '*📋 Butiran:*\n';
    msg += 'No. Resit: ' + (entry.ref || '-') + '\n';
    msg += 'Tarikh: ' + formatDate(entry.date) + '\n';
    if (student) msg += 'Pelajar: ' + student.name + '\n';
    msg += 'Pembayar: ' + (entry.person || '-') + '\n';
    msg += 'Kaedah: ' + (entry.payMethod || 'Tunai') + '\n\n';
    msg += '*💰 Bayaran:*\n' + itemsList + '\n';
    msg += '*JUMLAH: RM ' + totalAmount.toFixed(2) + '*\n\n';
    msg += '_' + numberToWords(totalAmount) + ' sahaja_\n\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Jazakumullah Khairan 🤲\n';
    msg += '_Madrasah Tahfiz Pekan Sungai Buloh_';

    openWhatsApp(phone, msg);
    showToast('📱 Membuka WhatsApp...');
}

// ===== 2. HANTAR REMINDER KEHADIRAN =====
function sendAttendanceReminder(studentId, date, status) {
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) {
        showToast('❌ Tiada no telefon ibu bapa');
        return;
    }

    var statusText = '';
    var icon = '';
    if (status === 'tidak_hadir') {
        statusText = 'TIDAK HADIR';
        icon = '❌';
    } else if (status === 'lewat') {
        statusText = 'LEWAT';
        icon = '⏰';
    } else if (status === 'hadir') {
        statusText = 'HADIR';
        icon = '✅';
    } else if (status === 'mc') {
        statusText = 'MC/UZUR';
        icon = '🏥';
    }

    var parentName = student.fatherName || student.motherName || student.parentName || 'Ayah/Ibu';

    var msg = '*📅 NOTIFIKASI KEHADIRAN*\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n\n';
    msg += 'Assalamualaikum ' + parentName + ',\n\n';
    msg += 'Maklumat kehadiran anak anda:\n\n';
    msg += '👨‍🎓 *Nama:* ' + student.name + '\n';
    msg += '📚 *Kelas:* ' + student.class + '\n';
    msg += '📅 *Tarikh:* ' + formatDate(date) + '\n';
    msg += icon + ' *Status:* ' + statusText + '\n\n';

    if (status === 'tidak_hadir') {
        msg += '⚠️ _Sila maklumkan kepada pihak madrasah sebab ketidakhadiran._\n\n';
    } else if (status === 'lewat') {
        msg += '⚠️ _Sila pastikan anak hadir tepat pada masanya._\n\n';
    }

    msg += '━━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Terima kasih 🤲\n';
    msg += '_Madrasah Tahfiz Pekan Sungai Buloh_';

    openWhatsApp(phone, msg);
}

// ===== 3. HANTAR UPDATE HAFAZAN =====
function sendHafazanUpdate(recordId) {
    var record = null;
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].id === recordId) {
            record = appData.records[i];
            break;
        }
    }
    if (!record) return;

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === record.studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) {
        showToast('❌ Tiada no telefon');
        return;
    }

    var surahText = formatSurahDisplay(record.surah);
    var juzText = formatJuzDisplay(record.juz);
    var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';

    var msg = '*📖 LAPORAN HAFAZAN*\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n\n';
    msg += 'Assalamualaikum ' + parentName + ',\n\n';
    msg += 'Laporan hafazan anak anda hari ini:\n\n';
    msg += '👨‍🎓 *Nama:* ' + student.name + '\n';
    msg += '📚 *Kelas:* ' + student.class + '\n';
    msg += '📅 *Tarikh:* ' + formatDate(record.date) + '\n\n';
    msg += '*📖 Hafazan:*\n';
    msg += 'Surah: ' + surahText + '\n';
    msg += 'Juz: ' + juzText + '\n';
    if (record.pageFrom) msg += 'Muka surat: ' + record.pageFrom + (record.pageTo ? '-' + record.pageTo : '') + '\n';
    msg += '\n';
    msg += '⭐ *Markah: ' + record.score + '/100*\n';
    msg += '🎯 *Status: ' + record.status + '*\n\n';

    if (record.notes) {
        msg += '*💬 Catatan Ustaz:*\n' + record.notes + '\n\n';
    }

    if (record.detailScores) {
        var ds = record.detailScores;
        var details = [];
        if (ds.kelancaran) details.push('Kelancaran: ' + ds.kelancaran);
        if (ds.tajwid) details.push('Tajwid: ' + ds.tajwid);
        if (ds.makhraj) details.push('Makhraj: ' + ds.makhraj);
        if (ds.adab) details.push('Adab: ' + ds.adab);

        if (details.length > 0) {
            msg += '*📊 Penilaian Detail:*\n';
            for (var i = 0; i < details.length; i++) {
                msg += '• ' + details[i] + '\n';
            }
            msg += '\n';
        }
    }

    msg += '━━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Teruskan usaha! 💪\n';
    msg += '_Madrasah Tahfiz Pekan Sungai Buloh_';

    openWhatsApp(phone, msg);
}

