// ===== 5. BROADCAST KE SEMUA PARENTS =====
function broadcastWhatsApp() {
    var modal = document.getElementById('broadcastModal');
    if (modal) {
        modal.classList.remove('hidden');
        return;
    }

    // Create modal
    var modalHtml = '<div id="broadcastModal" class="broadcast-modal">';
    modalHtml += '<div class="broadcast-modal-content">';
    modalHtml += '<div class="broadcast-header">';
    modalHtml += '<h2>📢 Broadcast WhatsApp</h2>';
    modalHtml += '<button onclick="closeBroadcast()" style="background:none;border:none;color:white;font-size:1.5rem;cursor:pointer;">✕</button>';
    modalHtml += '</div>';
    modalHtml += '<div class="broadcast-body">';

    modalHtml += '<div class="form-group">';
    modalHtml += '<label>Hantar Kepada</label>';
    modalHtml += '<select id="broadcastTarget" onchange="updateBroadcastCount()">';
    modalHtml += '<option value="all">Semua Pelajar</option>';
    var classes = {};
    for (var i = 0; i < appData.students.length; i++) {
        classes[appData.students[i].class] = true;
    }
    for (var c in classes) {
        modalHtml += '<option value="' + escapeHtml(c) + '">' + escapeHtml(c) + '</option>';
    }
    modalHtml += '</select>';
    modalHtml += '<div id="broadcastCount" style="margin-top:8px;font-size:0.85rem;color:var(--text-light);"></div>';
    modalHtml += '</div>';

    modalHtml += '<div class="form-group">';
    modalHtml += '<label>Template Mesej</label>';
    modalHtml += '<select onchange="loadBroadcastTemplate(this.value)">';
    modalHtml += '<option value="">-- Pilih template --</option>';
    modalHtml += '<option value="cuti">📅 Notis Cuti</option>';
    modalHtml += '<option value="majlis">🎉 Jemputan Majlis</option>';
    modalHtml += '<option value="reminder">⚠️ Reminder Umum</option>';
    modalHtml += '<option value="ucapan">🤲 Ucapan</option>';
    modalHtml += '<option value="aktiviti">📚 Aktiviti Baru</option>';
    modalHtml += '</select>';
    modalHtml += '</div>';

    modalHtml += '<div class="form-group">';
    modalHtml += '<label>Mesej</label>';
    modalHtml += '<textarea id="broadcastMessage" rows="10" placeholder="Tulis mesej anda di sini..."></textarea>';
    modalHtml += '</div>';

    modalHtml += '<div style="display:flex;gap:10px;">';
    modalHtml += '<button class="btn btn-primary" onclick="executeBroadcast()" style="flex:1;">📤 Mula Hantar</button>';
    modalHtml += '<button class="btn btn-secondary" onclick="closeBroadcast()">Batal</button>';
    modalHtml += '</div>';

    modalHtml += '</div></div></div>';

    var div = document.createElement('div');
    div.innerHTML = modalHtml;
    document.body.appendChild(div.firstChild);

    setTimeout(updateBroadcastCount, 100);
}

function updateBroadcastCount() {
    var target = document.getElementById('broadcastTarget').value;
    var count = 0;
    var noPhoneCount = 0;

    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (target === 'all' || s.class === target) {
            var phone = s.fatherPhone || s.motherPhone || s.parentPhone;
            if (phone) count++;
            else noPhoneCount++;
        }
    }

    var countEl = document.getElementById('broadcastCount');
    countEl.innerHTML = '📱 ' + count + ' parent ada no telefon';
    if (noPhoneCount > 0) {
        countEl.innerHTML += ' • ⚠️ ' + noPhoneCount + ' tiada no';
    }
}

