function executeBroadcast() {
    var target = document.getElementById('broadcastTarget').value;
    var message = document.getElementById('broadcastMessage').value.trim();

    if (!message) {
        showToast('❌ Sila tulis mesej');
        return;
    }

    // Filter students
    var students = [];
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (target === 'all' || s.class === target) {
            var phone = s.fatherPhone || s.motherPhone || s.parentPhone;
            if (phone) students.push(s);
        }
    }

    if (students.length === 0) {
        showToast('❌ Tiada parent dengan no telefon');
        return;
    }

    if (!confirm('Hantar mesej kepada ' + students.length + ' parent?\n\nNota: WhatsApp akan buka satu-satu. Tekan "Send" untuk setiap satu.')) {
        return;
    }

    closeBroadcast();
    showToast('📱 Membuka WhatsApp untuk ' + students.length + ' parent...');

    // Buka WhatsApp satu-satu dengan delay
    for (var i = 0; i < students.length; i++) {
        (function(student, idx) {
            setTimeout(function() {
                var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
                var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';

                // Personalize: replace [Nama] dengan nama parent
                var personalMsg = 'Assalamualaikum ' + parentName + ',\n\n' + message;

                openWhatsApp(phone, personalMsg);
            }, idx * 1500); // 1.5 saat delay setiap satu
        })(students[i], i);
    }
}

function closeBroadcast() {
    var modal = document.getElementById('broadcastModal');
    if (modal) modal.remove();
}

// ===== 6. CUSTOM MESSAGE TO PARENT =====
function sendCustomWhatsApp(studentId) {
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) {
        showToast('❌ Tiada no telefon');
        return;
    }

    var message = prompt('Tulis mesej untuk ' + student.name + ':\n(Akan dihantar ke ' + phone + ')');
    if (!message) return;

    var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';
    var fullMsg = 'Assalamualaikum ' + parentName + ',\n\n' + message + '\n\n_Madrasah Tahfiz Pekan Sungai Buloh_';

    openWhatsApp(phone, fullMsg);
}

function sendAttendanceBatchWA() {
    var date = document.getElementById('attendanceDate').value;
    if (!date) {
        showToast('❌ Pilih tarikh dahulu');
        return;
    }

    var selects = document.querySelectorAll('.att-status-select');
    var absentList = [];

    for (var i = 0; i < selects.length; i++) {
        var status = selects[i].value;
        if (status === 'tidak_hadir' || status === 'lewat') {
            var studentId = selects[i].id.replace('attStatus_', '');
            absentList.push({ studentId: studentId, status: status });
        }
    }

    if (absentList.length === 0) {
        showToast('✅ Tiada pelajar tidak hadir/lewat');
        return;
    }

    if (!confirm('Hantar notis WhatsApp kepada ' + absentList.length + ' parent?\n\nNota: WhatsApp akan buka satu-satu.')) {
        return;
    }

    for (var i = 0; i < absentList.length; i++) {
        (function(item, idx) {
            setTimeout(function() {
                sendAttendanceReminder(item.studentId, date, item.status);
            }, idx * 1500);
        })(absentList[i], i);
    }
}

// ============================
// ===== FINANCE PRO ==========
// ============================

function initFinancePro() {
    if (!appData.invoices) appData.invoices = [];
    if (!appData.feeSettings) appData.feeSettings = getDefaultFeeSettings();
    if (!appData.invoiceHistory) appData.invoiceHistory = [];

    populateFinanceFilters();
    renderDebts();
    renderInvoiceHistory();
    generateFinanceReport();
    renderFeeSettings();
}

function getDefaultFeeSettings() {
    return {
        DEFAULT: { 
            monthly: 300, 
            registration: 100 
        }
    };
}

// Helper: Get yuran untuk pelajar (semua sama)
function getStudentMonthlyFee() {
    if (appData.feeSettings && appData.feeSettings.DEFAULT) {
        return appData.feeSettings.DEFAULT.monthly || 300;
    }
    return 300; // Default RM300
}

function getStudentRegistrationFee() {
    if (appData.feeSettings && appData.feeSettings.DEFAULT) {
        return appData.feeSettings.DEFAULT.registration || 100;
    }
    return 100;
}

function switchFinanceTab(tabName, btn) {
    var contents = document.querySelectorAll('.finance-content');
    for (var i = 0; i < contents.length; i++) contents[i].classList.remove('active');

    var btns = document.querySelectorAll('.finance-tab');
    for (var i = 0; i < btns.length; i++) btns[i].classList.remove('active');

    document.getElementById('finance-' + tabName).classList.add('active');
    if (btn) btn.classList.add('active');

    if (tabName === 'reports') generateFinanceReport();
    if (tabName === 'debts') renderDebts();
    if (tabName === 'settings') renderFeeSettings();
}

function populateFinanceFilters() {
    var months = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun', 
                  'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    var currentMonth = new Date().getMonth() + 1;
    var currentYear = new Date().getFullYear();

    // Debt filters
    var debtMonth = document.getElementById('debtFilterMonth');
    if (debtMonth) {
        var html = '<option value="all">Semua Bulan</option>';
        for (var i = 1; i <= 12; i++) {
            html += '<option value="' + i + '"' + (i === currentMonth ? ' selected' : '') + '>' + months[i] + '</option>';
        }
        debtMonth.innerHTML = html;
    }

    var debtYear = document.getElementById('debtFilterYear');
    if (debtYear) {
        var html = '';
        for (var y = currentYear + 1; y >= currentYear - 2; y--) {
            html += '<option value="' + y + '"' + (y === currentYear ? ' selected' : '') + '>' + y + '</option>';
        }
        debtYear.innerHTML = html;
    }

    // Invoice filters
    var invMonth = document.getElementById('invoiceMonth');
    if (invMonth) {
        var html = '';
        for (var i = 1; i <= 12; i++) {
            html += '<option value="' + i + '"' + (i === currentMonth ? ' selected' : '') + '>' + months[i] + '</option>';
        }
        invMonth.innerHTML = html;
    }

    var invYear = document.getElementById('invoiceYear');
    if (invYear) {
        var html = '';
        for (var y = currentYear + 1; y >= currentYear - 1; y--) {
            html += '<option value="' + y + '"' + (y === currentYear ? ' selected' : '') + '>' + y + '</option>';
        }
        invYear.innerHTML = html;
    }

    // Class filter
    var invClass = document.getElementById('invoiceClass');
    if (invClass) {
        var html = '<option value="all">Semua Kelas</option>';
        var classes = {};
        for (var i = 0; i < appData.students.length; i++) {
            classes[appData.students[i].class] = true;
        }
        for (var c in classes) {
            html += '<option value="' + escapeHtml(c) + '">' + escapeHtml(c) + '</option>';
        }
        invClass.innerHTML = html;
    }

    // Report filters
    var reportMonth = document.getElementById('reportMonth');
    if (reportMonth) {
        var html = '';
        for (var i = 1; i <= 12; i++) {
            html += '<option value="' + i + '"' + (i === currentMonth ? ' selected' : '') + '>' + months[i] + '</option>';
        }
        reportMonth.innerHTML = html;
    }

    var reportYear = document.getElementById('reportYear');
    if (reportYear) {
        var html = '';
        for (var y = currentYear + 1; y >= currentYear - 2; y--) {
            html += '<option value="' + y + '"' + (y === currentYear ? ' selected' : '') + '>' + y + '</option>';
        }
        reportYear.innerHTML = html;
    }
}

// ===== MODULE 1: HUTANG =====

function renderDebts() {
    if (!appData.invoices) appData.invoices = [];

    var monthFilter = document.getElementById('debtFilterMonth').value;
    var yearFilter = document.getElementById('debtFilterYear').value;
    var statusFilter = document.getElementById('debtFilterStatus').value;

    var filtered = [];
    var today = new Date();

    for (var i = 0; i < appData.invoices.length; i++) {
        var inv = appData.invoices[i];
        var invMonth = inv.month;
        var invYear = inv.year;

        var monthOk = monthFilter === 'all' || parseInt(monthFilter) === invMonth;
        var yearOk = parseInt(yearFilter) === invYear;

        // Check overdue
        var isOverdue = false;
        if (inv.dueDate && !inv.paid) {
            isOverdue = new Date(inv.dueDate) < today;
        }

        var statusOk = true;
        if (statusFilter === 'paid') statusOk = inv.paid;
        else if (statusFilter === 'unpaid') statusOk = !inv.paid;
        else if (statusFilter === 'overdue') statusOk = isOverdue && !inv.paid;

        if (monthOk && yearOk && statusOk) {
            inv.isOverdue = isOverdue;
            filtered.push(inv);
        }
    }

    // Sort: unpaid first, then by name
    filtered.sort(function(a, b) {
        if (a.paid !== b.paid) return a.paid ? 1 : -1;
        return (a.studentName || '').localeCompare(b.studentName || '');
    });

    // Update stats
    updateDebtStats();

    var tbody = document.getElementById('debtsBody');
    if (!tbody) return;

    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" class="text-center" style="padding:40px;"><div class="empty-state"><div class="empty-icon">📭</div><p>Tiada rekod</p></div></td></tr>';
        return;
    }

    var months = ['', 'Jan', 'Feb', 'Mac', 'Apr', 'Mei', 'Jun', 'Jul', 'Ogo', 'Sep', 'Okt', 'Nov', 'Dis'];

    var html = '';
    for (var i = 0; i < filtered.length; i++) {
        var inv = filtered[i];

        var statusBadge = '';
        if (inv.paid) {
            statusBadge = '<span class="debt-status paid">✅ Bayar</span>';
        } else if (inv.isOverdue) {
            statusBadge = '<span class="debt-status overdue">🔴 Lewat</span>';
        } else {
            statusBadge = '<span class="debt-status unpaid">⚠️ Belum Bayar</span>';
        }

        html += '<tr>';
        html += '<td><strong>' + escapeHtml(inv.studentName) + '</strong></td>';
        html += '<td>' + escapeHtml(inv.className || '-') + '</td>';
        html += '<td>' + months[inv.month] + ' ' + inv.year + '</td>';
        html += '<td>' + escapeHtml(inv.type) + '</td>';
        html += '<td class="text-right"><strong>RM ' + inv.amount.toFixed(2) + '</strong></td>';
        html += '<td>' + statusBadge + '</td>';
        html += '<td><div style="display:flex;gap:5px;">';

        if (!inv.paid) {
            html += '<button class="btn btn-sm" style="background:var(--primary);color:white;" onclick="markInvoicePaid(\'' + inv.id + '\')" title="Mark as Paid">✅</button>';
            html += '<button class="btn btn-sm" style="background:#25d366;color:white;" onclick="sendInvoiceReminder(\'' + inv.id + '\')" title="Reminder WA">📱</button>';
        }
        html += '<button class="btn btn-sm btn-delete" onclick="deleteInvoice(\'' + inv.id + '\')" title="Padam">🗑</button>';
        html += '</div></td>';
        html += '</tr>';
    }

    tbody.innerHTML = html;
}

function updateDebtStats() {
    var unpaid = 0;
    var totalUnpaidAmount = 0;
    var paidStudents = {};
    var unpaidStudents = {};
    var totalAmount = 0;

    for (var i = 0; i < appData.invoices.length; i++) {
        var inv = appData.invoices[i];
        totalAmount += inv.amount;

        if (inv.paid) {
            paidStudents[inv.studentId] = true;
        } else {
            unpaid++;
            totalUnpaidAmount += inv.amount;
            unpaidStudents[inv.studentId] = true;
        }
    }

    var paidCount = Object.keys(paidStudents).length;
    var unpaidCount = Object.keys(unpaidStudents).length;

    var collectionRate = totalAmount > 0 ? Math.round(((totalAmount - totalUnpaidAmount) / totalAmount) * 100) : 0;

    document.getElementById('totalUnpaid').textContent = 'RM ' + totalUnpaidAmount.toFixed(0);
    document.getElementById('totalDebtStudents').textContent = unpaidCount;
    document.getElementById('totalPaidStudents').textContent = paidCount;
    document.getElementById('collectionRate').textContent = collectionRate + '%';
}

function markInvoicePaid(invoiceId) {
    if (!confirm('Tandakan invois ini sebagai DIBAYAR?')) return;

    for (var i = 0; i < appData.invoices.length; i++) {
        if (appData.invoices[i].id === invoiceId) {
            var inv = appData.invoices[i];
            inv.paid = true;
            inv.paidDate = new Date().toISOString().split('T')[0];

            // Auto add to cashbook
            if (!appData.cashbook) appData.cashbook = [];

            var entry = {
                id: 'CASH' + Date.now(),
                date: inv.paidDate,
                ref: getNextReceiptNumber(),
                description: inv.type + ' - ' + inv.studentName + ' (' + getMonthName(inv.month) + ' ' + inv.year + ')',
                category: inv.type,
                type: 'debit',
                amount: inv.amount,
                payMethod: 'Tunai',
                notes: 'Auto dari invois ' + inv.id,
                person: inv.parentName || inv.studentName,
                studentId: inv.studentId,
                invoiceId: inv.id,
                createdAt: new Date().toISOString()
            };
            appData.cashbook.push(entry);

            inv.receiptRef = entry.ref;
            saveData(appData);

            showToast('✅ Invois bertanda DIBAYAR & Resit ' + entry.ref + ' dijana!');
            renderDebts();
            return;
        }
    }
}

function deleteInvoice(invoiceId) {
    if (!confirm('Padam invois ini?')) return;

    var newList = [];
    for (var i = 0; i < appData.invoices.length; i++) {
        if (appData.invoices[i].id !== invoiceId) newList.push(appData.invoices[i]);
    }
    appData.invoices = newList;
    saveData(appData);
    showToast('🗑 Invois dipadam');
    renderDebts();
}

function sendInvoiceReminder(invoiceId) {
    var inv = null;
    for (var i = 0; i < appData.invoices.length; i++) {
        if (appData.invoices[i].id === invoiceId) {
            inv = appData.invoices[i];
            break;
        }
    }
    if (!inv) return;

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === inv.studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) {
        showToast('❌ Pelajar tidak ditemui');
        return;
    }

    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) {
        showToast('❌ Tiada no telefon');
        return;
    }

    var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';

    var msg = '*⚠️ PERINGATAN YURAN*\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n\n';
    msg += 'Assalamualaikum ' + parentName + ',\n\n';
    msg += 'Ini peringatan mesra untuk yuran:\n\n';
    msg += '👨‍🎓 *Pelajar:* ' + student.name + '\n';
    msg += '📚 *Kelas:* ' + student.class + '\n';
    msg += '📋 *Jenis:* ' + inv.type + '\n';
    msg += '📅 *Bulan:* ' + getMonthName(inv.month) + ' ' + inv.year + '\n';
    msg += '💰 *Jumlah:* RM ' + inv.amount.toFixed(2) + '\n';
    if (inv.dueDate) {
        msg += '⏰ *Tarikh Akhir:* ' + formatDate(inv.dueDate) + '\n';
    }
    msg += '\n';

    if (inv.isOverdue) {
        msg += '🔴 *AMARAN: Yuran telah LEWAT!*\n\n';
    }

    msg += 'Sila buat pembayaran secepat mungkin.\n\n';
    msg += '*📌 Cara Bayar:*\n';
    msg += '1. Tunai - Pejabat\n';
    msg += '2. Bank transfer\n';
    msg += '3. QR Pay / E-Wallet\n\n';
    msg += '━━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Jazakumullah Khairan 🤲\n';
    msg += '_Madrasah Tahfiz Pekan Sungai Buloh_';

    openWhatsApp(phone, msg);
}

function sendBulkReminders() {
    var unpaidInvoices = [];
    for (var i = 0; i < appData.invoices.length; i++) {
        if (!appData.invoices[i].paid) {
            unpaidInvoices.push(appData.invoices[i]);
        }
    }

    if (unpaidInvoices.length === 0) {
        showToast('✅ Tiada invois tertunggak');
        return;
    }

    if (!confirm('Hantar reminder WhatsApp kepada ' + unpaidInvoices.length + ' invois?\n\nWhatsApp akan buka satu-satu.')) {
        return;
    }

    showToast('📱 Membuka WhatsApp...');

    for (var i = 0; i < unpaidInvoices.length; i++) {
        (function(inv, idx) {
            setTimeout(function() {
                sendInvoiceReminder(inv.id);
            }, idx * 1500);
        })(unpaidInvoices[i], i);
    }
}

function generateMonthlyFees() {
    var month = new Date().getMonth() + 1;
    var year = new Date().getFullYear();
    var monthName = getMonthName(month);

    var feeAmount = getStudentMonthlyFee();

    if (!confirm('Jana yuran bulanan untuk SEMUA pelajar?\n\n' +
                 'Bulan: ' + monthName + ' ' + year + '\n' +
                 'Yuran per pelajar: RM ' + feeAmount + '\n' +
                 'Jumlah pelajar: ' + appData.students.length + ' orang\n' +
                 'Total: RM ' + (feeAmount * appData.students.length).toLocaleString() + '\n\n' +
                 'Nota: Sistem akan skip pelajar yang dah ada invois bulan ni.')) {
        return;
    }

    var created = 0;
    var skipped = 0;
    var totalAmount = 0;

    if (!appData.invoices) appData.invoices = [];

    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];

        // Check kalau dah ada invois bulan ni
        var exists = false;
        for (var j = 0; j < appData.invoices.length; j++) {
            var inv = appData.invoices[j];
            if (inv.studentId === s.id && 
                inv.month === month && 
                inv.year === year && 
                inv.type === 'Yuran Bulanan') {
                exists = true;
                break;
            }
        }

        if (exists) {
            skipped++;
            continue;
        }

        // Create invoice - SEMUA SAMA YURAN
        var dueDate = new Date(year, month - 1, 10).toISOString().split('T')[0];

        appData.invoices.push({
            id: 'INV' + Date.now() + '_' + i,
            studentId: s.id,
            studentName: s.name,
            className: s.class || '-',
            parentName: s.fatherName || s.motherName || '',
            type: 'Yuran Bulanan',
            month: month,
            year: year,
            amount: feeAmount,
            dueDate: dueDate,
            paid: false,
            createdAt: new Date().toISOString()
        });

        totalAmount += feeAmount;
        created++;
    }

    saveData(appData);
    showToast('✅ Berjaya jana ' + created + ' invois! Total: RM ' + totalAmount.toLocaleString() + (skipped > 0 ? ' (' + skipped + ' diskip)' : ''));
    renderDebts();
}

// ===== MODULE 2: INVOICES =====

function previewInvoices() {
    var month = parseInt(document.getElementById('invoiceMonth').value);
    var year = parseInt(document.getElementById('invoiceYear').value);

    var feeAmount = getStudentMonthlyFee();

    var preview = document.getElementById('invoicePreview');
    var content = document.getElementById('invoicePreviewContent');

    var students = appData.students;

    var html = '<table style="width:100%;font-size:0.85rem;border-collapse:collapse;">';
    html += '<thead><tr style="background:white;">';
    html += '<th style="padding:8px;text-align:left;">Pelajar</th>';
    html += '<th style="padding:8px;text-align:right;">Yuran</th>';
    html += '</tr></thead><tbody>';

    var total = 0;
    var count = 0;
    var existsCount = 0;

    for (var i = 0; i < students.length; i++) {
        var s = students[i];

        // Check existing
        var exists = false;
        for (var j = 0; j < appData.invoices.length; j++) {
            var inv = appData.invoices[j];
            if (inv.studentId === s.id && 
                inv.month === month && 
                inv.year === year && 
                inv.type === 'Yuran Bulanan') {
                exists = true;
                break;
            }
        }

        if (exists) {
            existsCount++;
            html += '<tr style="background:#fee;">';
            html += '<td style="padding:6px;">' + escapeHtml(s.name) + ' ⚠️ <small style="color:#999;">(dah ada invois)</small></td>';
            html += '<td style="padding:6px;text-align:right;color:#999;">SKIP</td>';
            html += '</tr>';
        } else {
            count++;
            total += feeAmount;
            html += '<tr>';
            html += '<td style="padding:6px;">' + escapeHtml(s.name) + '</td>';
            html += '<td style="padding:6px;text-align:right;">RM ' + feeAmount.toFixed(2) + '</td>';
            html += '</tr>';
        }
    }

    html += '<tr style="background:var(--primary);color:white;font-weight:700;">';
    html += '<td style="padding:10px;">JUMLAH BARU (' + count + ' invois)</td>';
    html += '<td style="padding:10px;text-align:right;">RM ' + total.toFixed(2) + '</td>';
    html += '</tr>';
    html += '</tbody></table>';

    if (existsCount > 0) {
        html += '<p style="margin-top:10px;color:#dc2626;font-size:0.82rem;">⚠️ ' + existsCount + ' pelajar dah ada invois - akan diskip.</p>';
    }

    content.innerHTML = html;
    preview.style.display = 'block';
}

function generateInvoices() {
    var month = parseInt(document.getElementById('invoiceMonth').value);
    var year = parseInt(document.getElementById('invoiceYear').value);
    var dueDate = document.getElementById('invoiceDueDate').value;
    var note = document.getElementById('invoiceNote') ? document.getElementById('invoiceNote').value.trim() : '';

    if (!dueDate) {
        dueDate = new Date(year, month - 1, 10).toISOString().split('T')[0];
    }

    var feeAmount = getStudentMonthlyFee();

    if (!confirm('Jana invois untuk SEMUA pelajar:\n\n' +
                 'Bulan: ' + getMonthName(month) + ' ' + year + '\n' +
                 'Yuran: RM ' + feeAmount + ' setiap pelajar\n' +
                 'Jumlah pelajar: ' + appData.students.length + ' orang\n\n' +
                 'Teruskan?')) {
        return;
    }

    if (!appData.invoices) appData.invoices = [];
    if (!appData.invoiceHistory) appData.invoiceHistory = [];

    var created = 0;
    var skipped = 0;
    var totalAmount = 0;
    var newInvoiceIds = [];

    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];

        var exists = false;
        for (var j = 0; j < appData.invoices.length; j++) {
            var inv = appData.invoices[j];
            if (inv.studentId === s.id && 
                inv.month === month && 
                inv.year === year && 
                inv.type === 'Yuran Bulanan') {
                exists = true;
                break;
            }
        }

        if (exists) {
            skipped++;
            continue;
        }

        var invId = 'INV' + Date.now() + '_' + i;
        appData.invoices.push({
            id: invId,
            studentId: s.id,
            studentName: s.name,
            className: s.class || '-',
            parentName: s.fatherName || s.motherName || '',
            type: 'Yuran Bulanan',
            month: month,
            year: year,
            amount: feeAmount,
            dueDate: dueDate,
            note: note,
            paid: false,
            createdAt: new Date().toISOString()
        });

        newInvoiceIds.push(invId);
        totalAmount += feeAmount;
        created++;
    }

    appData.invoiceHistory.push({
        id: 'HIST' + Date.now(),
        generatedAt: new Date().toISOString(),
        month: month,
        year: year,
        classFilter: 'all',
        count: created,
        totalAmount: totalAmount,
        invoiceIds: newInvoiceIds
    });

    saveData(appData);

    document.getElementById('invoicePreview').style.display = 'none';
    showToast('✅ ' + created + ' invois berjaya dijana! Total: RM ' + totalAmount.toFixed(2));
    renderInvoiceHistory();
}

function renderInvoiceHistory() {
    var tbody = document.getElementById('invoiceHistoryBody');
    if (!tbody) return;

    if (!appData.invoiceHistory || appData.invoiceHistory.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" class="text-center" style="padding:30px;color:var(--text-light);">Belum ada history</td></tr>';
        return;
    }

    var sorted = appData.invoiceHistory.slice().sort(function(a, b) {
        return new Date(b.generatedAt) - new Date(a.generatedAt);
    });

    var html = '';
    for (var i = 0; i < sorted.length; i++) {
        var h = sorted[i];

        // Calculate paid status
        var paidCount = 0;
        for (var j = 0; j < h.invoiceIds.length; j++) {
            for (var k = 0; k < appData.invoices.length; k++) {
                if (appData.invoices[k].id === h.invoiceIds[j] && appData.invoices[k].paid) {
                    paidCount++;
                    break;
                }
            }
        }

        var percent = h.count > 0 ? Math.round((paidCount / h.count) * 100) : 0;
        var statusColor = percent === 100 ? 'var(--primary)' : percent >= 50 ? 'var(--gold)' : 'var(--red)';

        html += '<tr>';
        html += '<td>' + formatDate(h.generatedAt.split('T')[0]) + '</td>';
        html += '<td>' + getMonthName(h.month) + ' ' + h.year + '</td>';
        html += '<td>' + escapeHtml(h.classFilter) + '</td>';
        html += '<td><strong>' + h.count + '</strong></td>';
        html += '<td class="text-right"><strong>RM ' + h.totalAmount.toFixed(2) + '</strong></td>';
        html += '<td><span style="color:' + statusColor + ';font-weight:700;">' + paidCount + '/' + h.count + ' (' + percent + '%)</span></td>';
        html += '<td><button class="btn btn-sm btn-delete" onclick="deleteInvoiceHistory(\'' + h.id + '\')" title="Padam history">🗑</button></td>';
        html += '</tr>';
    }

    tbody.innerHTML = html;
}

function deleteInvoiceHistory(historyId) {
    if (!confirm('Padam rekod history ini? (Invois tak akan dipadam)')) return;

    var newList = [];
    for (var i = 0; i < appData.invoiceHistory.length; i++) {
        if (appData.invoiceHistory[i].id !== historyId) newList.push(appData.invoiceHistory[i]);
    }
    appData.invoiceHistory = newList;
    saveData(appData);
    renderInvoiceHistory();
}

// ===== MODULE 3: REPORTS =====

function generateFinanceReport() {
    var container = document.getElementById('financeReportContent');
    if (!container) return;

    var month = parseInt(document.getElementById('reportMonth').value);
    var year = parseInt(document.getElementById('reportYear').value);
    var type = document.getElementById('reportType').value;

    if (!appData.cashbook) appData.cashbook = [];

    var income = 0;
    var expense = 0;
    var incomeByCategory = {};
    var expenseByCategory = {};
    var entries = [];

    for (var i = 0; i < appData.cashbook.length; i++) {
        var e = appData.cashbook[i];
        var entryDate = new Date(e.date);
        var entryYear = entryDate.getFullYear();
        var entryMonth = entryDate.getMonth() + 1;

        var matchPeriod = false;
        if (type === 'monthly') {
            matchPeriod = entryMonth === month && entryYear === year;
        } else if (type === 'yearly') {
            matchPeriod = entryYear === year;
        }

        if (!matchPeriod) continue;

        entries.push(e);

        if (e.type === 'debit') {
            income += e.amount;
            incomeByCategory[e.category] = (incomeByCategory[e.category] || 0) + e.amount;
        } else {
            expense += e.amount;
            expenseByCategory[e.category] = (expenseByCategory[e.category] || 0) + e.amount;
        }
    }

    var net = income - expense;
    var period = type === 'monthly' ? getMonthName(month) + ' ' + year : 'Tahun ' + year;

    var html = '<div class="print-finance-area">';

    // Header
    html += '<div class="report-header">';
    html += '<h1>📊 LAPORAN KEWANGAN</h1>';
    html += '<h2 style="color:var(--text-light);font-size:1.1rem;margin:5px 0;">Madrasah Tahfiz Pekan Sungai Buloh</h2>';
    html += '<p>Tempoh: <strong>' + period + '</strong></p>';
    html += '<p style="font-size:0.78rem;">Dijana pada: ' + new Date().toLocaleString('ms-MY') + '</p>';
    html += '</div>';

    // Summary
    html += '<div class="report-summary">';
    html += '<div class="report-summary-card income">';
    html += '<div style="font-size:2rem;">📥</div>';
    html += '<div class="amount">RM ' + income.toFixed(2) + '</div>';
    html += '<div class="label">JUMLAH PENDAPATAN</div>';
    html += '</div>';
    html += '<div class="report-summary-card expense">';
    html += '<div style="font-size:2rem;">📤</div>';
    html += '<div class="amount">RM ' + expense.toFixed(2) + '</div>';
    html += '<div class="label">JUMLAH PERBELANJAAN</div>';
    html += '</div>';
    html += '<div class="report-summary-card net">';
    html += '<div style="font-size:2rem;">' + (net >= 0 ? '💰' : '⚠️') + '</div>';
    html += '<div class="amount" style="color:' + (net >= 0 ? 'var(--primary)' : 'var(--red)') + ';">RM ' + net.toFixed(2) + '</div>';
    html += '<div class="label">' + (net >= 0 ? 'KEUNTUNGAN BERSIH' : 'KERUGIAN BERSIH') + '</div>';
    html += '</div>';
    html += '</div>';

    // Income breakdown
    html += '<div class="report-table-section">';
    html += '<h3>📥 Pecahan Pendapatan</h3>';
    html += '<table class="table"><thead><tr><th>Kategori</th><th class="text-right">Jumlah (RM)</th><th class="text-right">%</th></tr></thead><tbody>';

    var incomeArr = [];
    for (var cat in incomeByCategory) {
        incomeArr.push({ cat: cat, amount: incomeByCategory[cat] });
    }
    incomeArr.sort(function(a, b) { return b.amount - a.amount; });

    if (incomeArr.length === 0) {
        html += '<tr><td colspan="3" class="text-center" style="padding:15px;color:var(--text-light);">Tiada pendapatan</td></tr>';
    } else {
        for (var i = 0; i < incomeArr.length; i++) {
            var item = incomeArr[i];
            var pct = income > 0 ? ((item.amount / income) * 100).toFixed(1) : 0;
            html += '<tr><td>' + item.cat + '</td><td class="text-right" style="color:var(--primary);font-weight:700;">' + item.amount.toFixed(2) + '</td><td class="text-right">' + pct + '%</td></tr>';
        }
        html += '<tr style="background:#faf5ff;font-weight:700;"><td>JUMLAH</td><td class="text-right" style="color:var(--primary);">' + income.toFixed(2) + '</td><td class="text-right">100%</td></tr>';
    }
    html += '</tbody></table></div>';

    // Expense breakdown
    html += '<div class="report-table-section">';
    html += '<h3>📤 Pecahan Perbelanjaan</h3>';
    html += '<table class="table"><thead><tr><th>Kategori</th><th class="text-right">Jumlah (RM)</th><th class="text-right">%</th></tr></thead><tbody>';

    var expenseArr = [];
    for (var cat in expenseByCategory) {
        expenseArr.push({ cat: cat, amount: expenseByCategory[cat] });
    }
    expenseArr.sort(function(a, b) { return b.amount - a.amount; });

    if (expenseArr.length === 0) {
        html += '<tr><td colspan="3" class="text-center" style="padding:15px;color:var(--text-light);">Tiada perbelanjaan</td></tr>';
    } else {
        for (var i = 0; i < expenseArr.length; i++) {
            var item = expenseArr[i];
            var pct = expense > 0 ? ((item.amount / expense) * 100).toFixed(1) : 0;
            html += '<tr><td>' + item.cat + '</td><td class="text-right" style="color:var(--red);font-weight:700;">' + item.amount.toFixed(2) + '</td><td class="text-right">' + pct + '%</td></tr>';
        }
        html += '<tr style="background:#fef2f2;font-weight:700;"><td>JUMLAH</td><td class="text-right" style="color:var(--red);">' + expense.toFixed(2) + '</td><td class="text-right">100%</td></tr>';
    }
    html += '</tbody></table></div>';

    // P&L Statement
    html += '<div class="report-table-section">';
    html += '<h3>💼 Penyata Untung Rugi (P&L)</h3>';
    html += '<table class="table">';
    html += '<tr><td><strong>Jumlah Pendapatan</strong></td><td class="text-right" style="color:var(--primary);font-weight:700;">RM ' + income.toFixed(2) + '</td></tr>';
    html += '<tr><td><strong>(-) Jumlah Perbelanjaan</strong></td><td class="text-right" style="color:var(--red);font-weight:700;">(RM ' + expense.toFixed(2) + ')</td></tr>';
    html += '<tr style="background:' + (net >= 0 ? '#faf5ff' : '#fef2f2') + ';"><td><strong>' + (net >= 0 ? 'KEUNTUNGAN' : 'KERUGIAN') + ' BERSIH</strong></td><td class="text-right" style="font-size:1.2rem;color:' + (net >= 0 ? 'var(--primary)' : 'var(--red)') + ';font-weight:800;">RM ' + net.toFixed(2) + '</td></tr>';
    html += '</table>';
    html += '</div>';

    // Sign area
    html += '<div style="margin-top:50px;display:grid;grid-template-columns:1fr 1fr;gap:40px;">';
    html += '<div><div style="border-bottom:1px solid #333;height:40px;margin-bottom:8px;"></div><p style="font-size:0.85rem;"><strong>Disediakan oleh:</strong><br>Bendahari Madrasah</p></div>';
    html += '<div><div style="border-bottom:1px solid #333;height:40px;margin-bottom:8px;"></div><p style="font-size:0.85rem;"><strong>Diluluskan oleh:</strong><br>Pengetua Madrasah</p></div>';
    html += '</div>';

    html += '</div>'; // print area

    container.innerHTML = html;
}

