function saveFeeSettings() {
    if (!appData.feeSettings) appData.feeSettings = {};

    var monthlyEl = document.getElementById('feeMonthly');
    var regEl = document.getElementById('feeRegistration');

    if (!monthlyEl || !regEl) {
        showToast('❌ Element tak ditemui');
        return;
    }

    var monthly = parseFloat(monthlyEl.value) || 300;
    var registration = parseFloat(regEl.value) || 100;

    appData.feeSettings.DEFAULT = {
        monthly: monthly,
        registration: registration
    };

    saveData(appData);
    showToast('✅ Yuran disimpan! Bulanan: RM' + monthly + ' | Daftar: RM' + registration);

    // Re-render untuk update statistik
    renderFeeSettings();
}

// ============================
// ===== WAKTU SOLAT LIVE =====
// ============================

var prayerData = null;
var currentPrayerZone = 'SGR02'; // Default: Kuala Selangor
var prayerCountdownInterval = null;

function initPrayerTimes() {
    // Load saved zone
    var savedZone = localStorage.getItem('prayerZone');
    if (savedZone) {
        currentPrayerZone = savedZone;
        var select = document.getElementById('prayerZone');
        if (select) select.value = currentPrayerZone;
    }

    fetchPrayerTimes();
    updateDateDisplay();

    // Update countdown every second
    if (prayerCountdownInterval) clearInterval(prayerCountdownInterval);
    prayerCountdownInterval = setInterval(updateCountdown, 1000);

    // Refresh prayer times daily at midnight
    setInterval(function() {
        var now = new Date();
        if (now.getHours() === 0 && now.getMinutes() === 0) {
            fetchPrayerTimes();
            updateDateDisplay();
        }
    }, 60000); // Check every minute

    // Request notification permission
if ('Notification' in window && Notification.permission === 'default') {
    setTimeout(function() {
        Notification.requestPermission();
    }, 5000);
}
}

function changePrayerZone(zone) {
    currentPrayerZone = zone;
    localStorage.setItem('prayerZone', zone);
    fetchPrayerTimes();
}

function fetchPrayerTimes() {
    var widget = document.getElementById('prayerTimesWidget');
    if (!widget) return;

    widget.classList.add('loading');

    // Get current date
    var today = new Date();
    var year = today.getFullYear();
    var month = String(today.getMonth() + 1).padStart(2, '0');
    var day = String(today.getDate()).padStart(2, '0');
    var dateStr = year + '-' + month + '-' + day;

    // Use e-Solat JAKIM API via CORS proxy
    var apiUrl = 'https://api.waktusolat.app/v2/solat/' + currentPrayerZone;

    fetch(apiUrl)
        .then(function(response) {
            if (!response.ok) throw new Error('API error');
            return response.json();
        })
        .then(function(data) {
            if (data && data.prayers && data.prayers.length > 0) {
                // Cari hari ni
                var todayDay = today.getDate();
                var todayPrayer = null;

                for (var i = 0; i < data.prayers.length; i++) {
                    if (data.prayers[i].day === todayDay) {
                        todayPrayer = data.prayers[i];
                        break;
                    }
                }

                if (!todayPrayer) {
                    todayPrayer = data.prayers[0]; // Fallback to first
                }

                prayerData = {
                    Subuh: formatTime(todayPrayer.fajr),
                    Syuruk: formatTime(todayPrayer.syuruk),
                    Zohor: formatTime(todayPrayer.dhuhr),
                    Asar: formatTime(todayPrayer.asr),
                    Maghrib: formatTime(todayPrayer.maghrib),
                    Isyak: formatTime(todayPrayer.isha)
                };

                // Location info
                var locationEl = document.getElementById('prayerLocation');
                if (locationEl) {
                    locationEl.textContent = '📍 ' + (data.place || getZoneName(currentPrayerZone));
                }

                displayPrayerTimes();
                updateCountdown();
            } else {
                throw new Error('Invalid data');
            }
        })
        .catch(function(error) {
            console.log('Prayer API error, using fallback:', error);
            // Fallback waktu solat (anggaran)
            loadFallbackPrayerTimes();
        })
        .finally(function() {
            widget.classList.remove('loading');
        });
}

function loadFallbackPrayerTimes() {
    // Anggaran waktu solat (boleh tukar manual)
    prayerData = {
        Subuh: '05:50',
        Syuruk: '07:10',
        Zohor: '13:15',
        Asar: '16:35',
        Maghrib: '19:25',
        Isyak: '20:35'
    };

    var locationEl = document.getElementById('prayerLocation');
    if (locationEl) {
        locationEl.textContent = '📍 ' + getZoneName(currentPrayerZone) + ' (Anggaran)';
    }

    displayPrayerTimes();
    updateCountdown();
}

function formatTime(timestamp) {
    if (!timestamp) return '00:00';

    // Kalau timestamp adalah Unix timestamp
    if (typeof timestamp === 'number') {
        var date = new Date(timestamp * 1000);
        var hours = String(date.getHours()).padStart(2, '0');
        var minutes = String(date.getMinutes()).padStart(2, '0');
        return hours + ':' + minutes;
    }

    // Kalau dah dalam format string HH:MM
    if (typeof timestamp === 'string') {
        return timestamp.substring(0, 5);
    }

    return '00:00';
}

function displayPrayerTimes() {
    if (!prayerData) return;

    var prayers = ['Subuh', 'Zohor', 'Asar', 'Maghrib', 'Isyak'];

    for (var i = 0; i < prayers.length; i++) {
        var el = document.getElementById('time-' + prayers[i]);
        if (el) {
            el.textContent = formatTime12Hour(prayerData[prayers[i]]);
        }
    }

    highlightCurrentPrayer();
}

function formatTime12Hour(time24) {
    var parts = time24.split(':');
    var hours = parseInt(parts[0]);
    var minutes = parts[1];
    var period = hours >= 12 ? 'PM' : 'AM';

    if (hours === 0) hours = 12;
    else if (hours > 12) hours -= 12;

    return hours + ':' + minutes + ' ' + period;
}

function highlightCurrentPrayer() {
    if (!prayerData) return;

    var now = new Date();
    var nowMinutes = now.getHours() * 60 + now.getMinutes();

    var prayers = ['Subuh', 'Zohor', 'Asar', 'Maghrib', 'Isyak'];
    var prayerMinutes = {};

    for (var i = 0; i < prayers.length; i++) {
        var time = prayerData[prayers[i]];
        var parts = time.split(':');
        prayerMinutes[prayers[i]] = parseInt(parts[0]) * 60 + parseInt(parts[1]);
    }

    // Find current and next prayer
    var currentPrayer = null;
    var nextPrayer = null;

    for (var i = 0; i < prayers.length; i++) {
        var prayer = prayers[i];
        if (nowMinutes >= prayerMinutes[prayer]) {
            currentPrayer = prayer;
        } else {
            nextPrayer = prayer;
            break;
        }
    }

    // Kalau dah lepas Isyak, next prayer = Subuh esok
    if (!nextPrayer) {
        nextPrayer = 'Subuh';
    }

    // Highlight cards
    var cards = document.querySelectorAll('.prayer-time-card');
    for (var i = 0; i < cards.length; i++) {
        cards[i].classList.remove('active', 'passed');
        var cardPrayer = cards[i].dataset.prayer;

        if (cardPrayer === currentPrayer) {
            cards[i].classList.add('active');
        } else if (prayerMinutes[cardPrayer] < nowMinutes) {
            cards[i].classList.add('passed');
        }
    }
}

function updateCountdown() {
    if (!prayerData) return;

    var now = new Date();
    var nowMinutes = now.getHours() * 60 + now.getMinutes();
    var nowSeconds = now.getSeconds();

    var prayers = ['Subuh', 'Zohor', 'Asar', 'Maghrib', 'Isyak'];
    var nextPrayer = null;
    var nextPrayerTime = null;

    // Find next prayer today
    for (var i = 0; i < prayers.length; i++) {
        var prayer = prayers[i];
        var time = prayerData[prayer];
        var parts = time.split(':');
        var totalMinutes = parseInt(parts[0]) * 60 + parseInt(parts[1]);

        if (totalMinutes > nowMinutes) {
            nextPrayer = prayer;
            nextPrayerTime = time;
            break;
        }
    }

    // Kalau takde, next = Subuh esok
    if (!nextPrayer) {
        nextPrayer = 'Subuh';
        nextPrayerTime = prayerData.Subuh;
    }

    // Update next prayer display
    var nameEl = document.getElementById('nextPrayerName');
    var timeEl = document.getElementById('nextPrayerTime');
    if (nameEl) nameEl.textContent = nextPrayer;
    if (timeEl) timeEl.textContent = formatTime12Hour(nextPrayerTime);

    // Calculate countdown
    var parts = nextPrayerTime.split(':');
    var targetHour = parseInt(parts[0]);
    var targetMinute = parseInt(parts[1]);

    var target = new Date();
    target.setHours(targetHour, targetMinute, 0, 0);

    // Kalau Subuh esok
    if (nextPrayer === 'Subuh' && nowMinutes >= (parseInt(prayerData.Isyak.split(':')[0]) * 60)) {
        target.setDate(target.getDate() + 1);
    }

    var diff = target - now;

    if (diff < 0) {
        diff = 0;
        // Refresh prayer data
        setTimeout(function() {
            fetchPrayerTimes();
        }, 60000);
    }

    var hours = Math.floor(diff / 3600000);
    var minutes = Math.floor((diff % 3600000) / 60000);
    var seconds = Math.floor((diff % 60000) / 1000);

    var hEl = document.getElementById('countdownHours');
    var mEl = document.getElementById('countdownMinutes');
    var sEl = document.getElementById('countdownSeconds');

    if (hEl) hEl.textContent = String(hours).padStart(2, '0');
    if (mEl) mEl.textContent = String(minutes).padStart(2, '0');
    if (sEl) sEl.textContent = String(seconds).padStart(2, '0');

    // Update highlight setiap minit
    if (seconds === 0) {
        highlightCurrentPrayer();
    }

    // Bila countdown sampai 0
if (hours === 0 && minutes === 0 && seconds === 0) {
    if ('Notification' in window && Notification.permission === 'granted') {
        new Notification('🕌 Waktu ' + nextPrayer, {
            body: 'Telah masuk waktu solat ' + nextPrayer,
            icon: 'https://api.iconify.design/twemoji/mosque.svg'
        });
    }

    // Sound notification - Web Audio API (built-in browser)
try {
    var audioCtx = new (window.AudioContext || window.webkitAudioContext)();

    // 3 beep nada azan-like
    for (var b = 0; b < 3; b++) {
        var osc = audioCtx.createOscillator();
        var gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        osc.frequency.value = 880; // Note A5
        osc.type = 'sine';

        var startTime = audioCtx.currentTime + (b * 0.4);
        gain.gain.setValueAtTime(0.3, startTime);
        gain.gain.exponentialRampToValueAtTime(0.01, startTime + 0.3);

        osc.start(startTime);
        osc.stop(startTime + 0.3);
    }
} catch (e) {
    console.log('Audio not supported:', e.message);
}
}
}

function updateDateDisplay() {
    var now = new Date();

    // Tarikh Masihi
    var months = ['Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                  'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    var days = ['Ahad', 'Isnin', 'Selasa', 'Rabu', 'Khamis', 'Jumaat', 'Sabtu'];

    var masihiStr = days[now.getDay()] + ', ' + now.getDate() + ' ' + months[now.getMonth()] + ' ' + now.getFullYear();

    var masihiEl = document.getElementById('prayerDateMasihi');
    if (masihiEl) masihiEl.textContent = masihiStr;

    // Tarikh Hijri (anggaran - boleh guna API juga)
    fetchHijriDate();
}

function fetchHijriDate() {
    var hijriEl = document.getElementById('prayerDateHijri');
    if (!hijriEl) return;

    // Guna Aladhan API untuk tarikh Hijri
    var today = new Date();
    var dateStr = today.getDate() + '-' + (today.getMonth() + 1) + '-' + today.getFullYear();

    fetch('https://api.aladhan.com/v1/gToH/' + dateStr)
        .then(function(response) { return response.json(); })
        .then(function(data) {
            if (data && data.data && data.data.hijri) {
                var h = data.data.hijri;
                var hijriMonths = {
                    1: 'Muharram', 2: 'Safar', 3: 'Rabi al-Awwal', 4: 'Rabi al-Thani',
                    5: 'Jumada al-Awwal', 6: 'Jumada al-Thani', 7: 'Rajab', 8: 'Sya\'ban',
                    9: 'Ramadhan', 10: 'Syawal', 11: 'Dzulkaedah', 12: 'Dzulhijjah'
                };
                var monthName = hijriMonths[parseInt(h.month.number)] || h.month.en;
                hijriEl.textContent = h.day + ' ' + monthName + ' ' + h.year + ' H';
            }
        })
        .catch(function(error) {
            // Fallback - guna calculation manual
            hijriEl.textContent = calculateHijri(today);
        });
}

function calculateHijri(date) {
    // Simple Hijri calculation (anggaran)
    var hijriEpoch = new Date(622, 6, 16); // 16 July 622 CE
    var daysDiff = Math.floor((date - hijriEpoch) / (1000 * 60 * 60 * 24));
    var hijriYear = Math.floor(daysDiff / 354.367) + 1;
    var dayOfYear = daysDiff - Math.floor((hijriYear - 1) * 354.367);
    var hijriMonth = Math.min(12, Math.ceil(dayOfYear / 29.5));
    var hijriDay = Math.ceil(dayOfYear - (hijriMonth - 1) * 29.5);

    var monthNames = ['Muharram', 'Safar', 'Rabi al-Awwal', 'Rabi al-Thani',
                     'Jumada al-Awwal', 'Jumada al-Thani', 'Rajab', 'Sya\'ban',
                     'Ramadhan', 'Syawal', 'Dzulkaedah', 'Dzulhijjah'];

    return hijriDay + ' ' + monthNames[hijriMonth - 1] + ' ' + hijriYear + ' H';
}

function getZoneName(zone) {
    var zones = {
        'SGR01': 'Gombak, KL, Petaling, Hulu Langat',
        'SGR02': 'Kuala Selangor, Sabak Bernam',
        'SGR03': 'Klang, Kuala Langat',
        'WLY01': 'Kuala Lumpur, Putrajaya',
        'WLY02': 'Labuan',
        'JHR01': 'Pulau Aur, Pemanggil',
        'JHR02': 'Johor Bahru, Kota Tinggi',
        'JHR03': 'Kluang, Pontian',
        'JHR04': 'Batu Pahat, Muar, Segamat',
        'KDH01': 'Kota Setar, Kubang Pasu',
        'KDH02': 'Kuala Muda, Yan',
        'KDH06': 'Langkawi',
        'KTN01': 'Kota Bharu, Bachok',
        'MLK01': 'Melaka',
        'NGS02': 'Kuala Pilah, Rembau',
        'NGS03': 'Seremban, Port Dickson',
        'PHG02': 'Kuantan, Pekan',
        'PRK02': 'Ipoh, Batu Gajah',
        'PLS01': 'Perlis',
        'PNG01': 'Pulau Pinang',
        'SBH07': 'Kota Kinabalu',
        'SWK07': 'Kuching',
        'TRG01': 'Kuala Terengganu'
    };
    return zones[zone] || zone;
}

// ===== AUTO-CONVERT TABLES TO MOBILE CARDS =====
function applyMobileTableLabels() {
    // Skip cashbook table - jangan apply mobile cards
    var tables = document.querySelectorAll('.table:not(.cashbook-table)');

    for (var i = 0; i < tables.length; i++) {
        var table = tables[i];

        if (table.dataset.mobileApplied === 'true') continue;

        var headers = table.querySelectorAll('thead th');
        var headerTexts = [];

        for (var j = 0; j < headers.length; j++) {
            headerTexts.push(headers[j].textContent.trim());
        }

        var rows = table.querySelectorAll('tbody tr');
        for (var j = 0; j < rows.length; j++) {
            var cells = rows[j].querySelectorAll('td');
            for (var k = 0; k < cells.length && k < headerTexts.length; k++) {
                cells[k].setAttribute('data-label', headerTexts[k]);
            }
        }

        table.classList.add('table-stack-mobile');
        table.dataset.mobileApplied = 'true';
    }
}

// Only apply once after data loads, not every second
setTimeout(function() {
    if (typeof applyMobileTableLabels === 'function') {
        applyMobileTableLabels();
    }
}, 2000);
