// ============================
// ===== BACKUP SYSTEM ========
// ============================

function initBackupSystem() {
    updateBackupStats();
    loadAutoBackupSettings();
    renderAutoBackups();
}

function updateBackupStats() {
    var totalData = 0;
    if (appData.students) totalData += appData.students.length;
    if (appData.records) totalData += appData.records.length;
    if (appData.attendance) totalData += appData.attendance.length;
    if (appData.cashbook) totalData += appData.cashbook.length;
    if (appData.gallery) totalData += appData.gallery.length;

    document.getElementById('backupTotalData').textContent = totalData;

    // Last backup date
    var lastBackup = localStorage.getItem('lastBackupDate');
    document.getElementById('backupLastDate').textContent = lastBackup ? formatDate(lastBackup) : 'Belum';

    // Size
    var dataStr = JSON.stringify(appData);
    var sizeKB = Math.round(dataStr.length / 1024);
    document.getElementById('backupSize').textContent = sizeKB + ' KB';
}

// ===== DOWNLOAD FULL BACKUP =====
function downloadFullBackup() {
    var data = {
        backupDate: new Date().toISOString(),
        version: '1.0',
        madrasah: 'Madrasah Tahfiz Pekan Sungai Buloh',
        data: appData
    };

    var blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    var url = URL.createObjectURL(blob);
    var link = document.createElement('a');
    link.href = url;
    link.download = 'backup_madrasah_' + new Date().toISOString().split('T')[0] + '.json';
    link.click();

    localStorage.setItem('lastBackupDate', new Date().toISOString().split('T')[0]);
    updateBackupStats();
    showToast('✅ Backup berjaya didownload!');
}

// ===== DOWNLOAD EXCEL (CSV) =====

// ✅ FIXED: Helper untuk escape CSV field dengan betul (elak rosak bila ada aksara ")
function csvField(val) {
    return '"' + String(val || '').replace(/"/g, '""') + '"';
}

function downloadStudentsExcel() {
    if (!appData.students || appData.students.length === 0) {
        showToast('❌ Tiada data pelajar');
        return;
    }

    var csv = 'Nama,IC,Kelas,Jantina,Tarikh Lahir,Nama Bapa,Tel Bapa,Nama Ibu,Tel Ibu,Alamat,Bandar,Negeri,Sekolah Lama,Tahap Bacaan\n';

    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        var addr = s.address || {};
        var alamat = (addr.line1 || '') + (addr.line2 ? ', ' + addr.line2 : '');
        csv += csvField(s.name) + ',';
        csv += csvField(s.ic) + ',';
        csv += csvField(s.class) + ',';
        csv += csvField(s.gender) + ',';
        csv += csvField(s.dob) + ',';
        csv += csvField(s.fatherName) + ',';
        csv += csvField(s.fatherPhone) + ',';
        csv += csvField(s.motherName) + ',';
        csv += csvField(s.motherPhone) + ',';
        csv += csvField(alamat) + ',';
        csv += csvField(addr.city) + ',';
        csv += csvField(addr.state) + ',';
        csv += csvField(s.prevSchool) + ',';
        csv += csvField(s.quranLevel) + '\n';
    }

    downloadCSV(csv, 'pelajar_madrasah_' + new Date().toISOString().split('T')[0] + '.csv');
}

function downloadHafazanExcel() {
    if (!appData.records || appData.records.length === 0) {
        showToast('❌ Tiada data hafazan');
        return;
    }

    var csv = 'Tarikh,Pelajar,Kelas,Surah,Juz,Markah,Status,Catatan\n';

    for (var i = 0; i < appData.records.length; i++) {
        var r = appData.records[i];

        // Find student
        var student = null;
        for (var j = 0; j < appData.students.length; j++) {
            if (appData.students[j].id === r.studentId) {
                student = appData.students[j];
                break;
            }
        }

        var surahText = Array.isArray(r.surah) ? r.surah.join(', ') : (r.surah || '');
        var juzText = Array.isArray(r.juz) ? r.juz.join(', ') : (r.juz || '');

        csv += csvField(r.date) + ',';
        csv += csvField(student ? student.name : '') + ',';
        csv += csvField(student ? student.class : '') + ',';
        csv += csvField(surahText) + ',';
        csv += csvField(juzText) + ',';
        csv += csvField(r.score) + ',';
        csv += csvField(r.status) + ',';
        csv += csvField(r.notes) + '\n';
    }

    downloadCSV(csv, 'hafazan_madrasah_' + new Date().toISOString().split('T')[0] + '.csv');
}

function downloadCashbookExcel() {
    if (!appData.cashbook || appData.cashbook.length === 0) {
        showToast('❌ Tiada data buku tunai');
        return;
    }

    var csv = 'Tarikh,No Rujukan,Perkara,Kategori,Jenis,Debit,Kredit,Bayaran,Penerima/Pembayar,Catatan\n';

    var sorted = appData.cashbook.slice().sort(function(a, b) {
        return new Date(a.date) - new Date(b.date);
    });

    for (var i = 0; i < sorted.length; i++) {
        var e = sorted[i];
        var debit = e.type === 'debit' ? e.amount.toFixed(2) : '';
        var credit = e.type === 'credit' ? e.amount.toFixed(2) : '';

        csv += csvField(e.date) + ',';
        csv += csvField(e.ref) + ',';
        csv += csvField(e.description) + ',';
        csv += csvField(e.category) + ',';
        csv += csvField(e.type === 'debit' ? 'Masuk' : 'Keluar') + ',';
        csv += csvField(debit) + ',';
        csv += csvField(credit) + ',';
        csv += csvField(e.payMethod) + ',';
        csv += csvField(e.person) + ',';
        csv += csvField(e.notes) + '\n';
    }

    downloadCSV(csv, 'buku_tunai_' + new Date().toISOString().split('T')[0] + '.csv');
}

function downloadAttendanceExcel() {
    if (!appData.attendance || appData.attendance.length === 0) {
        showToast('❌ Tiada data kehadiran');
        return;
    }

    var csv = 'Tarikh,Pelajar,Kelas,Status,Masa Tiba,Catatan\n';

    for (var i = 0; i < appData.attendance.length; i++) {
        var att = appData.attendance[i];
        if (!att.records) continue;

        for (var j = 0; j < att.records.length; j++) {
            var rec = att.records[j];

            // Find student
            var student = null;
            for (var k = 0; k < appData.students.length; k++) {
                if (appData.students[k].id === rec.studentId) {
                    student = appData.students[k];
                    break;
                }
            }

            var statusText = rec.status === 'hadir' ? 'Hadir' :
                            rec.status === 'lewat' ? 'Lewat' :
                            rec.status === 'mc' ? 'MC/Uzur' : 'Tidak Hadir';

            csv += '"' + att.date + '",';
            csv += '"' + (student ? student.name : '') + '",';
            csv += '"' + (student ? student.class : '') + '",';
            csv += '"' + statusText + '",';
            csv += '"' + (rec.time || '') + '",';
            csv += '"' + (rec.note || '') + '"\n';
        }
    }

    downloadCSV(csv, 'kehadiran_' + new Date().toISOString().split('T')[0] + '.csv');
}

function downloadCSV(csv, filename) {
    // Add BOM for Excel UTF-8 support
    var BOM = '\uFEFF';
    var blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' });
    var url = URL.createObjectURL(blob);
    var link = document.createElement('a');
    link.href = url;
    link.download = filename;
    link.click();
    showToast('✅ ' + filename + ' berjaya didownload!');
}

// ===== RESTORE BACKUP =====
function handleRestoreFile(input) {
    var file = input.files[0];
    if (!file) return;

    var reader = new FileReader();
    reader.onload = function(e) {
        try {
            var data = JSON.parse(e.target.result);
            previewRestoreData(data);
        } catch (error) {
            showToast('❌ Fail tidak sah');
        }
    };
    reader.readAsText(file);
}

function previewRestoreData(data) {
    var preview = document.getElementById('restorePreview');
    if (!preview) return;

    var html = '<div style="background:#faf5ff;padding:20px;border-radius:12px;border-left:4px solid #a78bfa;">';
    html += '<h3 style="color:var(--primary-dark);margin-bottom:10px;">📋 Preview Fail Backup</h3>';

    if (data.backupDate) {
        html += '<p><strong>Tarikh Backup:</strong> ' + new Date(data.backupDate).toLocaleString('ms-MY') + '</p>';
    }
    if (data.madrasah) {
        html += '<p><strong>Madrasah:</strong> ' + data.madrasah + '</p>';
    }

    var dataToRestore = data.data || data;

    html += '<div style="margin-top:15px;padding:15px;background:white;border-radius:8px;">';
    html += '<h4 style="margin-bottom:10px;">📊 Data Yang Akan Direstore:</h4>';
    html += '<ul style="list-style:none;padding:0;">';
    html += '<li style="padding:5px 0;">👨‍🎓 Pelajar: <strong>' + (dataToRestore.students ? dataToRestore.students.length : 0) + '</strong></li>';
    html += '<li style="padding:5px 0;">📖 Rekod Hafazan: <strong>' + (dataToRestore.records ? dataToRestore.records.length : 0) + '</strong></li>';
    html += '<li style="padding:5px 0;">📅 Kehadiran: <strong>' + (dataToRestore.attendance ? dataToRestore.attendance.length : 0) + '</strong></li>';
    html += '<li style="padding:5px 0;">💰 Buku Tunai: <strong>' + (dataToRestore.cashbook ? dataToRestore.cashbook.length : 0) + '</strong></li>';
    html += '<li style="padding:5px 0;">📸 Album Gallery: <strong>' + (dataToRestore.gallery ? dataToRestore.gallery.length : 0) + '</strong></li>';
    html += '</ul>';
    html += '</div>';

    html += '<div style="margin-top:15px;display:flex;gap:10px;">';
    html += '<button class="btn btn-primary" onclick="confirmRestore()">✅ Confirm Restore</button>';
    html += '<button class="btn btn-secondary" onclick="cancelRestore()">❌ Batal</button>';
    html += '</div>';

    html += '</div>';

    preview.innerHTML = html;
    preview.style.display = 'block';

    // Save data temporarily
    window._restoreData = dataToRestore;
}

function confirmRestore() {
    if (!window._restoreData) return;

    if (!confirm('⚠️ AMARAN!\n\nSemua data sekarang akan diganti dengan data dari fail backup.\n\nAdakah anda PASTI?')) {
        return;
    }

    if (!confirm('Confirmation Akhir!\n\nTeruskan dengan restore?')) {
        return;
    }

    // Backup current data dulu
    var oldBackup = {
        backupDate: new Date().toISOString(),
        version: '1.0',
        note: 'Auto backup before restore',
        data: appData
    };
    localStorage.setItem('preRestoreBackup', JSON.stringify(oldBackup));

    // Restore
    appData = window._restoreData;
    saveData(appData);

    showToast('✅ Data berjaya direstore!');

    setTimeout(function() {
        location.reload();
    }, 1500);
}

function cancelRestore() {
    document.getElementById('restorePreview').style.display = 'none';
    document.getElementById('restoreFile').value = '';
    window._restoreData = null;
}

// ===== AUTO BACKUP =====
function loadAutoBackupSettings() {
    var enabled = localStorage.getItem('autoBackupEnabled') === 'true';
    var toggle = document.getElementById('autoBackupToggle');
    if (toggle) toggle.checked = enabled;
}

function toggleAutoBackup() {
    var toggle = document.getElementById('autoBackupToggle');
    if (!toggle) return;

    if (toggle.checked) {
        localStorage.setItem('autoBackupEnabled', 'true');
        showToast('✅ Auto backup harian diaktifkan');
        // Run backup now
        performAutoBackup();
    } else {
        localStorage.setItem('autoBackupEnabled', 'false');
        showToast('⏹ Auto backup dinyahaktifkan');
    }
}

function performAutoBackup() {
    var lastAuto = localStorage.getItem('lastAutoBackup');
    var today = new Date().toISOString().split('T')[0];

    if (lastAuto === today) {
        console.log('Auto backup already done today');
        return;
    }

    var backup = {
        backupDate: new Date().toISOString(),
        version: '1.0',
        type: 'auto',
        data: appData
    };

    // Get existing auto backups
    var backups = JSON.parse(localStorage.getItem('autoBackups') || '[]');

    // Add new one
    backups.unshift({
        date: today,
        size: JSON.stringify(backup).length,
        data: backup
    });

    // Keep only last 7 days
    backups = backups.slice(0, 7);

    localStorage.setItem('autoBackups', JSON.stringify(backups));
    localStorage.setItem('lastAutoBackup', today);

    renderAutoBackups();
    console.log('✅ Auto backup completed');
}

function renderAutoBackups() {
    var container = document.getElementById('autoBackupItems');
    if (!container) return;

    var backups = JSON.parse(localStorage.getItem('autoBackups') || '[]');

    if (backups.length === 0) {
        container.innerHTML = '<p style="text-align:center;color:var(--text-light);padding:20px;">Belum ada auto backup. Aktifkan toggle di atas untuk mula.</p>';
        return;
    }

    var html = '';
    for (var i = 0; i < backups.length; i++) {
        var b = backups[i];
        var sizeKB = Math.round(b.size / 1024);

        html += '<div class="auto-backup-item">';
        html += '<div class="auto-backup-info">';
        html += '<div class="auto-backup-date">📅 ' + formatDate(b.date) + '</div>';
        html += '<div class="auto-backup-size">💾 ' + sizeKB + ' KB</div>';
        html += '</div>';
        html += '<div class="auto-backup-actions">';
        html += '<button class="btn btn-sm btn-view" onclick="downloadAutoBackup(' + i + ')" title="Download">📥</button>';
        html += '<button class="btn btn-sm" style="background:var(--gold);color:white;" onclick="restoreAutoBackup(' + i + ')" title="Restore">📤</button>';
        html += '<button class="btn btn-sm btn-delete" onclick="deleteAutoBackup(' + i + ')" title="Padam">🗑</button>';
        html += '</div>';
        html += '</div>';
    }

    container.innerHTML = html;
}

function downloadAutoBackup(index) {
    var backups = JSON.parse(localStorage.getItem('autoBackups') || '[]');
    if (!backups[index]) return;

    var blob = new Blob([JSON.stringify(backups[index].data, null, 2)], { type: 'application/json' });
    var url = URL.createObjectURL(blob);
    var link = document.createElement('a');
    link.href = url;
    link.download = 'auto_backup_' + backups[index].date + '.json';
    link.click();

    showToast('✅ Auto backup didownload!');
}

function restoreAutoBackup(index) {
    var backups = JSON.parse(localStorage.getItem('autoBackups') || '[]');
    if (!backups[index]) return;

    window._restoreData = backups[index].data.data;
    confirmRestore();
}

function deleteAutoBackup(index) {
    if (!confirm('Padam backup ini?')) return;

    var backups = JSON.parse(localStorage.getItem('autoBackups') || '[]');
    backups.splice(index, 1);
    localStorage.setItem('autoBackups', JSON.stringify(backups));

    renderAutoBackups();
    showToast('🗑 Backup dipadam');
}

// Auto run backup on page load if enabled
if (localStorage.getItem('autoBackupEnabled') === 'true') {
    setTimeout(performAutoBackup, 5000);
}

