// Helper: numberToWords kalau takde
if (typeof numberToWords !== 'function') {
    window.numberToWords = function(amount) {
        var ones = ['', 'Satu', 'Dua', 'Tiga', 'Empat', 'Lima', 'Enam', 'Tujuh', 'Lapan', 'Sembilan'];
        var tens = ['', 'Sepuluh', 'Dua Puluh', 'Tiga Puluh', 'Empat Puluh', 'Lima Puluh', 'Enam Puluh', 'Tujuh Puluh', 'Lapan Puluh', 'Sembilan Puluh'];
        var teens = ['Sepuluh', 'Sebelas', 'Dua Belas', 'Tiga Belas', 'Empat Belas', 'Lima Belas', 'Enam Belas', 'Tujuh Belas', 'Lapan Belas', 'Sembilan Belas'];

        if (amount === 0) return 'Sifar Ringgit';

        var ringgit = Math.floor(amount);
        var sen = Math.round((amount - ringgit) * 100);

        function convertHundreds(num) {
            var result = '';
            if (num >= 100) {
                var ratus = Math.floor(num / 100);
                result += (ratus === 1 ? 'Seratus' : ones[ratus] + ' Ratus');
                num = num % 100;
                if (num > 0) result += ' ';
            }
            if (num >= 10 && num <= 19) {
                result += teens[num - 10];
            } else if (num >= 20) {
                result += tens[Math.floor(num / 10)];
                if (num % 10 > 0) result += ' ' + ones[num % 10];
            } else if (num > 0) {
                result += ones[num];
            }
            return result;
        }

        var result = '';
        if (ringgit >= 1000) {
            var ribu = Math.floor(ringgit / 1000);
            result += (ribu === 1 ? 'Seribu' : convertHundreds(ribu) + ' Ribu');
            ringgit = ringgit % 1000;
            if (ringgit > 0) result += ' ';
        }
        if (ringgit > 0) result += convertHundreds(ringgit);
        result += ' Ringgit';
        if (sen > 0) result += ' dan ' + convertHundreds(sen) + ' Sen';

        return result;
    };
}

// ===== PERSON AUTOSUGGEST FOR CASH FORM =====
function setupPersonAutosuggest() {
    var personInput = document.getElementById('cashPerson');
    if (!personInput) return;

    // Avoid duplicate event listeners
    if (personInput.dataset.autosuggestSetup === 'true') return;
    personInput.dataset.autosuggestSetup = 'true';

    personInput.addEventListener('input', function() {
        var value = this.value.toUpperCase().trim();
        if (value.length < 3) return;

        // Search matching student
        var matchedStudent = null;
        for (var i = 0; i < appData.students.length; i++) {
            var s = appData.students[i];
            var sName = (s.name || '').toUpperCase();
            var fName = (s.fatherName || '').toUpperCase();
            var mName = (s.motherName || '').toUpperCase();

            if (sName.indexOf(value) > -1 || fName.indexOf(value) > -1 || mName.indexOf(value) > -1) {
                matchedStudent = s;
                break;
            }
        }

        // Auto-select dalam dropdown
        var dropdown = document.getElementById('cashStudentLink');
        if (dropdown && matchedStudent) {
            dropdown.value = matchedStudent.id;
        }
    });
}

// ===== ATTENDANCE HELPER FUNCTIONS =====

// Update attendance summary stats
if (typeof updateAttendanceSummary !== 'function') {
    window.updateAttendanceSummary = function() {
        var selects = document.querySelectorAll('.att-status-select');
        var total = selects.length;
        var hadir = 0, lewat = 0, mc = 0, tidak = 0;

        for (var i = 0; i < selects.length; i++) {
            var val = selects[i].value;
            if (val === 'hadir') hadir++;
            else if (val === 'lewat') lewat++;
            else if (val === 'mc') mc++;
            else if (val === 'tidak_hadir') tidak++;
        }

        var setText = function(id, val) {
            var el = document.getElementById(id);
            if (el) el.textContent = val;
        };

        setText('attTotal', total);
        setText('attHadir', hadir);
        setText('attLewat', lewat);
        setText('attMC', mc);
        setText('attTidak', tidak);
    };
}

// Status change handler
if (typeof onStatusChange !== 'function') {
    window.onStatusChange = function(studentId) {
        var select = document.getElementById('attStatus_' + studentId);
        if (!select) return;

        select.className = 'att-status-select ' + select.value;
        updateAttendanceSummary();
    };
}

// Mark all status
if (typeof markAll !== 'function') {
    window.markAll = function(status) {
        var selects = document.querySelectorAll('.att-status-select');
        for (var i = 0; i < selects.length; i++) {
            selects[i].value = status;
            selects[i].className = 'att-status-select ' + status;
        }
        updateAttendanceSummary();
        showToast(status === 'hadir' ? '✅ Semua ditanda hadir' : '❌ Semua ditanda tidak hadir');
    };
}

// Build calendar
if (typeof buildCalendar !== 'function') {
    window.buildCalendar = function(year, month, monthRecords) {
        var calEl = document.getElementById('attendanceCalendar');
        if (!calEl) return;

        var daysInMonth = new Date(year, month, 0).getDate();
        var firstDay = new Date(year, month - 1, 1).getDay();
        var today = new Date();

        var recordDates = {};
        for (var i = 0; i < monthRecords.length; i++) {
            var d = new Date(monthRecords[i].date);
            var day = d.getDate();
            if (!recordDates[day]) recordDates[day] = [];
            recordDates[day].push(monthRecords[i]);
        }

        var days = ['Ahd', 'Isn', 'Sel', 'Rab', 'Kha', 'Jum', 'Sab'];
        var html = '<div class="cal-grid">';

        for (var i = 0; i < 7; i++) {
            html += '<div class="cal-header">' + days[i] + '</div>';
        }

        for (var i = 0; i < firstDay; i++) {
            html += '<div class="cal-day empty"></div>';
        }

        for (var d = 1; d <= daysInMonth; d++) {
            var isToday = (d === today.getDate() && month === today.getMonth() + 1 && year === today.getFullYear());
            var sessions = recordDates[d] || [];
            var hasRecord = sessions.length > 0;

            var cls = 'cal-day';
            if (isToday) cls += ' today';
            if (hasRecord) cls += ' has-record';
            else cls += ' no-record';

            var dateStr = year + '-' + ('0' + month).slice(-2) + '-' + ('0' + d).slice(-2);
            var sessionsText = sessions.length > 0 ? ' (' + sessions.length + ' sesi)' : '';

            html += '<div class="' + cls + '" onclick="viewAttendanceDay(\'' + dateStr + '\')" title="' + dateStr + sessionsText + '">';
            html += '<span class="cal-num">' + d + '</span>';
            if (hasRecord) {
                html += '<div style="display:flex;gap:2px;margin-top:2px;">';
                for (var s = 0; s < Math.min(sessions.length, 3); s++) {
                    var color = sessions[s].session === 'pagi' ? '#f59e0b' :
                                sessions[s].session === 'petang' ? '#ea580c' : '#7c3aed';
                    html += '<span style="width:5px;height:5px;border-radius:50%;background:' + color + ';"></span>';
                }
                html += '</div>';
            }
            html += '</div>';
        }

        html += '</div>';
        calEl.innerHTML = html;

        // Force calendar grid full width
        var calGrid = calEl.querySelector('.cal-grid');
        if (calGrid) {
            calGrid.style.cssText = 'display:grid !important; grid-template-columns:repeat(7,1fr) !important; gap:6px !important; width:100% !important;';
        }
    };
}

// ===== SESSION BADGE HELPER =====
function getSessionBadge(session) {
    if (!session) return '<span style="color:#94a3b8;font-size:0.75rem;">-</span>';

    if (session === 'pagi') {
        return '<span style="background:#fef3c7;color:#78350f;padding:3px 8px;border-radius:6px;font-size:0.72rem;font-weight:700;white-space:nowrap;">🌅 Pagi</span>';
    } else if (session === 'petang') {
        return '<span style="background:#fed7aa;color:#7c2d12;padding:3px 8px;border-radius:6px;font-size:0.72rem;font-weight:700;white-space:nowrap;">🌤 Petang</span>';
    } else if (session === 'malam') {
        return '<span style="background:#ddd6fe;color:#4c1d95;padding:3px 8px;border-radius:6px;font-size:0.72rem;font-weight:700;white-space:nowrap;">🌙 Malam</span>';
    }
    return '<span style="color:#94a3b8;font-size:0.75rem;">-</span>';
}

// Sama untuk parent
function getSessionBadgeParent(session) {
    return getSessionBadge(session);
}

