function populateCheckerDropdowns() {
    // Guru dropdown - guna admin names
    var guruSelect = document.getElementById('checkerGuru');
    if (guruSelect) {
        var html = '<option value="">Pilih guru penyemak</option>';

        // Tambah dari admins
        if (appData.admins) {
            for (var i = 0; i < appData.admins.length; i++) {
                html += '<option value="' + appData.admins[i].name + '">' + appData.admins[i].name + '</option>';
            }
        }

        // Tambah dari workers yang ustaz
        if (appData.workers) {
            for (var i = 0; i < appData.workers.length; i++) {
                var w = appData.workers[i];
                if (w.role && (w.role.toLowerCase().indexOf('ustaz') > -1 || w.role.toLowerCase().indexOf('guru') > -1)) {
                    html += '<option value="' + w.name + '">' + w.name + ' (' + w.role + ')</option>';
                }
            }
        }

        // Tambah option "Lain-lain"
        html += '<option value="__other__">✏️ Lain-lain (taip nama)</option>';

        guruSelect.innerHTML = html;
    }

    // Pelajar dropdown - HANYA AKTIF
var studentSelect = document.getElementById('checkerStudent');
if (studentSelect) {
    var html = '<option value="">Pilih pelajar penyemak</option>';

    var activeStudents = appData.students.filter(function(s) {
        var status = s.status || 'aktif';
        return status === 'aktif';
    });
    
    var sortedStudents = activeStudents.slice().sort(function(a, b) {
        return a.name.localeCompare(b.name);
    });

        for (var i = 0; i < sortedStudents.length; i++) {
            html += '<option value="' + sortedStudents[i].name + '">' + sortedStudents[i].name + '</option>';
        }

        studentSelect.innerHTML = html;
    }

    // Listen for "Lain-lain" selection
    if (guruSelect) {
        guruSelect.addEventListener('change', function() {
            if (this.value === '__other__') {
                var customName = prompt('Masukkan nama guru penyemak:');
                if (customName) {
                    var newOption = document.createElement('option');
                    newOption.value = customName;
                    newOption.textContent = customName;
                    this.insertBefore(newOption, this.lastElementChild);
                    this.value = customName;
                } else {
                    this.value = '';
                }
            }
        });
    }
}

