function initSchedule() {
    if (!appData.schedule) {
        appData.schedule = getDefaultSchedule();
        saveData(appData);
    }

    if (!appData.scheduleSuggestions) {
        appData.scheduleSuggestions = [];
    }

    renderSchedule();
    renderScheduleSuggestions();
}

function renderSchedule() {
    var container = document.getElementById('scheduleContent');
    if (!container) return;

    var dayType = document.getElementById('scheduleDay').value;

    if (!appData.schedule) appData.schedule = getDefaultSchedule();
    var items = appData.schedule[dayType] || [];

    if (items.length === 0 && dayType !== 'weekday') {
        items = JSON.parse(JSON.stringify(appData.schedule.weekday || []));
        appData.schedule[dayType] = items;
    }

    // Get prayer times
    var prayerTimes = {};
    if (typeof prayerData !== 'undefined' && prayerData) {
        prayerTimes = prayerData;
    }

    var dayLabel = dayType === 'weekday' ? 'ISNIN - KHAMIS' : dayType === 'friday' ? 'JUMAAT' : 'SABTU - AHAD';

    var html = '';

    // Header
    html += '<div class="schedule-header-banner">';
    html += '<div style="margin-bottom:8px;"><img src="https://i.ibb.co/DgSPkh8d/logo.png" style="width:80px;height:80px;object-fit:contain;" alt="Logo"></div>';
    html += '<h1>JADUAL HARIAN PELAJAR</h1>';
    html += '<p>Madrasah Tahfiz Pekan Sungai Buloh</p>';
    html += '<div class="schedule-year">' + dayLabel + ' • ' + new Date().getFullYear() + '</div>';
    html += '</div>';

    // Table
    html += '<table class="schedule-table">';
    html += '<thead><tr>';
    html += '<th style="width:260px;">WAKTU</th>';
    html += '<th>AKTIVITI</th>';
    html += '<th style="width:100px;text-align:center;">⚙️</th>';
    html += '</tr></thead>';
    html += '<tbody>';

    for (var i = 0; i < items.length; i++) {
        var item = items[i];

        // Auto-fill prayer times
        var displayTime = item.time || '';
        if (item.auto && item.prayerKey && prayerTimes[item.prayerKey]) {
            displayTime = prayerTimes[item.prayerKey];
        }

        // Row colors
        var rowBg = 'white';
        var borderColor = '#e2e8f0';

        if (item.type === 'prayer') {
            rowBg = 'linear-gradient(90deg, #fef3c7, #fffbeb)';
            borderColor = '#f59e0b';
        } else if (item.type === 'meal') {
            rowBg = 'linear-gradient(90deg, #fef2f2, #fff1f2)';
            borderColor = '#f43f5e';
        } else if (item.type === 'break') {
            rowBg = 'linear-gradient(90deg, #faf5ff, #f5f3ff)';
            borderColor = '#a78bfa';
        } else if (item.type === 'sleep') {
            rowBg = 'linear-gradient(90deg, #eef2ff, #e0e7ff)';
            borderColor = '#6366f1';
        }

        html += '<tr style="background:' + rowBg + ';border-left:4px solid ' + borderColor + ';">';

        // WAKTU column
        html += '<td style="padding:12px 15px;border-bottom:1px solid #e2e8f0;vertical-align:middle;">';

        // Safety: ensure endTime exists
        if (!item.endTime && !item.auto) {
            item.endTime = item.time || '';
        }

        if (item.auto) {
            // Waktu solat - auto dari API
            html += '<div style="display:flex;align-items:center;gap:8px;">';
            html += '<span style="font-size:1.2rem;">' + item.icon + '</span>';
            html += '<div>';
            html += '<strong style="color:#1f2937;">' + formatScheduleTime(displayTime) + '</strong>';
            html += '<div><span class="schedule-auto-tag">Auto</span></div>';
            html += '</div>';
            html += '</div>';
        } else {
            // Editable time - guna type="time" untuk time picker
            html += '<div style="display:flex;align-items:center;gap:5px;">';
            html += '<input type="time" class="schedule-edit-time" value="' + (item.time || '') + '" data-index="' + i + '" data-field="time">';
            html += '<span style="color:#94a3b8;font-weight:700;">→</span>';
            html += '<input type="time" class="schedule-edit-time" value="' + (item.endTime || '') + '" data-index="' + i + '" data-field="endTime">';
            html += '</div>';
        }

        html += '</td>';

        // AKTIVITI column
        html += '<td style="padding:12px 15px;border-bottom:1px solid #e2e8f0;vertical-align:middle;">';

        if (item.auto) {
            // Solat - tak boleh edit nama
            html += '<div style="display:flex;align-items:center;gap:10px;">';
            html += '<strong style="font-size:1rem;color:#1f2937;">' + item.activity + '</strong>';
            html += '<span class="schedule-prayer-tag">Solat</span>';
            html += '</div>';
        } else {
            // Editable activity
            html += '<div style="display:flex;align-items:center;gap:10px;">';
            html += '<span style="font-size:1.3rem;">' + item.icon + '</span>';
            html += '<input type="text" class="schedule-edit-activity" value="' + (item.activity || '') + '" data-index="' + i + '" data-field="activity" placeholder="Nama aktiviti...">';
            html += '</div>';
        }

        html += '</td>';

        // ACTIONS column
        html += '<td style="padding:8px;border-bottom:1px solid #e2e8f0;text-align:center;vertical-align:middle;">';

        if (!item.auto) {
            html += '<div style="display:flex;gap:3px;justify-content:center;">';
            html += '<button onclick="moveScheduleRow(' + i + ', -1)" style="width:28px;height:28px;border:none;border-radius:6px;cursor:pointer;background:#e2e8f0;font-size:0.7rem;" title="Naik">⬆</button>';
            html += '<button onclick="moveScheduleRow(' + i + ', 1)" style="width:28px;height:28px;border:none;border-radius:6px;cursor:pointer;background:#e2e8f0;font-size:0.7rem;" title="Turun">⬇</button>';
            html += '<button onclick="deleteScheduleRow(' + i + ')" style="width:28px;height:28px;border:none;border-radius:6px;cursor:pointer;background:#fee2e2;color:#dc2626;font-size:0.7rem;" title="Padam">🗑</button>';
            html += '</div>';
        } else {
            html += '<span style="color:#94a3b8;font-size:0.75rem;">🔒</span>';
        }

        html += '</td>';
        html += '</tr>';
    }

    html += '</tbody></table>';

    // Add buttons
    html += '<div style="margin-top:15px;display:flex;gap:8px;flex-wrap:wrap;">';
    html += '<button onclick="addScheduleRow(\'activity\')" style="padding:8px 16px;background:#a78bfa;color:white;border:none;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">➕ Aktiviti</button>';
    html += '<button onclick="addScheduleRow(\'meal\')" style="padding:8px 16px;background:#f43f5e;color:white;border:none;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">🍽️ Makan</button>';
    html += '<button onclick="addScheduleRow(\'break\')" style="padding:8px 16px;background:#a78bfa;color:white;border:none;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">☕ Rehat</button>';
    html += '<button onclick="addScheduleRow(\'sleep\')" style="padding:8px 16px;background:#6366f1;color:white;border:none;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">😴 Tidur</button>';
    html += '</div>';

    // Footer
    html += '<div class="schedule-footer">';
    html += '<p>🕌 Madrasah Tahfiz Pekan Sungai Buloh</p>';
    html += '<p style="font-size:0.78rem;">Waktu solat auto-update mengikut zon</p>';
    html += '</div>';

    container.innerHTML = html;
}

function formatScheduleTime(time24) {
    if (!time24 || time24 === 'undefined') return '-';
    var parts = time24.split(':');
    var hours = parseInt(parts[0]);
    var minutes = parts[1];
    var period = hours >= 12 ? 'PM' : 'AM';
    if (hours === 0) hours = 12;
    else if (hours > 12) hours -= 12;
    return hours + ':' + minutes + ' ' + period;
}

function addScheduleRow(type) {
    var dayType = document.getElementById('scheduleDay').value;
    if (!appData.schedule[dayType]) appData.schedule[dayType] = [];

    var icons = { activity: '📋', prayer: '🕌', meal: '🍽️', break: '☕', sleep: '😴' };
    var names = { activity: 'Aktiviti Baru', prayer: 'Solat', meal: 'Waktu Makan', break: 'Rehat', sleep: 'Tidur' };

    var newItem = {
        time: '',
        endTime: '',
        activity: names[type] || 'Aktiviti',
        type: type,
        icon: icons[type] || '📋',
        editable: true
    };

    if (type === 'prayer') {
        newItem.auto = true;
        newItem.prayerKey = '';
        var key = prompt('Pilih solat:\n1. Subuh\n2. Zohor\n3. Asar\n4. Maghrib\n5. Isyak');
        var keys = { '1': 'Subuh', '2': 'Zohor', '3': 'Asar', '4': 'Maghrib', '5': 'Isyak' };
        newItem.prayerKey = keys[key] || 'Zohor';
        newItem.activity = newItem.prayerKey;
    }

    appData.schedule[dayType].push(newItem);
    renderSchedule();
}

function deleteScheduleRow(index) {
    if (!confirm('Padam baris ini?')) return;
    var dayType = document.getElementById('scheduleDay').value;
    appData.schedule[dayType].splice(index, 1);
    renderSchedule();
}

function moveScheduleRow(index, direction) {
    var dayType = document.getElementById('scheduleDay').value;
    var items = appData.schedule[dayType];
    var newIndex = index + direction;

    if (newIndex < 0 || newIndex >= items.length) return;

    var temp = items[index];
    items[index] = items[newIndex];
    items[newIndex] = temp;

    renderSchedule();
}

function saveSchedule() {
    var dayType = document.getElementById('scheduleDay').value;
    var items = appData.schedule[dayType];

    // Collect edited values
    var timeInputs = document.querySelectorAll('.schedule-edit-time');
    for (var i = 0; i < timeInputs.length; i++) {
        var idx = parseInt(timeInputs[i].dataset.index);
        var field = timeInputs[i].dataset.field;
        var timeValue = timeInputs[i].value.trim();

        // type="time" sudah return format 24h (HH:MM)
        if (items[idx] && timeValue) {
            items[idx][field] = timeValue;
        }
    }

    var actInputs = document.querySelectorAll('.schedule-edit-activity');
    for (var i = 0; i < actInputs.length; i++) {
        var idx = parseInt(actInputs[i].dataset.index);
        if (items[idx]) items[idx].activity = actInputs[i].value;
    }

    saveData(appData);
    showToast('✅ Jadual disimpan!');
    renderSchedule();
}

// Convert "10:00 PM" or "4:50 AM" to "22:00" or "04:50"
function convertTo24Hour(timeStr) {
    if (!timeStr) return '';

    // Kalau dah format 24h (22:00), return terus
    if (timeStr.indexOf('AM') === -1 && timeStr.indexOf('PM') === -1 &&
        timeStr.indexOf('am') === -1 && timeStr.indexOf('pm') === -1) {
        return timeStr;
    }

    var isPM = timeStr.toUpperCase().indexOf('PM') > -1;
    var clean = timeStr.replace(/[APMapm ]/g, '').trim();
    var parts = clean.split(':');

    if (parts.length < 2) return timeStr;

    var hours = parseInt(parts[0]);
    var minutes = parts[1];

    if (isPM && hours < 12) hours += 12;
    if (!isPM && hours === 12) hours = 0;

    return String(hours).padStart(2, '0') + ':' + minutes;
}

function printSchedule() {
    document.body.classList.add('print-schedule');
    setTimeout(function() {
        window.print();
        document.body.classList.remove('print-schedule');
    }, 300);
}

// Suggestions
function renderScheduleSuggestions() {
    var container = document.getElementById('scheduleSuggestions');
    if (!container) return;

    if (!appData.scheduleSuggestions || appData.scheduleSuggestions.length === 0) {
        container.innerHTML = '<div style="text-align:center;padding:30px;color:#94a3b8;">Tiada cadangan</div>';
        return;
    }

    var html = '';
    var sorted = appData.scheduleSuggestions.slice().sort(function(a, b) {
        return new Date(b.date) - new Date(a.date);
    });

    for (var i = 0; i < sorted.length; i++) {
        var s = sorted[i];
        html += '<div class="suggestion-card">';
        html += '<div class="suggestion-header">';
        html += '<span class="suggestion-name">👤 ' + s.parentName + '</span>';
        html += '<span class="suggestion-date">' + formatDate(s.date) + '</span>';
        html += '</div>';
        html += '<div class="suggestion-text">' + s.text + '</div>';
        html += '<button onclick="deleteSuggestion(\'' + s.id + '\')" style="margin-top:8px;background:#fee2e2;color:#dc2626;border:none;padding:5px 12px;border-radius:6px;cursor:pointer;font-size:0.78rem;">🗑 Padam</button>';
        html += '</div>';
    }

    container.innerHTML = html;
}

function deleteSuggestion(id) {
    appData.scheduleSuggestions = appData.scheduleSuggestions.filter(function(s) { return s.id !== id; });
    saveData(appData);
    renderScheduleSuggestions();
    showToast('🗑 Cadangan dipadam');
}

