// ===== SORT TABLE =====

function sortMgrTable(column) {
    if (mgrSortColumn === column) {
        // Same column - toggle direction
        if (mgrSortDirection === 'asc') {
            mgrSortDirection = 'desc';
        } else if (mgrSortDirection === 'desc') {
            // Reset
            mgrSortColumn = null;
            mgrSortDirection = null;
        }
    } else {
        // New column - default ascending
        mgrSortColumn = column;
        mgrSortDirection = 'asc';
    }

    updateSortIndicators();
    renderManageRecords();
}

function updateSortIndicators() {
    // Clear all indicators
    var allIndicators = document.querySelectorAll('.sort-indicator');
    for (var i = 0; i < allIndicators.length; i++) {
        allIndicators[i].textContent = '';
        allIndicators[i].classList.remove('active');
    }

    var allHeaders = document.querySelectorAll('.mgr-sortable');
    for (var i = 0; i < allHeaders.length; i++) {
        allHeaders[i].classList.remove('sorted');
    }

    // Set active indicator
    if (mgrSortColumn && mgrSortDirection) {
        var indicator = document.getElementById('sort-' + mgrSortColumn);
        if (indicator) {
            indicator.textContent = mgrSortDirection === 'asc' ? '↑' : '↓';
            indicator.classList.add('active');
        }

        // Highlight header
        var headers = document.querySelectorAll('.mgr-sortable');
        for (var i = 0; i < headers.length; i++) {
            if (headers[i].getAttribute('onclick').indexOf("'" + mgrSortColumn + "'") > -1) {
                headers[i].classList.add('sorted');
            }
        }
    }
}

function applySortToRecords(records) {
    if (!mgrSortColumn || !mgrSortDirection) {
        // No sort - default by date desc (newest first)
        records.sort(function(a, b) {
            return new Date(b.date) - new Date(a.date);
        });
        return records;
    }

    records.sort(function(a, b) {
        var valA, valB;

        switch (mgrSortColumn) {
            case 'date':
                valA = new Date(a.date).getTime();
                valB = new Date(b.date).getTime();
                break;

            case 'student':
                valA = (a._student ? a._student.name : '').toLowerCase();
                valB = (b._student ? b._student.name : '').toLowerCase();
                break;

            case 'session':
                var sessionOrder = { 'pagi': 1, 'petang': 2, 'malam': 3 };
                valA = sessionOrder[a.session] || 0;
                valB = sessionOrder[b.session] || 0;
                break;

            case 'readingType':
                valA = (a.readingType || '').toLowerCase();
                valB = (b.readingType || '').toLowerCase();
                break;

            case 'score':
                valA = a.score || 0;
                valB = b.score || 0;
                break;

            case 'status':
                var statusOrder = { 'Lancar': 1, 'Sederhana': 2, 'Perlu Ulang': 3, 'Tidak Lulus': 4 };
                valA = statusOrder[a.status] || 0;
                valB = statusOrder[b.status] || 0;
                break;

            case 'checker':
                valA = (a.checkerName || '').toLowerCase();
                valB = (b.checkerName || '').toLowerCase();
                break;

            default:
                return 0;
        }

        if (valA < valB) return mgrSortDirection === 'asc' ? -1 : 1;
        if (valA > valB) return mgrSortDirection === 'asc' ? 1 : -1;
        return 0;
    });

    return records;
}

// ===== PAGINATION =====

function changeItemsPerPage(value) {
    if (value === 'all') {
        mgrItemsPerPage = 99999;
    } else {
        mgrItemsPerPage = parseInt(value) || 50;
    }
    mgrCurrentPage = 1;
    renderManageRecords();
}

function goToPage(page) {
    mgrCurrentPage = page;
    renderManageRecords();
    // Scroll to top of table
    var card = document.getElementById('mgrRecordsBody');
    if (card) {
        card.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
}

function renderPaginationControls(totalRecords, currentPage, itemsPerPage) {
    var container = document.getElementById('mgrPaginationControls');
    if (!container) return;

    var totalPages = Math.ceil(totalRecords / itemsPerPage);

    // Hide if only 1 page or no records
    if (totalPages <= 1) {
        container.style.display = 'none';
        return;
    }

    container.style.display = 'block';

    var startIdx = (currentPage - 1) * itemsPerPage + 1;
    var endIdx = Math.min(currentPage * itemsPerPage, totalRecords);

    var html = '<div class="pagination-wrapper">';

    // Info
    html += '<div class="pagination-info">';
    html += '📄 Menunjukkan <strong>' + startIdx + '-' + endIdx + '</strong> dari <strong>' + totalRecords + '</strong> rekod';
    html += ' • Halaman <strong>' + currentPage + '</strong> dari <strong>' + totalPages + '</strong>';
    html += '</div>';

    // Buttons
    html += '<div class="pagination-buttons">';

    // First button
    html += '<button class="pagination-btn" onclick="goToPage(1)" ' + (currentPage === 1 ? 'disabled' : '') + ' title="Halaman Pertama">⏮</button>';

    // Previous button
    html += '<button class="pagination-btn" onclick="goToPage(' + (currentPage - 1) + ')" ' + (currentPage === 1 ? 'disabled' : '') + ' title="Sebelum">‹</button>';

    // Page numbers (smart display)
    var pages = getPaginationPages(currentPage, totalPages);
    for (var i = 0; i < pages.length; i++) {
        if (pages[i] === '...') {
            html += '<span class="pagination-ellipsis">...</span>';
        } else {
            var isActive = pages[i] === currentPage;
            html += '<button class="pagination-btn ' + (isActive ? 'active' : '') + '" onclick="goToPage(' + pages[i] + ')">' + pages[i] + '</button>';
        }
    }

    // Next button
    html += '<button class="pagination-btn" onclick="goToPage(' + (currentPage + 1) + ')" ' + (currentPage === totalPages ? 'disabled' : '') + ' title="Seterusnya">›</button>';

    // Last button
    html += '<button class="pagination-btn" onclick="goToPage(' + totalPages + ')" ' + (currentPage === totalPages ? 'disabled' : '') + ' title="Halaman Akhir">⏭</button>';

    html += '</div>';

    html += '</div>';

    container.innerHTML = html;
}

function getPaginationPages(current, total) {
    // Smart pagination: always show first, last, current, and neighbors
    var pages = [];

    if (total <= 7) {
        // Show all pages if total <= 7
        for (var i = 1; i <= total; i++) {
            pages.push(i);
        }
        return pages;
    }

    // Always show first page
    pages.push(1);

    // Calculate range around current
    var start = Math.max(2, current - 1);
    var end = Math.min(total - 1, current + 1);

    // Add ellipsis after first if needed
    if (start > 2) {
        pages.push('...');
    }

    // Add range
    for (var i = start; i <= end; i++) {
        pages.push(i);
    }

    // Add ellipsis before last if needed
    if (end < total - 1) {
        pages.push('...');
    }

    // Always show last page
    pages.push(total);

    return pages;
}

function renderManageRecords() {
    var tbody = document.getElementById('mgrRecordsBody');
    if (!tbody) return;

    if (!appData.records) appData.records = [];

    // Get filters
    var search = (document.getElementById('mgrSearchInput').value || '').toLowerCase();
    var studentFilter = document.getElementById('mgrFilterStudent').value;
    var classFilter = document.getElementById('mgrFilterClass').value;
    var sessionFilter = document.getElementById('mgrFilterSession').value;
    var statusFilter = document.getElementById('mgrFilterStatus').value;
    var readingTypeFilter = document.getElementById('mgrFilterReadingType').value;
    var dateFrom = document.getElementById('mgrFilterDateFrom').value;
    var dateTo = document.getElementById('mgrFilterDateTo').value;

    // BARU: Markah range filter
    var markahRangeFilter = document.getElementById('mgrFilterMarkahRange').value;
    var markahMin = 0;
    var markahMax = 100;

    if (markahRangeFilter === 'custom') {
        markahMin = parseInt(document.getElementById('mgrMarkahMin').value) || 0;
        markahMax = parseInt(document.getElementById('mgrMarkahMax').value) || 100;
    } else if (markahRangeFilter !== 'all') {
        var parts = markahRangeFilter.split('-');
        markahMin = parseInt(parts[0]);
        markahMax = parseInt(parts[1]);
    }

    // Filter records
    var filtered = [];
    for (var i = 0; i < appData.records.length; i++) {
        var r = appData.records[i];

        // Find student
        var student = null;
        for (var j = 0; j < appData.students.length; j++) {
            if (appData.students[j].id === r.studentId) {
                student = appData.students[j];
                break;
            }
        }
        if (!student) continue;

                // Apply filters
        if (search && student.name.toLowerCase().indexOf(search) === -1) continue;
        if (studentFilter !== 'all' && r.studentId !== studentFilter) continue;
        if (classFilter !== 'all' && student.class !== classFilter) continue;
        if (sessionFilter !== 'all' && r.session !== sessionFilter) continue;
        if (statusFilter !== 'all' && r.status !== statusFilter) continue;
        if (readingTypeFilter !== 'all' && r.readingType !== readingTypeFilter) continue;
        if (dateFrom && r.date < dateFrom) continue;
        if (dateTo && r.date > dateTo) continue;

        // BARU: Markah range filter
        if (markahRangeFilter !== 'all') {
            var score = r.score || 0;
            if (score < markahMin || score > markahMax) continue;
        }

        r._student = student;  // Cache for rendering
        filtered.push(r);
    }

            // Apply sort (default: newest first)
    filtered = applySortToRecords(filtered);

    // Update stats (based on FILTERED, before pagination)
    updateMgrStats(filtered);

    // BARU: Apply pagination
    var totalFiltered = filtered.length;
    var startIdx = (mgrCurrentPage - 1) * mgrItemsPerPage;
    var endIdx = startIdx + mgrItemsPerPage;
    var paginated = filtered.slice(startIdx, endIdx);

    // Safety check - if current page invalid (cth: filter changed)
    if (paginated.length === 0 && mgrCurrentPage > 1) {
        mgrCurrentPage = 1;
        startIdx = 0;
        endIdx = mgrItemsPerPage;
        paginated = filtered.slice(0, mgrItemsPerPage);
    }

    // Update count
    document.getElementById('mgrShowingCount').textContent = 'Menunjukkan ' + paginated.length + ' dari ' + totalFiltered + ' rekod';

    // Render table
    if (paginated.length === 0) {
        tbody.innerHTML = '<tr><td colspan="10" class="text-center" style="padding:40px;"><div class="empty-state"><div class="empty-icon">📭</div><p>Tiada rekod ditemui</p><small>Cuba ubah filter</small></div></td></tr>';
        renderPaginationControls(0, 1, mgrItemsPerPage);
        return;
    }

    var html = '';
    for (var i = 0; i < paginated.length; i++) {
        var r = paginated[i];
        // ... rest of render (TAK BERUBAH)
        var isChecked = mgrSelectedRecords.indexOf(r.id) > -1;

        // Bacaan display
        var bacaanText = '';
        if (r.isIqra) {
            bacaanText = '📕 ' + (r.iqraBook || 'Iqra') + ' (ms ' + (r.iqraPage || '-') + ')';
        } else {
            bacaanText = typeof formatSurahWithAyat === 'function'
                ? formatSurahWithAyat(r)
                : (r.surah || '-');
        }

        var sessionBadge = typeof getSessionBadge === 'function' ? getSessionBadge(r.session) : (r.session || '-');
        var readingBadge = typeof getReadingTypeBadge === 'function' ? getReadingTypeBadge(r.readingType) : (r.readingType || '-');
        var checkerIcon = r.checkerType === 'pelajar' ? '👨‍🎓' : '👨‍🏫';

        html += '<tr>';
        html += '<td><input type="checkbox" class="mgr-record-check" data-id="' + r.id + '" ' + (isChecked ? 'checked' : '') + ' onchange="toggleRecordSelection(\'' + r.id + '\')"></td>';
        html += '<td>' + formatDate(r.date) + '</td>';
        html += '<td><strong>' + r._student.name + '</strong><br><small style="color:#64748b;">' + r._student.class + '</small></td>';
        html += '<td>' + sessionBadge + '</td>';
        html += '<td>' + readingBadge + '</td>';
        html += '<td style="max-width:250px;font-size:0.85rem;">' + bacaanText + '</td>';
        html += '<td><strong>' + r.score + '%</strong></td>';
        html += '<td><span class="badge ' + getBadgeClass(r.status) + '">' + r.status + '</span></td>';
        html += '<td><small>' + checkerIcon + ' ' + (r.checkerName || '-') + '</small></td>';
        html += '<td>';
        html += '<div style="display:flex;gap:5px;">';
        html += '<button class="btn btn-sm btn-view" onclick="editRecord(\'' + r.id + '\')" title="Edit">✏️</button>';
        html += '<button class="btn btn-sm btn-delete" onclick="deleteRecord(\'' + r.id + '\')" title="Padam">🗑</button>';
        html += '</div>';
        html += '</td>';
        html += '</tr>';
    }

    tbody.innerHTML = html;

    // Update bulk actions
    updateBulkActionsBar();
    // BARU: Render pagination
    renderPaginationControls(totalFiltered, mgrCurrentPage, mgrItemsPerPage);
}

function updateMgrStats(records) {
    var total = records.length;
    var lancar = 0, sederhana = 0, ulang = 0, gagal = 0;

    for (var i = 0; i < records.length; i++) {
        var s = records[i].status;
        if (s === 'Lancar') lancar++;
        else if (s === 'Sederhana') sederhana++;
        else if (s === 'Perlu Ulang') ulang++;
        else if (s === 'Tidak Lulus') gagal++;
    }

    document.getElementById('mgrTotalRecords').textContent = total;
    document.getElementById('mgrLancarCount').textContent = lancar;
    document.getElementById('mgrSederhanaCount').textContent = sederhana;
    document.getElementById('mgrUlangCount').textContent = ulang;
    document.getElementById('mgrGagalCount').textContent = gagal;
}

// ===== SELECTION =====

function toggleRecordSelection(recordId) {
    var idx = mgrSelectedRecords.indexOf(recordId);
    if (idx > -1) {
        mgrSelectedRecords.splice(idx, 1);
    } else {
        mgrSelectedRecords.push(recordId);
    }
    updateBulkActionsBar();
}

function toggleSelectAll(checkbox) {
    var checks = document.querySelectorAll('.mgr-record-check');
    mgrSelectedRecords = [];

    for (var i = 0; i < checks.length; i++) {
        checks[i].checked = checkbox.checked;
        if (checkbox.checked) {
            mgrSelectedRecords.push(checks[i].dataset.id);
        }
    }

    updateBulkActionsBar();
}

function clearMgrSelection() {
    mgrSelectedRecords = [];
    var checks = document.querySelectorAll('.mgr-record-check');
    for (var i = 0; i < checks.length; i++) {
        checks[i].checked = false;
    }
    document.getElementById('mgrSelectAll').checked = false;
    updateBulkActionsBar();
}

function updateBulkActionsBar() {
    var bar = document.getElementById('mgrBulkActions');
    var count = document.getElementById('mgrSelectedCount');

    if (mgrSelectedRecords.length > 0) {
        bar.style.display = 'block';
        count.textContent = mgrSelectedRecords.length + ' rekod dipilih';
    } else {
        bar.style.display = 'none';
    }
}

// ===== DELETE =====

function deleteRecord(recordId) {
    var record = null;
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].id === recordId) {
            record = appData.records[i];
            break;
        }
    }
    if (!record) return;

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === record.studentId) {
            student = appData.students[i];
            break;
        }
    }
    var studentName = student ? student.name : 'Unknown';

    if (!confirm('Padam rekod ini?\n\nPelajar: ' + studentName + '\nTarikh: ' + formatDate(record.date) + '\nMarkah: ' + record.score + '%\n\nTindakan ini TIDAK boleh diundo!')) {
        return;
    }

    var newRecords = [];
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].id !== recordId) {
            newRecords.push(appData.records[i]);
        }
    }
    appData.records = newRecords;

    // Remove from selection
    var idx = mgrSelectedRecords.indexOf(recordId);
    if (idx > -1) mgrSelectedRecords.splice(idx, 1);

    showToast('⏳ Memadam rekod...');
    saveData(appData, function(success) {
        if (success) {
            showToast('🗑 Rekod dipadam');
        } else {
            showToast('❌ Gagal padam rekod. Sila semak internet & cuba lagi.');
        }
        renderManageRecords();
        updateStats();
    });
}

function bulkDeleteRecords() {
    if (mgrSelectedRecords.length === 0) {
        showToast('❌ Tiada rekod dipilih');
        return;
    }

    if (!confirm('⚠️ AMARAN!\n\nPadam ' + mgrSelectedRecords.length + ' rekod sekaligus?\n\nTindakan ini TIDAK boleh diundo!')) {
        return;
    }

    if (!confirm('Pengesahan akhir!\n\nPasti nak padam ' + mgrSelectedRecords.length + ' rekod?')) {
        return;
    }

    var newRecords = [];
    for (var i = 0; i < appData.records.length; i++) {
        if (mgrSelectedRecords.indexOf(appData.records[i].id) === -1) {
            newRecords.push(appData.records[i]);
        }
    }

    var deletedCount = mgrSelectedRecords.length;
    appData.records = newRecords;
    mgrSelectedRecords = [];

    showToast('⏳ Memadam rekod...');
    saveData(appData, function(success) {
        if (success) {
            showToast('🗑 ' + deletedCount + ' rekod dipadam');
        } else {
            showToast('❌ Gagal padam rekod. Sila semak internet & cuba lagi.');
        }
        renderManageRecords();
        updateStats();
    });
}

// Global variables untuk edit record
var editSelectedJuz = [];
var editSelectedSurahAyat = {};  // {surahName: {from, to, juz}}

function editRecord(recordId) {
    var record = null;
    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].id === recordId) {
            record = appData.records[i];
            break;
        }
    }
    if (!record) {
        showToast('❌ Rekod tidak ditemui');
        return;
    }

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === record.studentId) {
            student = appData.students[i];
            break;
        }
    }

    mgrEditingRecordId = recordId;

    // Reset state
    editSelectedJuz = [];
    editSelectedSurahAyat = {};

    // Fill basic fields
    document.getElementById('editRecStudentName').value = student ? student.name + ' (' + student.class + ')' : 'Unknown';
    document.getElementById('editRecDate').value = record.date;
    document.getElementById('editRecSession').value = record.session || 'pagi';
    document.getElementById('editRecReadingType').value = record.readingType || '';
    document.getElementById('editRecScore').value = record.score;
    document.getElementById('editRecStatus').value = record.status;
    document.getElementById('editRecCheckerName').value = record.checkerName || '';
    document.getElementById('editRecNotes').value = record.notes || '';

    // Determine Iqra or Hafazan
    if (record.isIqra) {
        document.querySelector('input[name="editRecIsIqra"][value="yes"]').checked = true;
        document.getElementById('editIqraBook').value = record.iqraBook || '';
        document.getElementById('editIqraPage').value = record.iqraPage || '';
        document.getElementById('editIqraLineFrom').value = record.iqraLineFrom || '';
        document.getElementById('editIqraLineTo').value = record.iqraLineTo || '';
    } else {
        document.querySelector('input[name="editRecIsIqra"][value="no"]').checked = true;

        // Load Juz
        if (record.juzList && record.juzList.length > 0) {
            editSelectedJuz = record.juzList.slice();
        } else if (record.juz) {
            editSelectedJuz = Array.isArray(record.juz) ? record.juz.slice() : [record.juz];
        }

        // Load Surah with ayat
        if (record.surahDetails && record.surahDetails.length > 0) {
            for (var i = 0; i < record.surahDetails.length; i++) {
                var sd = record.surahDetails[i];
                editSelectedSurahAyat[sd.name] = {
                    from: sd.ayatFrom || 1,
                    to: sd.ayatTo || 0,
                    juz: sd.juz || 0
                };
            }
        } else if (record.surah) {
            // Fallback for old data
            var surahs = Array.isArray(record.surah) ? record.surah : [record.surah];
            for (var i = 0; i < surahs.length; i++) {
                var info = getSurahInfo(surahs[i]);
                editSelectedSurahAyat[surahs[i]] = {
                    from: 1,
                    to: info ? info.ayat : 0,
                    juz: info ? info.juz : 0
                };
            }
        }
    }

    toggleEditIqraSection();
    renderEditJuzDisplay();
    renderEditSurahList();

    // Show overlay
    var overlay = document.getElementById('editRecordOverlay');
    if (overlay) {
        if (overlay.parentNode !== document.body) {
            document.body.appendChild(overlay);
        }
        overlay.classList.remove('hidden');
        overlay.setAttribute('style',
            'position:fixed !important;top:0 !important;left:0 !important;right:0 !important;' +
            'bottom:0 !important;width:100vw !important;height:100vh !important;' +
            'background:var(--bg) !important;z-index:99999 !important;' +
            'display:flex !important;flex-direction:column !important;' +
            'visibility:visible !important;opacity:1 !important;overflow:hidden !important;'
        );
        document.body.style.overflow = 'hidden';
    }
    // Letak kod ini di baris akhir sekali fungsi editRecord(recordId) anda
setTimeout(function() {
    var editType = document.getElementById('editRecReadingType').value;
    var editContainer = document.getElementById('editMukhtarContainer');
    if (editContainer && editType && editType.indexOf('Mukhtar Khatam') > -1) {
        editContainer.style.display = 'block';
        
        // Cuba dapatkan data Lulus/Gagal lama daripada medan r.notes
        var currentNotes = document.getElementById('editRecNotes').value;
        if (currentNotes.indexOf('[🔴 TIDAK LULUS]') > -1) {
            var radio = document.querySelector('input[name="editMukhtarResult"][value="Tidak Lulus"]');
            if (radio) radio.checked = true;
            // Bersihkan label daripada dipaparkan di text area biasa
            document.getElementById('editRecNotes').value = currentNotes.replace('[🔴 TIDAK LULUS] | ', '').replace('[🔴 TIDAK LULUS]', '').trim();
            document.getElementById('editMukhtarNotes').value = '';
        } else if (currentNotes.indexOf('[🟢 LULUS]') > -1) {
            var radio = document.querySelector('input[name="editMukhtarResult"][value="Lulus"]');
            if (radio) radio.checked = true;
            document.getElementById('editRecNotes').value = currentNotes.replace('[🟢 LULUS] | ', '').replace('[🟢 LULUS]', '').trim();
            document.getElementById('editMukhtarNotes').value = '';
        }
    }
}, 200);
}

function toggleEditIqraSection() {
    var isIqra = document.querySelector('input[name="editRecIsIqra"]:checked');
    var isIqraValue = isIqra ? isIqra.value === 'yes' : false;

    var iqraSection = document.getElementById('editIqraSection');
    var hafazanSection = document.getElementById('editHafazanSection');

    if (isIqraValue) {
        iqraSection.classList.remove('hidden');
        hafazanSection.style.display = 'none';
    } else {
        iqraSection.classList.add('hidden');
        hafazanSection.style.display = 'block';
    }
}

// ===== JUZ MANAGEMENT =====

function renderEditJuzDisplay() {
    var container = document.getElementById('editSelectedJuzDisplay');
    if (!container) return;

    if (editSelectedJuz.length === 0) {
        container.innerHTML = '<span style="color:#94a3b8;font-size:0.85rem;">Tiada Juz dipilih</span>';
        return;
    }

    editSelectedJuz.sort(function(a, b) { return a - b; });

    var html = '';
    for (var i = 0; i < editSelectedJuz.length; i++) {
        html += '<span class="tag" style="background:linear-gradient(135deg,#a78bfa,#7c3aed);">Juz ' + editSelectedJuz[i] +
                '<button type="button" class="tag-remove" onclick="editRemoveJuz(' + editSelectedJuz[i] + ')">✕</button></span>';
    }
    container.innerHTML = html;
}

function editQuickAddJuz(juzNum) {
    if (editSelectedJuz.indexOf(juzNum) > -1) {
        showToast('⚠️ Juz ' + juzNum + ' sudah dipilih');
        return;
    }
    editSelectedJuz.push(juzNum);
    renderEditJuzDisplay();
    showToast('✅ Juz ' + juzNum + ' ditambah');
}

function editRemoveJuz(juzNum) {
    var idx = editSelectedJuz.indexOf(juzNum);
    if (idx > -1) editSelectedJuz.splice(idx, 1);

    // Remove surahs yang takda juz lain dipilih
    var newSurahAyat = {};
    for (var surahName in editSelectedSurahAyat) {
        var info = getSurahInfo(surahName);
        if (info) {
            var hasJuz = false;
            for (var i = 0; i < editSelectedJuz.length; i++) {
                if (isSurahInJuz(info, editSelectedJuz[i])) {
                    hasJuz = true;
                    break;
                }
            }
            if (hasJuz) {
                newSurahAyat[surahName] = editSelectedSurahAyat[surahName];
            }
        }
    }
    editSelectedSurahAyat = newSurahAyat;

    renderEditJuzDisplay();
    renderEditSurahList();
}

function editShowJuzPicker() {
    var juzNum = prompt('Masukkan nombor Juz (1-30):');
    if (!juzNum) return;

    var num = parseInt(juzNum);
    if (isNaN(num) || num < 1 || num > 30) {
        showToast('❌ Nombor Juz tidak sah (1-30)');
        return;
    }

    editQuickAddJuz(num);
}

// ===== SURAH MANAGEMENT =====

function renderEditSurahList() {
    var container = document.getElementById('editSelectedSurahList');
    if (!container) return;

    var surahNames = Object.keys(editSelectedSurahAyat);

    if (surahNames.length === 0) {
        container.innerHTML = '<p style="color:#94a3b8;font-size:0.85rem;text-align:center;margin:20px 0;">' +
            (editSelectedJuz.length === 0 ? 'Tiada Surah. Pilih Juz dahulu.' : 'Klik "Tambah Surah" di bawah') + '</p>';
        return;
    }

    // Sort by surah number
    surahNames.sort(function(a, b) {
        var infoA = getSurahInfo(a);
        var infoB = getSurahInfo(b);
        return (infoA ? infoA.no : 0) - (infoB ? infoB.no : 0);
    });

    var html = '';
    for (var i = 0; i < surahNames.length; i++) {
        var name = surahNames[i];
        var data = editSelectedSurahAyat[name];
        var info = getSurahInfo(name);
        var totalAyat = info ? info.ayat : 0;
        var juzNo = info ? (info.juzList ? info.juzList[0] : info.juz) : 0;

        html += '<div style="background:white;border:1px solid #e2e8f0;border-radius:10px;padding:12px;margin-bottom:8px;">';

        html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">';
        html += '<div>';
        html += '<strong>' + (info ? info.no : '?') + '. ' + name + '</strong>';
        html += ' <span style="background:#a78bfa;color:white;padding:2px 8px;border-radius:10px;font-size:0.7rem;">Juz ' + juzNo + '</span>';
        html += '<div style="font-size:0.75rem;color:#64748b;">Jumlah ayat: ' + totalAyat + '</div>';
        html += '</div>';
        html += '<button type="button" class="btn btn-sm btn-delete" onclick="editRemoveSurah(\'' + name + '\')" title="Buang">🗑</button>';
        html += '</div>';

        html += '<div style="display:flex;gap:10px;align-items:center;flex-wrap:wrap;">';
        html += '<label style="font-size:0.82rem;color:#64748b;">Ayat:</label>';
        html += '<input type="number" id="editAyatFrom_' + (info ? info.no : i) + '" value="' + data.from + '" min="1" max="' + totalAyat + '" style="width:70px;padding:6px;border:2px solid #e2e8f0;border-radius:6px;text-align:center;" onchange="editUpdateAyat(\'' + name + '\')">';
        html += '<span>→</span>';
        html += '<input type="number" id="editAyatTo_' + (info ? info.no : i) + '" value="' + data.to + '" min="1" max="' + totalAyat + '" style="width:70px;padding:6px;border:2px solid #e2e8f0;border-radius:6px;text-align:center;" onchange="editUpdateAyat(\'' + name + '\')">';
        html += '<button type="button" class="btn btn-sm" style="background:#a78bfa;color:white;" onclick="editSetFullSurah(\'' + name + '\')">📖 Penuh</button>';
        html += '</div>';

        html += '</div>';
    }

    container.innerHTML = html;
}

function editShowSurahPicker() {
    if (editSelectedJuz.length === 0) {
        showToast('❌ Sila pilih Juz dahulu');
        return;
    }

    // Populate dropdown
    var select = document.getElementById('editSurahPickerSelect');
    var html = '<option value="">-- Pilih Surah --</option>';

    // Get surahs in selected juz
    var availableSurahs = [];
    for (var i = 0; i < SURAH_LIST.length; i++) {
        var surah = SURAH_LIST[i];
        for (var j = 0; j < editSelectedJuz.length; j++) {
            if (isSurahInJuz(surah, editSelectedJuz[j])) {
                if (!editSelectedSurahAyat[surah.name]) {  // not already selected
                    availableSurahs.push(surah);
                }
                break;
            }
        }
    }

    if (availableSurahs.length === 0) {
        html += '<option disabled>Semua surah dalam Juz dipilih sudah ditambah</option>';
    } else {
        for (var i = 0; i < availableSurahs.length; i++) {
            var s = availableSurahs[i];
            html += '<option value="' + s.name + '">' + s.no + '. ' + s.name + ' (Juz ' + s.juzList.join(',') + ')</option>';
        }
    }

    select.innerHTML = html;
    document.getElementById('editSurahPicker').classList.remove('hidden');
}

function editHideSurahPicker() {
    document.getElementById('editSurahPicker').classList.add('hidden');
}

function editAddSurah() {
    var select = document.getElementById('editSurahPickerSelect');
    var surahName = select.value;
    if (!surahName) {
        showToast('❌ Sila pilih surah');
        return;
    }

    var info = getSurahInfo(surahName);
    if (!info) return;

    editSelectedSurahAyat[surahName] = {
        from: 1,
        to: info.ayat,
        juz: info.juzList ? info.juzList[0] : info.juz
    };

    editHideSurahPicker();
    renderEditSurahList();
    showToast('✅ ' + surahName + ' ditambah');
}

function editRemoveSurah(surahName) {
    delete editSelectedSurahAyat[surahName];
    renderEditSurahList();
}

function editUpdateAyat(surahName) {
    var info = getSurahInfo(surahName);
    if (!info) return;

    var fromEl = document.getElementById('editAyatFrom_' + info.no);
    var toEl = document.getElementById('editAyatTo_' + info.no);

    var from = parseInt(fromEl.value) || 1;
    var to = parseInt(toEl.value) || info.ayat;

    // Validation
    if (from < 1) from = 1;
    if (to > info.ayat) to = info.ayat;
    if (from > to) from = to;

    fromEl.value = from;
    toEl.value = to;

    editSelectedSurahAyat[surahName].from = from;
    editSelectedSurahAyat[surahName].to = to;
}

function editSetFullSurah(surahName) {
    var info = getSurahInfo(surahName);
    if (!info) return;

    var fromEl = document.getElementById('editAyatFrom_' + info.no);
    var toEl = document.getElementById('editAyatTo_' + info.no);

    fromEl.value = 1;
    toEl.value = info.ayat;

    editSelectedSurahAyat[surahName].from = 1;
    editSelectedSurahAyat[surahName].to = info.ayat;

    showToast('✅ ' + surahName + ' set penuh');
}

// ===== SAVE =====

function saveEditRecord() {
    if (!mgrEditingRecordId) return;

    var isIqra = document.querySelector('input[name="editRecIsIqra"]:checked');
    var isIqraValue = isIqra ? isIqra.value === 'yes' : false;

    // Validation
    if (!isIqraValue) {
        if (editSelectedJuz.length === 0) {
            showToast('❌ Sila pilih sekurang-kurangnya satu Juz');
            return;
        }
        if (Object.keys(editSelectedSurahAyat).length === 0) {
            showToast('❌ Sila pilih sekurang-kurangnya satu Surah');
            return;
        }
    }

    for (var i = 0; i < appData.records.length; i++) {
        if (appData.records[i].id === mgrEditingRecordId) {
            var r = appData.records[i];

            // Basic fields
            r.date = document.getElementById('editRecDate').value;
            r.session = document.getElementById('editRecSession').value;
            r.readingType = document.getElementById('editRecReadingType').value;
            r.score = parseInt(document.getElementById('editRecScore').value);
            r.status = document.getElementById('editRecStatus').value;
            r.checkerName = document.getElementById('editRecCheckerName').value.trim();
            
            var notesInput = document.getElementById('editRecNotes').value.trim();

            // === INTEGRASI MUKHTAR KHATAM (EDIT REKOD) ===
            if (r.readingType && r.readingType.toLowerCase().indexOf('mukhtar') > -1 && r.readingType.toLowerCase().indexOf('khatam') > -1) {
                var editResultInput = document.getElementById('editMukhtarResult');
                var editResult = editResultInput ? editResultInput.value : 'Lulus';
                
                var customEditNotesEl = document.getElementById('editMukhtarNotes');
                var customEditNotes = customEditNotesEl ? customEditNotesEl.value.trim() : '';

                var prefix = (editResult === 'Lulus') ? '🟢 LULUS' : '🔴 TIDAK LULUS';
                var formattedNotes = '[' + prefix + ']';
                if (customEditNotes) {
                    formattedNotes += ' ' + customEditNotes;
                }

                // Satukan catatan keputusan dengan catatan am (jika ada)
                if (notesInput) {
                    r.notes = formattedNotes + ' | ' + notesInput;
                } else {
                    r.notes = formattedNotes;
                }
            } else {
                r.notes = notesInput;
            }

            r.updatedAt = new Date().toISOString();

            // Bacaan fields
            r.isIqra = isIqraValue;

            if (isIqraValue) {
                r.iqraBook = document.getElementById('editIqraBook').value;
                r.iqraPage = document.getElementById('editIqraPage').value;
                r.iqraLineFrom = document.getElementById('editIqraLineFrom').value;
                r.iqraLineTo = document.getElementById('editIqraLineTo').value;

                // Clear hafazan
                r.juz = null;
                r.juzList = [];
                r.surah = null;
                r.surahList = [];
                r.surahDetails = [];
            } else {
                // Clear iqra
                r.iqraBook = '';
                r.iqraPage = '';
                r.iqraLineFrom = '';
                r.iqraLineTo = '';

                // Update Juz
                editSelectedJuz.sort(function(a, b) { return a - b; });
                r.juzList = editSelectedJuz.slice();
                r.juz = editSelectedJuz.length === 1 ? editSelectedJuz[0] : editSelectedJuz.slice();

                // Update Surah
                var surahNames = Object.keys(editSelectedSurahAyat);
                surahNames.sort(function(a, b) {
                    var infoA = getSurahInfo(a);
                    var infoB = getSurahInfo(b);
                    return (infoA ? infoA.no : 0) - (infoB ? infoB.no : 0);
                });

                var surahDetails = [];
                for (var j = 0; j < surahNames.length; j++) {
                    var name = surahNames[j];
                    var data = editSelectedSurahAyat[name];
                    var info = getSurahInfo(name);

                    surahDetails.push({
                        name: name,
                        juz: data.juz || (info ? (info.juzList ? info.juzList[0] : info.juz) : 0),
                        ayatFrom: data.from || 1,
                        ayatTo: data.to || (info ? info.ayat : 0)
                    });
                }

                r.surahList = surahNames;
                r.surah = surahNames.length === 1 ? surahNames[0] : surahNames;
                r.surahDetails = surahDetails;
            }

            saveData(appData);
            
            var editContainer = document.getElementById('editMukhtarContainer');
            if (editContainer) editContainer.style.display = 'none';

            showToast('✅ Rekod dikemaskini');
            closeEditRecord();
            renderManageRecords();
            updateStats();
            return;
        }
    }
}

function closeEditRecord() {
    var overlay = document.getElementById('editRecordOverlay');
    if (overlay) {
        overlay.classList.add('hidden');
        overlay.setAttribute('style', 'display:none !important;');
    }
    document.body.style.overflow = '';
    mgrEditingRecordId = null;
    editSelectedJuz = [];
    editSelectedSurahAyat = {};
}

// ===== EXPORT =====

function exportRecordsCSV() {
    if (!appData.records || appData.records.length === 0) {
        showToast('❌ Tiada rekod untuk export');
        return;
    }

    var csv = 'Tarikh,Pelajar,Kelas,Sesi,Jenis Bacaan,Surah/Iqra,Markah,Status,Penyemak,Catatan\n';

    for (var i = 0; i < appData.records.length; i++) {
        var r = appData.records[i];

        var student = null;
        for (var j = 0; j < appData.students.length; j++) {
            if (appData.students[j].id === r.studentId) {
                student = appData.students[j];
                break;
            }
        }
        if (!student) continue;

        var bacaanText = '';
        if (r.isIqra) {
            bacaanText = (r.iqraBook || 'Iqra') + ' ms ' + (r.iqraPage || '-');
        } else if (r.surahDetails) {
            var parts = [];
            for (var k = 0; k < r.surahDetails.length; k++) {
                var sd = r.surahDetails[k];
                parts.push(sd.name + (sd.ayatFrom ? ' (' + sd.ayatFrom + '-' + sd.ayatTo + ')' : ''));
            }
            bacaanText = parts.join('; ');
        } else {
            bacaanText = Array.isArray(r.surah) ? r.surah.join('; ') : (r.surah || '');
        }

        csv += '"' + r.date + '",';
        csv += '"' + student.name + '",';
        csv += '"' + student.class + '",';
        csv += '"' + (r.session || '') + '",';
        csv += '"' + (r.readingType || '') + '",';
        csv += '"' + bacaanText.replace(/"/g, '""') + '",';
        csv += '"' + r.score + '",';
        csv += '"' + r.status + '",';
        csv += '"' + (r.checkerName || '') + '",';
        csv += '"' + (r.notes || '').replace(/"/g, '""') + '"\n';
    }

    var BOM = '\uFEFF';
    var blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'rekod_hafazan_' + new Date().toISOString().split('T')[0] + '.csv';
    link.click();

    showToast('✅ Berjaya export ' + appData.records.length + ' rekod');
}

// ============================================
// ===== PROGRESS HAFAZAN (VISUAL GRID) =======
// ============================================

var currentProgressStudent = null;
var currentProgressSet = 'sabakBaru';

function initProgressHafazan() {
    populateProgressStudentDropdown();
    renderProgressHafazan();
}

function populateProgressStudentDropdown() {
    var select = document.getElementById('progressStudent');
    if (!select) return;

    // Filter HANYA pelajar aktif
    var activeStudents = appData.students.filter(function(s) {
        var status = s.status || 'aktif';
        return status === 'aktif';
    });
    
    var sorted = activeStudents.slice().sort(function(a, b) {
        return a.name.localeCompare(b.name);
    });

    var html = '<option value="">-- Pilih Pelajar --</option>';
    for (var i = 0; i < sorted.length; i++) {
        html += '<option value="' + sorted[i].id + '">' + sorted[i].name + ' (' + sorted[i].class + ')</option>';
    }
    select.innerHTML = html;
}
function renderProgressHafazan() {
    var studentId = document.getElementById('progressStudent').value;
    var setRadio = document.querySelector('input[name="progressSet"]:checked');
    var currentSet = setRadio ? setRadio.value : 'sabakBaru';

    currentProgressStudent = studentId;
    currentProgressSet = currentSet;

    var container = document.getElementById('progressGridContainer');
    var statsContainer = document.getElementById('progressStats');
    var title = document.getElementById('progressGridTitle');
    var searchCard = document.getElementById('progressSearchCard');

    if (!studentId) {
        if (container) container.innerHTML = '<div class="empty-state" style="padding:60px;"><div class="empty-icon">👈</div><p>Pilih pelajar untuk lihat progress</p></div>';
        if (statsContainer) statsContainer.innerHTML = '';
        if (searchCard) searchCard.style.display = 'none';
        return;
    }

    // Show search card bila ada pelajar
    if (searchCard) searchCard.style.display = 'block';

    // Find student
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    // Update title
    var setNames = {
        sabakBaru: '🆕 Sabak Baru',
        paraSabak: '🔄 Para Sabak',
        mukhtar: '📋 Mukhtar'
    };
    title.textContent = '📖 Grid Surah - ' + setNames[currentSet] + ' (' + student.name + ')';

    // Get progress data
    var progress = calculateProgress(studentId, currentSet);

    // Render stats
    renderProgressStats(progress);

        // BARU: Pre-calculate dependency progress untuk Para Sabak & Mukhtar
    var dependencyProgress = null;
    if (currentSet === 'paraSabak') {
        dependencyProgress = calculateProgress(studentId, 'sabakBaru');
    } else if (currentSet === 'mukhtar') {
        dependencyProgress = calculateProgress(studentId, 'paraSabak');
    }

    // Render grid
    var html = '';
    for (var i = 0; i < SURAH_LIST.length; i++) {
        var surah = SURAH_LIST[i];
        html += renderSurahGrid(surah, progress, currentSet, dependencyProgress);
    }

    container.innerHTML = html;
    // 🌟 TAMBAH BARIS INI DI SINI 🌟
    // Jalankan filter sejurus selepas melukis grid baru
    setTimeout(function() {
        filterProgressGrid();
    }, 50);
}

function calculateProgress(studentId, setType) {
    // Get manual overrides
    var manualKey = 'progress_' + studentId + '_' + setType;
    var manualOverrides = {};
    if (appData.progressOverrides && appData.progressOverrides[manualKey]) {
        manualOverrides = appData.progressOverrides[manualKey];
    }

    // Map reading types to sets
    var readingTypeMap = {
        sabakBaru: ['sabak_baru'],
        paraSabak: ['para_sabak'],
        mukhtar: ['mukhtar', 'mukhtar_khatam']
    };

    var allowedTypes = readingTypeMap[setType] || [];

    // Get all records untuk pelajar ni
    var progress = {};  // {surahNo: {ayatNo: status}}

    for (var i = 0; i < appData.records.length; i++) {
        var r = appData.records[i];
        if (r.studentId !== studentId) continue;
        if (r.isIqra) continue;
        if (allowedTypes.indexOf(r.readingType) === -1) continue;

        // Determine status color
        var status = getStatusKey(r.status);

        // Get surah details
        if (r.surahDetails && r.surahDetails.length > 0) {
            for (var j = 0; j < r.surahDetails.length; j++) {
                var sd = r.surahDetails[j];
                var info = getSurahInfo(sd.name);
                if (!info) continue;

                if (!progress[info.no]) progress[info.no] = {};

                var fromAyat = sd.ayatFrom || 1;
                var toAyat = sd.ayatTo || info.ayat;

                for (var a = fromAyat; a <= toAyat; a++) {
                    // Newer record takes priority (but kekal jika manual override)
                    progress[info.no][a] = status;
                }
            }
        } else if (r.surah) {
            // Fallback for old data - assume surah penuh
            var surahs = Array.isArray(r.surah) ? r.surah : [r.surah];
            for (var k = 0; k < surahs.length; k++) {
                var info = getSurahInfo(surahs[k]);
                if (!info) continue;

                if (!progress[info.no]) progress[info.no] = {};
                for (var a = 1; a <= info.ayat; a++) {
                    progress[info.no][a] = status;
                }
            }
        }
    }

    // Apply manual overrides
    for (var key in manualOverrides) {
        var parts = key.split('_');
        var surahNo = parseInt(parts[0]);
        var ayatNo = parseInt(parts[1]);

        if (!progress[surahNo]) progress[surahNo] = {};
        progress[surahNo][ayatNo] = manualOverrides[key];
    }

    return {
        data: progress,
        manual: manualOverrides
    };
}

function getStatusKey(status) {
    if (status === 'Lancar') return 'lancar';
    if (status === 'Sederhana') return 'sederhana';
    if (status === 'Perlu Ulang') return 'ulang';
    if (status === 'Tidak Lulus') return 'gagal';
    return 'lancar';  // default
}

function renderSurahGrid(surah, progress, setType, dependencyProgress) {
    var surahData = progress.data[surah.no] || {};
    var manualOverrides = progress.manual || {};

    // Use pre-calculated dependency progress (passed as parameter)
    // dependencyProgress contains data from previous set (Sabak Baru for Para Sabak, etc)

    // Count stats
    var filledCount = 0;
    var totalCount = surah.ayat;

    for (var a = 1; a <= surah.ayat; a++) {
        if (surahData[a]) filledCount++;
    }

    var percentage = totalCount > 0 ? Math.round((filledCount / totalCount) * 100) : 0;

    var html = '<div class="progress-surah-section">';

    // Header
    html += '<div class="progress-surah-header">';
    html += '<div>';
    html += '<div class="progress-surah-name">' + surah.no + '. Surah ' + surah.name + '</div>';
    html += '<small style="opacity:0.85;">Juz ' + (surah.juzList ? surah.juzList.join(',') : surah.juz) + ' • ' + totalCount + ' ayat</small>';
    html += '</div>';
    html += '<div class="progress-surah-stats">';
    html += '<span>📊 ' + filledCount + '/' + totalCount + ' (' + percentage + '%)</span>';
    html += '</div>';
    html += '</div>';

    // Grid
    html += '<div class="progress-ayat-grid">';
    for (var a = 1; a <= surah.ayat; a++) {
        var status = surahData[a] || '';
        var statusClass = status ? 'status-' + status : '';

                // Check if locked (untuk paraSabak/mukhtar)
        var isLocked = false;
        if (setType !== 'sabakBaru' && dependencyProgress) {
            var prevData = dependencyProgress.data[surah.no] || {};
            if (!prevData[a]) {
                isLocked = true;
            }
        }

        var manualKey = surah.no + '_' + a;
        var isManual = manualOverrides[manualKey] !== undefined;

        var classes = ['progress-ayat-box'];
        if (statusClass) classes.push(statusClass);
        if (isLocked) classes.push('locked');
        if (isManual) classes.push('manual-override');

        var onclick = isLocked ? '' : 'onclick="cycleProgressBox(' + surah.no + ', ' + a + ')"';
        var title = isLocked ?
            'Locked - hantar di Sabak Baru/Para Sabak dulu' :
            'Ayat ' + a + (status ? ' - ' + getStatusLabel(status) : ' - Klik untuk tukar') + (isManual ? ' (Manual)' : '');

        html += '<div class="' + classes.join(' ') + '" ' + onclick + ' title="' + title + '">' + a + '</div>';
    }
    html += '</div>';

    html += '</div>';

    return html;
}

function getStatusLabel(status) {
    var labels = {
        lancar: 'Lancar 🟢',
        sederhana: 'Sederhana 🟠',
        ulang: 'Perlu Ulang 🔴',
        gagal: 'Tidak Lulus ⚫'
    };
    return labels[status] || '';
}

// ===== CYCLE CLICK =====

function cycleProgressBox(surahNo, ayatNo) {
    if (!currentProgressStudent) return;

    var key = surahNo + '_' + ayatNo;
    var manualKey = 'progress_' + currentProgressStudent + '_' + currentProgressSet;

    if (!appData.progressOverrides) appData.progressOverrides = {};
    if (!appData.progressOverrides[manualKey]) appData.progressOverrides[manualKey] = {};

    // Get current status
    var progress = calculateProgress(currentProgressStudent, currentProgressSet);
    var currentStatus = (progress.data[surahNo] && progress.data[surahNo][ayatNo]) || '';

    // Cycle: empty → lancar → sederhana → ulang → gagal → empty
    var cycle = ['', 'lancar', 'sederhana', 'ulang', 'gagal'];
    var currentIdx = cycle.indexOf(currentStatus);
    var nextIdx = (currentIdx + 1) % cycle.length;
    var nextStatus = cycle[nextIdx];

    if (nextStatus === '') {
        delete appData.progressOverrides[manualKey][key];
    } else {
        appData.progressOverrides[manualKey][key] = nextStatus;
    }

    saveData(appData);

    // Update HANYA box yang diklik (tanpa re-render seluruh page)
    var boxes = document.querySelectorAll('.progress-ayat-box');
    for (var i = 0; i < boxes.length; i++) {
        var box = boxes[i];
        var onclick = box.getAttribute('onclick');
        if (onclick && onclick.indexOf('(' + surahNo + ', ' + ayatNo + ')') > -1) {
            // Remove old status classes
            box.classList.remove('status-lancar', 'status-sederhana', 'status-ulang', 'status-gagal', 'manual-override');

            // Add new status class
            if (nextStatus) {
                box.classList.add('status-' + nextStatus);
                box.classList.add('manual-override');
            }

            // Update title
            var statusLabels = {
                lancar: 'Lancar 🟢',
                sederhana: 'Sederhana 🟠',
                ulang: 'Perlu Ulang 🔴',
                gagal: 'Tidak Lulus ⚫'
            };
            box.title = 'Ayat ' + ayatNo + (nextStatus ? ' - ' + statusLabels[nextStatus] + ' (Manual)' : ' - Klik untuk tukar');

            break;
        }
    }

    // Update stats tanpa scroll
    var progressData = calculateProgress(currentProgressStudent, currentProgressSet);
    renderProgressStats(progressData);
}

// ===== RESET MANUAL =====

function resetProgressManual() {
    if (!currentProgressStudent) {
        showToast('❌ Sila pilih pelajar dahulu');
        return;
    }

    var manualKey = 'progress_' + currentProgressStudent + '_' + currentProgressSet;

    if (!appData.progressOverrides || !appData.progressOverrides[manualKey]) {
        showToast('ℹ️ Tiada manual override untuk reset');
        return;
    }

    var count = Object.keys(appData.progressOverrides[manualKey]).length;

    if (!confirm('Reset ' + count + ' manual override untuk set ini?\n\nProgress akan kembali ikut data records sahaja.')) {
        return;
    }

    delete appData.progressOverrides[manualKey];
    saveData(appData);

    showToast('✅ ' + count + ' manual override direset');
    renderProgressHafazan();
}

// ===== STATS =====

function renderProgressStats(progress) {
    var container = document.getElementById('progressStats');
    if (!container) return;

    var totalAyatAlQuran = 6236;  // Total ayat dalam Al-Quran
    var totalFilled = 0;
    var countLancar = 0, countSederhana = 0, countUlang = 0, countGagal = 0;

    for (var surahNo in progress.data) {
        for (var ayatNo in progress.data[surahNo]) {
            totalFilled++;
            var status = progress.data[surahNo][ayatNo];
            if (status === 'lancar') countLancar++;
            else if (status === 'sederhana') countSederhana++;
            else if (status === 'ulang') countUlang++;
            else if (status === 'gagal') countGagal++;
        }
    }

    var percentage = totalAyatAlQuran > 0 ? ((totalFilled / totalAyatAlQuran) * 100).toFixed(2) : 0;
    var manualCount = Object.keys(progress.manual || {}).length;

    var html = '';

    html += '<div class="stat-card">';
    html += '<div class="stat-icon">📖</div>';
    html += '<div class="stat-info">';
    html += '<h3>' + totalFilled + '</h3>';
    html += '<p>Total Ayat (' + percentage + '%)</p>';
    html += '</div></div>';

    html += '<div class="stat-card">';
    html += '<div class="stat-icon">🟢</div>';
    html += '<div class="stat-info">';
    html += '<h3 style="color:#a78bfa;">' + countLancar + '</h3>';
    html += '<p>Lancar</p>';
    html += '</div></div>';

    html += '<div class="stat-card">';
    html += '<div class="stat-icon">🟠</div>';
    html += '<div class="stat-info">';
    html += '<h3 style="color:#f59e0b;">' + countSederhana + '</h3>';
    html += '<p>Sederhana</p>';
    html += '</div></div>';

    html += '<div class="stat-card">';
    html += '<div class="stat-icon">🔴</div>';
    html += '<div class="stat-info">';
    html += '<h3 style="color:#ef4444;">' + countUlang + '</h3>';
    html += '<p>Perlu Ulang</p>';
    html += '</div></div>';

    html += '<div class="stat-card">';
    html += '<div class="stat-icon">⚫</div>';
    html += '<div class="stat-info">';
    html += '<h3 style="color:#1f2937;">' + countGagal + '</h3>';
    html += '<p>Tidak Lulus</p>';
    html += '</div></div>';

    if (manualCount > 0) {
        html += '<div class="stat-card">';
        html += '<div class="stat-icon">✏️</div>';
        html += '<div class="stat-info">';
        html += '<h3 style="color:#3b82f6;">' + manualCount + '</h3>';
        html += '<p>Manual Override</p>';
        html += '</div></div>';
    }

    container.innerHTML = html;
}

// ===== PRINT =====

function printProgressHafazan() {
    if (!currentProgressStudent) {
        showToast('❌ Sila pilih pelajar dahulu');
        return;
    }

    document.body.classList.add('print-progress');
    setTimeout(function() {
        window.print();
        setTimeout(function() {
            document.body.classList.remove('print-progress');
        }, 500);
    }, 300);
}

// ===== EXPORT CSV =====

function exportProgressCSV() {
    if (!currentProgressStudent) {
        showToast('❌ Sila pilih pelajar dahulu');
        return;
    }

    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === currentProgressStudent) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;

    var setNames = {
        sabakBaru: 'Sabak Baru',
        paraSabak: 'Para Sabak',
        mukhtar: 'Mukhtar'
    };

    var progress = calculateProgress(currentProgressStudent, currentProgressSet);

    var csv = 'Pelajar: ' + student.name + '\n';
    csv += 'Set: ' + setNames[currentProgressSet] + '\n';
    csv += 'Tarikh Export: ' + new Date().toLocaleDateString('ms-MY') + '\n\n';
    csv += 'Surah,Jumlah Ayat,Lancar,Sederhana,Perlu Ulang,Tidak Lulus,Belum,Peratus\n';

    for (var i = 0; i < SURAH_LIST.length; i++) {
        var surah = SURAH_LIST[i];
        var surahData = progress.data[surah.no] || {};

        var lancar = 0, sederhana = 0, ulang = 0, gagal = 0, belum = 0;
        for (var a = 1; a <= surah.ayat; a++) {
            var s = surahData[a];
            if (s === 'lancar') lancar++;
            else if (s === 'sederhana') sederhana++;
            else if (s === 'ulang') ulang++;
            else if (s === 'gagal') gagal++;
            else belum++;
        }

        var filled = lancar + sederhana + ulang + gagal;
        var pct = surah.ayat > 0 ? Math.round((filled / surah.ayat) * 100) : 0;

        csv += '"' + surah.no + '. ' + surah.name + '",';
        csv += surah.ayat + ',';
        csv += lancar + ',';
        csv += sederhana + ',';
        csv += ulang + ',';
        csv += gagal + ',';
        csv += belum + ',';
        csv += pct + '%\n';
    }

    var BOM = '\uFEFF';
    var blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'progress_' + student.name.replace(/\s/g, '_') + '_' + setNames[currentProgressSet].replace(/\s/g, '_') + '.csv';
    link.click();

    showToast('✅ Berjaya export progress');
}

// ============================================
// ===== PROGRESS HAFAZAN FILTERS ============
// ============================================

function filterProgressGrid() {
    var searchVal = (document.getElementById('progressSearchSurah').value || '').toLowerCase().trim();
    var juzFilter = document.getElementById('progressFilterJuz').value;
    var statusFilter = document.getElementById('progressFilterStatus').value;

    var sections = document.querySelectorAll('.progress-surah-section');
    var visibleCount = 0;

    for (var i = 0; i < sections.length; i++) {
        var section = sections[i];
        var surahName = section.querySelector('.progress-surah-name').textContent.toLowerCase();

        // Get surah number from name
        var match = surahName.match(/^(\d+)\.\s*surah\s+(.+)/i);
        var surahNo = match ? parseInt(match[1]) : 0;
        var surahNameOnly = match ? match[2].toLowerCase() : surahName;

        // Get juz from header
        var headerInfo = section.querySelector('.progress-surah-header small');
        var juzText = headerInfo ? headerInfo.textContent : '';
        var juzNumbers = [];
        var juzMatch = juzText.match(/juz\s+([\d,]+)/i);
        if (juzMatch) {
            juzNumbers = juzMatch[1].split(',').map(function(j) { return parseInt(j.trim()); });
        }

        // Apply filters
        var showSearch = true;
        var showJuz = true;
        var showStatus = true;

        // Search filter
        if (searchVal) {
            var matchName = surahNameOnly.indexOf(searchVal) > -1;
            var matchNum = surahNo.toString() === searchVal || surahNo.toString().indexOf(searchVal) === 0;
            showSearch = matchName || matchNum;
        }

        // Juz filter
        if (juzFilter !== 'all') {
            showJuz = juzNumbers.indexOf(parseInt(juzFilter)) > -1;
        }

        // Status filter
        if (statusFilter !== 'all') {
            var stats = section.querySelector('.progress-surah-stats');
            var statsText = stats ? stats.textContent : '';
            var pctMatch = statsText.match(/\((\d+)%\)/);
            var percentage = pctMatch ? parseInt(pctMatch[1]) : 0;
            var filledMatch = statsText.match(/(\d+)\/\d+/);
            var filled = filledMatch ? parseInt(filledMatch[1]) : 0;

            if (statusFilter === 'has-progress') {
                showStatus = filled > 0;
            } else if (statusFilter === 'no-progress') {
                showStatus = filled === 0;
            } else if (statusFilter === 'complete') {
                showStatus = percentage === 100;
            } else if (statusFilter === 'incomplete') {
                showStatus = percentage < 100 && filled > 0;
            }
        }

        // Show/hide
        if (showSearch && showJuz && showStatus) {
            section.style.setProperty('display', 'block', 'important');
            visibleCount++;
        } else {
            section.style.setProperty('display', 'none', 'important');
        }
    }

    // Update count
    var resultsEl = document.getElementById('progressFilterResults');
    if (resultsEl) {
        var totalCount = sections.length;
        if (visibleCount === totalCount) {
            resultsEl.innerHTML = '📖 Menunjukkan <strong>' + visibleCount + '</strong> surah';
            resultsEl.style.background = '#faf5ff';
            resultsEl.style.borderLeftColor = '#a78bfa';
            resultsEl.style.color = '#7c3aed';
        } else if (visibleCount === 0) {
            resultsEl.innerHTML = '❌ Tiada surah ditemui. Cuba kata kunci lain.';
            resultsEl.style.background = '#fef2f2';
            resultsEl.style.borderLeftColor = '#ef4444';
            resultsEl.style.color = '#991b1b';
        } else {
            resultsEl.innerHTML = '🔍 Menunjukkan <strong>' + visibleCount + '</strong> dari ' + totalCount + ' surah';
            resultsEl.style.background = '#dbeafe';
            resultsEl.style.borderLeftColor = '#3b82f6';
            resultsEl.style.color = '#1e40af';
        }
    }

    // Scroll to first visible
    if (visibleCount > 0 && (searchVal || juzFilter !== 'all' || statusFilter !== 'all')) {
        for (var i = 0; i < sections.length; i++) {
            if (sections[i].style.display !== 'none') {
                sections[i].scrollIntoView({ behavior: 'smooth', block: 'start' });
                break;
            }
        }
    }
}

function quickFilterProgress(type) {
    var searchInput = document.getElementById('progressSearchSurah');
    var juzSelect = document.getElementById('progressFilterJuz');
    var statusSelect = document.getElementById('progressFilterStatus');

    // Reset others
    if (searchInput) searchInput.value = '';
    if (statusSelect) statusSelect.value = 'all';

    if (type === 'juz30') {
        if (juzSelect) juzSelect.value = '30';
    } else if (type === 'juz29') {
        if (juzSelect) juzSelect.value = '29';
    } else if (type === 'juz1') {
        if (juzSelect) juzSelect.value = '1';
    } else if (type === 'lazim') {
        // Surah lazim (yang biasa hafaz) - dari surah 100 ke atas
        if (juzSelect) juzSelect.value = 'all';
        if (searchInput) {
            // Show surah Al-'Adiyat (100) hingga An-Nas (114)
            // Guna status filter custom
            showLazimSurah();
            return;
        }
    }

    filterProgressGrid();
}

function showLazimSurah() {
    // Tunjuk surah 100-114 sahaja
    var sections = document.querySelectorAll('.progress-surah-section');
    var visibleCount = 0;

    for (var i = 0; i < sections.length; i++) {
        var section = sections[i];
        var nameEl = section.querySelector('.progress-surah-name');
        var match = nameEl.textContent.match(/^(\d+)\./);
        var surahNo = match ? parseInt(match[1]) : 0;

        if (surahNo >= 100 && surahNo <= 114) {
            section.style.display = '';
            visibleCount++;
        } else {
            section.style.display = 'none';
        }
    }

    var resultsEl = document.getElementById('progressFilterResults');
    if (resultsEl) {
        resultsEl.innerHTML = '🌟 Menunjukkan <strong>' + visibleCount + '</strong> Surah Lazim (Al-Adiyat → An-Nas)';
        resultsEl.style.background = '#fef3c7';
        resultsEl.style.borderLeftColor = '#f59e0b';
        resultsEl.style.color = '#78350f';
    }

    // Scroll to first
    for (var i = 0; i < sections.length; i++) {
        if (sections[i].style.display !== 'none') {
            sections[i].scrollIntoView({ behavior: 'smooth', block: 'start' });
            break;
        }
    }
}

function resetProgressFilters() {
    document.getElementById('progressSearchSurah').value = '';
    document.getElementById('progressFilterJuz').value = 'all';
    document.getElementById('progressFilterStatus').value = 'all';
    filterProgressGrid();
    showToast('🔄 Filter direset');
}

