function editEvent(eventId) {
    var event = null;
    for (var i = 0; i < appData.events.length; i++) {
        if (appData.events[i].id === eventId) {
            event = appData.events[i];
            break;
        }
    }
    if (!event) return;

    editingEventId = eventId;
    document.getElementById('eventFormTitle').textContent = '✏️ Edit Acara';
    document.getElementById('eventEditId').value = eventId;

    document.getElementById('eventTitle').value = event.title || '';
    document.getElementById('eventDesc').value = event.description || '';
    document.getElementById('eventLocation').value = event.location || '';
    document.getElementById('eventCategory').value = event.category || '';
    document.getElementById('eventColor').value = event.color || '';
    document.getElementById('eventFeatured').checked = event.featured || false;
    document.getElementById('eventStatus').value = event.status || 'active';
    document.getElementById('featuredFields').style.display = event.featured ? 'block' : 'none';
    document.getElementById('eventIcon').value = event.icon || '';
    document.getElementById('eventWAMessage').value = event.waMessage || '';

    // Handle date type
    if (event.dateEnd && event.dateEnd !== event.date) {
        var rangeRadio = document.querySelector('input[name="eventDateType"][value="range"]');
        if (rangeRadio) rangeRadio.checked = true;
        document.getElementById('eventDateStart').value = event.date || '';
        document.getElementById('eventDateEnd').value = event.dateEnd || '';
        document.getElementById('eventTimeRange').value = event.time || '';
    } else {
        var singleRadio = document.querySelector('input[name="eventDateType"][value="single"]');
        if (singleRadio) singleRadio.checked = true;
        document.getElementById('eventDate').value = event.date || '';
        document.getElementById('eventTime').value = event.time || '';
    }
    toggleEventDateType();

            // 🍱 RESTORE INFAQ SLOT CHECKBOXES
    var autoBlockEl = document.getElementById('eventAutoBlockInfaq');
    if (autoBlockEl) {
        autoBlockEl.checked = event.autoBlockInfaq || false;
        toggleInfaqSlots(); // Show/hide wrapper + update visual

        var slots = event.infaqSlots || [];
        var slotMap = [
            { key: 'sarapan', id: 'infaqSlotSarapan' },
            { key: 'tengahari', id: 'infaqSlotTengahHari' },
            { key: 'minumpetang', id: 'infaqSlotMinumPetang' },
            { key: 'malam', id: 'infaqSlotMalam' }
        ];
        slotMap.forEach(function(item) {
            var cb = document.getElementById(item.id);
            var btn = document.querySelector('.infaq-slot-btn[data-slot="' + item.key + '"]');
            var isChecked = slots.indexOf(item.key) !== -1;
            if (cb) cb.checked = isChecked;
            if (btn) {
                var iconEl = btn.querySelector('.slot-check-icon');
                if (isChecked) {
                    btn.style.background = '#dcfce7';
                    btn.style.borderColor = '#16a34a';
                    if (iconEl) iconEl.style.background = '#16a34a';
                } else {
                    btn.style.background = '#f0fdf4';
                    btn.style.borderColor = '#d1fae5';
                    if (iconEl) iconEl.style.background = '#e2e8f0';
                }
            }
        });
    }

    document.getElementById('eventFormModal').classList.remove('hidden');
}

function closeEventForm() {
    document.getElementById('eventFormModal').classList.add('hidden');
    editingEventId = null;
}

function saveEvent(e) {
    e.preventDefault();

    if (!appData.events) appData.events = [];

    // Get date type
    var dateTypeEl = document.querySelector('input[name="eventDateType"]:checked');
    var dateType = dateTypeEl ? dateTypeEl.value : 'single';

    var eventDate, eventDateEnd, eventTime;

    if (dateType === 'range') {
        eventDate = document.getElementById('eventDateStart').value;
        eventDateEnd = document.getElementById('eventDateEnd').value;
        eventTime = document.getElementById('eventTimeRange').value.trim();

        if (!eventDate || !eventDateEnd) {
            showToast('❌ Sila isi tarikh mula dan tamat');
            return;
        }
        if (new Date(eventDateEnd) < new Date(eventDate)) {
            showToast('❌ Tarikh tamat mesti selepas tarikh mula');
            return;
        }
    } else {
        eventDate = document.getElementById('eventDate').value;
        eventDateEnd = eventDate;
        eventTime = document.getElementById('eventTime').value.trim();

        if (!eventDate) {
            showToast('❌ Sila pilih tarikh');
            return;
        }
    }

    // 🍱 GET INFAQ SLOT DATA
    var autoBlockInfaq = document.getElementById('eventAutoBlockInfaq') 
        ? document.getElementById('eventAutoBlockInfaq').checked 
        : false;
    
    var infaqSlots = [];
    if (autoBlockInfaq) {
        if (document.getElementById('infaqSlotSarapan').checked) infaqSlots.push('sarapan');
if (document.getElementById('infaqSlotTengahHari').checked) infaqSlots.push('tengahari');
if (document.getElementById('infaqSlotMinumPetang').checked) infaqSlots.push('minumpetang');
if (document.getElementById('infaqSlotMalam').checked) infaqSlots.push('malam');
        
        if (infaqSlots.length === 0) {
            showToast('❌ Sila pilih sekurang-kurangnya 1 slot infaq atau matikan auto-block');
            return;
        }
    }

    var eventData = {
        id: editingEventId || 'EVT' + Date.now(),
        title: document.getElementById('eventTitle').value.trim(),
        description: document.getElementById('eventDesc').value.trim(),
        date: eventDate,
        dateEnd: eventDateEnd,
        dateType: dateType,
        time: eventTime,
        location: document.getElementById('eventLocation').value.trim(),
        category: document.getElementById('eventCategory').value,
        color: document.getElementById('eventColor').value,
        featured: document.getElementById('eventFeatured').checked,
        icon: document.getElementById('eventIcon').value.trim(),
        waMessage: document.getElementById('eventWAMessage').value.trim(),
        status: document.getElementById('eventStatus').value,
        // 🍱 NEW INFAQ FIELDS
        autoBlockInfaq: autoBlockInfaq,
        infaqSlots: infaqSlots,
        updatedAt: new Date().toISOString()
    };

    if (!eventData.createdAt) {
        eventData.createdAt = new Date().toISOString();
    }

    // If featured, unfeature others
    if (eventData.featured) {
        for (var i = 0; i < appData.events.length; i++) {
            if (appData.events[i].id !== editingEventId) {
                appData.events[i] = false;
                appData.events[i].featured = false;
            }
        }
    }

    // 🍱 CLEAR OLD INFAQ SLOTS (kalau edit event)
    var oldEvent = null;
    if (editingEventId) {
        for (var i = 0; i < appData.events.length; i++) {
            if (appData.events[i].id === editingEventId) {
                oldEvent = appData.events[i];
                break;
            }
        }
        if (oldEvent && oldEvent.autoBlockInfaq && oldEvent.infaqSlots && oldEvent.infaqSlots.length > 0) {
            clearInfaqSlotsFromEvent(oldEvent);
        }
    }

    // Save/update event
    if (editingEventId) {
        for (var i = 0; i < appData.events.length; i++) {
            if (appData.events[i].id === editingEventId) {
                appData.events[i] = eventData;
                break;
            }
        }
        showToast('✅ Acara dikemas kini');
    } else {
        appData.events.push(eventData);
        showToast('✅ Acara baru ditambah');
    }

    // 🍱 AUTO-WRITE INFAQ SLOTS (kalau ada)
    if (autoBlockInfaq && infaqSlots.length > 0) {
        writeInfaqSlotsFromEvent(eventData);
    }

    saveData(appData);
    closeEventForm();
    renderEventsList();
    updateEventsStats();
}

// 🍱 Helper: Get semua tarikh dalam range (YYYY-MM-DD format)
function getDatesInRange(startDate, endDate) {
    var dates = [];
    var current = new Date(startDate);
    var end = new Date(endDate);
    while (current <= end) {
        var y = current.getFullYear();
        var m = String(current.getMonth() + 1).padStart(2, '0');
        var d = String(current.getDate()).padStart(2, '0');
        dates.push(y + '-' + m + '-' + d);
        current.setDate(current.getDate() + 1);
    }
    return dates;
}

// 🍱 Helper: Write infaq slots dari event ke Firebase
function writeInfaqSlotsFromEvent(event) {
    if (!event || !event.autoBlockInfaq || !event.infaqSlots || event.infaqSlots.length === 0) return;
    if (!firebase || !firebase.database) {
        console.warn('Firebase tak tersedia untuk write infaq');
        return;
    }

    var dates = getDatesInRange(event.date, event.dateEnd || event.date);
    var db = firebase.database();
    var totalSlots = dates.length * event.infaqSlots.length;
    var checkedCount = 0;
    var skippedSlots = [];

    dates.forEach(function(dateKey) {
        event.infaqSlots.forEach(function(slot) {
            var infaqKey = dateKey + '_' + slot;

            // 🛡️ SEMAK DULU sebelum tulis - jangan overwrite penaja sebenar
            db.ref('infaq/' + infaqKey).once('value').then(function(snap) {
                var existing = snap.val();

                // Boleh tulis kalau: slot kosong ATAU slot ni memang dari event ini sendiri (edit semula)
                var isEmpty = !existing;
                var isSameEventSlot = existing && existing.source === 'takwim' && existing.eventId === event.id;

                if (isEmpty || isSameEventSlot) {
                    var infaqData = {
                        dateKey: dateKey,
                        slot: slot,
                        status: 'SPONSORED',
                        sponsorName: event.title,
                        sponsorPhone: '',
                        sponsorNote: 'Dari Takwim: ' + event.title,
                        source: 'takwim',
                        eventId: event.id,
                        createdAt: new Date().toISOString(),
                        confirmedAt: new Date().toISOString()
                    };
                    db.ref('infaq/' + infaqKey).set(infaqData).catch(function(err) {
                        console.error('Error write infaq ' + infaqKey, err);
                    });
                } else {
                    // ⚠️ Slot dah ada penaja sebenar (pending/confirmed) - JANGAN overwrite
                    skippedSlots.push(dateKey + ' (' + slot + ')');
                    console.warn('⚠️ Slot ' + infaqKey + ' dah ditaja, auto-block dilangkau:', existing);
                }
            }).catch(function(err) {
                console.error('Error check infaq ' + infaqKey, err);
            }).finally(function() {
                checkedCount++;
                if (checkedCount === totalSlots) {
                    console.log('✅ Auto-block selesai: ' + (totalSlots - skippedSlots.length) + ' slot ditulis, ' + skippedSlots.length + ' slot dilangkau (dah ditaja).');
                    if (skippedSlots.length > 0 && typeof showToast === 'function') {
                        showToast('⚠️ ' + skippedSlots.length + ' slot infaq SUDAH ditaja - auto-block dilangkau untuk slot tu, rekod penaja sedia ada dikekalkan.');
                    }
                }
            });
        });
    });
}
// 🍱 Helper: Clear infaq slots yang berkaitan dengan event
function clearInfaqSlotsFromEvent(event) {
    if (!event || !event.infaqSlots || event.infaqSlots.length === 0) return;
    if (!firebase || !firebase.database) return;

    var dates = getDatesInRange(event.date, event.dateEnd || event.date);
    var db = firebase.database();

    dates.forEach(function(dateKey) {
        event.infaqSlots.forEach(function(slot) {
            var infaqKey = dateKey + '_' + slot;
            // Hanya remove kalau source = takwim & eventId sama
            db.ref('infaq/' + infaqKey).once('value').then(function(snap) {
                var data = snap.val();
                if (data && data.source === 'takwim' && data.eventId === event.id) {
                    db.ref('infaq/' + infaqKey).remove();
                }
            }).catch(function(err) {
                console.error('Error clear infaq ' + infaqKey, err);
            });
        });
    });
}

function deleteEvent(eventId) {
    var event = null;
    for (var i = 0; i < appData.events.length; i++) {
        if (appData.events[i].id === eventId) {
            event = appData.events[i];
            break;
        }
    }
    if (!event) return;

    // 🍱 Check if event ada infaq slots yang di-block
    var confirmMsg = 'Padam acara "' + event.title + '"?\n\nTindakan ini tidak boleh diundo!';
    if (event.autoBlockInfaq && event.infaqSlots && event.infaqSlots.length > 0) {
        confirmMsg += '\n\n⚠️ ' + event.infaqSlots.length + ' slot infaq akan dilepaskan (boleh ditaja semula).';
    }
    if (!confirm(confirmMsg)) return;

    // 🍱 CLEAR INFAQ SLOTS berkaitan sebelum padam event
    if (event.autoBlockInfaq && event.infaqSlots && event.infaqSlots.length > 0) {
        clearInfaqSlotsFromEvent(event);
    }

    var newEvents = [];
    for (var i = 0; i < appData.events.length; i++) {
        if (appData.events[i].id !== eventId) {
            newEvents.push(appData.events[i]);
        }
    }
    appData.events = newEvents;

    saveData(appData);
    showToast('🗑 Acara dipadam');
    renderEventsList();
    updateEventsStats();
}

function toggleEventStatus(eventId) {
    for (var i = 0; i < appData.events.length; i++) {
        if (appData.events[i].id === eventId) {
            appData.events[i].status = appData.events[i].status === 'active' ? 'hidden' : 'active';
            saveData(appData);
            renderEventsList();
            showToast(appData.events[i].status === 'active' ? '✅ Acara dipaparkan' : '🚫 Acara disembunyikan');
            return;
        }
    }
}

function toggleEventFeatured(eventId) {
    var targetEvent = null;
    for (var i = 0; i < appData.events.length; i++) {
        if (appData.events[i].id === eventId) {
            targetEvent = appData.events[i];
            break;
        }
    }
    if (!targetEvent) return;

    // Unfeature all first
    if (!targetEvent.featured) {
        for (var i = 0; i < appData.events.length; i++) {
            appData.events[i].featured = false;
        }
    }

    // Toggle current
    targetEvent.featured = !targetEvent.featured;

    saveData(appData);
    renderEventsList();
    updateEventsStats();
    showToast(targetEvent.featured ? '⭐ Acara di-feature' : '✅ Featured dibuang');
}

function renderEventsList() {
    var container = document.getElementById('eventsList');
    if (!container) return;

    if (!appData.events || appData.events.length === 0) {
        container.innerHTML = '<div class="empty-state" style="padding:40px;">' +
            '<div class="empty-icon">📅</div>' +
            '<p>Belum ada acara</p>' +
            '<small>Klik "Tambah Acara Baru" untuk mula</small>' +
            '</div>';
        return;
    }

    var filter = document.getElementById('eventsFilter').value;
    var today = new Date().toISOString().split('T')[0];

    var filtered = appData.events.slice();

    if (filter === 'upcoming') {
        filtered = filtered.filter(function(e) { return e.date >= today; });
    } else if (filter === 'past') {
        filtered = filtered.filter(function(e) { return e.date < today; });
    } else if (filter === 'featured') {
        filtered = filtered.filter(function(e) { return e.featured; });
    }

    // Sort by date (newest upcoming first)
    filtered.sort(function(a, b) {
        return new Date(a.date) - new Date(b.date);
    });

    if (filtered.length === 0) {
        container.innerHTML = '<div class="empty-state" style="padding:40px;">' +
            '<div class="empty-icon">🔍</div>' +
            '<p>Tiada acara untuk filter ini</p>' +
            '</div>';
        return;
    }

    var months = ['Jan', 'Feb', 'Mac', 'Apr', 'Mei', 'Jun', 'Jul', 'Ogo', 'Sep', 'Okt', 'Nov', 'Dis'];

    var categories = {
        class: '📚 Kelas',
        event: '🎉 Majlis',
        activity: '🌟 Aktiviti',
        meeting: '👨‍👩‍👧 Perjumpaan',
        holiday: '🏖️ Cuti',
        special: '⭐ Sambutan'
    };

    var colors = {
        purple: '#8b5cf6',
        blue: '#3b82f6',
        orange: '#f97316',
        green: '#a78bfa',
        red: '#ef4444',
        gold: '#fbbf24'
    };

    var html = '';

    for (var i = 0; i < filtered.length; i++) {
    var event = filtered[i];
    var d = new Date(event.date);
    var dEnd = event.dateEnd ? new Date(event.dateEnd) : d;
    var isRange = event.dateEnd && event.dateEnd !== event.date;
    var isPast = event.date < today;
    var bgColor = colors[event.color] || '#a78bfa';

    html += '<div style="background:white;border:2px solid ' + (event.featured ? '#fbbf24' : '#e2e8f0') + ';border-radius:14px;padding:20px;margin-bottom:12px;display:flex;gap:20px;align-items:flex-start;flex-wrap:wrap;' + (event.status === 'hidden' ? 'opacity:0.5;' : '') + (isPast ? 'background:#f8fafc;' : '') + '">';

    // Date Badge
    html += '<div style="background:' + bgColor + ';color:white;padding:15px 20px;border-radius:12px;text-align:center;min-width:80px;flex-shrink:0;">';

    if (isRange) {
        // Range display
        var sameMonth = d.getMonth() === dEnd.getMonth();
        var sameYear = d.getFullYear() === dEnd.getFullYear();

        if (sameMonth && sameYear) {
            html += '<div style="font-size:1.3rem;font-weight:900;line-height:1;">' + d.getDate() + '-' + dEnd.getDate() + '</div>';
            html += '<div style="font-size:0.75rem;font-weight:700;text-transform:uppercase;margin-top:4px;">' + months[d.getMonth()] + '</div>';
            html += '<div style="font-size:0.7rem;opacity:0.8;margin-top:2px;">' + d.getFullYear() + '</div>';
        } else {
            html += '<div style="font-size:1rem;font-weight:900;line-height:1.2;">' + d.getDate() + ' ' + months[d.getMonth()] + '</div>';
            html += '<div style="font-size:0.7rem;margin:3px 0;">↓</div>';
            html += '<div style="font-size:1rem;font-weight:900;line-height:1.2;">' + dEnd.getDate() + ' ' + months[dEnd.getMonth()] + '</div>';
            html += '<div style="font-size:0.65rem;opacity:0.8;margin-top:2px;">' + d.getFullYear() + '</div>';
        }
    } else {
        // Single date
        html += '<div style="font-size:1.8rem;font-weight:900;line-height:1;">' + d.getDate() + '</div>';
        html += '<div style="font-size:0.75rem;font-weight:700;text-transform:uppercase;margin-top:4px;">' + months[d.getMonth()] + '</div>';
        html += '<div style="font-size:0.7rem;opacity:0.8;margin-top:2px;">' + d.getFullYear() + '</div>';
    }

    html += '</div>';

    // Content
    html += '<div style="flex:1;min-width:250px;">';

    // Badges
    html += '<div style="display:flex;gap:6px;margin-bottom:8px;flex-wrap:wrap;">';
    if (event.featured) {
        html += '<span style="background:linear-gradient(135deg,#fbbf24,#f59e0b);color:#1f2937;padding:3px 10px;border-radius:12px;font-size:0.72rem;font-weight:800;">⭐ FEATURED</span>';
    }
    html += '<span style="background:#faf5ff;color:#7c3aed;padding:3px 10px;border-radius:12px;font-size:0.72rem;font-weight:700;">' + (categories[event.category] || event.category) + '</span>';
    if (isRange) {
        var daysDiff = Math.ceil((dEnd - d) / (1000 * 60 * 60 * 24)) + 1;
        html += '<span style="background:#dbeafe;color:#1e40af;padding:3px 10px;border-radius:12px;font-size:0.72rem;font-weight:700;">📆 ' + daysDiff + ' Hari</span>';
    }
    if (event.status === 'hidden') {
        html += '<span style="background:#fee2e2;color:#991b1b;padding:3px 10px;border-radius:12px;font-size:0.72rem;font-weight:700;">🚫 TERSEMBUNYI</span>';
    }
    if (isPast) {
        html += '<span style="background:#f1f5f9;color:#64748b;padding:3px 10px;border-radius:12px;font-size:0.72rem;font-weight:700;">📜 SELESAI</span>';
    }
    html += '</div>';

    // Title
    html += '<h4 style="margin:0 0 5px;color:#1f2937;font-size:1.1rem;">' + event.title + '</h4>';

    // Description
    html += '<p style="margin:0 0 10px;color:#64748b;font-size:0.88rem;line-height:1.5;">' + event.description + '</p>';

    // Meta info
    html += '<div style="display:flex;gap:15px;font-size:0.82rem;color:#475569;flex-wrap:wrap;">';
    if (event.time) html += '<span>🕐 ' + event.time + '</span>';
    if (event.location) html += '<span>📍 ' + event.location + '</span>';
    if (isRange) {
        html += '<span>📅 ' + formatDate(event.date) + ' → ' + formatDate(event.dateEnd) + '</span>';
    }
    html += '</div>';

    html += '</div>';

    // Actions
    html += '<div style="display:flex;flex-direction:column;gap:6px;">';
    html += '<button onclick="editEvent(\'' + event.id + '\')" style="background:#3b82f6;color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.82rem;">✏️ Edit</button>';
    html += '<button onclick="toggleEventFeatured(\'' + event.id + '\')" style="background:' + (event.featured ? '#fbbf24' : '#94a3b8') + ';color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.82rem;">' + (event.featured ? '⭐ Featured' : '☆ Feature') + '</button>';
    html += '<button onclick="toggleEventStatus(\'' + event.id + '\')" style="background:' + (event.status === 'active' ? '#a78bfa' : '#ef4444') + ';color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.82rem;">' + (event.status === 'active' ? '👁 Aktif' : '🚫 Hidden') + '</button>';
    html += '<button onclick="deleteEvent(\'' + event.id + '\')" style="background:#ef4444;color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.82rem;">🗑 Padam</button>';
    html += '</div>';

    html += '</div>';
}

    container.innerHTML = html;
}

// Auto-init bila switch ke tab events
var originalSwitchTabEvents = window.switchTab;
window.switchTab = function(tabName, btn) {
    if (typeof originalSwitchTabEvents === 'function') {
        originalSwitchTabEvents(tabName, btn);
    }

    if (tabName === 'manageEvents' && typeof initManageEvents === 'function') {
        initManageEvents();
    }
};

// ============================================
// ===== CALENDAR VIEW ========================
// ============================================

var currentCalDate = new Date();
var currentCalSelectedDate = null;

function switchEventView(view, btn) {
    var calendar = document.getElementById('calendarView');
    var list = document.getElementById('listView');
    var btns = document.querySelectorAll('.view-btn');

    for (var i = 0; i < btns.length; i++) {
        btns[i].classList.remove('active');
    }
    if (btn) btn.classList.add('active');

    if (view === 'calendar') {
        calendar.classList.add('active');
        list.classList.remove('active');
        renderCalendar();
    } else {
        calendar.classList.remove('active');
        list.classList.add('active');
        renderEventsList();
    }
}

function renderCalendar() {
    var year = currentCalDate.getFullYear();
    var month = currentCalDate.getMonth();

    var months = ['Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                  'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];

    document.getElementById('calMonthYear').textContent = months[month] + ' ' + year;

    var firstDay = new Date(year, month, 1);
    var lastDay = new Date(year, month + 1, 0);
    var totalDays = lastDay.getDate();
    var startWeekday = firstDay.getDay();

    var today = new Date();
    var todayStr = today.toISOString().split('T')[0];

    // Get events for this month (including range events)
var eventsByDate = {};
if (appData.events) {
    for (var i = 0; i < appData.events.length; i++) {
        var event = appData.events[i];
        if (event.status === 'hidden') continue;

        var eventStart = new Date(event.date);
        var eventEnd = event.dateEnd ? new Date(event.dateEnd) : eventStart;

        // Loop through each day in the range
        var current = new Date(eventStart);
        current.setHours(0, 0, 0, 0);
        eventEnd.setHours(0, 0, 0, 0);

        while (current <= eventEnd) {
            if (current.getFullYear() === year && current.getMonth() === month) {
                var dateKey = current.getFullYear() + '-' +
                              String(current.getMonth() + 1).padStart(2, '0') + '-' +
                              String(current.getDate()).padStart(2, '0');
                if (!eventsByDate[dateKey]) eventsByDate[dateKey] = [];
                eventsByDate[dateKey].push(event);
            }
            current.setDate(current.getDate() + 1);
        }
    }
}

    var html = '';

    // Previous month padding
    var prevMonthLastDay = new Date(year, month, 0).getDate();
    for (var i = startWeekday - 1; i >= 0; i--) {
        var prevDay = prevMonthLastDay - i;
        html += '<div class="cal-day empty other-month">';
        html += '<div class="cal-day-number">' + prevDay + '</div>';
        html += '</div>';
    }

    // Current month days
    for (var day = 1; day <= totalDays; day++) {
        var dateStr = year + '-' + String(month + 1).padStart(2, '0') + '-' + String(day).padStart(2, '0');
        var date = new Date(year, month, day);
        var dayOfWeek = date.getDay();
        var isToday = dateStr === todayStr;
        var isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
        var dayEvents = eventsByDate[dateStr] || [];

        var classes = ['cal-day'];
        if (isToday) classes.push('today');
        if (isWeekend) classes.push('weekend');

        html += '<div class="' + classes.join(' ') + '" onclick="openDayEvents(\'' + dateStr + '\')">';
        html += '<div class="cal-day-number">' + day + '</div>';
        html += '<div class="cal-day-events">';

        // Show max 3 events
var maxShow = 3;
for (var i = 0; i < Math.min(dayEvents.length, maxShow); i++) {
    var e = dayEvents[i];
    var color = e.color || 'green';
    var featuredClass = e.featured ? ' featured' : '';

    // BARU: Better tooltip dengan masa & lokasi
    var tooltipText = e.title;
    if (e.time) tooltipText += ' • ' + e.time;
    if (e.location) tooltipText += ' • 📍 ' + e.location;

    html += '<div class="cal-event color-' + color + featuredClass + '" onclick="event.stopPropagation(); editEvent(\'' + e.id + '\')" title="' + tooltipText.replace(/"/g, '&quot;') + '">';
    html += (e.featured ? '⭐ ' : '') + e.title;
    html += '</div>';
}

if (dayEvents.length > maxShow) {
    html += '<div class="cal-event-more" onclick="event.stopPropagation(); openDayEvents(\'' + dateStr + '\')">+' + (dayEvents.length - maxShow) + ' lagi</div>';
}

        html += '</div></div>';
    }

    // Next month padding
    var totalCells = startWeekday + totalDays;
    var remaining = 42 - totalCells; // 6 rows × 7 days
    if (remaining > 7) remaining -= 7;

    for (var i = 1; i <= remaining; i++) {
        html += '<div class="cal-day empty other-month">';
        html += '<div class="cal-day-number">' + i + '</div>';
        html += '</div>';
    }

    var grid = document.getElementById('calGrid');
    grid.innerHTML = html;

    // FORCE GRID dengan inline style
    grid.style.cssText = 'display: grid !important; grid-template-columns: repeat(7, minmax(0, 1fr)) !important; gap: 6px !important; width: 100% !important; max-width: 100% !important; box-sizing: border-box !important;';

    // Force weekdays sama
    var weekdays = document.querySelector('#tab-manageEvents .cal-weekdays');
    if (weekdays) {
        weekdays.style.cssText = 'display: grid !important; grid-template-columns: repeat(7, minmax(0, 1fr)) !important; gap: 6px !important; width: 100% !important; max-width: 100% !important; box-sizing: border-box !important; margin-bottom: 8px !important;';
    }

    // Force calendar container
    var calContainer = document.querySelector('#tab-manageEvents .calendar-container');
    if (calContainer) {
        calContainer.style.cssText = 'width: 100% !important; padding: 20px !important; box-sizing: border-box !important;';
    }

    // Force setiap cell
    var cells = grid.children;
    for (var c = 0; c < cells.length; c++) {
        cells[c].style.cssText += '; width: 100% !important; min-width: 0 !important; max-width: 100% !important; box-sizing: border-box !important;';
    }
}

function changeMonth(direction) {
    currentCalDate.setMonth(currentCalDate.getMonth() + direction);
    renderCalendar();
}

function goToToday() {
    currentCalDate = new Date();
    renderCalendar();
}

// ===== DAY EVENTS MODAL =====

function openDayEvents(dateStr) {
    currentCalSelectedDate = dateStr;

    var dayEvents = [];
    if (appData.events) {
        for (var i = 0; i < appData.events.length; i++) {
            if (appData.events[i].date === dateStr && appData.events[i].status !== 'hidden') {
                dayEvents.push(appData.events[i]);
            }
        }
    }

    var d = new Date(dateStr);
    var months = ['Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                  'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    var days = ['Ahad', 'Isnin', 'Selasa', 'Rabu', 'Khamis', 'Jumaat', 'Sabtu'];

    var dateDisplay = days[d.getDay()] + ', ' + d.getDate() + ' ' + months[d.getMonth()] + ' ' + d.getFullYear();

    document.getElementById('dayEventsTitle').textContent = '📅 ' + dateDisplay;

    var listContainer = document.getElementById('dayEventsList');

    if (dayEvents.length === 0) {
        listContainer.innerHTML = '<div class="empty-state" style="padding:30px;">' +
            '<div class="empty-icon">📭</div>' +
            '<p>Tiada acara pada tarikh ini</p>' +
            '<small>Klik butang di bawah untuk tambah</small>' +
            '</div>';
    } else {
        var categories = {
            class: '📚 Kelas',
            event: '🎉 Majlis',
            activity: '🌟 Aktiviti',
            meeting: '👨‍👩‍👧 Perjumpaan',
            holiday: '🏖️ Cuti',
            special: '⭐ Sambutan'
        };

        var colors = {
            purple: '#8b5cf6',
            blue: '#3b82f6',
            orange: '#f97316',
            green: '#a78bfa',
            red: '#ef4444',
            gold: '#fbbf24'
        };

        var html = '';
        for (var i = 0; i < dayEvents.length; i++) {
            var event = dayEvents[i];
            var color = colors[event.color] || '#a78bfa';

            html += '<div class="day-event-card">';
            html += '<div class="day-event-color" style="background:' + color + ';"></div>';
            html += '<div class="day-event-content">';

            if (event.featured) {
                html += '<span style="background:linear-gradient(135deg,#fbbf24,#f59e0b);color:#1f2937;padding:2px 8px;border-radius:10px;font-size:0.7rem;font-weight:800;margin-right:6px;">⭐ FEATURED</span>';
            }
            html += '<span style="background:#faf5ff;color:#7c3aed;padding:2px 8px;border-radius:10px;font-size:0.7rem;font-weight:700;">' + (categories[event.category] || event.category) + '</span>';

            html += '<h4 class="day-event-title" style="margin-top:8px;">' + event.title + '</h4>';
            html += '<p class="day-event-desc">' + event.description + '</p>';
            html += '<div class="day-event-meta">';
            if (event.time) html += '<span>🕐 ' + event.time + '</span>';
            if (event.location) html += '<span>📍 ' + event.location + '</span>';
            html += '</div>';
            html += '</div>';

            html += '<div class="day-event-actions">';
            html += '<button onclick="editEvent(\'' + event.id + '\'); closeDayEvents();" style="background:#3b82f6;color:white;">✏️ Edit</button>';
            html += '<button onclick="deleteEvent(\'' + event.id + '\'); closeDayEvents();" style="background:#ef4444;color:white;">🗑 Padam</button>';
            html += '</div>';

            html += '</div>';
        }

        listContainer.innerHTML = html;
    }

    document.getElementById('dayEventsModal').classList.remove('hidden');
}

function closeDayEvents() {
    document.getElementById('dayEventsModal').classList.add('hidden');
}

function addEventForDay() {
    closeDayEvents();
    openEventForm();
    // Pre-fill date
    setTimeout(function() {
        if (currentCalSelectedDate) {
            document.getElementById('eventDate').value = currentCalSelectedDate;
        }
    }, 100);
}

// Update saveEvent to refresh calendar
var originalSaveEvent = window.saveEvent;
window.saveEvent = function(e) {
    if (typeof originalSaveEvent === 'function') {
        originalSaveEvent(e);
    }
    setTimeout(function() {
        if (document.getElementById('calendarView').classList.contains('active')) {
            renderCalendar();
        }
    }, 100);
};

// Update deleteEvent to refresh calendar
var originalDeleteEvent = window.deleteEvent;
window.deleteEvent = function(eventId) {
    if (typeof originalDeleteEvent === 'function') {
        originalDeleteEvent(eventId);
    }
    setTimeout(function() {
        if (document.getElementById('calendarView').classList.contains('active')) {
            renderCalendar();
        }
    }, 100);
};

