// Initialize web content
function initWebContent() {
    if (!appData.siteContent) {
        appData.siteContent = getDefaultSiteContent();
        saveData(appData);
    }
    updateWebContentStats();
}

// Update stats
function updateWebContentStats() {
    if (!appData.siteContent) return;

    var content = appData.siteContent;
    var sections = Object.keys(content).filter(function(k) {
        return k !== 'lastUpdated';
    });

    var totalEl = document.getElementById('contentTotal');
    if (totalEl) totalEl.textContent = sections.length;

    // Count edited sections (sections with non-default content)
    var editedCount = 0;
    var defaults = getDefaultSiteContent();

    for (var i = 0; i < sections.length; i++) {
        var key = sections[i];
        if (content[key] && JSON.stringify(content[key]) !== JSON.stringify(defaults[key])) {
            editedCount++;
        }
    }

    var editedEl = document.getElementById('contentEdited');
    if (editedEl) editedEl.textContent = editedCount;

    // Last update
    var lastUpdateEl = document.getElementById('contentLastUpdate');
    if (lastUpdateEl) {
        if (content.lastUpdated) {
            var d = new Date(content.lastUpdated);
            var months = ['Jan', 'Feb', 'Mac', 'Apr', 'Mei', 'Jun', 'Jul', 'Ogo', 'Sep', 'Okt', 'Nov', 'Dis'];
            lastUpdateEl.textContent = d.getDate() + ' ' + months[d.getMonth()];
        } else {
            lastUpdateEl.textContent = '-';
        }
    }

    // Firebase status
    var syncEl = document.getElementById('contentSyncStatus');
    if (syncEl) {
        syncEl.textContent = (typeof firebaseReady !== 'undefined' && firebaseReady) ? 'Synced' : 'Offline';
        syncEl.style.color = (typeof firebaseReady !== 'undefined' && firebaseReady) ? '#a78bfa' : '#ef4444';
    }
}

// Switch sub-tab
function switchWebContentTab(section, btn) {
    // Hide all
    var contents = document.querySelectorAll('.wc-content');
    for (var i = 0; i < contents.length; i++) {
        contents[i].classList.remove('active');
    }

    // Remove active from all buttons
    var btns = document.querySelectorAll('.wc-tab-btn');
    for (var i = 0; i < btns.length; i++) {
        btns[i].classList.remove('active');
    }

    // Show selected
    var target = document.getElementById('wc-' + section);
    if (target) target.classList.add('active');

    if (btn) btn.classList.add('active');

    // Call init function if exists
    var initFunc = window['initWC_' + section];
    if (typeof initFunc === 'function') {
        initFunc();
    }
}

// Save content to Firebase
function saveSiteContent() {
    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();

    appData.siteContent.lastUpdated = new Date().toISOString();
    saveData(appData);

    showToast('✅ Content disimpan & sync ke website');
    updateWebContentStats();
}

// Auto-init when tab clicked
var originalSwitchTabWebContent = window.switchTab;
window.switchTab = function(tabName, btn) {
    if (typeof originalSwitchTabWebContent === 'function') {
        originalSwitchTabWebContent(tabName, btn);
    }

    if (tabName === 'webContent' && typeof initWebContent === 'function') {
        initWebContent();
    }
};

