var editingTeamMemberId = null;

function initWC_team() {
    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.team) {
        appData.siteContent.team = {
            badge: 'Pasukan Kami',
            title: 'Diajar Oleh Ustaz',
            subtitle: 'Pengajar berpengalaman',
            members: []
        };
    }

    renderTeamMembersList();
}

function renderTeamMembersList() {
    var container = document.getElementById('teamMembersList');
    if (!container) return;

    var members = (appData.siteContent && appData.siteContent.team && appData.siteContent.team.members) || [];

    if (members.length === 0) {
        container.innerHTML =
            '<div class="wc-empty-state">' +
            '<div class="wc-empty-state-icon">👨‍🏫</div>' +
            '<p>Belum ada ahli team</p>' +
            '<small>Klik "Tambah Ahli" untuk mula</small>' +
            '</div>';
        return;
    }

    // Sort: featured first, then by createdAt
    members.sort(function(a, b) {
        if (a.featured && !b.featured) return -1;
        if (!a.featured && b.featured) return 1;
        return 0;
    });

    var html = '';
    for (var i = 0; i < members.length; i++) {
        var m = members[i];
        var featuredClass = m.featured ? ' featured' : '';
        var statusBadge = m.status === 'hidden'
            ? '<span class="wc-status-badge wc-status-hidden">🚫 Hidden</span>'
            : '<span class="wc-status-badge wc-status-active">✅ Active</span>';

        var featuredBadge = m.featured
            ? '<span class="wc-status-badge wc-status-featured">👑 MUDIR</span>'
            : '';

        html += '<div class="team-member-card' + featuredClass + '">';
        html += '<div class="team-member-avatar">' + (m.icon || '👨‍🏫') + '</div>';
        html += '<div class="team-member-content">';
        html += '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:5px;">' + featuredBadge + statusBadge + '</div>';
        html += '<h4 class="team-member-name">' + m.name + '</h4>';
        html += '<p class="team-member-role">' + m.role + '</p>';

        if (m.education || m.experience) {
            html += '<div class="team-member-meta">';
            if (m.education) html += '<span>🎓 ' + m.education + '</span>';
            if (m.experience) html += '<span>⭐ ' + m.experience + '</span>';
            html += '</div>';
        }

        if (m.bio) {
            html += '<p class="team-member-bio">' + m.bio + '</p>';
        }

        if (m.specialty1 || m.specialty2) {
            html += '<div class="team-member-specialties">';
            if (m.specialty1) html += '<span class="team-member-specialty">' + m.specialty1 + '</span>';
            if (m.specialty2) html += '<span class="team-member-specialty">' + m.specialty2 + '</span>';
            html += '</div>';
        }

        html += '</div>';

        html += '<div class="team-member-actions">';
        html += '<button class="wc-btn-edit" onclick="editTeamMember(\'' + m.id + '\')">✏️ Edit</button>';
        html += '<button class="wc-btn-toggle' + (m.status === 'hidden' ? ' hidden' : '') + '" onclick="toggleTeamMemberStatus(\'' + m.id + '\')">';
        html += m.status === 'hidden' ? '👁 Show' : '🚫 Hide';
        html += '</button>';
        html += '<button class="wc-btn-delete" onclick="deleteTeamMember(\'' + m.id + '\')">🗑 Padam</button>';
        html += '</div>';

        html += '</div>';
    }

    container.innerHTML = html;
}

function openTeamMemberForm() {
    editingTeamMemberId = null;
    document.getElementById('teamMemberModalTitle').textContent = '➕ Tambah Ahli Team';
    document.getElementById('teamMemberForm').reset();
    document.getElementById('teamMemberEditId').value = '';
    document.getElementById('teamMemberModal').classList.remove('hidden');
}

function editTeamMember(memberId) {
    var member = null;
    var members = (appData.siteContent && appData.siteContent.team && appData.siteContent.team.members) || [];

    for (var i = 0; i < members.length; i++) {
        if (members[i].id === memberId) {
            member = members[i];
            break;
        }
    }
    if (!member) return;

    editingTeamMemberId = memberId;
    document.getElementById('teamMemberModalTitle').textContent = '✏️ Edit Ahli Team';
    document.getElementById('teamMemberEditId').value = memberId;

    document.getElementById('teamMemberFeatured').checked = member.featured || false;
    document.getElementById('teamMemberName').value = member.name || '';
    document.getElementById('teamMemberRole').value = member.role || '';
    document.getElementById('teamMemberEducation').value = member.education || '';
    document.getElementById('teamMemberExperience').value = member.experience || '';
    document.getElementById('teamMemberBio').value = member.bio || '';
    document.getElementById('teamMemberSpecialty1').value = member.specialty1 || '';
    document.getElementById('teamMemberSpecialty2').value = member.specialty2 || '';
    document.getElementById('teamMemberIcon').value = member.icon || '👨‍🏫';
    document.getElementById('teamMemberPhone').value = member.phone || '';
    document.getElementById('teamMemberStatus').value = member.status || 'active';

    document.getElementById('teamMemberModal').classList.remove('hidden');
}

function closeTeamMemberForm() {
    document.getElementById('teamMemberModal').classList.add('hidden');
    editingTeamMemberId = null;
}

function saveTeamMember(e) {
    e.preventDefault();

    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.team) appData.siteContent.team = { members: [] };
    if (!appData.siteContent.team.members) appData.siteContent.team.members = [];

    var isFeatured = document.getElementById('teamMemberFeatured').checked;

    // If featured, unfeature others
    if (isFeatured) {
        for (var i = 0; i < appData.siteContent.team.members.length; i++) {
            if (appData.siteContent.team.members[i].id !== editingTeamMemberId) {
                appData.siteContent.team.members[i].featured = false;
            }
        }
    }

    var memberData = {
        id: editingTeamMemberId || 'TEAM' + Date.now(),
        featured: isFeatured,
        name: document.getElementById('teamMemberName').value.trim(),
        role: document.getElementById('teamMemberRole').value.trim(),
        education: document.getElementById('teamMemberEducation').value.trim(),
        experience: document.getElementById('teamMemberExperience').value.trim(),
        bio: document.getElementById('teamMemberBio').value.trim(),
        specialty1: document.getElementById('teamMemberSpecialty1').value.trim(),
        specialty2: document.getElementById('teamMemberSpecialty2').value.trim(),
        icon: document.getElementById('teamMemberIcon').value,
        phone: document.getElementById('teamMemberPhone').value.trim(),
        status: document.getElementById('teamMemberStatus').value,
        updatedAt: new Date().toISOString()
    };

    if (!memberData.createdAt) {
        memberData.createdAt = new Date().toISOString();
    }

    if (editingTeamMemberId) {
        // Update
        for (var i = 0; i < appData.siteContent.team.members.length; i++) {
            if (appData.siteContent.team.members[i].id === editingTeamMemberId) {
                appData.siteContent.team.members[i] = memberData;
                break;
            }
        }
        showToast('✅ Ahli team dikemaskini');
    } else {
        appData.siteContent.team.members.push(memberData);
        showToast('✅ Ahli team baru ditambah');
    }

    saveSiteContent();
    closeTeamMemberForm();
    renderTeamMembersList();
}

function deleteTeamMember(memberId) {
    var member = null;
    for (var i = 0; i < appData.siteContent.team.members.length; i++) {
        if (appData.siteContent.team.members[i].id === memberId) {
            member = appData.siteContent.team.members[i];
            break;
        }
    }
    if (!member) return;

    if (!confirm('Padam ahli team "' + member.name + '"?\n\nTindakan ini tidak boleh diundo!')) return;

    var newList = [];
    for (var i = 0; i < appData.siteContent.team.members.length; i++) {
        if (appData.siteContent.team.members[i].id !== memberId) {
            newList.push(appData.siteContent.team.members[i]);
        }
    }
    appData.siteContent.team.members = newList;

    saveSiteContent();
    renderTeamMembersList();
    showToast('🗑 Ahli team dipadam');
}

function toggleTeamMemberStatus(memberId) {
    for (var i = 0; i < appData.siteContent.team.members.length; i++) {
        if (appData.siteContent.team.members[i].id === memberId) {
            appData.siteContent.team.members[i].status =
                appData.siteContent.team.members[i].status === 'active' ? 'hidden' : 'active';
            saveSiteContent();
            renderTeamMembersList();
            showToast(appData.siteContent.team.members[i].status === 'active' ? '✅ Dipaparkan' : '🚫 Disembunyikan');
            return;
        }
    }
}

