function renderTestimoniList() {
    var container = document.getElementById('testimoniList');
    if (!container) return;

    var list = (appData.siteContent && appData.siteContent.testimoni && appData.siteContent.testimoni.list) || [];

    if (list.length === 0) {
        container.innerHTML =
            '<div class="wc-empty-state">' +
            '<div class="wc-empty-state-icon">💬</div>' +
            '<p>Belum ada testimoni</p>' +
            '<small>Klik "Tambah Testimoni" untuk mula</small>' +
            '</div>';
        return;
    }

    var html = '';
    for (var i = 0; i < list.length; i++) {
        var t = list[i];
        var statusBadge = t.status === 'hidden'
            ? '<span class="wc-status-badge wc-status-hidden">🚫 Hidden</span>'
            : '<span class="wc-status-badge wc-status-active">✅ Active</span>';

        var stars = '';
        for (var s = 0; s < (t.rating || 5); s++) {
            stars += '⭐';
        }

        // Media indicator
        var mediaIcon = '';
        var mediaTag = '';
        if (t.type === 'photo' && t.photoUrl) {
            mediaIcon = '<div style="width:60px;height:60px;border-radius:10px;overflow:hidden;flex-shrink:0;border:2px solid #a78bfa;">';
            mediaIcon += '<img src="' + t.photoUrl + '" style="width:100%;height:100%;object-fit:cover;">';
            mediaIcon += '</div>';
            mediaTag = '<span style="background:#dbeafe;color:#1e40af;padding:2px 8px;border-radius:10px;font-size:0.7rem;font-weight:700;">📷 PHOTO</span>';
        } else if (t.type === 'video' && t.videoUrl) {
            mediaIcon = '<div style="width:60px;height:60px;background:linear-gradient(135deg,#ef4444,#dc2626);border-radius:10px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">';
            mediaIcon += '<span style="font-size:2rem;">🎥</span>';
            mediaIcon += '</div>';
            mediaTag = '<span style="background:#fee2e2;color:#991b1b;padding:2px 8px;border-radius:10px;font-size:0.7rem;font-weight:700;">🎥 VIDEO</span>';
        } else {
            mediaIcon = '<div style="width:50px;height:50px;background:linear-gradient(135deg,#fef3c7,#fde68a);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:1.8rem;flex-shrink:0;">';
            mediaIcon += (t.icon || '👤');
            mediaIcon += '</div>';
        }

        html += '<div class="wc-item-card">';
        html += mediaIcon;

        html += '<div class="wc-item-content">';
        html += '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:5px;">' + statusBadge + mediaTag + '</div>';
        html += '<div style="color:#fbbf24;font-size:1rem;margin-bottom:5px;">' + stars + '</div>';
        html += '<p style="color:#475569;font-style:italic;font-size:0.92rem;line-height:1.6;margin:0 0 10px;">"' + t.text + '"</p>';
        html += '<div>';
        html += '<strong style="color:#1f2937;">— ' + t.name + '</strong>';
        html += '<span style="color:#64748b;font-size:0.85rem;"> ' + t.role + '</span>';
        html += '</div>';
        html += '</div>';

        html += '<div class="wc-item-actions">';
        html += '<button class="wc-btn-edit" onclick="editTestimoni(\'' + t.id + '\')">✏️ Edit</button>';
        html += '<button class="wc-btn-toggle' + (t.status === 'hidden' ? ' hidden' : '') + '" onclick="toggleTestimoniStatus(\'' + t.id + '\')">';
        html += t.status === 'hidden' ? '👁 Show' : '🚫 Hide';
        html += '</button>';
        html += '<button class="wc-btn-delete" onclick="deleteTestimoni(\'' + t.id + '\')">🗑</button>';
        html += '</div>';

        html += '</div>';
    }

    container.innerHTML = html;
}

function openTestimoniForm() {
    editingTestimoniId = null;
    document.getElementById('testimoniModalTitle').textContent = '➕ Tambah Testimoni';
    document.getElementById('testimoniForm').reset();
    document.getElementById('testimoniEditId').value = '';

    // Reset type to text
    document.querySelector('input[name="testimoniType"][value="text"]').checked = true;
    selectTestimoniType('text');

    // Clear previews
    removeTestimoniPhoto();
    removeTestimoniVideo();

    document.getElementById('testimoniModal').classList.remove('hidden');
}

function editTestimoni(testimoniId) {
    var testimoni = null;
    var list = (appData.siteContent && appData.siteContent.testimoni && appData.siteContent.testimoni.list) || [];

    for (var i = 0; i < list.length; i++) {
        if (list[i].id === testimoniId) {
            testimoni = list[i];
            break;
        }
    }
    if (!testimoni) return;

    editingTestimoniId = testimoniId;
    document.getElementById('testimoniModalTitle').textContent = '✏️ Edit Testimoni';
    document.getElementById('testimoniEditId').value = testimoniId;

    // Set type
    var type = testimoni.type || 'text';
    document.querySelector('input[name="testimoniType"][value="' + type + '"]').checked = true;
    selectTestimoniType(type);

    document.getElementById('testimoniText').value = testimoni.text || '';
    document.getElementById('testimoniName').value = testimoni.name || '';
    document.getElementById('testimoniRole').value = testimoni.role || '';
    document.getElementById('testimoniRating').value = testimoni.rating || 5;
    document.getElementById('testimoniIcon').value = testimoni.icon || '👨';
    document.getElementById('testimoniStatus').value = testimoni.status || 'active';

    // Load photo
    if (testimoni.type === 'photo' && testimoni.photoUrl) {
        document.getElementById('testimoniPhotoUrl').value = testimoni.photoUrl;
        updateTestimoniPhotoPreview();
    }

    // Load video
    if (testimoni.type === 'video' && testimoni.videoUrl) {
        document.getElementById('testimoniVideoUrl').value = testimoni.videoUrl;
        updateTestimoniVideoPreview();
    }

    document.getElementById('testimoniModal').classList.remove('hidden');
}

function closeTestimoniForm() {
    document.getElementById('testimoniModal').classList.add('hidden');
    editingTestimoniId = null;
}

// ===== TYPE SELECTOR =====
function selectTestimoniType(type, element) {
    // Update visual selection
    var allLabels = document.querySelectorAll('input[name="testimoniType"]');
    for (var i = 0; i < allLabels.length; i++) {
        var label = allLabels[i].closest('label');
        if (label) {
            label.style.borderColor = '#e2e8f0';
            label.style.background = 'white';
        }
    }

    if (element) {
        element.style.borderColor = '#a78bfa';
        element.style.background = '#faf5ff';
    } else {
        // Find current selected
        var checked = document.querySelector('input[name="testimoniType"]:checked');
        if (checked) {
            var label = checked.closest('label');
            if (label) {
                label.style.borderColor = '#a78bfa';
                label.style.background = '#faf5ff';
            }
        }
    }

    // Show/hide sections
    document.getElementById('testimoniPhotoSection').style.display = type === 'photo' ? 'block' : 'none';
    document.getElementById('testimoniVideoSection').style.display = type === 'video' ? 'block' : 'none';
}

// ===== PHOTO HANDLING =====
function previewTestimoniPhoto(input) {
    if (!input.files || !input.files[0]) return;

    var file = input.files[0];

    // Check size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
        alert('❌ Fail terlalu besar! Max 5MB');
        input.value = '';
        return;
    }

    // Show uploading state
    showToast('⏳ Uploading gambar...');

    // Upload to ImgBB
    var reader = new FileReader();
    reader.onload = function(e) {
        var base64 = e.target.result.split(',')[1];

        var formData = new FormData();
        formData.append('image', base64);

        fetch('/api/upload-image', {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json'
    },
    body: JSON.stringify({ image: base64 })
})
        .then(function(response) { return response.json(); })
        .then(function(data) {
            if (data.success && data.data) {
                document.getElementById('testimoniPhotoUrl').value = data.data.url;
                updateTestimoniPhotoPreview();
                showToast('✅ Gambar berjaya diupload!');
            } else {
                alert('❌ Upload gagal. Sila guna URL manual.');
            }
        })
        .catch(function(error) {
            console.log('Upload error:', error);
            alert('❌ Upload gagal. Sila guna URL manual atau cuba lagi.');
        });
    };
    reader.readAsDataURL(file);
}

function updateTestimoniPhotoPreview() {
    var url = document.getElementById('testimoniPhotoUrl').value.trim();
    var preview = document.getElementById('testimoniPhotoPreview');
    var img = document.getElementById('testimoniPhotoPreviewImg');

    if (url) {
        img.src = url;
        preview.style.display = 'block';
    } else {
        preview.style.display = 'none';
    }
}

function removeTestimoniPhoto() {
    document.getElementById('testimoniPhotoUrl').value = '';
    document.getElementById('testimoniPhotoUpload').value = '';
    document.getElementById('testimoniPhotoPreview').style.display = 'none';
}

// ===== VIDEO HANDLING =====
// ===== VIDEO HANDLING =====
var videoUploadData = null; // Simpan uploaded video URL

function switchVideoMode(mode) {
    var uploadMode = document.getElementById('videoUploadMode');
    var urlMode = document.getElementById('videoUrlMode');

    // Update radio buttons visual
    var labels = document.querySelectorAll('input[name="videoMode"]');
    for (var i = 0; i < labels.length; i++) {
        var label = labels[i].closest('label');
        if (label) {
            label.style.borderColor = '#e2e8f0';
            label.style.background = 'white';
        }
    }

    var checked = document.querySelector('input[name="videoMode"]:checked');
    if (checked) {
        var label = checked.closest('label');
        if (label) {
            label.style.borderColor = '#a78bfa';
            label.style.background = '#faf5ff';
        }
    }

    if (mode === 'upload') {
        uploadMode.style.display = 'block';
        urlMode.style.display = 'none';
    } else {
        uploadMode.style.display = 'none';
        urlMode.style.display = 'block';
    }
}

function handleVideoUpload(input) {
    if (!input.files || !input.files[0]) return;

    var file = input.files[0];

    // Check file size (max 32MB)
    if (file.size > 32 * 1024 * 1024) {
        alert('❌ Video terlalu besar! Maksimum 32MB.\n\nCara lain:\n1. Compress video guna HandBrake\n2. Upload ke YouTube & paste link');
        input.value = '';
        return;
    }

    // Show preview using local URL (for display purposes)
    var videoUrl = URL.createObjectURL(file);
    var videoEl = document.getElementById('testimoniVideoElement');
    videoEl.src = videoUrl;
    document.getElementById('videoUploadPreview').classList.remove('hidden');
    document.getElementById('videoUploadArea').style.display = 'none';

    // Show progress
    document.getElementById('videoUploadProgress').classList.remove('hidden');
    document.getElementById('videoUploadStatus').textContent = '⏳ Compressing & uploading video...';

    // Convert to base64 then upload to ImgBB
    var reader = new FileReader();
    reader.onload = function(e) {
        var base64 = e.target.result.split(',')[1];

        var progressBar = document.getElementById('videoUploadProgressBar');
        progressBar.style.width = '30%';
        document.getElementById('videoUploadStatus').textContent = '📤 Uploading to server...';

        var formData = new FormData();
        formData.append('image', base64);

        fetch('/api/upload-image', {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json'
    },
    body: JSON.stringify({ image: base64 })
})
        .then(function(response) {
            progressBar.style.width = '70%';
            return response.json();
        })
        .then(function(data) {
            progressBar.style.width = '100%';

            if (data.success && data.data) {
                videoUploadData = data.data.url;
                document.getElementById('videoUploadStatus').innerHTML = '✅ Video berjaya diupload! <strong style="color:#7c3aed;">URL: ' + data.data.url + '</strong>';

                // Update video element source to uploaded URL
                videoEl.src = data.data.url;
                showToast('✅ Video berjaya diupload!');

                // Set hidden field
                document.getElementById('testimoniVideoUrlUpload').value = data.data.url;
            } else {
                document.getElementById('videoUploadStatus').innerHTML = '❌ Upload gagal. Sila cuba guna URL manual.';
                document.getElementById('videoUploadStatus').style.color = '#ef4444';
            }
        })
        .catch(function(error) {
            console.log('Video upload error:', error);
            document.getElementById('videoUploadStatus').innerHTML = '❌ Upload gagal. Error: ' + error.message + '<br>Sila cuba guna URL manual.';
            document.getElementById('videoUploadStatus').style.color = '#ef4444';
        });
    };

    reader.onerror = function() {
        alert('❌ Gagal membaca fail video');
        document.getElementById('videoUploadProgress').classList.add('hidden');
    };

    reader.readAsDataURL(file);
}

function updateTestimoniVideoPreview() {
    var url = document.getElementById('testimoniVideoUrl').value.trim();
    var preview = document.getElementById('testimoniVideoPreview');
    var iframe = document.getElementById('testimoniVideoIframe');

    if (!url) {
        preview.classList.add('hidden');
        return;
    }

    var videoId = extractYouTubeId(url);
    if (videoId) {
        iframe.src = 'https://www.youtube.com/embed/' + videoId;
        preview.classList.remove('hidden');
    } else {
        preview.classList.add('hidden');
    }
}

function extractYouTubeId(url) {
    if (!url) return null;

    var patterns = [
        /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([^&\n?#]+)/,
        /youtube\.com\/v\/([^&\n?#]+)/,
        /youtube\.com\/shorts\/([^&\n?#]+)/
    ];

    for (var i = 0; i < patterns.length; i++) {
        var match = url.match(patterns[i]);
        if (match && match[1]) {
            return match[1];
        }
    }

    return null;
}

function removeTestimoniVideo() {
    // Clear upload
    document.getElementById('testimoniVideoUpload').value = '';
    document.getElementById('testimoniVideoElement').src = '';
    document.getElementById('videoUploadPreview').classList.add('hidden');
    document.getElementById('videoUploadArea').style.display = 'block';
    document.getElementById('videoUploadProgress').classList.add('hidden');
    document.getElementById('videoUploadProgressBar').style.width = '0%';
    document.getElementById('testimoniVideoUrlUpload').value = '';
    videoUploadData = null;
}

function removeTestimoniVideoUrl() {
    document.getElementById('testimoniVideoUrl').value = '';
    document.getElementById('testimoniVideoIframe').src = '';
    document.getElementById('testimoniVideoPreview').classList.add('hidden');
}

// ===== SAVE =====
function saveTestimoni(e) {
    e.preventDefault();

    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.testimoni) appData.siteContent.testimoni = { list: [] };
    if (!appData.siteContent.testimoni.list) appData.siteContent.testimoni.list = [];

        var typeRadio = document.querySelector('input[name="testimoniType"]:checked');
    var type = typeRadio ? typeRadio.value : 'text';

    var testimoniData = {
        id: editingTestimoniId || 'TEST' + Date.now(),
        type: type,
        text: document.getElementById('testimoniText').value.trim(),
        name: document.getElementById('testimoniName').value.trim(),
        role: document.getElementById('testimoniRole').value.trim(),
        rating: parseInt(document.getElementById('testimoniRating').value) || 5,
        icon: document.getElementById('testimoniIcon').value,
        photoUrl: type === 'photo' ? document.getElementById('testimoniPhotoUrl').value.trim() : '',
        videoUrl: '',  // Akan di-set bawah
        status: document.getElementById('testimoniStatus').value,
        updatedAt: new Date().toISOString()
    };

    // ===== VIDEO URL HANDLING =====
    if (type === 'video') {
        var videoModeRadio = document.querySelector('input[name="videoMode"]:checked');
        var videoMode = videoModeRadio ? videoModeRadio.value : 'upload';

        if (videoMode === 'upload') {
            // Guna URL dari upload
            var uploadedUrl = document.getElementById('testimoniVideoUrlUpload').value.trim();
            var directUrl = videoUploadData || '';

            if (directUrl) {
                testimoniData.videoUrl = directUrl;
            } else if (uploadedUrl) {
                testimoniData.videoUrl = uploadedUrl;
            } else {
                alert('⚠️ Sila upload video atau masukkan URL');
                return;
            }
        } else {
            // Guna YouTube URL
            var youtubeUrl = document.getElementById('testimoniVideoUrl').value.trim();
            if (!youtubeUrl) {
                alert('⚠️ Sila masukkan YouTube URL');
                return;
            }
            var videoId = extractYouTubeId(youtubeUrl);
            if (!videoId) {
                alert('⚠️ URL YouTube tidak sah. Sila guna format:\n- youtube.com/watch?v=XXX\n- youtu.be/XXX');
                return;
            }
            testimoniData.videoUrl = youtubeUrl;
        }
    }

    // Validate
    if (type === 'photo' && !testimoniData.photoUrl) {
        alert('⚠️ Sila upload atau masukkan URL gambar');
        return;
    }

    if (!testimoniData.createdAt) {
        testimoniData.createdAt = new Date().toISOString();
    }

    if (editingTestimoniId) {
        for (var i = 0; i < appData.siteContent.testimoni.list.length; i++) {
            if (appData.siteContent.testimoni.list[i].id === editingTestimoniId) {
                appData.siteContent.testimoni.list[i] = testimoniData;
                break;
            }
        }
        showToast('✅ Testimoni dikemaskini');
    } else {
        appData.siteContent.testimoni.list.push(testimoniData);
        showToast('✅ Testimoni baru ditambah');
    }

    saveSiteContent();
    closeTestimoniForm();
    renderTestimoniList();
}

function deleteTestimoni(testimoniId) {
    if (!confirm('Padam testimoni ini?\n\nTindakan ini tidak boleh diundo!')) return;

    var newList = [];
    for (var i = 0; i < appData.siteContent.testimoni.list.length; i++) {
        if (appData.siteContent.testimoni.list[i].id !== testimoniId) {
            newList.push(appData.siteContent.testimoni.list[i]);
        }
    }
    appData.siteContent.testimoni.list = newList;

    saveSiteContent();
    renderTestimoniList();
    showToast('🗑 Testimoni dipadam');
}

function toggleTestimoniStatus(testimoniId) {
    for (var i = 0; i < appData.siteContent.testimoni.list.length; i++) {
        if (appData.siteContent.testimoni.list[i].id === testimoniId) {
            appData.siteContent.testimoni.list[i].status =
                appData.siteContent.testimoni.list[i].status === 'active' ? 'hidden' : 'active';
            saveSiteContent();
            renderTestimoniList();
            showToast(appData.siteContent.testimoni.list[i].status === 'active' ? '✅ Dipaparkan' : '🚫 Disembunyikan');
            return;
        }
    }
}

