var editingProgramId = null;

function initWC_programs() {
    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.programs) {
        appData.siteContent.programs = {
            badge: 'Program Kami',
            title: 'Pelbagai Program',
            subtitle: 'Untuk Semua Peringkat',
            list: []
        };
    }

    loadProgramsHeader();
    renderProgramsList();
}

function loadProgramsHeader() {
    var p = appData.siteContent.programs || {};
    document.getElementById('programsBadge').value = p.badge || 'Program Kami';
    document.getElementById('programsTitle').value = p.title || 'Pelbagai Program';
    document.getElementById('programsSubtitle').value = p.subtitle || 'Untuk Semua Peringkat';
}

function saveProgramsHeader() {
    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.programs) appData.siteContent.programs = {};

    appData.siteContent.programs.badge = document.getElementById('programsBadge').value.trim();
    appData.siteContent.programs.title = document.getElementById('programsTitle').value.trim();
    appData.siteContent.programs.subtitle = document.getElementById('programsSubtitle').value.trim();

    saveSiteContent();
}

function renderProgramsList() {
    var container = document.getElementById('programsList');
    if (!container) return;

    var list = (appData.siteContent && appData.siteContent.programs && appData.siteContent.programs.list) || [];

    if (list.length === 0) {
        container.innerHTML =
            '<div class="wc-empty-state">' +
            '<div class="wc-empty-state-icon">📚</div>' +
            '<p>Belum ada program</p>' +
            '<small>Klik "Tambah Program" untuk mula</small>' +
            '</div>';
        return;
    }

    // Sort by order
    list.sort(function(a, b) {
        return (a.order || 0) - (b.order || 0);
    });

    var html = '';
    for (var i = 0; i < list.length; i++) {
        var p = list[i];
        var featuredBadge = p.featured ? '<span class="wc-status-badge wc-status-featured">⭐ FEATURED</span>' : '';
        var statusBadge = p.status === 'hidden'
            ? '<span class="wc-status-badge wc-status-hidden">🚫 Hidden</span>'
            : '<span class="wc-status-badge wc-status-active">✅ Active</span>';

        html += '<div class="wc-item-card' + (p.featured ? ' featured' : '') + '">';
        html += '<div style="font-size:3rem;flex-shrink:0;">' + (p.icon || '📚') + '</div>';
        html += '<div class="wc-item-content">';
        html += '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:8px;">' + featuredBadge + statusBadge + '</div>';
        html += '<h4 class="wc-item-title">' + p.name + '</h4>';
        html += '<p class="wc-item-desc">' + p.description + '</p>';

        if (p.features && p.features.length > 0) {
            html += '<div style="display:flex;gap:5px;flex-wrap:wrap;margin-top:8px;">';
            for (var j = 0; j < p.features.length; j++) {
                html += '<span style="background:#faf5ff;color:#7c3aed;padding:3px 8px;border-radius:10px;font-size:0.75rem;">✓ ' + p.features[j] + '</span>';
            }
            html += '</div>';
        }

        html += '<div style="margin-top:8px;display:flex;gap:10px;font-size:0.82rem;color:#64748b;">';
        if (p.age) html += '<span>👶 ' + p.age + '</span>';
        if (p.classLabel) html += '<span>📋 ' + p.classLabel + '</span>';
        html += '</div>';

        html += '</div>';

        html += '<div class="wc-item-actions">';
        html += '<button class="wc-btn-edit" onclick="editProgram(\'' + p.id + '\')">✏️ Edit</button>';
        html += '<button class="wc-btn-toggle' + (p.status === 'hidden' ? ' hidden' : '') + '" onclick="toggleProgramStatus(\'' + p.id + '\')">';
        html += p.status === 'hidden' ? '👁 Show' : '🚫 Hide';
        html += '</button>';
        html += '<button class="wc-btn-delete" onclick="deleteProgram(\'' + p.id + '\')">🗑</button>';
        html += '</div>';

        html += '</div>';
    }

    container.innerHTML = html;
}

function openProgramForm() {
    editingProgramId = null;
    document.getElementById('programModalTitle').textContent = '➕ Tambah Program';
    document.getElementById('programForm').reset();
    document.getElementById('programEditId').value = '';

    var list = (appData.siteContent && appData.siteContent.programs && appData.siteContent.programs.list) || [];
    document.getElementById('programOrder').value = list.length + 1;

    document.getElementById('programModal').classList.remove('hidden');
}

function editProgram(programId) {
    var program = null;
    var list = (appData.siteContent && appData.siteContent.programs && appData.siteContent.programs.list) || [];

    for (var i = 0; i < list.length; i++) {
        if (list[i].id === programId) {
            program = list[i];
            break;
        }
    }
    if (!program) return;

    editingProgramId = programId;
    document.getElementById('programModalTitle').textContent = '✏️ Edit Program';
    document.getElementById('programEditId').value = programId;

    document.getElementById('programFeatured').checked = program.featured || false;
    document.getElementById('programName').value = program.name || '';
    document.getElementById('programIcon').value = program.icon || '📚';
    document.getElementById('programDesc').value = program.description || '';
    document.getElementById('programFeatures').value = (program.features || []).join('\n');
    document.getElementById('programAge').value = program.age || '';
    document.getElementById('programClass').value = program.classLabel || '';
    document.getElementById('programOrder').value = program.order || 1;
    document.getElementById('programStatus').value = program.status || 'active';

    document.getElementById('programModal').classList.remove('hidden');
}

function closeProgramForm() {
    document.getElementById('programModal').classList.add('hidden');
    editingProgramId = null;
}

function saveProgram(e) {
    e.preventDefault();

    if (!appData.siteContent) appData.siteContent = getDefaultSiteContent();
    if (!appData.siteContent.programs) appData.siteContent.programs = { list: [] };
    if (!appData.siteContent.programs.list) appData.siteContent.programs.list = [];

    var isFeatured = document.getElementById('programFeatured').checked;

    if (isFeatured) {
        for (var i = 0; i < appData.siteContent.programs.list.length; i++) {
            if (appData.siteContent.programs.list[i].id !== editingProgramId) {
                appData.siteContent.programs.list[i].featured = false;
            }
        }
    }

    var features = document.getElementById('programFeatures').value
        .split('\n').map(function(s) { return s.trim(); }).filter(function(s) { return s; });

    var programData = {
        id: editingProgramId || 'PROG' + Date.now(),
        featured: isFeatured,
        name: document.getElementById('programName').value.trim(),
        icon: document.getElementById('programIcon').value.trim() || '📚',
        description: document.getElementById('programDesc').value.trim(),
        features: features,
        age: document.getElementById('programAge').value.trim(),
        classLabel: document.getElementById('programClass').value.trim(),
        order: parseInt(document.getElementById('programOrder').value) || 1,
        status: document.getElementById('programStatus').value,
        updatedAt: new Date().toISOString()
    };

    if (!programData.createdAt) {
        programData.createdAt = new Date().toISOString();
    }

    if (editingProgramId) {
        for (var i = 0; i < appData.siteContent.programs.list.length; i++) {
            if (appData.siteContent.programs.list[i].id === editingProgramId) {
                appData.siteContent.programs.list[i] = programData;
                break;
            }
        }
        showToast('✅ Program dikemaskini');
    } else {
        appData.siteContent.programs.list.push(programData);
        showToast('✅ Program baru ditambah');
    }

    saveSiteContent();
    closeProgramForm();
    renderProgramsList();
}

function deleteProgram(programId) {
    if (!confirm('Padam program ini?\n\nTindakan ini tidak boleh diundo!')) return;

    var newList = [];
    for (var i = 0; i < appData.siteContent.programs.list.length; i++) {
        if (appData.siteContent.programs.list[i].id !== programId) {
            newList.push(appData.siteContent.programs.list[i]);
        }
    }
    appData.siteContent.programs.list = newList;

    saveSiteContent();
    renderProgramsList();
    showToast('🗑 Program dipadam');
}

function toggleProgramStatus(programId) {
    for (var i = 0; i < appData.siteContent.programs.list.length; i++) {
        if (appData.siteContent.programs.list[i].id === programId) {
            appData.siteContent.programs.list[i].status =
                appData.siteContent.programs.list[i].status === 'active' ? 'hidden' : 'active';
            saveSiteContent();
            renderProgramsList();
            showToast(appData.siteContent.programs.list[i].status === 'active' ? '✅ Dipaparkan' : '🚫 Disembunyikan');
            return;
        }
    }
}

