// ===== FILTER TABLE =====
function filterPrestasiTable() {
    var searchEl = document.getElementById('prestasiSearchInput');
    var filterEl = document.getElementById('prestasiFilterKelas');
    
    if (!searchEl || !filterEl) return;
    
    var searchVal = searchEl.value.toLowerCase();
    var classFilter = filterEl.value;
    
    var rows = document.querySelectorAll('.prestasi-row');
    var visibleCount = 0;
    
    for (var i = 0; i < rows.length; i++) {
        var row = rows[i];
        var name = row.dataset.name || '';
        var className = row.dataset.class || '';
        
        var matchSearch = !searchVal || name.indexOf(searchVal) > -1;
        var matchClass = classFilter === 'all' || className === classFilter;
        
        if (matchSearch && matchClass) {
            row.style.display = '';
            visibleCount++;
        } else {
            row.style.display = 'none';
        }
    }
    
    // Update info
    var infoEl = document.getElementById('prestasiResultsInfo');
    if (infoEl) {
        var total = rows.length;
        if (visibleCount === total) {
            infoEl.innerHTML = '📊 Menunjukkan <strong>' + visibleCount + '</strong> pelajar';
            infoEl.style.background = '#faf5ff';
            infoEl.style.color = '#5b21b6';
        } else if (visibleCount === 0) {
            infoEl.innerHTML = '❌ Tiada pelajar ditemui - cuba kata kunci lain';
            infoEl.style.background = '#fee2e2';
            infoEl.style.color = '#991b1b';
        } else {
            infoEl.innerHTML = '🔍 Menunjukkan <strong>' + visibleCount + '</strong> dari <strong>' + total + '</strong> pelajar';
            infoEl.style.background = '#dbeafe';
            infoEl.style.color = '#1e40af';
        }
    }
}

// ===== SORT TABLE =====
function sortPrestasiTable() {
    var sortEl = document.getElementById('prestasiSortBy');
    if (!sortEl) return;
    
    var sortBy = sortEl.value;
    var tbody = document.getElementById('prestasiTableBody');
    if (!tbody) return;
    
    var rows = Array.prototype.slice.call(tbody.querySelectorAll('.prestasi-row'));
    
    rows.sort(function(a, b) {
        if (sortBy === 'name') {
            return a.dataset.name.localeCompare(b.dataset.name);
        } else if (sortBy === 'name_desc') {
            return b.dataset.name.localeCompare(a.dataset.name);
        } else if (sortBy === 'progress') {
            return parseInt(b.dataset.totalJuz) - parseInt(a.dataset.totalJuz);
        } else if (sortBy === 'progress_asc') {
            return parseInt(a.dataset.totalJuz) - parseInt(b.dataset.totalJuz);
        } else if (sortBy === 'lancar') {
            return parseInt(b.dataset.lancar) - parseInt(a.dataset.lancar);
        }
        return 0;
    });
    
    for (var i = 0; i < rows.length; i++) {
        tbody.appendChild(rows[i]);
        // Update row number
        var noCell = rows[i].querySelector('td:first-child');
        if (noCell) noCell.textContent = (i + 1);
        // Update bg color for zebra
        var bg = i % 2 === 0 ? '#ffffff' : '#faf5ff';
        rows[i].style.background = bg;
    }
}

// ===== SHOW JUZ DETAIL (POPUP) =====
function showJuzDetail(studentId, juzNum, year, month) {
    appData = loadData();
    var students = appData.students || [];
    var records = appData.records || [];
    
    var student = null;
    for (var i = 0; i < students.length; i++) {
        if (students[i].id === studentId) {
            student = students[i];
            break;
        }
    }
    if (!student) return;
    
    var monthNames = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    
    var monthStr = month < 10 ? '0' + month : String(month);
    var datePrefix = year + '-' + monthStr;
    
    // Cari records untuk juz ni
    var juzRecords = [];
    for (var i = 0; i < records.length; i++) {
        var r = records[i];
        if (r.studentId !== studentId) continue;
        if (r.date.indexOf(datePrefix) !== 0) continue;
        
        // Check kalau ada juz ni
        var juzList = [];
        if (Array.isArray(r.juz)) juzList = r.juz;
        else if (r.juzList && Array.isArray(r.juzList)) juzList = r.juzList;
        else if (r.juz) juzList = [r.juz];
        
        if (juzList.indexOf(juzNum) > -1) {
            juzRecords.push(r);
        }
    }
    
    // Build modal
    var html = '';
    html += '<div id="juzDetailModal" style="position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:99999;display:flex;align-items:center;justify-content:center;padding:20px;" onclick="if(event.target===this)closeJuzDetail()">';
    html += '<div style="background:white;border-radius:20px;max-width:700px;width:100%;max-height:90vh;overflow-y:auto;box-shadow:0 25px 80px rgba(0,0,0,0.3);">';
    
    // Header
    html += '<div style="background:linear-gradient(135deg,#7c3aed,#5b21b6);color:white;padding:25px;border-radius:20px 20px 0 0;position:relative;">';
    html += '<button onclick="closeJuzDetail()" style="position:absolute;top:15px;right:15px;background:rgba(255,255,255,0.2);color:white;border:none;width:36px;height:36px;border-radius:50%;cursor:pointer;font-size:1.1rem;">✕</button>';
    html += '<div style="display:flex;align-items:center;gap:15px;">';
    html += '<div style="background:rgba(255,255,255,0.2);width:55px;height:55px;border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:1.6rem;">📖</div>';
    html += '<div>';
    html += '<div style="font-size:1.2rem;font-weight:900;">Juz ' + juzNum + '</div>';
    html += '<div style="font-size:0.88rem;opacity:0.95;margin-top:3px;">' + student.name + '</div>';
    html += '<div style="font-size:0.78rem;opacity:0.85;">' + monthNames[month] + ' ' + year + '</div>';
    html += '</div>';
    html += '</div>';
    html += '</div>';
    
    // Content
    html += '<div style="padding:25px;">';
    
    if (juzRecords.length === 0) {
        html += '<div style="text-align:center;padding:40px 20px;">';
        html += '<div style="font-size:3rem;margin-bottom:15px;opacity:0.5;">📭</div>';
        html += '<h3 style="color:#5b21b6;margin-bottom:8px;">Tiada Rekod</h3>';
        html += '<p style="color:#64748b;">Tiada rekod hafazan untuk Juz ' + juzNum + ' dalam ' + monthNames[month] + ' ' + year + '</p>';
        html += '</div>';
    } else {
        html += '<div style="background:#faf5ff;padding:15px;border-radius:12px;margin-bottom:20px;">';
        html += '<div style="font-size:0.85rem;color:#5b21b6;font-weight:700;">📊 ' + juzRecords.length + ' rekod hafazan untuk Juz ' + juzNum + '</div>';
        html += '</div>';
        
        for (var i = 0; i < juzRecords.length; i++) {
            var r = juzRecords[i];
            var scoreColor = r.score >= 80 ? '#16a34a' : r.score >= 60 ? '#eab308' : '#dc2626';
            var statusIcon = r.score >= 80 ? '🟢' : r.score >= 60 ? '🟡' : '🔴';
            var sessionIcon = r.session === 'pagi' ? '🌅' : r.session === 'petang' ? '🌤' : '🌙';
            var sessionText = r.session === 'pagi' ? 'Pagi' : r.session === 'petang' ? 'Petang' : 'Malam';
            
            html += '<div style="background:white;border:2px solid #e9d5ff;border-left:5px solid ' + scoreColor + ';border-radius:12px;padding:15px;margin-bottom:12px;">';
            html += '<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px;">';
            html += '<div>';
            html += '<div style="font-weight:800;color:#1f2937;font-size:1.05rem;">' + statusIcon + ' Markah: ' + r.score + '%</div>';
            html += '<div style="font-size:0.85rem;color:#64748b;margin-top:3px;">📅 ' + formatDate(r.date) + ' • ' + sessionIcon + ' ' + sessionText + '</div>';
            html += '</div>';
            html += '<div style="background:' + scoreColor + ';color:white;padding:4px 12px;border-radius:20px;font-size:0.78rem;font-weight:700;">' + r.status + '</div>';
            html += '</div>';
            
            if (r.readingType) {
                html += '<div style="background:#f3e8ff;padding:6px 12px;border-radius:8px;margin-bottom:8px;font-size:0.82rem;color:#5b21b6;">';
                html += '📖 <strong>Jenis:</strong> ' + r.readingType;
                html += '</div>';
            }
            
            // Surah
            if (r.surahDetails && r.surahDetails.length > 0) {
                html += '<div style="background:#faf5ff;padding:10px;border-radius:8px;margin-top:8px;">';
                html += '<div style="font-size:0.78rem;color:#5b21b6;font-weight:700;margin-bottom:5px;">📚 Surah:</div>';
                for (var s = 0; s < r.surahDetails.length; s++) {
                    var sd = r.surahDetails[s];
                    html += '<div style="font-size:0.85rem;color:#1f2937;">• ' + sd.name;
                    if (sd.ayatFrom && sd.ayatTo) html += ' (Ayat ' + sd.ayatFrom + '-' + sd.ayatTo + ')';
                    html += '</div>';
                }
                html += '</div>';
            }
            
            if (r.checkerName) {
                html += '<div style="margin-top:10px;font-size:0.8rem;color:#64748b;">👤 <strong>Penyemak:</strong> ' + r.checkerName + '</div>';
            }
            
            if (r.notes) {
                html += '<div style="margin-top:10px;padding:8px 12px;background:#fef3c7;border-radius:8px;font-size:0.82rem;color:#78350f;font-style:italic;">💬 "' + r.notes + '"</div>';
            }
            
            html += '</div>';
        }
    }
    
    html += '</div>';
    html += '</div>';
    html += '</div>';
    
    // Append to body
    var existing = document.getElementById('juzDetailModal');
    if (existing) existing.remove();
    
    var div = document.createElement('div');
    div.innerHTML = html;
    document.body.appendChild(div.firstChild);
}

function closeJuzDetail() {
    var modal = document.getElementById('juzDetailModal');
    if (modal) modal.remove();
}

// ===== EXPORT EXCEL (CSV) =====
function exportPrestasiExcel() {
    if (!window._prestasiDataGlobal) {
        alert('Sila render prestasi dulu');
        return;
    }
    
    var month = parseInt(document.getElementById('prestasiMonth').value);
    var year = parseInt(document.getElementById('prestasiYear').value);
    var monthNames = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    
    var csv = 'PRESTASI PELAJAR - ' + monthNames[month] + ' ' + year + '\n\n';
    csv += 'No,Nama,Kelas,Total Juz,Lancar,Kurang,Tidak Lancar';
    for (var j = 1; j <= 30; j++) {
        csv += ',Juz ' + j;
    }
    csv += '\n';
    
    var data = window._prestasiDataGlobal;
    for (var i = 0; i < data.length; i++) {
        var pd = data[i];
        csv += (i + 1) + ',"' + pd.student.name + '","' + (pd.student.class || '') + '",';
        csv += pd.totalJuz + ',' + pd.lancarCount + ',' + pd.kurangCount + ',' + pd.tidakCount;
        
        for (var j = 1; j <= 30; j++) {
            var juzData = pd.prestasi.juzData[j];
            if (!juzData) {
                csv += ',-';
            } else if (juzData.type === 'iqra') {
                csv += ',Iqra';
            } else if (juzData.type === 'nazirah') {
                csv += ',Nazirah (' + juzData.count + 'x)';
            } else {
                csv += ',' + Math.round(juzData.avgScore) + '%';
            }
        }
        csv += '\n';
    }
    
    var BOM = '\uFEFF';
    var blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'prestasi_' + monthNames[month] + '_' + year + '.csv';
    link.click();
    
    if (typeof showToast === 'function') showToast('✅ Prestasi diexport ke Excel');
}

// ===== CALCULATE PRESTASI =====
function calculateStudentPrestasi(student, records) {
    var prestasi = {
        juzData: {} // {juzNum: {type, avgScore, count, records}}
    };

    // Separate records by type
    for (var i = 0; i < records.length; i++) {
        var r = records[i];
        var juzList = [];

        // Get juz numbers
        if (Array.isArray(r.juz)) {
            juzList = r.juz;
        } else if (r.juzList && Array.isArray(r.juzList)) {
            juzList = r.juzList;
        } else if (r.juz) {
            juzList = [r.juz];
        }

        // Iqra - skip juz logic, just mark
        if (r.isIqra) {
            // Untuk iqra, anggap dalam Juz 30 (atau juz semasa)
            // Atau boleh skip - depends on logic
            continue;
        }

        // Process by reading type
        var readingType = r.readingType || '';

        for (var j = 0; j < juzList.length; j++) {
            var juzNum = parseInt(juzList[j]);
            if (!juzNum || juzNum < 1 || juzNum > 30) continue;

            if (!prestasi.juzData[juzNum]) {
                prestasi.juzData[juzNum] = {
                    type: null,
                    scores: [],
                    count: 0,
                    records: []
                };
            }

            // Nazirah Khatam - kira kali baca
            if (readingType === 'nazirah_khatam') {
                if (prestasi.juzData[juzNum].type !== 'hafazan') {
                    prestasi.juzData[juzNum].type = 'nazirah';
                    prestasi.juzData[juzNum].count++;
                }
            }
            // Para Sabak & Mukhtar - kira average
            else if (readingType === 'para_sabak' || readingType === 'mukhtar' || readingType === 'mukhtar_khatam') {
                prestasi.juzData[juzNum].type = 'hafazan';
                prestasi.juzData[juzNum].scores.push(r.score || 0);
                prestasi.juzData[juzNum].count++;
                prestasi.juzData[juzNum].records.push(r);
            }
            // Sabak Baru - sama dengan hafazan
            else if (readingType === 'sabak_baru') {
                if (prestasi.juzData[juzNum].type !== 'hafazan') {
                    prestasi.juzData[juzNum].type = 'hafazan';
                }
                prestasi.juzData[juzNum].scores.push(r.score || 0);
                prestasi.juzData[juzNum].count++;
            }
        }
    }

    // Calculate averages
    for (var juzNum in prestasi.juzData) {
        var data = prestasi.juzData[juzNum];
        if (data.scores.length > 0) {
            var total = 0;
            for (var i = 0; i < data.scores.length; i++) {
                total += data.scores[i];
            }
            data.avgScore = total / data.scores.length;
        }
    }

    // Check kalau pelajar masih Iqra'
    var iqraOnly = true;
    var hasAnyRecord = false;
    for (var i = 0; i < records.length; i++) {
        hasAnyRecord = true;
        if (!records[i].isIqra) {
            iqraOnly = false;
            break;
        }
    }

    // Kalau semua records adalah Iqra, mark juz 30 sebagai iqra
    if (iqraOnly && hasAnyRecord) {
        // Mark Juz 30 sebagai Iqra
        if (!prestasi.juzData[30]) {
            prestasi.juzData[30] = {
                type: 'iqra',
                count: records.length
            };
        }
    }

    return prestasi;
}

// ===== PRINT =====
function printPrestasi() {
    document.body.classList.add('print-prestasi');
    setTimeout(function() {
        window.print();
        setTimeout(function() {
            document.body.classList.remove('print-prestasi');
        }, 500);
    }, 300);
}

// ===== WHATSAPP BLAST =====
function confirmBlastWhatsApp() {
    var month = parseInt(document.getElementById('prestasiMonth').value);
    var year = parseInt(document.getElementById('prestasiYear').value);
    var monthNames = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];

    var students = appData.students || [];
    var withPhone = 0;
    for (var i = 0; i < students.length; i++) {
        var phone = students[i].fatherPhone || students[i].motherPhone || students[i].parentPhone;
        if (phone) withPhone++;
    }

    if (!confirm(
        '📱 Blast Prestasi WhatsApp\n\n' +
        'Bulan: ' + monthNames[month] + ' ' + year + '\n' +
        'Jumlah parents: ' + withPhone + ' orang\n\n' +
        'WhatsApp akan buka satu-satu untuk setiap parent.\n' +
        'Tekan "Send" pada setiap WhatsApp.\n\n' +
        'Teruskan?'
    )) return;

    blastWhatsAppPrestasi();
}

function blastWhatsAppPrestasi() {
    var month = parseInt(document.getElementById('prestasiMonth').value);
    var year = parseInt(document.getElementById('prestasiYear').value);
    var monthStr = month < 10 ? '0' + month : String(month);
    var datePrefix = year + '-' + monthStr;
    var monthNames = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];

    var students = appData.students || [];
    var records = appData.records || [];

    var monthRecords = records.filter(function(r) {
        return r.date && r.date.indexOf(datePrefix) === 0;
    });

    var sentCount = 0;

    for (var i = 0; i < students.length; i++) {
        (function(student, index) {
            setTimeout(function() {
                var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
                if (!phone) return;

                var studentRecords = monthRecords.filter(function(r) {
                    return r.studentId === student.id;
                });

                var prestasi = calculateStudentPrestasi(student, studentRecords);
                var msg = buildWhatsAppMessage(student, prestasi, month, year);

                // Format phone
                phone = phone.replace(/[^0-9]/g, '');
                if (phone.startsWith('0')) phone = '60' + phone.substring(1);

                var url = 'https://wa.me/' + phone + '?text=' + encodeURIComponent(msg);
                window.open(url, '_blank');
                sentCount++;

                if (typeof showToast === 'function') {
                    showToast('📱 Membuka WhatsApp untuk ' + student.name + ' (' + sentCount + ')');
                }
            }, index * 2000); // 2 saat delay
        })(students[i], i);
    }
}

function buildWhatsAppMessage(student, prestasi, month, year) {
    var monthNames = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
                      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';

    var msg = '*📊 PRESTASI BULANAN HAFAZAN*\n';
    msg += '━━━━━━━━━━━━━━━━━━━\n\n';
    msg += 'Assalamualaikum ' + parentName + ',\n\n';
    msg += 'Berikut adalah prestasi anak anda untuk bulan *' + monthNames[month] + ' ' + year + '*:\n\n';

    msg += '👨‍🎓 *Pelajar:* ' + student.name + '\n';
    msg += '📚 *Kelas:* ' + (student.class || '-') + '\n\n';

    // Count statuses
    var lancar = 0, kurang = 0, tidak = 0, nazirah = 0, iqra = 0;
    var juzDetails = [];

    for (var juzNum = 1; juzNum <= 30; juzNum++) {
        var data = prestasi.juzData[juzNum];
        if (!data) continue;

        if (data.type === 'iqra') {
            iqra++;
        } else if (data.type === 'nazirah') {
            nazirah++;
            juzDetails.push('Juz ' + juzNum + ': 📖 Nazirah Khatam (Kali ke-' + data.count + ')');
        } else if (data.type === 'hafazan') {
            var avg = Math.round(data.avgScore);
            var status = '';
            var icon = '';

            if (avg >= 80) {
                lancar++;
                status = 'Lancar';
                icon = '🟢';
            } else if (avg >= 60) {
                kurang++;
                status = 'Kurang Lancar';
                icon = '🟡';
            } else {
                tidak++;
                status = 'Tidak Lancar';
                icon = '🔴';
            }
            juzDetails.push('Juz ' + juzNum + ': ' + icon + ' ' + status + ' (' + avg + '%)');
        }
    }

    // Summary
    if (iqra > 0 && lancar === 0 && kurang === 0 && tidak === 0 && nazirah === 0) {
        msg += '📖 *Status:* IQRA\'\n';
        msg += 'Anak masih dalam peringkat Iqra\'. Teruskan usaha!\n\n';
    } else {
        msg += '*📊 RINGKASAN:*\n';
        if (lancar > 0) msg += '🟢 Lancar: ' + lancar + ' Juz\n';
        if (kurang > 0) msg += '🟡 Kurang Lancar: ' + kurang + ' Juz\n';
        if (tidak > 0) msg += '🔴 Tidak Lancar: ' + tidak + ' Juz\n';
        if (nazirah > 0) msg += '📖 Nazirah Khatam: ' + nazirah + ' Juz\n';
        if (iqra > 0) msg += '📕 Iqra\': ' + iqra + ' (masih Iqra\')\n';
        msg += '\n';

        // Detail Juz
        if (juzDetails.length > 0) {
            msg += '*📋 DETAIL PRESTASI:*\n';
            for (var i = 0; i < juzDetails.length; i++) {
                msg += '• ' + juzDetails[i] + '\n';
            }
            msg += '\n';
        }
    }

    // Tiada rekod
    if (juzDetails.length === 0 && iqra === 0) {
        msg += '⚠️ *Tiada rekod hafazan untuk bulan ini.*\n';
        msg += 'Sila berbincang dengan guru.\n\n';
    }

    msg += '━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Sebarang pertanyaan, sila hubungi guru.\n\n';
    msg += '_Madrasah Tahfiz Pekan Sungai Buloh_\n';
    msg += '_Jazakumullah Khairan 🤲_';

    return msg;
}

