// ===== EDIT CASH ENTRY ======================
// ============================================

var editingCashEntryId = null;

function editCashEntry(entryId) {
    appData = loadData();
    if (!appData.cashbook) return;

    // Find entry
    var entry = null;
    for (var i = 0; i < appData.cashbook.length; i++) {
        if (appData.cashbook[i].id === entryId) {
            entry = appData.cashbook[i];
            break;
        }
    }

    if (!entry) {
        showToast('❌ Catatan tidak ditemui');
        return;
    }

    editingCashEntryId = entryId;

    // SIMPAN ref asal sebelum form dibuka
    var originalRef = entry.ref || '';

    // Open form if not already open
    var section = document.getElementById('cashFormSection');
    if (section.classList.contains('hidden')) {
        toggleCashForm();
    }

    // Fill form with existing data
    document.getElementById('cashDate').value = entry.date || '';
    document.getElementById('cashType').value = entry.type || '';
    document.getElementById('cashPayMethod').value = entry.payMethod || 'Tunai';
    document.getElementById('cashPerson').value = entry.person || '';
    document.getElementById('cashNotes').value = entry.notes || '';

    // Set student link
    var studentLink = document.getElementById('cashStudentLink');
    if (studentLink && entry.studentId) {
        studentLink.value = entry.studentId;
    }

    // Set ref styling WITHOUT generating new number
    var refInput = document.getElementById('cashRef');
    if (entry.type === 'debit') {
        refInput.style.background = '#f0faf4';
        refInput.style.fontWeight = '700';
        refInput.style.color = 'var(--primary-dark)';
        updateRefHint('🧾 Resit Rasmi');
    } else {
        refInput.style.background = '#faf0f0';
        refInput.style.fontWeight = '700';
        refInput.style.color = '#8b1a1a';
        updateRefHint('📋 Payment Voucher');
    }

    // FORCE set ref ASAL (selepas styling, jangan bagi override)
    refInput.value = originalRef;

    // Clear existing items
    cashItemCount = 0;
    document.getElementById('cashItemsList').innerHTML = '';

    // Check if part of batch
    var batchEntries = [];
    if (entry.batchId) {
        for (var i = 0; i < appData.cashbook.length; i++) {
            if (appData.cashbook[i].batchId === entry.batchId) {
                batchEntries.push(appData.cashbook[i]);
            }
        }
        batchEntries.sort(function(a, b) {
            return (a.batchIndex || 0) - (b.batchIndex || 0);
        });
    } else {
        batchEntries = [entry];
    }

    // Add items to form
    for (var i = 0; i < batchEntries.length; i++) {
        addCashItem();

        var lastItem = document.querySelector('#cashItemsList .cash-item-row:last-child');
        if (lastItem) {
            var descInput = lastItem.querySelector('.cash-item-desc');
            var catSelect = lastItem.querySelector('.cash-item-category');
            var amtInput = lastItem.querySelector('.cash-item-amount');

            if (descInput) descInput.value = batchEntries[i].description || '';
            if (catSelect) catSelect.value = batchEntries[i].category || '';
            if (amtInput) amtInput.value = batchEntries[i].amount || 0;
        }
    }

    updateItemsTotal();

    // FORCE set ref ASAL sekali lagi (safety - pastikan tak override)
    setTimeout(function() {
        document.getElementById('cashRef').value = originalRef;
    }, 100);

    // Change submit button text
    var form = document.getElementById('cashEntryForm');
    var submitBtn = form.querySelector('button[type="submit"]');
    if (submitBtn) {
        submitBtn.innerHTML = '💾 Kemaskini Catatan';
        submitBtn.style.background = 'linear-gradient(135deg, #f59e0b, #d97706)';
    }

    // Scroll to form
    section.scrollIntoView({ behavior: 'smooth', block: 'start' });

    showToast('✏️ Mode edit - No. ' + originalRef + ' (kekal)');
}

// Override addCashEntry to handle edit mode
var originalAddCashEntry = window.addCashEntry;
window.addCashEntry = function(event) {
    event.preventDefault();

    if (editingCashEntryId) {
        // EDIT MODE - update existing
        updateCashEntry();
    } else {
        // ADD MODE - original function
        originalAddCashEntry(event);
    }
};

function updateCashEntry() {
    if (!editingCashEntryId) return;

    appData = loadData();
    if (!appData.cashbook) appData.cashbook = [];

    var type = document.getElementById('cashType').value;
    if (!type) {
        showToast('❌ Sila pilih jenis transaksi');
        return;
    }

    var items = [];
    var itemRows = document.querySelectorAll('#cashItemsList .cash-item-row');

    if (itemRows.length === 0) {
        showToast('❌ Sila tambah sekurang-kurangnya satu butiran');
        return;
    }

    for (var i = 0; i < itemRows.length; i++) {
        var row = itemRows[i];
        var desc = row.querySelector('.cash-item-desc').value.trim();
        var cat = row.querySelector('.cash-item-category').value;
        var amt = parseFloat(row.querySelector('.cash-item-amount').value);

        if (!desc || !cat || !amt) {
            showToast('❌ Sila lengkapkan butiran #' + (i + 1));
            return;
        }

        items.push({
            description: desc,
            category: cat,
            amount: amt
        });
    }

    var commonDate = document.getElementById('cashDate').value;
    var commonRef = document.getElementById('cashRef').value.trim();
    var commonPayMethod = document.getElementById('cashPayMethod').value;
    var commonPerson = document.getElementById('cashPerson').value.trim();
    var commonNotes = document.getElementById('cashNotes').value.trim();
    var commonStudentId = document.getElementById('cashStudentLink').value;

    // Find original entry to get batchId
    var originalEntry = null;
    for (var i = 0; i < appData.cashbook.length; i++) {
        if (appData.cashbook[i].id === editingCashEntryId) {
            originalEntry = appData.cashbook[i];
            break;
        }
    }

    if (!originalEntry) {
        showToast('❌ Catatan asal tidak ditemui');
        return;
    }

    var batchId = originalEntry.batchId || editingCashEntryId;

    // Remove all old batch entries
    var newCashbook = [];
    for (var i = 0; i < appData.cashbook.length; i++) {
        var isSameBatch = appData.cashbook[i].batchId === batchId;
        var isSameEntry = appData.cashbook[i].id === editingCashEntryId;

        if (!isSameBatch && !isSameEntry) {
            newCashbook.push(appData.cashbook[i]);
        }
    }

    // Add updated entries
    var newBatchId = 'BATCH' + Date.now();
    for (var i = 0; i < items.length; i++) {
        var entry = {
            id: 'CASH' + Date.now() + '_' + i,
            batchId: newBatchId,
            batchIndex: i + 1,
            batchTotal: items.length,
            date: commonDate,
            ref: commonRef,
            description: items[i].description,
            category: items[i].category,
            type: type,
            amount: items[i].amount,
            payMethod: commonPayMethod,
            notes: commonNotes,
            person: commonPerson,
            studentId: commonStudentId || null,
            createdAt: originalEntry.createdAt || new Date().toISOString(),
            updatedAt: new Date().toISOString()
        };
        newCashbook.push(entry);
    }

    appData.cashbook = newCashbook;
    saveData(appData);

    var totalAmount = 0;
    for (var i = 0; i < items.length; i++) totalAmount += items[i].amount;

    showToast('✅ Catatan dikemaskini! Total: RM ' + totalAmount.toFixed(2));

    // Reset edit mode
    editingCashEntryId = null;
    resetCashForm();
    renderCashbook();
}

