    var config = adminCategoryConfig[category];
    if (config && config.tabs.length > 0) {
        var firstTab = config.tabs[0];
        switchTab(firstTab.id, null);

        // Highlight first subtab
        setTimeout(function() {
            var firstSubtab = document.querySelector('.admin-subtab');
            if (firstSubtab) firstSubtab.classList.add('active');
        }, 50);
    }

     if (category === 'hutang') {
        initHutang();
    }

