// ============================================
// ===== REORDER CASHBOOK ENTRIES =============
// ============================================

function moveCashEntry(entryId, direction) {
    appData = loadData();
    if (!appData.cashbook) return;

    // Sort cashbook by date first
    appData.cashbook.sort(function(a, b) {
        return new Date(a.date) - new Date(b.date);
    });

    // Find entry index
    var currentIdx = -1;
    for (var i = 0; i < appData.cashbook.length; i++) {
        if (appData.cashbook[i].id === entryId) {
            currentIdx = i;
            break;
        }
    }

    if (currentIdx === -1) return;

    var entry = appData.cashbook[currentIdx];
    var targetIdx = currentIdx + direction; // -1 = naik, +1 = turun

    // Boundary check
    if (targetIdx < 0 || targetIdx >= appData.cashbook.length) return;

    var targetEntry = appData.cashbook[targetIdx];

    // Hanya boleh swap kalau TARIKH SAMA
    if (entry.date !== targetEntry.date) {
        showToast('⚠️ Hanya boleh susun entry tarikh yang sama');
        return;
    }

    // Swap positions
    appData.cashbook[currentIdx] = targetEntry;
    appData.cashbook[targetIdx] = entry;

    // Add sortOrder to maintain position
    for (var i = 0; i < appData.cashbook.length; i++) {
        appData.cashbook[i].sortOrder = i;
    }

    saveData(appData);
    renderCashbook();
    showToast('✅ Entry disusun semula');
}

