// Get unique persons dari cashbook
function getAllPersons() {
    if (!appData || !appData.cashbook) return [];
    
    var personsMap = {};
    
    for (var i = 0; i < appData.cashbook.length; i++) {
        var person = appData.cashbook[i].person;
        if (person && person.trim()) {
            var key = person.toUpperCase().trim();
            if (!personsMap[key]) {
                personsMap[key] = {
                    name: person.trim(),
                    count: 0,
                    lastUsed: appData.cashbook[i].date
                };
            }
            personsMap[key].count++;
            
            // Update lastUsed kalau lebih recent
            if (appData.cashbook[i].date > personsMap[key].lastUsed) {
                personsMap[key].lastUsed = appData.cashbook[i].date;
            }
        }
    }
    
    // Convert to array & sort by count (terbanyak dulu)
    var persons = [];
    for (var key in personsMap) {
        persons.push(personsMap[key]);
    }
    
    persons.sort(function(a, b) {
        return b.count - a.count; // Sort by count descending
    });
    
    return persons;
}

// Show suggestions
function showPersonSuggestions() {
    var input = document.getElementById('cashPerson');
    if (input) {
        filterPersonSuggestions(input.value);
    }
}

// Hide suggestions
function hidePersonSuggestions() {
    var el = document.getElementById('personSuggestions');
    if (el) el.style.display = 'none';
}

// Filter suggestions based on input
function filterPersonSuggestions(searchValue) {
    var container = document.getElementById('personSuggestions');
    if (!container) return;
    
    var persons = getAllPersons();
    
    if (persons.length === 0) {
        container.style.display = 'none';
        return;
    }
    
    var search = (searchValue || '').toUpperCase().trim();
    
    // Filter
    var filtered = persons.filter(function(p) {
        if (!search) return true;
        return p.name.toUpperCase().indexOf(search) > -1;
    });
    
    if (filtered.length === 0) {
        container.style.display = 'none';
        return;
    }
    
    // Build dropdown HTML
    var html = '';
    
    // Header
    html += '<div style="padding:8px 12px;background:#f8fafc;font-size:0.75rem;color:#64748b;font-weight:700;border-bottom:1px solid #e2e8f0;">';
    html += '💡 ' + filtered.length + ' nama dari rekod sebelum';
    html += '</div>';
    
    // Limit to top 20
    var displayCount = Math.min(filtered.length, 20);
    
    for (var i = 0; i < displayCount; i++) {
        var p = filtered[i];
        html += '<div onclick="selectPerson(\'' + p.name.replace(/'/g, "\\'") + '\')" ';
        html += 'style="padding:10px 12px;cursor:pointer;border-bottom:1px solid #f1f5f9;transition:background 0.2s;display:flex;justify-content:space-between;align-items:center;" ';
        html += 'onmouseover="this.style.background=\'#faf5ff\';" ';
        html += 'onmouseout="this.style.background=\'white\';">';
        
        html += '<div>';
        html += '<div style="font-weight:600;color:#1f2937;font-size:0.92rem;">' + p.name + '</div>';
        html += '<div style="font-size:0.72rem;color:#94a3b8;margin-top:2px;">📊 Digunakan ' + p.count + ' kali</div>';
        html += '</div>';
        
        html += '<div style="font-size:0.7rem;color:#94a3b8;">Klik untuk pilih</div>';
        html += '</div>';
    }
    
    if (filtered.length > 20) {
        html += '<div style="padding:8px 12px;background:#fef3c7;font-size:0.72rem;color:#92400e;text-align:center;">';
        html += '⚠️ Menunjukkan 20 teratas. Taip untuk cari lebih...';
        html += '</div>';
    }
    
    container.innerHTML = html;
    container.style.display = 'block';
}

// Select person dari dropdown
function selectPerson(name) {
    var input = document.getElementById('cashPerson');
    if (input) {
        input.value = name;
        hidePersonSuggestions();
        
        // Trigger autosuggest student
        if (typeof setupPersonAutosuggest === 'function') {
            input.dispatchEvent(new Event('input'));
        }
    }
}

// ============================================
// ===== TITLE CASE (AUTO CAPITALIZE) =========
// ============================================

var KATA_HUBUNG = [
    // Malay
    'dan', 'atau', 'untuk', 'dari', 'ke', 'di', 'pada', 'oleh', 'dengan',
    'bin', 'binti', 'bt', 'b', 'a/l', 'a/p',
    'dll', 'dsb', 'iaitu', 'serta', 'tapi', 'sebab', 'kerana',
    'yang', 'ini', 'itu', 'juga', 'agar', 'supaya', 'kalau',
    // English
    'and', 'or', 'for', 'from', 'to', 'at', 'on', 'by', 'with', 'in', 'of',
    'the', 'a', 'an', 'is', 'are', 'was', 'were',
    // Arabic
    'al', 'el', 'ibn', 'ibnu', 'abu', 'abd', 'abdul',
    // Common
    'pn', 'en', 'tn', 'dr', 'haji', 'hj', 'hjh', 'sdr', 'sdri'
];

function toTitleCase(str) {
    if (!str) return '';
    
    return str.toLowerCase().split(/\s+/).map(function(word, index) {
        if (!word) return word;
        
        // Always capitalize first word
        if (index === 0) {
            return word.charAt(0).toUpperCase() + word.slice(1);
        }
        
        // Check kalau kata hubung
        if (KATA_HUBUNG.indexOf(word) > -1) {
            return word; // Keep lowercase
        }
        
        // Handle hyphenated words (cth: "Al-Quran")
        if (word.indexOf('-') > -1) {
            return word.split('-').map(function(part) {
                if (!part) return part;
                return part.charAt(0).toUpperCase() + part.slice(1);
            }).join('-');
        }
        
        // Handle apostrophe (cth: D'Aman)
        if (word.indexOf("'") > -1) {
            return word.split("'").map(function(part) {
                if (!part) return part;
                return part.charAt(0).toUpperCase() + part.slice(1);
            }).join("'");
        }
        
        // Normal capitalize
        return word.charAt(0).toUpperCase() + word.slice(1);
    }).join(' ');
}

// Apply title case ke input
function applyTitleCase(inputElement) {
    if (!inputElement) return;
    var cursorPos = inputElement.selectionStart;
    inputElement.value = toTitleCase(inputElement.value);
    inputElement.setSelectionRange(cursorPos, cursorPos);
}

// Setup auto title case untuk fields tertentu
// Setup auto title case untuk SEMUA text input
document.addEventListener('DOMContentLoaded', function() {
    setTimeout(function() {
        applyAutoTitleCaseToAllFields();
    }, 1000);
});

// Apply juga setiap 2 saat untuk dynamic content
setInterval(applyAutoTitleCaseToAllFields, 2000);

function applyAutoTitleCaseToAllFields() {
    // Get semua text inputs & textareas
    var allInputs = document.querySelectorAll('input[type="text"], textarea');
    
    for (var i = 0; i < allInputs.length; i++) {
        var input = allInputs[i];
        
        // Skip kalau dah ada listener
        if (input.dataset.titleCaseApplied === 'true') continue;
        
        // Skip fields tertentu
        var skipFields = [
            'loginId', 'loginPass',
            'parentLoginId', 'parentLoginPass',
            'editParentLoginId', 'editParentLoginPass',
            'workerLoginId', 'workerLoginPass',
            'searchStudent', 'profileSearch',
            'cashRef', 'cashFilterYear',
            'studentPhoto', 'fatherEmail', 'motherEmail',
            'galleryFiles', 'heroVideoUrl', 'heroFallbackImage',
            'studentIC', 'fatherIC', 'motherIC', 'emergencyIC',
            'editStudentIC', 'editFatherIC', 'editMotherIC',
            'fatherPhone', 'motherPhone', 'emergencyPhone',
            'editFatherPhone', 'editMotherPhone', 'editEmergencyPhone',
            'workerPhone', 'workerIC', 'workerBank',
            'hutangProfit', 'hutangJumlah', 'hutangBilanganBulan',
            'invoiceMonth', 'invoiceYear'
        ];
        
        var shouldSkip = false;
        for (var s = 0; s < skipFields.length; s++) {
            if (input.id === skipFields[s]) {
                shouldSkip = true;
                break;
            }
        }
        
        // Skip kalau type number, email, tel, password, date, url
        var inputType = input.type || '';
        if (['number', 'email', 'tel', 'password', 'date', 'time', 'url', 'file'].indexOf(inputType) > -1) {
            shouldSkip = true;
        }
        
        // Skip kalau ada class no-title-case
        if (input.classList.contains('no-title-case')) {
            shouldSkip = true;
        }
        
        if (shouldSkip) {
            input.dataset.titleCaseApplied = 'true';
            continue;
        }
        
        // Apply auto title case
        input.addEventListener('blur', function() {
            applyTitleCase(this);
        });
        
        input.dataset.titleCaseApplied = 'true';
    }
}

