// Get unique descriptions dari cashbook
function getAllDescriptions() {
    if (!appData || !appData.cashbook) return [];
    
    var descMap = {};
    
    for (var i = 0; i < appData.cashbook.length; i++) {
        var desc = appData.cashbook[i].description;
        var category = appData.cashbook[i].category;
        
        if (desc && desc.trim()) {
            var key = desc.toUpperCase().trim();
            if (!descMap[key]) {
                descMap[key] = {
                    description: desc.trim(),
                    category: category || '',
                    count: 0,
                    lastUsed: appData.cashbook[i].date,
                    lastAmount: appData.cashbook[i].amount || 0
                };
            }
            descMap[key].count++;
            
            // Update lastUsed kalau lebih recent
            if (appData.cashbook[i].date > descMap[key].lastUsed) {
                descMap[key].lastUsed = appData.cashbook[i].date;
                descMap[key].lastAmount = appData.cashbook[i].amount || 0;
                descMap[key].category = category || descMap[key].category;
            }
        }
    }
    
    // Convert to array & sort by count (terbanyak dulu)
    var descriptions = [];
    for (var key in descMap) {
        descriptions.push(descMap[key]);
    }
    
    descriptions.sort(function(a, b) {
        return b.count - a.count;
    });
    
    return descriptions;
}

