// Filter suggestions
function filterDescSuggestions(inputElement, searchValue) {
    var dropdownId = inputElement.getAttribute('data-suggestions-id');
    if (!dropdownId) return;
    
    var container = document.getElementById(dropdownId);
    if (!container) return;
    
    var descriptions = getAllDescriptions();
    
    if (descriptions.length === 0) {
        container.style.display = 'none';
        return;
    }
    
    var search = (searchValue || '').toUpperCase().trim();
    
    var filtered = descriptions.filter(function(d) {
        if (!search) return true;
        return d.description.toUpperCase().indexOf(search) > -1;
    });
    
    if (filtered.length === 0) {
        container.style.display = 'none';
        return;
    }
    
    var html = '';
    
    // Header
    html += '<div style="padding:8px 12px;background:#f8fafc;font-size:0.75rem;color:#64748b;font-weight:700;border-bottom:1px solid #e2e8f0;">';
    html += '💡 ' + filtered.length + ' butiran dari rekod sebelum';
    html += '</div>';
    
    var displayCount = Math.min(filtered.length, 15);
    
    for (var i = 0; i < displayCount; i++) {
        var d = filtered[i];
        var escapedDesc = d.description.replace(/'/g, "\\'");
        var escapedCat = d.category.replace(/'/g, "\\'");
        
        html += '<div onclick="selectDescription(\'' + dropdownId + '\', \'' + escapedDesc + '\', \'' + escapedCat + '\', ' + d.lastAmount + ')" ';
        html += 'style="padding:10px 12px;cursor:pointer;border-bottom:1px solid #f1f5f9;transition:background 0.2s;" ';
        html += 'onmouseover="this.style.background=\'#faf5ff\';" ';
        html += 'onmouseout="this.style.background=\'white\';">';
        
        html += '<div style="font-weight:600;color:#1f2937;font-size:0.92rem;">' + d.description + '</div>';
        
        html += '<div style="display:flex;gap:10px;align-items:center;margin-top:4px;font-size:0.72rem;">';
        if (d.category) {
            html += '<span style="background:#dbeafe;color:#1e40af;padding:2px 6px;border-radius:4px;font-weight:600;">' + d.category + '</span>';
        }
        html += '<span style="color:#94a3b8;">📊 ' + d.count + 'x digunakan</span>';
        if (d.lastAmount > 0) {
            html += '<span style="color:#7c3aed;font-weight:600;">RM ' + d.lastAmount.toFixed(2) + '</span>';
        }
        html += '</div>';
        
        html += '</div>';
    }
    
    if (filtered.length > 15) {
        html += '<div style="padding:8px 12px;background:#fef3c7;font-size:0.72rem;color:#92400e;text-align:center;">';
        html += '⚠️ Menunjukkan 15 teratas. Taip untuk cari lebih...';
        html += '</div>';
    }
    
    container.innerHTML = html;
    container.style.display = 'block';
}

// Select description dari dropdown
function selectDescription(dropdownId, desc, category, amount) {
    var dropdown = document.getElementById(dropdownId);
    if (!dropdown) return;
    
    // Find parent row
    var row = dropdown.closest('.cash-item-row');
    if (!row) return;
    
    // Set description
    var descInput = row.querySelector('.cash-item-desc');
    if (descInput) {
        descInput.value = desc;
    }
    
    // Auto-set category
    var catSelect = row.querySelector('.cash-item-category');
    if (catSelect && category) {
        catSelect.value = category;
    }
    
    // Optional: Auto-suggest amount (uncomment kalau nak)
    // var amountInput = row.querySelector('.cash-item-amount');
    // if (amountInput && amount > 0) {
    //     amountInput.value = amount;
    //     if (typeof updateItemsTotal === 'function') updateItemsTotal();
    // }
    
    // Hide dropdown
    dropdown.style.display = 'none';
    
    showToast('✅ Butiran dipilih: ' + desc);
}

// Setup autocomplete untuk semua butiran input
function setupDescAutocomplete() {
    // Listen for input events on all cash-item-desc fields
    document.addEventListener('input', function(e) {
        if (e.target && e.target.classList && e.target.classList.contains('cash-item-desc')) {
            // Create dropdown if not exist
            if (!e.target.getAttribute('data-suggestions-id')) {
                var uniqueId = 'descSuggest_' + Date.now() + '_' + Math.random().toString(36).substr(2, 5);
                e.target.setAttribute('data-suggestions-id', uniqueId);
                
                // Wrap input in relative container
                var wrapper = document.createElement('div');
                wrapper.style.cssText = 'position:relative;';
                e.target.parentNode.insertBefore(wrapper, e.target);
                wrapper.appendChild(e.target);
                
                // Add dropdown
                var dropdown = document.createElement('div');
                dropdown.id = uniqueId;
                dropdown.style.cssText = 'display:none;position:absolute;top:100%;left:0;right:0;background:white;border:2px solid #e2e8f0;border-radius:8px;max-height:300px;overflow-y:auto;z-index:1000;box-shadow:0 8px 25px rgba(0,0,0,0.1);margin-top:4px;';
                wrapper.appendChild(dropdown);
                
                // Set autocomplete off
                e.target.setAttribute('autocomplete', 'off');
            }
            
            filterDescSuggestions(e.target, e.target.value);
        }
    });
    
    // Listen for focus events
    document.addEventListener('focus', function(e) {
        if (e.target && e.target.classList && e.target.classList.contains('cash-item-desc')) {
            if (e.target.getAttribute('data-suggestions-id')) {
                showDescSuggestions(e.target);
            } else {
                // Trigger input event to setup
                e.target.dispatchEvent(new Event('input'));
            }
        }
    }, true);
    
    // Listen for blur events
    document.addEventListener('blur', function(e) {
        if (e.target && e.target.classList && e.target.classList.contains('cash-item-desc')) {
            // Delay supaya boleh click suggestion
            setTimeout(function() {
                hideDescSuggestions(e.target);
            }, 200);
            
            // Apply title case
            applyTitleCase(e.target);
        }
    }, true);
}

// Auto-setup bila page load
document.addEventListener('DOMContentLoaded', function() {
    setTimeout(setupDescAutocomplete, 500);
});

// Trigger juga kalau setup later
setTimeout(setupDescAutocomplete, 1000);
setTimeout(setupDescAutocomplete, 2000);

