// ============================================
// ===== REKOD HUTANG MODULE ==================
// ============================================

var hutangData = [];

function initHutang() {
    console.log('💰 Init Hutang module...');
    loadHutangData();
}

// Load data from localStorage
function loadHutangData() {
    // Try localStorage first
    var saved = localStorage.getItem('hutangData');
    if (saved) {
        try {
            hutangData = JSON.parse(saved);
            console.log('✅ Loaded from localStorage:', hutangData.length, 'records');
            renderAllHutang();
            return;
        } catch(e) {
            console.log('❌ Parse error:', e);
            hutangData = [];
        }
    }

    // If no localStorage, try Firebase
    if (typeof firebaseReady !== 'undefined' && firebaseReady && typeof firebaseDb !== 'undefined') {
        firebaseDb.ref('hafazanData/hutangData').once('value').then(function(snapshot) {
            var data = snapshot.val();
            if (data && data.length > 0) {
                hutangData = data;
                saveHutangData();
                renderAllHutang();
                console.log('✅ Loaded from Firebase:', hutangData.length, 'records');
            } else {
                hutangData = [];
                renderAllHutang();
                console.log('📭 No data in Firebase');
            }
        }).catch(function(err) {
            console.log('❌ Firebase error:', err);
            hutangData = [];
            renderAllHutang();
        });
    } else {
        hutangData = [];
        renderAllHutang();
        console.log('⚠️ Firebase not ready');
    }
}
function saveHutangData() {
    localStorage.setItem('hutangData', JSON.stringify(hutangData));
    // Sync to Firebase
    if (typeof firebaseReady !== 'undefined' && firebaseReady && typeof firebaseDb !== 'undefined') {
        firebaseDb.ref('hafazanData/hutangData').set(hutangData).catch(function(err) {
            console.log('Firebase sync error:', err);
        });
    }
}

function renderHutangStats() {
    var total = hutangData.length;
    var belum = hutangData.filter(function(d) { return d.status === 'Belum Bayar'; }).length;
    var lunas = hutangData.filter(function(d) { return d.status === 'Lunas'; }).length;
    var totalAmount = hutangData.reduce(function(sum, d) { return sum + d.jumlah; }, 0);

    var el = function(id) { return document.getElementById(id); };
    if (el('hutangTotal')) el('hutangTotal').textContent = total;
    if (el('hutangBelum')) el('hutangBelum').textContent = belum;
    if (el('hutangLunas')) el('hutangLunas').textContent = lunas;
    if (el('hutangTotalAmount')) el('hutangTotalAmount').textContent = 'RM ' + totalAmount.toFixed(0);
}

