    // Copy button
    modalHtml += '<button onclick="copyUpdateLink()" style="padding:12px;background:linear-gradient(135deg,#3b82f6,#2563eb);color:white;border:none;border-radius:10px;font-weight:800;cursor:pointer;font-size:0.9rem;">📋 Copy Link</button>';
    
    // WhatsApp button
    var waLink = 'https://wa.me/';
    if (parentPhone) {
        var cleanPhone = parentPhone.replace(/[^0-9]/g, '');
        if (cleanPhone.startsWith('0')) cleanPhone = '60' + cleanPhone.substring(1);
        waLink += cleanPhone;
    }
    waLink += '?text=' + encodeURIComponent(message);
    
    modalHtml += '<a href="' + waLink + '" target="_blank" style="padding:12px;background:linear-gradient(135deg,#25d366,#128c7e);color:white;border:none;border-radius:10px;font-weight:800;cursor:pointer;font-size:0.9rem;text-decoration:none;text-align:center;display:flex;align-items:center;justify-content:center;gap:6px;">💬 WhatsApp</a>';
    
    modalHtml += '</div>';
    
