// ===== POPULATE HUTANG DROPDOWN =====
function populateHutangDropdown() {
    var select = document.getElementById('cashHutangLink');
    if (!select) return;
    
    appData = loadData();
    if (!appData.hutangList) appData.hutangList = [];
    
    var html = '<option value="">-- Tidak Link ke Hutang --</option>';
    
    // Filter hanya hutang aktif (belum lunas)
    var aktifList = [];
    for (var i = 0; i < appData.hutangList.length; i++) {
        var h = appData.hutangList[i];
        var totalBayar = 0;
        if (h.bayaranLog) {
            for (var j = 0; j < h.bayaranLog.length; j++) {
                totalBayar += h.bayaranLog[j].amount || 0;
            }
        }
        var baki = (h.totalDenganProfit || 0) - totalBayar;
        if (baki > 0) {
            aktifList.push({ index: i, data: h, baki: baki });
        }
    }
    
    if (aktifList.length === 0) {
        html += '<option value="" disabled>Tiada hutang aktif</option>';
    } else {
        for (var i = 0; i < aktifList.length; i++) {
            var item = aktifList[i];
            var h = item.data;
            var icon = h.jenis === 'peribadi' ? '👤' : '🕌';
            html += '<option value="' + item.index + '" data-bulanan="' + (h.bayaranBulanan || 0) + '">';
            html += icon + ' ' + h.nama + ' - Baki: RM ' + item.baki.toFixed(2);
            html += '</option>';
        }
    }
    
    select.innerHTML = html;
}

// ===== SHOW/HIDE HUTANG SECTION =====
function toggleHutangSection() {
    var typeEl = document.getElementById('cashType');
    var hutangSection = document.getElementById('hutangLinkSection');
    
    if (!typeEl || !hutangSection) return;
    
    var type = typeEl.value;
    
    // Check kalau ada item dengan kategori hutang
    var hasHutangCategory = false;
    var itemCategories = document.querySelectorAll('.cash-item-category');
    
    for (var i = 0; i < itemCategories.length; i++) {
        var catValue = itemCategories[i].value;
        if (catValue === 'Bayaran Hutang Madrasah' || 
            catValue === 'Bayaran Hutang Peribadi' || 
            catValue === 'Ansuran Bulanan' ||
            catValue === 'Pinjaman') {
            hasHutangCategory = true;
            break;
        }
    }
    
    // Tunjuk dropdown hutang kalau:
    // 1. Type = Credit DAN ada item dengan kategori hutang
    if (type === 'credit' && hasHutangCategory) {
        hutangSection.style.display = 'block';
        populateHutangDropdown();
    } else {
        hutangSection.style.display = 'none';
    }
}
// ===== AUTO-SUGGEST HUTANG bila taip description =====
function autoSuggestHutang() {
    var descEl = document.getElementById('cashDescription');
    var hutangSelect = document.getElementById('cashHutangLink');
    
    if (!descEl || !hutangSelect) return;
    
    var desc = descEl.value.toLowerCase();
    if (desc.length < 3) return;
    
    appData = loadData();
    if (!appData.hutangList) return;
    
    // Cari hutang yang nama match dengan description
    for (var i = 0; i < appData.hutangList.length; i++) {
        var h = appData.hutangList[i];
        var hutangNama = (h.nama || '').toLowerCase();
        
        if (hutangNama && desc.indexOf(hutangNama) > -1) {
            // Found match!
            hutangSelect.value = i;
            
            // Show notification
            if (typeof showToast === 'function') {
                showToast('💡 Auto-detected: ' + h.nama);
            }
            
            // Trigger change
            onHutangSelect();
            return;
        }
    }
}

// ===== ON HUTANG SELECT =====
function onHutangSelect() {
    var select = document.getElementById('cashHutangLink');
    if (!select || !select.value) return;
    
    var amountEl = document.getElementById('cashAmount');
    if (!amountEl) return;
    
    var selected = select.options[select.selectedIndex];
    var bulanan = parseFloat(selected.dataset.bulanan) || 0;
    
    // Auto-fill amount kalau kosong
    if (!amountEl.value || amountEl.value === '0') {
        amountEl.value = bulanan.toFixed(2);
    }
    
    if (typeof showToast === 'function') {
        showToast('💰 Bayaran bulanan: RM ' + bulanan.toFixed(2));
    }
}

// ===== AUTO-RECORD HUTANG PAYMENT bila Save =====
function autoRecordHutangPayment(cashEntry) {
    var hutangSelect = document.getElementById('cashHutangLink');
    if (!hutangSelect || !hutangSelect.value) return false;
    
    var hutangIndex = parseInt(hutangSelect.value);
    if (isNaN(hutangIndex)) return false;
    
    // PENTING: Load data SEGAR
    var freshData = loadData();
    if (!freshData.hutangList || !freshData.hutangList[hutangIndex]) return false;
    
    var hutang = freshData.hutangList[hutangIndex];
    
    // Get amount and date from cash entry
    var amount = cashEntry.amount || 0;
    var date = cashEntry.date || new Date().toISOString().split('T')[0];
    var cashEntryId = cashEntry.id || ('CASH_' + Date.now());
    
    if (amount <= 0) return false;
    
    // ===== CHECK DUPLICATE - PENTING! =====
    if (!hutang.bayaranLog) hutang.bayaranLog = [];
    
    // Cek kalau dah ada bayaran dengan cashEntryId yang sama
    var alreadyExists = false;
    for (var i = 0; i < hutang.bayaranLog.length; i++) {
        if (hutang.bayaranLog[i].cashEntryId === cashEntryId) {
            alreadyExists = true;
            break;
        }
    }
    
    if (alreadyExists) {
        console.log('⚠️ Bayaran ini sudah direkod sebelum ini');
        return false;
    }
    
    // Get bulan
    var dateParts = date.split('-');
    var bulan = dateParts[0] + '-' + dateParts[1];
    
    // Add to bayaranLog
    hutang.bayaranLog.push({
        date: date,
        bulan: bulan,
        amount: amount,
        catatan: 'Auto dari Buku Tunai: ' + (cashEntry.ref || cashEntry.description || ''),
        cashEntryId: cashEntryId,
        timestamp: new Date().toISOString()
    });
    
    // Save dengan data segar
    saveData(freshData);
    
    // Update global appData
    appData = freshData;
    
    if (typeof showToast === 'function') {
        showToast('✅ Bayaran RM ' + amount.toFixed(2) + ' direkod ke hutang ' + hutang.nama);
    }
    
    console.log('✅ Hutang payment recorded:', hutang.nama, 'RM', amount);
    
    return true;
}

// ===== AUTO-RECORD HUTANG PAYMENT (Manual - dengan hutang index) =====
function autoRecordHutangPaymentManual(cashEntry, hutangIndex) {
    var idx = parseInt(hutangIndex);
    if (isNaN(idx)) return false;
    
    var freshData = loadData();
    if (!freshData.hutangList || !freshData.hutangList[idx]) return false;
    
    var hutang = freshData.hutangList[idx];
    
    var amount = cashEntry.amount || 0;
    var date = cashEntry.date || new Date().toISOString().split('T')[0];
    var cashEntryId = cashEntry.id || ('CASH_' + Date.now());
    
    if (amount <= 0) return false;
    
    if (!hutang.bayaranLog) hutang.bayaranLog = [];
    
    // Check duplicate
    for (var i = 0; i < hutang.bayaranLog.length; i++) {
        if (hutang.bayaranLog[i].cashEntryId === cashEntryId) {
            console.log('⚠️ Bayaran ini sudah direkod');
            return false;
        }
    }
    
    var dateParts = date.split('-');
    var bulan = dateParts[0] + '-' + dateParts[1];
    
    hutang.bayaranLog.push({
        date: date,
        bulan: bulan,
        amount: amount,
        catatan: 'Auto dari Buku Tunai: ' + (cashEntry.ref || cashEntry.description || ''),
        cashEntryId: cashEntryId,
        timestamp: new Date().toISOString()
    });
    
    saveData(freshData);
    appData = freshData;
    
    if (typeof showToast === 'function') {
        showToast('✅ Bayaran RM ' + amount.toFixed(2) + ' direkod ke hutang ' + hutang.nama);
    }
    
    console.log('✅ Hutang payment recorded:', hutang.nama, 'RM', amount);
    return true;
}

