// ===== CHECK GAJI CUKUP (selepas add cash entry) =====
function checkGajiCukup(savedEntries) {
    appData = loadData();
    if (!appData.workers || !appData.cashbook) return;
    
    // Get unique ustaz dari entries yang baru ditambah
    var ustazChecked = {};
    
    for (var i = 0; i < savedEntries.length; i++) {
        var entry = savedEntries[i];
        var cat = (entry.category || '').toUpperCase();
        var desc = (entry.description || '').toUpperCase();
        
        // Hanya check kalau ini gaji-related
        var isGaji = cat.indexOf('GAJI') > -1 || cat.indexOf('ELAUN') > -1 || desc.indexOf('ELAUN') > -1;
        if (!isGaji) continue;
        
        // Detect ustaz
        var ustaz = detectUstazFromDescription(entry.description, appData.workers);
        if (!ustaz) continue;
        
        // Detect bulan & tahun dari description
        var detectedInfo = detectMonthYearFromDescription(entry.description);
        var month = detectedInfo.month || parseInt(entry.date.split('-')[1]);
        var year = detectedInfo.year || parseInt(entry.date.split('-')[0]);
        
        // Unique key untuk avoid duplicate check
        var key = ustaz + '_' + year + '_' + month;
        if (ustazChecked[key]) continue;
        ustazChecked[key] = true;
        
        // Get worker info
        var worker = null;
        for (var w = 0; w < appData.workers.length; w++) {
            if (appData.workers[w].name === ustaz) {
                worker = appData.workers[w];
                break;
            }
        }
        
        if (!worker || !worker.monthlySalary) continue;
        
        var monthlySalary = parseFloat(worker.monthlySalary) || 0;
        if (monthlySalary <= 0) continue;
        
        // Calculate total bayaran untuk ustaz ni dalam bulan ni
        var totalPaid = 0;
        var paymentsForMonth = [];
        
        for (var c = 0; c < appData.cashbook.length; c++) {
            var cashEntry = appData.cashbook[c];
            if (cashEntry.type !== 'credit') continue;
            
            var cDesc = (cashEntry.description || '').toUpperCase();
            var cCat = (cashEntry.category || '').toUpperCase();
            
            var cIsGaji = cCat.indexOf('GAJI') > -1 || cCat.indexOf('ELAUN') > -1 || cDesc.indexOf('ELAUN') > -1;
            if (!cIsGaji) continue;
            
            var cUstaz = detectUstazFromDescription(cashEntry.description, appData.workers);
            if (cUstaz !== ustaz) continue;
            
            var cInfo = detectMonthYearFromDescription(cashEntry.description);
            var cMonth = cInfo.month || parseInt(cashEntry.date.split('-')[1]);
            var cYear = cInfo.year || parseInt(cashEntry.date.split('-')[0]);
            
            if (cMonth === month && cYear === year) {
                totalPaid += cashEntry.amount;
                paymentsForMonth.push({
                    date: cashEntry.date,
                    amount: cashEntry.amount,
                    ref: cashEntry.ref,
                    description: cashEntry.description
                });
            }
        }
        
        // Check kalau dah cukup atau lebih
        if (totalPaid >= monthlySalary) {
            // GAJI CUKUP! Show popup
            showGajiCukupPopup({
                worker: worker,
                ustaz: ustaz,
                month: month,
                year: year,
                monthlySalary: monthlySalary,
                totalPaid: totalPaid,
                payments: paymentsForMonth,
                isExceed: totalPaid > monthlySalary
            });
            
            // Hanya tunjuk satu popup sekali
            return;
        }
    }
}

