// ✅ FIX: Update quick action toggle + AUTO-SAVE ke Firebase
function updateQuickActionToggle(checkbox) {
    var key = checkbox.dataset.qa;
    var checked = checkbox.checked;

    if (!appData.parentPortalSettings) {
        appData.parentPortalSettings = getDefaultParentSettings();
    }
    if (!appData.parentPortalSettings.quickActions) {
        appData.parentPortalSettings.quickActions = {};
    }

    // Update memory
    appData.parentPortalSettings.quickActions[key] = checked;

    // Re-render visual
    renderQuickActionToggles(appData.parentPortalSettings.quickActions);

    // ✅ AUTO-SAVE ke Firebase (path spesifik)
    if (typeof firebase !== 'undefined' && firebase.database) {
        firebase.database().ref('hafazanData/parentPortalSettings/quickActions/' + key).set(checked)
            .then(function() {
                console.log('✅ Quick Action "' + key + '" saved: ' + checked);
            })
            .catch(function(err) {
                console.error('❌ Save gagal:', err.message);
                if (typeof showToast === 'function') {
                    showToast('❌ Gagal simpan: ' + err.message);
                }
                // Rollback UI kalau gagal
                checkbox.checked = !checked;
                appData.parentPortalSettings.quickActions[key] = !checked;
                renderQuickActionToggles(appData.parentPortalSettings.quickActions);
            });
    }
}

// ✅ FIX: Update tab toggle + AUTO-SAVE ke Firebase
function updateTabToggle(checkbox) {
    var key = checkbox.dataset.tab;
    var checked = checkbox.checked;

    if (!appData.parentPortalSettings) {
        appData.parentPortalSettings = getDefaultParentSettings();
    }
    if (!appData.parentPortalSettings.tabs) {
        appData.parentPortalSettings.tabs = {};
    }

    // Update memory
    appData.parentPortalSettings.tabs[key] = checked;

    // Re-render visual
    renderTabNavToggles(appData.parentPortalSettings.tabs);

    // ✅ AUTO-SAVE ke Firebase (path spesifik)
    if (typeof firebase !== 'undefined' && firebase.database) {
        firebase.database().ref('hafazanData/parentPortalSettings/tabs/' + key).set(checked)
            .then(function() {
                console.log('✅ Tab "' + key + '" saved: ' + checked);
            })
            .catch(function(err) {
                console.error('❌ Save gagal:', err.message);
                if (typeof showToast === 'function') {
                    showToast('❌ Gagal simpan: ' + err.message);
                }
                // Rollback UI kalau gagal
                checkbox.checked = !checked;
                appData.parentPortalSettings.tabs[key] = !checked;
                renderTabNavToggles(appData.parentPortalSettings.tabs);
            });
    }
}

// ✅ FIX: Save settings — guna specific path (bukan whole tree)
function saveParentPortalSettings() {
    if (!appData.parentPortalSettings) {
        appData.parentPortalSettings = getDefaultParentSettings();
    }

    if (typeof firebase !== 'undefined' && firebase.database) {
        firebase.database().ref('hafazanData/parentPortalSettings').set(appData.parentPortalSettings)
            .then(function() {
                if (typeof showToast === 'function') {
                    showToast('✅ Tetapan portal ibu bapa disimpan!');
                }

                // Summary log
                var qa = appData.parentPortalSettings.quickActions || {};
                var tabs = appData.parentPortalSettings.tabs || {};
                var qaActive = 0, tabsActive = 0;
                for (var k in qa) if (qa[k]) qaActive++;
                for (var k in tabs) if (tabs[k]) tabsActive++;

                console.log('✅ Parent Portal Settings Saved');
                console.log('   Quick Actions Active: ' + qaActive);
                console.log('   Tabs Active: ' + tabsActive);
            })
            .catch(function(err) {
                console.error('❌ Save gagal:', err.message);
                if (typeof showToast === 'function') {
                    showToast('❌ Gagal simpan: ' + err.message);
                }
            });
    } else {
        console.error('❌ Firebase tidak tersedia');
        if (typeof showToast === 'function') {
            showToast('❌ Firebase tidak tersedia');
        }
    }
}

// Auto-init when tab clicked
var _origSwitchTabParentSettings = window.switchTab;
window.switchTab = function(tabName, btn) {
    if (typeof _origSwitchTabParentSettings === 'function') {
        _origSwitchTabParentSettings(tabName, btn);
    }

    if (tabName === 'parentSettings' && typeof initParentSettings === 'function') {
        setTimeout(initParentSettings, 100);
    }
};

