// Populate location filter dropdown
function populateLocationFilter() {
    var select = document.getElementById('galleryFilterLocation');
    if (!select) return;
    
    // Save current value
    var currentValue = select.value;
    
    // Collect all unique locations
    var locationsMap = {};
    if (appData.gallery) {
        for (var i = 0; i < appData.gallery.length; i++) {
            var album = appData.gallery[i];
            if (album.location) {
                var locs = album.location.split(',');
                for (var j = 0; j < locs.length; j++) {
                    var loc = locs[j].trim();
                    if (loc) locationsMap[loc] = true;
                }
            }
        }
    }
    
    var locations = Object.keys(locationsMap).sort();
    
    // Build options
    var html = '<option value="all">Semua Lokasi (' + locations.length + ')</option>';
    for (var i = 0; i < locations.length; i++) {
        html += '<option value="' + locations[i] + '">📍 ' + locations[i] + '</option>';
    }
    
    // Only update if changed (to preserve selection)
    if (select.innerHTML !== html) {
        select.innerHTML = html;
        // Restore value if still exists
        if (currentValue && (currentValue === 'all' || locations.indexOf(currentValue) > -1)) {
            select.value = currentValue;
        }
    }
}

// Clear search
function clearGallerySearch() {
    var input = document.getElementById('gallerySearchInput');
    if (input) {
        input.value = '';
        renderGallery();
        input.focus();
    }
}

// Reset all filters
function resetGalleryFilters() {
    var searchInput = document.getElementById('gallerySearchInput');
    var categoryFilter = document.getElementById('galleryFilterCategory');
    var yearFilter = document.getElementById('galleryFilterYear');
    var locationFilter = document.getElementById('galleryFilterLocation');
    var sortBy = document.getElementById('gallerySortBy');
    
    if (searchInput) searchInput.value = '';
    if (categoryFilter) categoryFilter.value = 'all';
    if (yearFilter) yearFilter.value = 'all';
    if (locationFilter) locationFilter.value = 'all';
    if (sortBy) sortBy.value = 'newest';
    
    renderGallery();
    showToast('🔄 Filter direset');
}

