    html += '</div>';
    html += '</div>';
    html += '</div>';
    
    // Content
    html += '<div style="padding:25px;">';
    
    // Info
    html += '<div style="background:#f0fdf4;padding:15px;border-radius:12px;margin-bottom:20px;border-left:4px solid #10b981;">';
