    html += '<div id="downloadProgressFill" style="background:linear-gradient(90deg,#10b981,#047857);height:100%;width:0%;transition:width 0.3s;"></div>';
    html += '</div>';
    html += '<div id="downloadProgressText" style="text-align:center;font-weight:600;color:#047857;">Downloading...</div>';
