function closeDownloadModal() {
    var modal = document.getElementById('downloadModal');
    if (modal) modal.remove();
}

function startDownload(albumId, type) {
    var album = null;
    for (var i = 0; i < appData.gallery.length; i++) {
        if (appData.gallery[i].id === albumId) {
            album = appData.gallery[i];
            break;
        }
    }
    
    if (!album) return;
    
    var files = [];
    
    if (type === 'photos' || type === 'all') {
        if (album.photos) {
            for (var i = 0; i < album.photos.length; i++) {
                files.push({
                    url: album.photos[i].url || album.photos[i].displayUrl,
                    name: 'photo_' + (i + 1) + '.jpg',
                    type: 'photo'
                });
            }
        }
    }
    
    if (type === 'videos' || type === 'all') {
        if (album.videos) {
            for (var i = 0; i < album.videos.length; i++) {
                files.push({
                    url: album.videos[i].url,
                    name: 'video_' + (i + 1) + '.mp4',
                    type: 'video'
                });
            }
        }
    }
    
    if (files.length === 0) {
        alert('❌ Tiada fail untuk didownload');
        return;
    }
    
    // Confirm
    if (!confirm('📥 Download ' + files.length + ' fail?\n\nBrowser akan download satu-satu (ada delay 1 saat).\nAda kemungkinan browser tanya permission - klik "Allow" untuk semua.')) {
        return;
    }
    
    // Show progress
    document.getElementById('downloadProgress').style.display = 'block';
    
    // Sanitize album name for filename
    var albumName = (album.title || 'album').replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '_').substring(0, 40);
    
    var downloaded = 0;
    var failed = 0;
    
    function updateProgress() {
        var percent = Math.round((downloaded / files.length) * 100);
        document.getElementById('downloadProgressFill').style.width = percent + '%';
        document.getElementById('downloadProgressText').textContent = 'Downloaded ' + downloaded + '/' + files.length + ' (' + percent + '%)';
    }
    
    function downloadNext(index) {
        if (index >= files.length) {
            // Done
            setTimeout(function() {
                var msg = '✅ Selesai! Downloaded ' + downloaded + ' fail';
                if (failed > 0) msg += ' (' + failed + ' gagal)';
                document.getElementById('downloadProgressText').textContent = msg;
                showToast(msg);
                
                setTimeout(closeDownloadModal, 2000);
            }, 500);
            return;
        }
        
        var file = files[index];
        var filename = albumName + '_' + file.name;
        
        // Download using fetch + blob (better than direct link)
        fetch(file.url)
            .then(function(response) {
                if (!response.ok) throw new Error('Failed');
                return response.blob();
            })
            .then(function(blob) {
                var url = window.URL.createObjectURL(blob);
                var link = document.createElement('a');
                link.href = url;
                link.download = filename;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                setTimeout(function() { window.URL.revokeObjectURL(url); }, 100);
                
                downloaded++;
                updateProgress();
                
                setTimeout(function() { downloadNext(index + 1); }, 1000);
            })
            .catch(function(err) {
                console.log('Download failed:', filename, err);
                
                // Fallback: try direct link
                var link = document.createElement('a');
                link.href = file.url;
                link.download = filename;
                link.target = '_blank';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                
                downloaded++;
                failed++;
                updateProgress();
                
                setTimeout(function() { downloadNext(index + 1); }, 1000);
            });
    }
    
    downloadNext(0);
}

