// ============================================
// ===== OUTING SYSTEM (ADMIN) ===============
// ============================================

function initOuting() {
    if (!appData.outings) appData.outings = [];
    
    // Populate month filter
    var monthSelect = document.getElementById('outingFilterMonth');
    if (monthSelect && monthSelect.options.length <= 1) {
        var months = ['', 'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun', 'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
        for (var m = 1; m <= 12; m++) {
            monthSelect.innerHTML += '<option value="' + m + '">' + months[m] + '</option>';
        }
    }
    
    renderOutingList();
}

function renderOutingList() {
    if (!appData.outings) appData.outings = [];
    
    var tbody = document.getElementById('outingTableBody');
    if (!tbody) return;
    
    var searchVal = (document.getElementById('outingSearchInput').value || '').toLowerCase();
    var statusFilter = document.getElementById('outingFilterStatus').value;
    var monthFilter = document.getElementById('outingFilterMonth').value;
    
    // Filter
    var filtered = [];
    for (var i = 0; i < appData.outings.length; i++) {
        var o = appData.outings[i];
        
        // Search
        if (searchVal && (o.studentName || '').toLowerCase().indexOf(searchVal) === -1) continue;
        
        // Status
        if (statusFilter !== 'all' && o.status !== statusFilter) continue;
        
        // Month
        if (monthFilter !== 'all' && o.date) {
            var oMonth = parseInt(o.date.split('-')[1]);
            if (oMonth !== parseInt(monthFilter)) continue;
        }
        
        filtered.push(o);
    }
    
    // Sort newest first
    filtered.sort(function(a, b) { return new Date(b.date || b.appliedAt) - new Date(a.date || a.appliedAt); });
    
    // Update stats
    var total = appData.outings.length;
    var pending = 0, approved = 0, active = 0;
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].status === 'pending') pending++;
        else if (appData.outings[i].status === 'approved') approved++;
        else if (appData.outings[i].status === 'checkedout') active++;
    }
    
    var el = function(id) { return document.getElementById(id); };
    if (el('outingStatTotal')) el('outingStatTotal').textContent = total;
    if (el('outingStatPending')) el('outingStatPending').textContent = pending;
    if (el('outingStatApproved')) el('outingStatApproved').textContent = approved;
    if (el('outingStatActive')) el('outingStatActive').textContent = active;
    
    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="9" class="text-center" style="padding:40px;"><div class="empty-state"><div class="empty-icon">🚗</div><p>Tiada permohonan outing</p></div></td></tr>';
        return;
    }
    
    var statusConfig = {
        pending: { label: '⏳ Menunggu', bg: '#fef3c7', color: '#78350f' },
        approved: { label: '✅ Diluluskan', bg: '#d1fae5', color: '#065f46' },
        rejected: { label: '❌ Ditolak', bg: '#fee2e2', color: '#991b1b' },
        checkedout: { label: '🚗 Sedang Outing', bg: '#dbeafe', color: '#1e40af' },
        completed: { label: '✅ Selesai', bg: '#f0fdf4', color: '#047857' }
    };
    
    var html = '';
    for (var i = 0; i < filtered.length; i++) {
        var o = filtered[i];
        var sc = statusConfig[o.status] || statusConfig.pending;
        
        // Calculate duration
        var durationText = '-';
        if (o.actualCheckOut && o.actualCheckIn) {
            var outTime = o.actualCheckOut.split(':');
            var inTime = o.actualCheckIn.split(':');
            var outMin = parseInt(outTime[0]) * 60 + parseInt(outTime[1]);
            var inMin = parseInt(inTime[0]) * 60 + parseInt(inTime[1]);
            var diff = inMin - outMin;
            var hours = Math.floor(diff / 60);
            var mins = diff % 60;
            durationText = hours + 'j ' + mins + 'm';
            if (diff > 240) durationText += ' ⚠️';
        }
        
        // Check outing count this month
        var outingMonth = o.date ? parseInt(o.date.split('-')[1]) : 0;
        var outingYear = o.date ? parseInt(o.date.split('-')[0]) : 0;
        var monthCount = 0;
        for (var j = 0; j < appData.outings.length; j++) {
            var oj = appData.outings[j];
            if (oj.studentId === o.studentId && oj.date) {
                var ojM = parseInt(oj.date.split('-')[1]);
                var ojY = parseInt(oj.date.split('-')[0]);
                if (ojM === outingMonth && ojY === outingYear && (oj.status === 'approved' || oj.status === 'checkedout' || oj.status === 'completed')) {
                    monthCount++;
                }
            }
        }
        
        html += '<tr>';
        html += '<td>' + (i + 1) + '</td>';
        html += '<td><strong>' + (o.studentName || '-') + '</strong>';
        if (monthCount > 1) html += '<br><span style="background:#fee2e2;color:#991b1b;padding:2px 6px;border-radius:8px;font-size:0.65rem;font-weight:700;">⚠️ ' + monthCount + 'x bulan ini</span>';
        html += '</td>';
        html += '<td>' + (o.date ? formatDate(o.date) : '-') + '</td>';
        html += '<td><small>' + (o.timeOut || '-') + ' - ' + (o.expectedReturn || '-') + '</small></td>';
        html += '<td><small>' + (o.pickupName || '-') + '<br>' + (o.pickupRelation || '') + '<br>' + (o.pickupPhone || '') + '</small></td>';
        html += '<td style="max-width:150px;font-size:0.82rem;">' + (o.reason || '-') + '</td>';
        html += '<td><span style="background:' + sc.bg + ';color:' + sc.color + ';padding:4px 10px;border-radius:10px;font-size:0.75rem;font-weight:700;">' + sc.label + '</span></td>';
        
        // Check out/in
        html += '<td style="font-size:0.78rem;">';
        if (o.actualCheckOut) html += '🚗 Out: ' + o.actualCheckOut + '<br>';
        if (o.actualCheckIn) html += '🏠 In: ' + o.actualCheckIn + '<br>';
        if (o.actualCheckOut && o.actualCheckIn) html += '⏱ ' + durationText;
        if (!o.actualCheckOut && !o.actualCheckIn) html += '-';
        html += '</td>';
        
        // Actions
        html += '<td><div style="display:flex;gap:4px;flex-wrap:wrap;">';
        
        if (o.status === 'pending') {
            html += '<button class="btn btn-sm" style="background:#10b981;color:white;" onclick="approveOuting(\'' + o.id + '\')" title="Luluskan">✅</button>';
            html += '<button class="btn btn-sm" style="background:#ef4444;color:white;" onclick="rejectOuting(\'' + o.id + '\')" title="Tolak">❌</button>';
        }
        
        if (o.status === 'approved') {
            html += '<button class="btn btn-sm" style="background:#3b82f6;color:white;" onclick="checkOutOuting(\'' + o.id + '\')" title="Check Out">🚗 Out</button>';
        }
        
        if (o.status === 'checkedout') {
            html += '<button class="btn btn-sm" style="background:#10b981;color:white;" onclick="checkInOuting(\'' + o.id + '\')" title="Check In">🏠 In</button>';
        }
        
        html += '<button class="btn btn-sm btn-view" onclick="openOutingEdit(\'' + o.id + '\')" title="Edit">✏️</button>';
        html += '<button class="btn btn-sm btn-delete" onclick="deleteOuting(\'' + o.id + '\')" title="Padam">🗑</button>';
        
        html += '</div></td>';
        html += '</tr>';
    }
    
    tbody.innerHTML = html;
}

// Approve
function approveOuting(outingId) {
    if (!confirm('Luluskan permohonan outing ini?')) return;
    
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            appData.outings[i].status = 'approved';
            appData.outings[i].approvedAt = new Date().toISOString();
            appData.outings[i].approvedBy = currentUser ? currentUser.name : 'Admin';
            break;
        }
    }
    
    saveData(appData);
    showToast('✅ Outing diluluskan');
    renderOutingList();
    
    // Send WhatsApp
    sendOutingNotification(outingId, 'approved');
}

// Reject
function rejectOuting(outingId) {
    var reason = prompt('Sebab ditolak (optional):');
    
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            appData.outings[i].status = 'rejected';
            appData.outings[i].rejectedAt = new Date().toISOString();
            appData.outings[i].rejectedBy = currentUser ? currentUser.name : 'Admin';
            appData.outings[i].rejectReason = reason || '';
            break;
        }
    }
    
    saveData(appData);
    showToast('❌ Outing ditolak');
    renderOutingList();
    
    sendOutingNotification(outingId, 'rejected');
}

// Check Out
function checkOutOuting(outingId) {
    var now = new Date();
    var timeStr = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0');
    
    if (!confirm('Pelajar check out sekarang? (' + timeStr + ')')) return;
    
    var outing = null;
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            appData.outings[i].status = 'checkedout';
            appData.outings[i].actualCheckOut = timeStr;
            appData.outings[i].checkOutAt = now.toISOString();
            outing = appData.outings[i];
            break;
        }
    }
    
    saveData(appData);
    showToast('🚗 Pelajar telah check out');
    renderOutingList();
    
    // ===== AUTO SEND WA TO PARENT =====
    if (outing && confirm('📱 Hantar notifikasi WhatsApp ke ibu bapa?')) {
        sendOutingNotification(outingId, 'checkedout');
    }
}

// Check In
function checkInOuting(outingId) {
    var now = new Date();
    var timeStr = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0');
    
    // Check duration
    var outing = null;
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            outing = appData.outings[i];
            break;
        }
    }
    
    var warningMsg = '';
    if (outing && outing.actualCheckOut) {
        var outParts = outing.actualCheckOut.split(':');
        var outMin = parseInt(outParts[0]) * 60 + parseInt(outParts[1]);
        var inMin = now.getHours() * 60 + now.getMinutes();
        var diff = inMin - outMin;
        
        if (diff > 240) {
            warningMsg = '\n\n⚠️ AMARAN: Pelajar telah outing ' + Math.floor(diff/60) + ' jam ' + (diff%60) + ' minit!\n(Melebihi had 4 jam)';
        }
    }
    
    if (!confirm('Pelajar check in sekarang? (' + timeStr + ')' + warningMsg)) return;
    
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            appData.outings[i].status = 'completed';
            appData.outings[i].actualCheckIn = timeStr;
            appData.outings[i].checkInAt = now.toISOString();
            break;
        }
    }
    
        saveData(appData);
    showToast('🏠 Pelajar telah check in');
    renderOutingList();
    
    // ===== AUTO SEND WA TO PARENT =====
    if (outing && confirm('📱 Hantar notifikasi WhatsApp ke ibu bapa?')) {
        sendOutingNotification(outingId, 'checkedin');
    }
}

// Edit
function openOutingEdit(outingId) {
    var o = null;
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            o = appData.outings[i];
            break;
        }
    }
    if (!o) return;
    
    document.getElementById('outingEditId').value = o.id;
    document.getElementById('outingEditDate').value = o.date || '';
    document.getElementById('outingEditStatus').value = o.status || 'pending';
    document.getElementById('outingEditTimeOut').value = o.actualCheckOut || '';
    document.getElementById('outingEditTimeIn').value = o.actualCheckIn || '';
    document.getElementById('outingEditPickupName').value = o.pickupName || '';
    document.getElementById('outingEditReason').value = o.reason || '';
    document.getElementById('outingEditAdminNotes').value = o.adminNotes || '';
    
    document.getElementById('outingEditModal').classList.remove('hidden');
}

function closeOutingEdit() {
    document.getElementById('outingEditModal').classList.add('hidden');
}

function saveOutingEdit(e) {
    e.preventDefault();
    
    var id = document.getElementById('outingEditId').value;
    
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === id) {
            appData.outings[i].date = document.getElementById('outingEditDate').value;
            appData.outings[i].status = document.getElementById('outingEditStatus').value;
            appData.outings[i].actualCheckOut = document.getElementById('outingEditTimeOut').value;
            appData.outings[i].actualCheckIn = document.getElementById('outingEditTimeIn').value;
            appData.outings[i].pickupName = document.getElementById('outingEditPickupName').value;
            appData.outings[i].reason = document.getElementById('outingEditReason').value;
            appData.outings[i].adminNotes = document.getElementById('outingEditAdminNotes').value;
            appData.outings[i].updatedAt = new Date().toISOString();
            break;
        }
    }
    
    saveData(appData);
    closeOutingEdit();
    renderOutingList();
    showToast('✅ Rekod outing dikemaskini');
}

// Delete
function deleteOuting(outingId) {
    if (!confirm('Padam rekod outing ini?')) return;
    
    appData.outings = appData.outings.filter(function(o) { return o.id !== outingId; });
    saveData(appData);
    renderOutingList();
    showToast('🗑 Rekod dipadam');
}

// WhatsApp Notification
function sendOutingNotification(outingId, type) {
    var o = null;
    for (var i = 0; i < appData.outings.length; i++) {
        if (appData.outings[i].id === outingId) {
            o = appData.outings[i];
            break;
        }
    }
    if (!o) return;
    
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === o.studentId) {
            student = appData.students[i];
            break;
        }
    }
    if (!student) return;
    
    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) return;
    
    var parentName = student.fatherName || student.motherName || 'Ayah/Ibu';
    
    var msg = '🕌 *MADRASAH TAHFIZ PEKAN SUNGAI BULOH*\n';
    msg += '━━━━━━━━━━━━━━━━━━━\n\n';
    
    // ===== TYPE 1: APPROVED =====
    if (type === 'approved') {
        msg += '✅ *OUTING DILULUSKAN*\n\n';
        msg += 'Assalamualaikum ' + parentName + ',\n\n';
        msg += 'Permohonan outing anak telah *DILULUSKAN*.\n\n';
        msg += '👨‍🎓 *Pelajar:* ' + o.studentName + '\n';
        msg += '📅 *Tarikh:* ' + formatDate(o.date) + '\n';
        msg += '🕐 *Masa:* ' + (o.timeOut || '-') + ' - ' + (o.expectedReturn || '-') + '\n';
        msg += '👤 *Pengambil:* ' + (o.pickupName || '-') + '\n\n';
        msg += '⚠️ *Peringatan Penting:*\n';
        msg += '• Tempoh outing max 4 jam\n';
        msg += '• Pulang sebelum 7:00 PM\n';
        msg += '• Guna masa untuk keperluan sahaja\n';
        msg += '• Elakkan beri anak main henset\n';
    } 
    // ===== TYPE 2: REJECTED =====
    else if (type === 'rejected') {
        msg += '❌ *OUTING DITOLAK*\n\n';
        msg += 'Assalamualaikum ' + parentName + ',\n\n';
        msg += 'Kami mohon maaf, permohonan outing anak telah *DITOLAK*.\n\n';
        msg += '👨‍🎓 *Pelajar:* ' + o.studentName + '\n';
        msg += '📅 *Tarikh:* ' + formatDate(o.date) + '\n';
        if (o.rejectReason) {
            msg += '📝 *Sebab Ditolak:*\n' + o.rejectReason + '\n\n';
        } else {
            msg += '\n';
        }
        msg += 'Sila hubungi kami untuk keterangan lanjut.\n';
    } 
    // ===== TYPE 3: CHECKED OUT (BARU!) =====
    else if (type === 'checkedout') {
        msg += '🚗 *ANAK TELAH KELUAR MADRASAH*\n\n';
        msg += 'Assalamualaikum ' + parentName + ',\n\n';
        msg += 'Ini pemberitahuan bahawa anak anda telah *check out* dari madrasah untuk outing.\n\n';
        msg += '👨‍🎓 *Pelajar:* ' + o.studentName + '\n';
        msg += '📅 *Tarikh:* ' + formatDate(o.date) + '\n';
        msg += '🕐 *Masa Keluar:* ' + o.actualCheckOut + '\n';
        msg += '👤 *Pengambil:* ' + (o.pickupName || '-') + '\n\n';
        msg += '⏰ *Dijangka pulang:* ' + (o.expectedReturn || '-') + '\n\n';
        msg += 'Sila pastikan anak pulang tepat pada masanya.\n';
    } 
    // ===== TYPE 4: CHECKED IN (BARU!) =====
    else if (type === 'checkedin') {
        // Kira duration outing
        var durationText = '';
        if (o.actualCheckOut && o.actualCheckIn) {
            var outT = o.actualCheckOut.split(':');
            var inT = o.actualCheckIn.split(':');
            var diff = (parseInt(inT[0])*60 + parseInt(inT[1])) - (parseInt(outT[0])*60 + parseInt(outT[1]));
            var h = Math.floor(diff / 60);
            var m = diff % 60;
            durationText = h + ' jam ' + m + ' minit';
            if (diff > 240) durationText += ' ⚠️ (Overtime!)';
        }
        
        msg += '🏠 *ANAK TELAH PULANG KE MADRASAH*\n\n';
        msg += 'Assalamualaikum ' + parentName + ',\n\n';
        msg += 'Alhamdulillah, anak anda telah *pulang* ke madrasah.\n\n';
        msg += '👨‍🎓 *Pelajar:* ' + o.studentName + '\n';
        msg += '📅 *Tarikh:* ' + formatDate(o.date) + '\n';
        msg += '🚗 *Check Out:* ' + o.actualCheckOut + '\n';
        msg += '🏠 *Check In:* ' + o.actualCheckIn + '\n';
        if (durationText) msg += '⏱ *Tempoh:* ' + durationText + '\n';
        msg += '\n';
        msg += 'Terima kasih atas kerjasama anda. 🙏\n';
    }
    
    msg += '\n━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Sebarang pertanyaan:\n';
    msg += '📞 Ustaz Aisamuddin: 01161000542\n';
    msg += '📞 Haji Khaidir: 0192363638\n\n';
    msg += '_Pengurusan MTSB_';
    
    var cleanPhone = phone.replace(/[^0-9]/g, '');
    if (cleanPhone.startsWith('0')) cleanPhone = '60' + cleanPhone.substring(1);
    
    var waUrl = 'https://wa.me/' + cleanPhone + '?text=' + encodeURIComponent(msg);
    window.open(waUrl, '_blank');
}

