// ============================================
// ===== PARENT UPDATES MANAGEMENT ============
// ============================================

/**
 * Initialize parent updates tab
 */
function initParentUpdates() {
    console.log('📝 Init Parent Updates tab...');
    refreshParentUpdates();
}

/**
 * Refresh all data
 */
function refreshParentUpdates() {
    appData = loadData();
    
    updatePUStats();
    renderStudentCompleteness();
    renderUpdateHistory();
}

/**
 * Update statistics
 */
function updatePUStats() {
    if (!appData.students) return;
    
    var total = appData.students.length;
    var complete = 0;
    var incomplete = 0;
    var totalPercent = 0;
    
    for (var i = 0; i < appData.students.length; i++) {
        var student = appData.students[i];
        if (!student) continue;
        
        var comp = checkStudentDataCompleteness(student);
        if (!comp) continue;
        
        if (comp.isComplete) {
            complete++;
        } else {
            incomplete++;
        }
        
        totalPercent += comp.overall;
    }
    
    var avg = total > 0 ? Math.round(totalPercent / total) : 0;
    
    document.getElementById('puTotalStudents').textContent = total;
    document.getElementById('puCompleteCount').textContent = complete;
    document.getElementById('puIncompleteCount').textContent = incomplete;
    document.getElementById('puAvgCompleteness').textContent = avg + '%';
}

/**
 * Switch sub-tab
 */
function switchPUTab(tab, btn) {
    // Hide all
    var contents = document.querySelectorAll('.pu-content');
    for (var i = 0; i < contents.length; i++) {
        contents[i].style.display = 'none';
    }
    
    // Reset buttons
    var btns = document.querySelectorAll('.pu-tab-btn');
    for (var i = 0; i < btns.length; i++) {
        btns[i].style.background = 'transparent';
        btns[i].style.color = '#64748b';
    }
    
    // Show selected
    document.getElementById('pu-' + tab).style.display = 'block';
    if (btn) {
        btn.style.background = 'linear-gradient(135deg,#a78bfa,#7c3aed)';
        btn.style.color = 'white';
    }
    
    // Render content
    if (tab === 'students') renderStudentCompleteness();
    else if (tab === 'history') renderUpdateHistory();
}

/**
 * Render student completeness table
 */
function renderStudentCompleteness() {
    var tbody = document.getElementById('puStudentsBody');
    if (!tbody) return;
    
    if (!appData.students || appData.students.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:40px;color:#64748b;">Tiada pelajar</td></tr>';
        return;
    }
    
    var search = (document.getElementById('puSearchStudent').value || '').toLowerCase();
    var filter = document.getElementById('puFilterStatus').value;
    
    // Filter students
    var filtered = [];
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (!s) continue;
        
        // Search filter
        if (search && s.name && s.name.toLowerCase().indexOf(search) === -1) continue;
        
        // Get completeness
        var comp = checkStudentDataCompleteness(s);
        if (!comp) continue;
        
        // Status filter
        if (filter === 'complete' && !comp.isComplete) continue;
        if (filter === 'incomplete' && comp.isComplete) continue;
        if (filter === 'empty' && comp.overall >= 10) continue;
        
        filtered.push({ student: s, comp: comp });
    }
    
    // Sort by completeness (lowest first)
    filtered.sort(function(a, b) {
        return a.comp.overall - b.comp.overall;
    });
    
    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:40px;color:#64748b;">Tiada pelajar match</td></tr>';
        return;
    }
    
    var html = '';
    for (var i = 0; i < filtered.length; i++) {
        var s = filtered[i].student;
        var comp = filtered[i].comp;
        
        // Progress color
        var color = '#ef4444'; // red
        if (comp.overall >= 100) color = '#10b981'; // green
        else if (comp.overall >= 70) color = '#3b82f6'; // blue
        else if (comp.overall >= 40) color = '#f59e0b'; // yellow
        
        // Missing sections
        var missingSections = [];
        for (var key in comp.sections) {
            if (comp.sections[key].percentage < 100) {
                missingSections.push(PARENT_DATA_SECTIONS[key].icon);
            }
        }
        
        // Last update
        var lastUpdate = s.lastUpdatedByParent ? 
            new Date(s.lastUpdatedByParent).toLocaleDateString('ms-MY') : 
            '<span style="color:#94a3b8;">Belum</span>';
        
        // Phone untuk WhatsApp
        var phone = s.fatherPhone || s.motherPhone || s.parentPhone || '';
        
        html += '<tr>';
        html += '<td><strong>' + (s.name || '-') + '</strong></td>';
        html += '<td>' + (s.class || '-') + '</td>';
        html += '<td style="font-weight:800;color:' + color + ';font-size:1.1rem;">' + comp.overall + '%</td>';
        html += '<td>';
        html += '<div style="background:#e5e7eb;height:8px;border-radius:5px;overflow:hidden;min-width:100px;">';
        html += '<div style="height:100%;background:' + color + ';width:' + comp.overall + '%;transition:width 0.5s;"></div>';
        html += '</div>';
        html += '</td>';
        html += '<td>';
        if (missingSections.length === 0) {
            html += '<span style="color:#10b981;font-weight:700;">✅ Complete</span>';
        } else {
            html += '<span style="font-size:1.2rem;" title="' + missingSections.length + ' section belum lengkap">' + missingSections.join(' ') + '</span>';
        }
        html += '</td>';
        html += '<td style="font-size:0.85rem;color:#64748b;">' + lastUpdate + '</td>';
        html += '<td>';
        html += '<div style="display:flex;gap:5px;">';
        
        // View details button
        html += '<button onclick="viewStudentDetails(\'' + s.id + '\')" style="padding:5px 10px;background:#3b82f6;color:white;border:none;border-radius:6px;font-size:0.75rem;cursor:pointer;" title="Lihat details">👁</button>';
        
        // WhatsApp reminder (kalau ada phone)
        if (phone && !comp.isComplete) {
            html += '<button onclick="sendReminderWA(\'' + s.id + '\')" style="padding:5px 10px;background:#10b981;color:white;border:none;border-radius:6px;font-size:0.75rem;cursor:pointer;" title="Hantar reminder">📱</button>';
        }
        
        // Reset skip
        html += '<button onclick="resetStudentSkip(\'' + s.id + '\')" style="padding:5px 10px;background:#f59e0b;color:white;border:none;border-radius:6px;font-size:0.75rem;cursor:pointer;" title="Reset skip">🔄</button>';
        
        html += '</div>';
        html += '</td>';
        html += '</tr>';
    }
    
    tbody.innerHTML = html;
}

/**
 * Render update history
 */
function renderUpdateHistory() {
    var container = document.getElementById('puHistoryBody');
    if (!container) return;
    
    if (!appData.parentUpdates || appData.parentUpdates.length === 0) {
        container.innerHTML = '<div style="text-align:center;padding:40px;color:#64748b;"><div style="font-size:3rem;margin-bottom:15px;">📭</div>Tiada history update</div>';
        return;
    }
    
    // Filter by time
    var filter = document.getElementById('puHistoryFilter').value;
    var updates = appData.parentUpdates.slice();
    var now = new Date();
    
    if (filter !== 'all') {
        updates = updates.filter(function(u) {
            var updateDate = new Date(u.updatedAt);
            var daysDiff = (now - updateDate) / (1000 * 60 * 60 * 24);
            
            if (filter === 'today') return daysDiff < 1;
            if (filter === 'week') return daysDiff < 7;
            if (filter === 'month') return daysDiff < 30;
            return true;
        });
    }
    
    // Sort newest first
    updates.sort(function(a, b) {
        return new Date(b.updatedAt) - new Date(a.updatedAt);
    });
    
    if (updates.length === 0) {
        container.innerHTML = '<div style="text-align:center;padding:40px;color:#64748b;">Tiada update dalam tempoh ini</div>';
        return;
    }
    
    var html = '<div style="display:flex;flex-direction:column;gap:10px;">';
    
    for (var i = 0; i < updates.length; i++) {
        var u = updates[i];
        var date = new Date(u.updatedAt);
        var dateStr = date.toLocaleString('ms-MY', {
            day: 'numeric',
            month: 'short',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
        
        // Color based on completeness
        var color = '#ef4444';
        if (u.completeness >= 100) color = '#10b981';
        else if (u.completeness >= 70) color = '#3b82f6';
        else if (u.completeness >= 40) color = '#f59e0b';
        
        html += '<div style="display:flex;gap:15px;padding:15px;background:white;border-radius:12px;border-left:4px solid ' + color + ';box-shadow:0 2px 8px rgba(0,0,0,0.05);align-items:center;">';
        
        // Icon
        html += '<div style="font-size:2rem;">👨‍👩‍👧</div>';
        
        // Info
        html += '<div style="flex:1;">';
        html += '<div style="font-weight:700;color:#1f2937;">' + (u.studentName || 'Unknown') + '</div>';
        html += '<div style="font-size:0.82rem;color:#64748b;margin-top:3px;">📅 ' + dateStr + '</div>';
        html += '</div>';
        
        // Completeness badge
        html += '<div style="text-align:center;">';
        html += '<div style="font-weight:800;color:' + color + ';font-size:1.3rem;">' + u.completeness + '%</div>';
        html += '<div style="font-size:0.75rem;color:#64748b;">Complete</div>';
        html += '</div>';
        
        html += '</div>';
    }
    
    html += '</div>';
    container.innerHTML = html;
}

/**
 * View student details
 */
function viewStudentDetails(studentId) {
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    
    if (!student) {
        alert('Pelajar tidak dijumpai');
        return;
    }
    
    var comp = checkStudentDataCompleteness(student);
    
    var msg = '📋 ' + student.name + '\n';
    msg += '━━━━━━━━━━━━━━━━━━━\n';
    msg += 'Kelengkapan: ' + comp.overall + '%\n\n';
    msg += 'Status Section:\n';
    
    for (var key in comp.sections) {
        var s = comp.sections[key];
        var config = PARENT_DATA_SECTIONS[key];
        var icon = s.percentage === 100 ? '✅' : (s.percentage > 0 ? '⚠️' : '❌');
        msg += icon + ' ' + config.title + ': ' + s.percentage + '%\n';
    }
    
    if (comp.missingFields.length > 0) {
        msg += '\n❌ Missing Fields (' + comp.missingFields.length + '):\n';
        for (var i = 0; i < Math.min(10, comp.missingFields.length); i++) {
            msg += '• ' + comp.missingFields[i].label + '\n';
        }
        if (comp.missingFields.length > 10) {
            msg += '... dan ' + (comp.missingFields.length - 10) + ' lagi\n';
        }
    }
    
    alert(msg);
}

/**
 * Send WhatsApp reminder to specific parent
 */
function sendReminderWA(studentId) {
    var student = null;
    for (var i = 0; i < appData.students.length; i++) {
        if (appData.students[i].id === studentId) {
            student = appData.students[i];
            break;
        }
    }
    
    if (!student) return;
    
    var phone = student.fatherPhone || student.motherPhone || student.parentPhone;
    if (!phone) {
        alert('❌ Tiada nombor telefon');
        return;
    }
    
    var comp = checkStudentDataCompleteness(student);
    
    var msg = 'Assalamualaikum,\n\n';
    msg += 'Ibu/bapa kepada *' + student.name + '*,\n\n';
    msg += 'Maklumat anak anda dalam sistem madrasah masih *' + comp.overall + '% lengkap*.\n\n';
    msg += 'Sila lengkapkan maklumat untuk keselamatan dan komunikasi yang lebih baik.\n\n';
    msg += '🔗 Log masuk ke portal untuk lengkapkan.\n\n';
    msg += 'Terima kasih,\n';
    msg += 'Pihak Pengurusan Madrasah';
    
    // Clean phone
    var cleanPhone = phone.replace(/[^0-9]/g, '');
    if (cleanPhone.length === 10 || cleanPhone.length === 11) {
        cleanPhone = '6' + cleanPhone;
    }
    
    var url = 'https://wa.me/' + cleanPhone + '?text=' + encodeURIComponent(msg);
    window.open(url, '_blank');
}

/**
 * Send bulk reminder
 */
function sendBulkReminderWA(type) {
    if (!appData.students) return;
    
    var targets = [];
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (!s) continue;
        
        var comp = checkStudentDataCompleteness(s);
        if (!comp || comp.isComplete) continue;
        
        // Filter type
        if (type === 'critical' && comp.overall >= 50) continue;
        
        var phone = s.fatherPhone || s.motherPhone || s.parentPhone;
        if (phone) {
            targets.push(s);
        }
    }
    
    if (targets.length === 0) {
        alert('Tiada target untuk dihantar');
        return;
    }
    
    if (!confirm('Hantar reminder kepada ' + targets.length + ' parent?\n\nWhatsApp akan buka satu-satu.')) return;
    
    // Open WhatsApp one by one dengan delay
    for (var i = 0; i < targets.length; i++) {
        (function(student, index) {
            setTimeout(function() {
                sendReminderWA(student.id);
            }, index * 2000); // 2 saat delay
        })(targets[i], i);
    }
    
    alert('✅ Sedang buka ' + targets.length + ' WhatsApp tab...\n\nSila hantar satu-satu.');
}

/**
 * Reset skip data for specific student
 */
function resetStudentSkip(studentId) {
    try {
        localStorage.removeItem('pdwSkip_' + studentId);
        localStorage.removeItem('pdwDraft_' + studentId);
        alert('✅ Skip data reset untuk pelajar ini');
    } catch(e) {
        alert('❌ Error: ' + e.message);
    }
}

/**
 * Reset ALL skip data
 */
function resetAllSkipData() {
    if (!confirm('Reset skip data untuk SEMUA parent?\n\nPopup akan force muncul lagi bila mereka login.')) return;
    
    try {
        var count = 0;
        for (var key in localStorage) {
            if (key.indexOf('pdwSkip_') === 0 || key.indexOf('pdwDraft_') === 0) {
                localStorage.removeItem(key);
                count++;
            }
        }
        alert('✅ Reset ' + count + ' skip data');
    } catch(e) {
        alert('❌ Error: ' + e.message);
    }
}

/**
 * Export completeness CSV
 */
function exportCompletenessCSV() {
    if (!appData.students) return;
    
    var csv = 'Nama Pelajar,Kelas,Completeness %,Total Missing,Pelajar %,Bapa %,Ibu %,Kecemasan %,Kesihatan %,Pendidikan %,Last Update\n';
    
    for (var i = 0; i < appData.students.length; i++) {
        var s = appData.students[i];
        if (!s) continue;
        
        var comp = checkStudentDataCompleteness(s);
        if (!comp) continue;
        
        var lastUpdate = s.lastUpdatedByParent ? 
            new Date(s.lastUpdatedByParent).toLocaleDateString('ms-MY') : 
            'Belum';
        
        csv += '"' + (s.name || '') + '",';
        csv += '"' + (s.class || '') + '",';
        csv += comp.overall + ',';
        csv += comp.missingFields.length + ',';
        csv += (comp.sections.pelajar ? comp.sections.pelajar.percentage : 0) + ',';
        csv += (comp.sections.bapa ? comp.sections.bapa.percentage : 0) + ',';
        csv += (comp.sections.ibu ? comp.sections.ibu.percentage : 0) + ',';
        csv += (comp.sections.kecemasan ? comp.sections.kecemasan.percentage : 0) + ',';
        csv += (comp.sections.kesihatan ? comp.sections.kesihatan.percentage : 0) + ',';
        csv += (comp.sections.pendidikan ? comp.sections.pendidikan.percentage : 0) + ',';
        csv += '"' + lastUpdate + '"\n';
    }
    
    downloadCSV(csv, 'completeness_report_' + new Date().toISOString().split('T')[0] + '.csv');
}

/**
 * Export parent updates history CSV
 */
function exportParentUpdatesCSV() {
    if (!appData.parentUpdates || appData.parentUpdates.length === 0) {
        alert('Tiada history untuk export');
        return;
    }
    
    var csv = 'Tarikh,Nama Pelajar,Updated By,Completeness %\n';
    
    var sorted = appData.parentUpdates.slice().sort(function(a, b) {
        return new Date(b.updatedAt) - new Date(a.updatedAt);
    });
    
    for (var i = 0; i < sorted.length; i++) {
        var u = sorted[i];
        var date = new Date(u.updatedAt).toLocaleString('ms-MY');
        
        csv += '"' + date + '",';
        csv += '"' + (u.studentName || '') + '",';
        csv += '"' + (u.updatedBy || 'parent') + '",';
        csv += (u.completeness || 0) + '\n';
    }
    
    downloadCSV(csv, 'parent_updates_history_' + new Date().toISOString().split('T')[0] + '.csv');
}

/**
 * Helper: Download CSV
 */
function downloadCSV(csv, filename) {
    var blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = filename;
    link.click();
    URL.revokeObjectURL(link.href);
}

// Auto-init when tab clicked
var _origSwitchTabPU = window.switchTab;
window.switchTab = function(tabName, btn) {
    if (typeof _origSwitchTabPU === 'function') {
        _origSwitchTabPU(tabName, btn);
    }
    
    if (tabName === 'parentUpdates') {
        setTimeout(initParentUpdates, 100);
    }
};

