// ============================================
// ===== INFAQ ADMIN MANAGEMENT ===============
// ============================================

let infaqAdminData = {};
let dapurMenuData = {};        // 🍳 NEW: Cache menu dapur
let infaqListenerActive = false;
let dapurMenuListenerActive = false;  // 🍳 NEW

function initInfaqAdmin() {
    if (infaqListenerActive) return;
    infaqListenerActive = true;

    const db = firebase.database();

    // Listener 1: Infaq data
    db.ref('infaq').on('value', (snapshot) => {
        infaqAdminData = snapshot.val() || {};
        renderInfaqAdmin();
        updateInfaqStats();
        renderAdminInfaqCalendar();
    });

    // 🍳 Listener 2: Dapur menu data
    if (!dapurMenuListenerActive) {
        dapurMenuListenerActive = true;
        db.ref('dapurMenu').on('value', (snapshot) => {
            dapurMenuData = snapshot.val() || {};
            renderAdminInfaqCalendar();  // Refresh calendar untuk dot oren
            // Kalau modal dibuka, refresh juga
            var modal = document.getElementById('adminInfaqDateModal');
            if (modal && !modal.classList.contains('hidden') && adminInfaqSelectedDate) {
                adminInfaqOpenDate(adminInfaqSelectedDate);
            }
        });
    }
}

function loadInfaqAdmin() {
    initInfaqAdmin();
    showToast('🔄 Refreshing...');
}

function updateInfaqStats() {
    if (!document.getElementById('statPending')) return;
    
    let pending = 0, confirmed = 0, totalDuit = 0, totalMakanan = 0;
    
    Object.values(infaqAdminData).forEach(item => {
        if (item.status === 'pending') pending++;
        if (item.status === 'confirmed') {
            confirmed++;
            if (item.jenis === 'Duit') totalDuit += parseFloat(item.jumlah || 0);
            if (item.jenis === 'Makanan') totalMakanan++;
        }
    });

    document.getElementById('statPending').textContent = pending;
    document.getElementById('statConfirmed').textContent = confirmed;
    document.getElementById('statDuit').textContent = 'RM ' + totalDuit.toFixed(2);
    document.getElementById('statMakanan').textContent = totalMakanan;
}

function renderInfaqAdmin() {
    const container = document.getElementById('infaqAdminList');
    if (!container) return;
    
    const filterStatus = document.getElementById('infaqFilterStatus').value;
    const filterJenis = document.getElementById('infaqFilterJenis').value;
    const search = document.getElementById('infaqSearch').value.toLowerCase();

    let items = Object.entries(infaqAdminData).map(([key, val]) => ({...val, key}));
    items.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
    
    // 🍱 Skip slot dari takwim (bukan sponsorship public)
    items = items.filter(i => i.source !== 'takwim');

    if (filterStatus !== 'all') items = items.filter(i => i.status === filterStatus);
    if (filterJenis !== 'all') items = items.filter(i => i.jenis === filterJenis);
    if (search) {
        items = items.filter(i => 
            (i.nama || '').toLowerCase().includes(search) ||
            (i.whatsapp || '').includes(search)
        );
    }

    if (items.length === 0) {
        container.innerHTML = '<div class="empty-state" style="grid-column:1/-1;text-align:center;padding:60px;color:#999;background:white;border-radius:12px;">📭 Tiada rekod infaq</div>';
        return;
    }

    let html = '';
    items.forEach(item => {
        const dateStr = formatInfaqDate(item.dateKey);
        const statusClass = 'status-' + item.status;
        const statusIcon = item.status === 'pending' ? '🟡' : item.status === 'confirmed' ? '🟢' : '🔴';
        const jenisIcon = item.jenis === 'Duit' ? '💰' : '🍱';
        const detail = item.jenis === 'Duit' ? `RM ${item.jumlah}` : item.menu;

        html += `
        <div class="infaq-card ${statusClass}">
            <div class="infaq-card-header">
                <div class="infaq-card-title">
                    ${statusIcon} ${jenisIcon} ${item.nama}
                    ${item.dedah ? '' : '<span class="anon-badge">Anonymous</span>'}
                </div>
                <div class="infaq-card-status">${item.status.toUpperCase()}</div>
            </div>
            
            <div class="infaq-card-body">
                <div class="infaq-detail-row">
                    <span>📅</span> <strong>${dateStr}</strong> - ${item.slotLabel}
                </div>
                <div class="infaq-detail-row">
                    <span>${jenisIcon}</span> ${item.jenis}: <strong>${detail}</strong>
                </div>
                <div class="infaq-detail-row">
                    <span>📞</span> 
                    <a href="https://wa.me/${cleanInfaqPhone(item.whatsapp)}" target="_blank" class="wa-link">
                        ${item.whatsapp}
                    </a>
                </div>
                ${item.catatan ? `<div class="infaq-detail-row"><span>📝</span> <em>${item.catatan}</em></div>` : ''}

${item.sertakanDoa && item.doaData ? `
<div class="doa-box">
    <div class="doa-box-header">🤲 Niat Doa: <strong>${item.doaData.jenisDoa}</strong></div>
    ${item.doaData.namaList && item.doaData.namaList.length > 0 ? `
        <div class="doa-nama-list">
            <div class="doa-nama-label">Nama-nama:</div>
            <ol>
                ${item.doaData.namaList.map(n => `<li>${n}</li>`).join('')}
            </ol>
        </div>
    ` : ''}
    ${item.doaData.doaCustom ? `
        <div class="doa-custom">
            <div class="doa-nama-label">Doa Khas:</div>
            <p>${item.doaData.doaCustom}</p>
        </div>
    ` : ''}
</div>
` : ''}

<div class="infaq-detail-row-small">
    <span>🕐 Submit:</span> ${new Date(item.timestamp).toLocaleString('ms-MY')}
</div>
            </div>

            <div class="infaq-card-actions">
                ${item.status === 'pending' ? `
                    <button class="btn-sm btn-confirm" onclick="confirmInfaq('${item.key}')">✅ Confirm</button>
                    <button class="btn-sm btn-reject" onclick="rejectInfaq('${item.key}')">❌ Reject</button>
                ` : ''}
                ${item.status === 'confirmed' ? `
                    <button class="btn-sm btn-warning" onclick="unconfirmInfaq('${item.key}')">↩️ Unconfirm</button>
                ` : ''}
                ${item.status === 'rejected' ? `
                    <button class="btn-sm btn-warning" onclick="reopenInfaq('${item.key}')">↩️ Reopen</button>
                ` : ''}
                <button class="btn-sm btn-wa" onclick="waPenaja('${item.key}')">💬 WA</button>
                <button class="btn-sm btn-delete" onclick="deleteInfaq('${item.key}')">🗑️</button>
            </div>
        </div>`;
    });

    container.innerHTML = html;
}

// ============================================
// 📅 ADMIN INFAQ CALENDAR
// ============================================
var adminInfaqCurrentView = 'thisMonth';
var adminInfaqSelectedDate = null;

var ADMIN_INFAQ_SLOTS = [
    { key: 'sarapan', label: 'Sarapan', icon: '🌅', time: '7:00 pagi' },
    { key: 'tengahari', label: 'Tengah Hari', icon: '☀️', time: '12:30 tgh' },
    { key: 'minumpetang', label: 'Minum Petang', icon: '🍵', time: '4:30 ptg' },
    { key: 'malam', label: 'Malam', icon: '🌙', time: '7:30 mlm' }
];

var ADMIN_INFAQ_MONTHS = ['Januari','Februari','Mac','April','Mei','Jun','Julai','Ogos','September','Oktober','November','Disember'];
var ADMIN_INFAQ_DAYS = ['Ahad','Isnin','Selasa','Rabu','Khamis','Jumaat','Sabtu'];

function adminInfaqSwitchMonth(view) {
    adminInfaqCurrentView = view;
    var btnThis = document.getElementById('adminInfaqBtnThis');
    var btnNext = document.getElementById('adminInfaqBtnNext');
    if (btnThis && btnNext) {
        if (view === 'thisMonth') {
            btnThis.style.background = '#22c55e';
            btnThis.style.color = 'white';
            btnThis.style.border = 'none';
            btnNext.style.background = 'white';
            btnNext.style.color = '#16a34a';
            btnNext.style.border = '2px solid #22c55e';
        } else {
            btnNext.style.background = '#22c55e';
            btnNext.style.color = 'white';
            btnNext.style.border = 'none';
            btnThis.style.background = 'white';
            btnThis.style.color = '#16a34a';
            btnThis.style.border = '2px solid #22c55e';
        }
    }
    renderAdminInfaqCalendar();
}

function adminInfaqFormatDateKey(date) {
    var y = date.getFullYear();
    var m = String(date.getMonth() + 1).padStart(2, '0');
    var d = String(date.getDate()).padStart(2, '0');
    return y + '-' + m + '-' + d;
}

function renderAdminInfaqCalendar() {
    var grid = document.getElementById('adminInfaqCalGrid');
    var title = document.getElementById('adminInfaqCalTitle');
    if (!grid || !title) return;

    var today = new Date();
    today.setHours(0, 0, 0, 0);

    var year, month;
    if (adminInfaqCurrentView === 'thisMonth') {
        year = today.getFullYear();
        month = today.getMonth();
    } else {
        var next = new Date(today.getFullYear(), today.getMonth() + 1, 1);
        year = next.getFullYear();
        month = next.getMonth();
    }

    title.textContent = ADMIN_INFAQ_MONTHS[month] + ' ' + year;

    var firstDay = new Date(year, month, 1).getDay();
    var daysInMonth = new Date(year, month + 1, 0).getDate();

    var data = (typeof infaqAdminData !== 'undefined') ? infaqAdminData : {};
    var dapurData = (typeof dapurMenuData !== 'undefined') ? dapurMenuData : {};

    var html = '';

    // Padding kosong sebelum hari 1
    for (var i = 0; i < firstDay; i++) {
        html += '<div style="aspect-ratio:1;"></div>';
    }

    for (var d = 1; d <= daysInMonth; d++) {
        var dateObj = new Date(year, month, d);
        var dateKey = adminInfaqFormatDateKey(dateObj);
        var isPast = dateObj < today;
        var isToday = dateObj.getTime() === today.getTime();
        var dayOfWeek = dateObj.getDay();

        // 🎨 Kira warna setiap slot ikut priority: DAPUR > TAKWIM > CONFIRMED > PENDING > KOSONG
        var slotColors = [];
        var slotStatuses = [];  // Untuk tooltip
        var filledCount = 0;

        ADMIN_INFAQ_SLOTS.forEach(function(slot) {
            var rec = data[dateKey + '_' + slot.key];
            var menuRec = dapurData[dateKey] && dapurData[dateKey][slot.key];
            var hasMenu = menuRec && menuRec.menu;

            var color = 'transparent';  // kosong
            var status = 'kosong';

            if (hasMenu) {
                color = '#ea580c';  // Oren - dimasak
                status = 'dimasak';
                filledCount++;
            } else if (rec) {
                if (rec.source === 'takwim' || rec.status === 'SPONSORED') {
                    color = '#a855f7';  // Ungu - sponsored takwim
                    status = 'sponsored';
                    filledCount++;
                } else if (rec.status === 'confirmed') {
                    color = '#22c55e';  // Hijau - confirmed
                    status = 'confirmed';
                    filledCount++;
                } else if (rec.status === 'pending') {
                    color = '#facc15';  // Kuning - pending
                    status = 'pending';
                    filledCount++;
                }
            }

            slotColors.push(color);
            slotStatuses.push(slot.label + ': ' + status);
        });

        // Cell styling
        var cellStyle = 'position:relative;aspect-ratio:1;background:#f9fafb;border:2px solid #e5e7eb;border-radius:8px;overflow:hidden;cursor:pointer;transition:all 0.2s;min-height:70px;display:flex;flex-direction:column;';
        if (isPast) cellStyle += 'opacity:0.75;';
        if (isToday) cellStyle += 'border-color:#dc2626;border-width:3px;';

        var numColor = '#333';
        if (dayOfWeek === 5 || dayOfWeek === 0) numColor = '#dc2626';
        if (isPast) numColor = '#9ca3af';

        // Nombor tarikh
        var numHtml = isToday
            ? '<div style="position:absolute;top:4px;left:4px;background:#dc2626;color:white;width:22px;height:22px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:bold;z-index:5;">' + d + '</div>'
            : '<div style="position:absolute;top:4px;left:6px;font-size:14px;font-weight:bold;color:' + numColor + ';z-index:5;text-shadow:0 0 3px rgba(255,255,255,0.9);">' + d + '</div>';

        // Count badge (kanan atas)
        var countHtml = filledCount > 0
            ? '<div style="position:absolute;top:4px;right:4px;background:rgba(255,255,255,0.95);color:#333;font-size:9px;font-weight:bold;padding:1px 5px;border-radius:8px;z-index:5;">' + filledCount + '/4</div>'
            : '';

        // 🎨 4 Segmented bars (25% tinggi setiap satu)
        var segmentsHtml = '<div style="position:absolute;inset:0;display:flex;flex-direction:column;z-index:1;">';
        slotColors.forEach(function(color, idx) {
            var bg = color === 'transparent' ? 'transparent' : color;
            var borderBottom = (idx < 3) ? 'border-bottom:1px solid rgba(255,255,255,0.5);' : '';
            segmentsHtml += '<div style="flex:1;background:' + bg + ';' + borderBottom + '" title="' + slotStatuses[idx] + '"></div>';
        });
        segmentsHtml += '</div>';

        html += '<div style="' + cellStyle + '" onmouseover="this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 4px 12px rgba(0,0,0,0.15)\';" onmouseout="this.style.transform=\'\';this.style.boxShadow=\'\';" onclick="adminInfaqOpenDate(\'' + dateKey + '\')">' +
            segmentsHtml +
            numHtml +
            countHtml +
        '</div>';
    }

    grid.innerHTML = html;
}

function adminInfaqOpenDate(dateKey) {
    adminInfaqSelectedDate = dateKey;
    var modal = document.getElementById('adminInfaqDateModal');
    var title = document.getElementById('adminInfaqModalTitle');
    var body = document.getElementById('adminInfaqModalBody');
    if (!modal || !body) return;

    var parts = dateKey.split('-');
    var dateObj = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
    var dayName = ADMIN_INFAQ_DAYS[dateObj.getDay()];
    var dateStr = parseInt(parts[2]) + ' ' + ADMIN_INFAQ_MONTHS[parseInt(parts[1]) - 1] + ' ' + parts[0];

    title.textContent = '📅 ' + dateStr + ' (' + dayName + ')';

    var data = (typeof infaqAdminData !== 'undefined') ? infaqAdminData : {};
    var dapurData = (typeof dapurMenuData !== 'undefined') ? dapurMenuData : {};
    var dayDapur = dapurData[dateKey] || {};  // 🍳 Menu dapur untuk hari ini

    var html = '';

    ADMIN_INFAQ_SLOTS.forEach(function(slot) {
        var slotKey = dateKey + '_' + slot.key;
        var rec = data[slotKey];
        var menuRec = dayDapur[slot.key];  // 🍳 Menu dapur untuk slot ni
        var hasMenu = menuRec && menuRec.menu;

        var bgColor = '#f8f9fa';
        var borderColor = '#e5e7eb';
        var statusHtml = '<span style="background:#94a3b8;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">KOSONG</span>';
        var infoHtml = '<em style="color:#999;font-size:13px;">Belum ada penaja</em>';
        var actionHtml = '<button onclick="adminInfaqAddManual(\'' + dateKey + '\',\'' + slot.key + '\',\'' + slot.label + '\')" style="background:#22c55e;color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">+ Tambah Manual</button>';

        // 🍳 PRIORITY 1: Semak dulu kalau slot ni dah DIMASAK
        if (hasMenu) {
            bgColor = '#fff7ed';        // Oren muda
            borderColor = '#ea580c';    // Oren gelap
            statusHtml = '<span style="background:#ea580c;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">🍳 DIMASAK</span>';

            var cookName = menuRec.cook || 'Tukang masak';
            var menuTime = menuRec.updatedAt || menuRec.timestamp;
            var timeStr = menuTime ? new Date(menuTime).toLocaleString('ms-MY', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' }) : '';

            infoHtml =
                '<div style="background:white;padding:10px;border-radius:8px;border:1px dashed #ea580c;">' +
                    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">' +
                        '<span style="font-size:18px;">🍽️</span>' +
                        '<strong style="color:#c2410c;font-size:14px;">' + escapeHtmlAdmin(menuRec.menu) + '</strong>' +
                    '</div>' +
                    '<div style="font-size:12px;color:#666;">' +
                        '👤 <strong>' + escapeHtmlAdmin(cookName) + '</strong>' +
                        (timeStr ? ' · <span style="color:#999;">' + timeStr + '</span>' : '') +
                    '</div>' +
                    (menuRec.note ? '<div style="font-size:12px;color:#666;margin-top:4px;font-style:italic;">💬 ' + escapeHtmlAdmin(menuRec.note) + '</div>' : '') +
                '</div>';

            // Kalau ada penaja (rec) — papar juga info penaja bawah menu
            if (rec && rec.status !== 'rejected') {
                infoHtml += '<div style="margin-top:8px;padding:8px;background:#fef3c7;border-radius:6px;font-size:12px;color:#78350f;">' +
                    '⚠️ <strong>Ada penaja:</strong> ' + escapeHtmlAdmin(rec.nama || '-') +
                    ' (' + (rec.jenis || '-') +
                    (rec.jenis === 'Duit' ? ' RM' + (rec.jumlah || 0) : (rec.menu ? ' - ' + escapeHtmlAdmin(rec.menu) : '')) + ')' +
                    '</div>';
            }

            actionHtml =
                '<button onclick="adminInfaqGotoDapurTab()" style="background:#ea580c;color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;margin-right:4px;">✏️ Edit Menu</button>';

            // Kalau ada rec (penaja), tetap tunjuk action penaja
            if (rec) {
                if (rec.status === 'pending') {
                    actionHtml += '<button onclick="confirmInfaq(\'' + slotKey + '\');adminInfaqCloseModal();" style="background:#22c55e;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;margin-right:4px;">✅</button>' +
                                  '<button onclick="rejectInfaq(\'' + slotKey + '\');adminInfaqCloseModal();" style="background:#ef4444;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">❌</button>';
                } else if (rec.status === 'confirmed' || rec.status === 'rejected') {
                    actionHtml += '<button onclick="adminInfaqDeleteSlot(\'' + slotKey + '\')" style="background:#ef4444;color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">🗑️ Padam Penaja</button>';
                }
            }
        }
        // PRIORITY 2: Kalau tak ada menu dapur, ikut logik lama (penaja)
        else if (rec) {
            if (rec.source === 'takwim') {
                bgColor = '#faf5ff';
                borderColor = '#a855f7';
                statusHtml = '<span style="background:#a855f7;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">🎪 DARI TAKWIM</span>';
                infoHtml = '<div style="color:#7c3aed;font-weight:600;">📌 ' + escapeHtmlAdmin(rec.sponsorName || 'Dari Takwim') + '</div>';
                actionHtml = '<em style="color:#7c3aed;font-size:11px;">Edit dari Takwim</em>';
            } else if (rec.status === 'confirmed') {
                bgColor = '#f0fdf4';
                borderColor = '#22c55e';
                statusHtml = '<span style="background:#22c55e;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">✅ CONFIRMED</span>';
                infoHtml = '<div><strong>' + escapeHtmlAdmin(rec.nama || '-') + '</strong> · ' + escapeHtmlAdmin(rec.jenis || '-') + (rec.jenis === 'Duit' ? ' RM' + (rec.jumlah || 0) : (rec.menu ? ' - ' + escapeHtmlAdmin(rec.menu) : '')) + '</div><div style="font-size:12px;color:#666;">📞 ' + escapeHtmlAdmin(rec.whatsapp || '-') + '</div>';
                actionHtml = '<button onclick="adminInfaqDeleteSlot(\'' + slotKey + '\')" style="background:#ef4444;color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">🗑️ Padam</button>';
            } else if (rec.status === 'pending') {
                bgColor = '#fffbeb';
                borderColor = '#f59e0b';
                statusHtml = '<span style="background:#f59e0b;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">🟡 PENDING</span>';
                infoHtml = '<div><strong>' + escapeHtmlAdmin(rec.nama || '-') + '</strong> · ' + escapeHtmlAdmin(rec.jenis || '-') + (rec.jenis === 'Duit' ? ' RM' + (rec.jumlah || 0) : (rec.menu ? ' - ' + escapeHtmlAdmin(rec.menu) : '')) + '</div><div style="font-size:12px;color:#666;">📞 ' + escapeHtmlAdmin(rec.whatsapp || '-') + '</div>';
                actionHtml = '<button onclick="confirmInfaq(\'' + slotKey + '\');adminInfaqCloseModal();" style="background:#22c55e;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;margin-right:4px;">✅</button>' +
                             '<button onclick="rejectInfaq(\'' + slotKey + '\');adminInfaqCloseModal();" style="background:#ef4444;color:white;border:none;padding:6px 10px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">❌</button>';
            } else if (rec.status === 'rejected') {
                bgColor = '#fef2f2';
                borderColor = '#ef4444';
                statusHtml = '<span style="background:#ef4444;color:white;padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;">🔴 REJECTED</span>';
                infoHtml = '<div style="text-decoration:line-through;color:#999;">' + escapeHtmlAdmin(rec.nama || '-') + '</div>';
                actionHtml = '<button onclick="adminInfaqDeleteSlot(\'' + slotKey + '\')" style="background:#ef4444;color:white;border:none;padding:6px 12px;border-radius:6px;font-size:12px;cursor:pointer;font-weight:600;">🗑️ Padam</button>';
            }
        }

        html += '<div style="background:' + bgColor + ';border-left:4px solid ' + borderColor + ';border-radius:10px;padding:14px;margin-bottom:10px;">' +
            '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;flex-wrap:wrap;gap:8px;">' +
                '<div style="display:flex;align-items:center;gap:10px;">' +
                    '<span style="font-size:22px;">' + slot.icon + '</span>' +
                    '<strong style="font-size:15px;">' + slot.label + '</strong>' +
                    '<span style="color:#999;font-size:12px;">(' + slot.time + ')</span>' +
                '</div>' +
                statusHtml +
            '</div>' +
            '<div style="margin-bottom:10px;">' + infoHtml + '</div>' +
            '<div style="text-align:right;">' + actionHtml + '</div>' +
        '</div>';
    });

    body.innerHTML = html;
    modal.style.display = 'flex';
    modal.classList.remove('hidden');
}

function adminInfaqCloseModal() {
    var modal = document.getElementById('adminInfaqDateModal');
    if (modal) {
        modal.style.display = 'none';
        modal.classList.add('hidden');
    }
}

function adminInfaqDeleteSlot(slotKey) {
    if (!confirm('Padam slot infaq ini?\n\nTindakan ini tidak boleh diundo.')) return;
    if (!firebase || !firebase.database) return;
    firebase.database().ref('infaq/' + slotKey).remove().then(function() {
        showToast('🗑️ Slot dipadam');
        // Refresh modal
        if (adminInfaqSelectedDate) {
            setTimeout(function() { adminInfaqOpenDate(adminInfaqSelectedDate); }, 300);
        }
    }).catch(function(err) {
        alert('❌ Ralat: ' + err.message);
    });
}

function adminInfaqAddManual(dateKey, slotKey, slotLabel) {
    var nama = prompt('👤 Nama penaja:');
    if (!nama || !nama.trim()) return;
    
    var wa = prompt('📞 No WhatsApp (contoh: 0123456789):');
    if (!wa || !wa.trim()) wa = '';
    
    var jenis = prompt('Jenis infaq: taip "duit" atau "makanan"');
    if (!jenis) return;
    jenis = jenis.toLowerCase().trim();
    if (jenis !== 'duit' && jenis !== 'makanan') {
        alert('❌ Sila taip "duit" atau "makanan" sahaja');
        return;
    }
    
    var jumlah = '', menu = '';
    if (jenis === 'duit') {
        jumlah = prompt('💰 Jumlah RM:') || '';
    } else {
        menu = prompt('🍱 Menu makanan:') || '';
    }

    var record = {
        nama: nama.trim(),
        whatsapp: wa.trim(),
        jenis: jenis === 'duit' ? 'Duit' : 'Makanan',
        jumlah: jumlah,
        menu: menu,
        catatan: 'Tambah manual oleh admin',
        dedah: true,
        dateKey: dateKey,
        slot: slotKey,
        slotLabel: slotLabel,
        status: 'confirmed',
        timestamp: Date.now(),
        createdAt: new Date().toISOString(),
        sertakanDoa: false,
        source: 'manual'
    };

    firebase.database().ref('infaq/' + dateKey + '_' + slotKey).set(record).then(function() {
        showToast('✅ Slot ditambah');
        if (adminInfaqSelectedDate) {
            setTimeout(function() { adminInfaqOpenDate(adminInfaqSelectedDate); }, 300);
        }
    }).catch(function(err) {
        alert('❌ Ralat: ' + err.message);
    });
}

// 🍳 Helper: Escape HTML untuk elak XSS
function escapeHtmlAdmin(str) {
    if (!str && str !== 0) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// 🍳 Helper: Navigate ke tab "Jadual Menu" (Dapur)
function adminInfaqGotoDapurTab() {
    adminInfaqCloseModal();
    // Switch ke kategori dapur
    if (typeof switchAdminCategory === 'function') {
        switchAdminCategory('dapur');
        setTimeout(function() {
            // Cari button tab "Jadual Menu"
            var dapurTabBtn = document.querySelector('[onclick*="dapur"][onclick*="switchTab"]') ||
                              document.querySelector('.tab-btn[onclick*="dapur"]');
            if (dapurTabBtn) dapurTabBtn.click();
            showToast('🍳 Beralih ke Jadual Menu Dapur');
        }, 300);
    } else {
        showToast('⚠️ Sila navigate ke: Dapur & Menu → Jadual Menu');
    }
}

function formatInfaqDate(dateKey) {
    const [y, m, d] = dateKey.split('-');
    const months = ['Jan','Feb','Mac','Apr','Mei','Jun','Jul','Ogos','Sep','Okt','Nov','Dis'];
    return `${d} ${months[parseInt(m)-1]} ${y}`;
}

function cleanInfaqPhone(phone) {
    if (!phone) return '';
    let p = String(phone).replace(/[^0-9]/g, '');
    if (!p) return '';
    if (p.startsWith('0')) p = '6' + p;
    if (!p.startsWith('60')) p = '60' + p;
    return p;
}

function confirmInfaq(key) {
    if (!confirm('Confirm infaq ini?')) return;
    firebase.database().ref('infaq/' + key + '/status').set('confirmed').then(() => {
        showToast('✅ Infaq confirmed');
    });
}

function rejectInfaq(key) {
    if (!confirm('Reject infaq ini? Slot akan kekal ditutup.')) return;
    firebase.database().ref('infaq/' + key + '/status').set('rejected').then(() => {
        showToast('❌ Infaq rejected');
    });
}

function unconfirmInfaq(key) {
    if (!confirm('Batal confirmation? Kembali ke pending.')) return;
    firebase.database().ref('infaq/' + key + '/status').set('pending').then(() => {
        showToast('↩️ Kembali ke pending');
    });
}

function reopenInfaq(key) {
    if (!confirm('Buka semula? Kembali ke pending.')) return;
    firebase.database().ref('infaq/' + key + '/status').set('pending').then(() => {
        showToast('↩️ Dibuka semula');
    });
}

function deleteInfaq(key) {
    if (!confirm('⚠️ Padam rekod infaq ini secara kekal? Slot akan jadi kosong semula.')) return;
    firebase.database().ref('infaq/' + key).remove().then(() => {
        showToast('🗑️ Rekod dipadam');
    });
}

function waPenaja(key) {
    const item = infaqAdminData[key];
    if (!item) return;
    const phone = cleanInfaqPhone(item.whatsapp);
    const dateStr = formatInfaqDate(item.dateKey);
    let msg = `Assalamualaikum ${item.nama},\n\nBerkenaan infaq anda:\n📅 ${dateStr} - ${item.slotLabel}\n${item.jenis === 'Duit' ? '💰 RM' + item.jumlah : '🍱 ' + item.menu}\n\n`;
    
    if (item.sertakanDoa && item.doaData) {
        msg += `🤲 Niat Doa: ${item.doaData.jenisDoa}\n`;
        if (item.doaData.namaList && item.doaData.namaList.length > 0) {
            msg += `Nama: ${item.doaData.namaList.join(', ')}\n`;
        }
        msg += `\n`;
    }
    
    const url = `https://wa.me/${phone}?text=${encodeURIComponent(msg)}`;
    window.open(url, '_blank');
}

function exportInfaqCSV() {
    const items = Object.values(infaqAdminData);
    if (items.length === 0) {
        alert('Tiada data untuk export');
        return;
    }

    let csv = 'Tarikh,Waktu,Nama,WhatsApp,Jenis,Jumlah/Menu,Catatan,Jenis Doa,Nama Doa,Doa Khas,Status,Submit\n';
items.forEach(i => {
    const detail = i.jenis === 'Duit' ? `RM${i.jumlah}` : i.menu;
    const submitTime = new Date(i.timestamp).toLocaleString('ms-MY');
    const jenisDoa = i.doaData ? i.doaData.jenisDoa : '';
    const namaDoa = i.doaData && i.doaData.namaList ? i.doaData.namaList.join('; ') : '';
    const doaCustom = i.doaData ? (i.doaData.doaCustom || '') : '';
    csv += `"${i.dateKey}","${i.slotLabel}","${i.nama}","${i.whatsapp}","${i.jenis}","${detail}","${i.catatan || ''}","${jenisDoa}","${namaDoa}","${doaCustom}","${i.status}","${submitTime}"\n`;
});

    const blob = new Blob(['\uFEFF' + csv], {type: 'text/csv;charset=utf-8'});
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `infaq_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
    showToast('📥 CSV downloaded');
}

