// Toggle show/hide password dalam loginInfoModal
function toggleLoginInfoPass() {
    var el = document.getElementById('loginInfoPass');
    if (!el) return;
    var pass = el.dataset.pass;

    if (el.dataset.shown === '1') {
        el.textContent = '•'.repeat(pass.length);
        el.dataset.shown = '0';
    } else {
        el.textContent = pass;
        el.dataset.shown = '1';

        // Auto-hide selepas 10 saat
        setTimeout(function() {
            if (el && el.dataset.shown === '1') {
                el.textContent = '•'.repeat(pass.length);
                el.dataset.shown = '0';
            }
        }, 10000);
    }
}

// Copy text dari element ke clipboard
function copyLoginInfo(elementId, btn) {
    var el = document.getElementById(elementId);
    if (!el) return;

    // Kalau password, salin nilai sebenar (bukan dots)
    var textToCopy = el.dataset.pass || el.textContent;

    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(textToCopy).then(function() {
            var orig = btn.textContent;
            btn.textContent = '✅ Disalin';
            setTimeout(function() { btn.textContent = orig; }, 2000);
        });
    } else {
        // Fallback untuk browser lama
        var ta = document.createElement('textarea');
        ta.value = textToCopy;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
        var orig = btn.textContent;
        btn.textContent = '✅ Disalin';
        setTimeout(function() { btn.textContent = orig; }, 2000);
    }
}

